export const CARDS = [
  { id: 1, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "ちょれい", jp: "朝礼", id_text: "Apel pagi", desc: "Pertemuan wajib setiap pagi sebelum kerja. Ada 2 jenis: apel umum dan apel per jenis pekerjaan. Mandor:「朝礼には絶対遅れるな」(jangan pernah telat apel pagi)." },
  { id: 2, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "きけんよちかつどうかつどう", jp: "危険予知活動（KY活動）", id_text: "Kegiatan Prediksi Bahaya (KY)", desc: "Kegiatan identifikasi bahaya sebelum mulai bekerja, dilakukan saat apel per jenis pekerjaan. Mandor:「KY表はちゃんと書けよ」(isi formulir KY dengan benar)." },
  { id: 3, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "らじおたいそう", jp: "ラジオ体操", id_text: "Senam radio", desc: "Senam pemanasan saat apel pagi untuk mencegah cedera. Wajib diikuti semua pekerja sebelum kerja dimulai. Mandor:「体操しっかりやれ、怪我の予防になる」(senam sungguh-sungguh, cegah cedera)." },
  { id: 4, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "ゆびさしこしょう", jp: "指差し呼称", id_text: "Tunjuk dan panggil", desc: "Metode konfirmasi keselamatan dengan menunjuk dan menyebut keras. Wajib digunakan setiap cek kondisi kerja. Mandor:「確認は必ず指差し呼称でやれよ」(konfirmasi wajib pakai tunjuk dan ucapkan)." },
  { id: 6, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうどうきじゅんほう", jp: "労働基準法", id_text: "UU Standar Ketenagakerjaan", desc: "UU standar kerja minimum: max 8 jam/hari & 40 jam/minggu. Lembur di atas batas wajib dibayar 割増賃金. Mandor:「8時間超えたら記録してくれ」(catat kalau lebih 8 jam, ada upah tambahan)." },
  { id: 7, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうどうあんぜんえいせいほう", jp: "労働安全衛生法", id_text: "UU Keselamatan dan Kesehatan Kerja", desc: "UU yang menjamin keselamatan dan kesehatan pekerja. Di lapangan: dasar aturan APD dan pendidikan K3. Mandor:「ヘルメットと安全帯は必ず着けてくれよ」(wajib pakai helm dan sabuk pengaman)." },
  { id: 8, category: "hourei", source: "jac-ch2", type: "hukum", furi: "さいていちんぎんほう", jp: "最低賃金法", id_text: "UU Upah Minimum", desc: "UU batas terendah upah yang boleh diberikan, ditetapkan per prefektur. Besaran berbeda tiap daerah. Mandor:「最低賃金以上は必ず払うよ」(pasti bayar di atas upah minimum daerah)." },
  { id: 9, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんせつぎょうほう", jp: "建設業法", id_text: "UU Industri Konstruksi", desc: "UU yang mengatur izin usaha, kontrak, dan tanggung jawab konstruksi. Perusahaan wajib punya izin per jenis pekerjaan. Mandor:「うちはちゃんと許可を持ってるから安心して」(punya izin resmi, tenang saja)." },
  { id: 10, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんちくきじゅんほう", jp: "建築基準法", id_text: "UU Standar Bangunan", desc: "UU standar minimum untuk membangun dan menggunakan bangunan. Semua pekerjaan wajib memenuhi standar ini. Mandor:「図面通りに施工しないと検査に通らないぞ」(tidak sesuai gambar, tidak lolos inspeksi)." },
  { id: 11, category: "hourei", source: "jac-ch2", type: "hukum", furi: "しょうぼうほう", jp: "消防法", id_text: "UU Pemadam Kebakaran", desc: "UU yang mengatur alat pemadam, sprinkler, dan alarm kebakaran. Di lapangan: posisi APAR wajib diketahui. Mandor:「消火器の場所は必ず覚えておけよ」(wajib hafal posisi APAR di lapangan)." },
  { id: 12, category: "hourei", source: "jac-ch2", type: "hukum", furi: "すいどうほう", jp: "水道法", id_text: "UU Air Bersih", desc: "UU yang mengatur usaha dan instalasi pasokan air bersih. Hanya insinyur berlisensi yang boleh mengerjakannya. Mandor:「水道工事は有資格者しかできないぞ」(hanya yang bersertifikat boleh kerja)." },
  { id: 13, category: "hourei", source: "jac-ch2", type: "hukum", furi: "でんきじぎょうほう", jp: "電気事業法", id_text: "UU Usaha Kelistrikan", desc: "UU standar konstruksi dan pemeliharaan fasilitas ketenagalistrikan. Dasar keamanan semua instalasi listrik. Mandor:「電気設備は専門業者に任せろ、触るな」(instalasi listrik serahkan ke ahlinya)." },
  { id: 14, category: "hourei", source: "jac-ch2", type: "hukum", furi: "でんきつうしんじぎょうほう", jp: "電気通信事業法", id_text: "UU Usaha Telekomunikasi", desc: "UU yang mengatur pemasangan jaringan dan peralatan telekomunikasi. Wajib dikerjakan insinyur berkualifikasi. Mandor:「通信配線は有資格者しか触れないぞ」(hanya yang bersertifikat boleh pegang)." },
  { id: 15, category: "hourei", source: "jac-ch2", type: "hukum", furi: "さぶろくきょうてい", jp: "36協定", id_text: "Perjanjian 36 (perjanjian lembur)", desc: "Perjanjian berdasar Pasal 36 UU Ketenagakerjaan yang membolehkan lembur. Tanpa ini, perusahaan tidak boleh minta lembur. Mandor:「36協定の範囲内で残業を頼むよ」(lembur sesuai batas perjanjian 36)." },
  { id: 16, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうさいほけん", jp: "労災保険", id_text: "Asuransi kecelakaan kerja", desc: "Asuransi negara untuk pekerja yang terluka, sakit, atau meninggal akibat kerja. Premi 100% ditanggung pemberi kerja. Mandor:「怪我したらすぐ報告してくれ」(cedera langsung lapor, ada asuransi kerja)." },
  { id: 17, category: "hourei", source: "jac-ch2", type: "hukum", furi: "まにえすと", jp: "マニフェスト", id_text: "Manifest (lembar kontrol limbah konstruksi)", desc: "Dokumen wajib yang membuktikan limbah industri dibuang dengan benar. Kontraktor utama wajib membuatnya. Mandor:「産廃はマニフェスト書いてから出してくれよ」(tulis manifest dulu sebelum keluarkan limbah)." },
  { id: 18, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんせつりさいくるほう", jp: "建設リサイクル法", id_text: "UU Daur Ulang Konstruksi", desc: "UU yang mewajibkan pemilahan dan daur ulang limbah konstruksi. Sampah di lokasi wajib disimpan sesuai jenis (分別). Mandor:「ゴミは必ず分別してから置いとけよ」(sampah wajib dipilah sesuai jenis)." },
  { id: 19, category: "hourei", source: "jac-ch2", type: "hukum", furi: "こようほけんほう", jp: "雇用保険法", id_text: "UU Asuransi Ketenagakerjaan", desc: "UU yang mengatur tunjangan pengangguran bagi yang kehilangan pekerjaan. Premi ditanggung bersama pemberi kerja dan pekerja. Mandor:「雇用保険は失業した時のためだよ」(potongan asuransi itu persiapan kalau PHK)." },
  { id: 20, category: "hourei", source: "jac-ch2", type: "hukum", furi: "がすじぎょうほう", jp: "ガス事業法", id_text: "UU Usaha Gas", desc: "UU yang mengatur usaha gas kota (都市ガス), berbeda dari gas LPG. Pekerjaan gas kota hanya oleh kontraktor berlisensi khusus. Mandor:「都市ガス工事は専門業者に任せろ」(serahkan ke kontraktor berlisensi khusus)." },
  { id: 21, category: "hourei", source: "jac-ch2", type: "hukum", furi: "げすいどうほう", jp: "下水道法", id_text: "UU Saluran Air Limbah", desc: "UU yang mengatur sistem saluran pembuangan air limbah kota. Instalasi gedung wajib terhubung ke sistem pembuangan resmi. Mandor:「排水は直接側溝に流すな、下水へ」(air limbah jangan ke parit, ke saluran resmi)." },
  { id: 22, category: "hourei", source: "jac-ch2", type: "hukum", furi: "はいきぶものしょりほう", jp: "廃棄物処理法", id_text: "UU Pengelolaan Limbah", desc: "UU yang mengatur pengelolaan dan pembuangan limbah industri. Manifest wajib dibuat kontraktor utama sebelum limbah diangkut. Mandor:「産廃は許可業者しか運べないぞ」(limbah industri hanya oleh yang berizin)." },
  { id: 23, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうさいかくし", jp: "労災かくし", id_text: "Penyembunyian kecelakaan kerja — KEJAHATAN", desc: "Menyembunyikan kecelakaan kerja dari kantor inspeksi adalah kejahatan. Setiap kecelakaan wajib segera dilaporkan. Mandor:「労災を隠すのは犯罪だ、必ず報告しろよ」(menyembunyikan kecelakaan adalah kejahatan)." },
  { id: 24, category: "hourei", source: "jac-ch2", type: "hukum", furi: "でんきこうじぎょうほう", jp: "電気工事業法", id_text: "UU Pekerjaan Listrik (≠ UU Kelistrikan)", desc: "UU yang mengatur kontraktor pekerjaan listrik, berbeda dari 電気事業法. Kontraktor listrik wajib terdaftar terpisah. Mandor:「電気工事業の登録なしには工事できないぞ」(tanpa registrasi, tidak boleh kerja)." },
  { id: 25, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんせつぎょうほうのにじゅうきゅうぎょうしゅ", jp: "建設業法の29業種", id_text: "29 jenis usaha yang perlu izin konstruksi", desc: "29 jenis usaha konstruksi yang memerlukan izin sesuai 建設業法. Termasuk listrik, pipa, insulasi termal, telekomunikasi, dll. Mandor:「業種ごとに許可を取らないといけないんだ」(izin harus diambil per jenis pekerjaan)." },
  { id: 26, category: "hourei", source: "jac-ch2", type: "hukum", furi: "あすべすと", jp: "アスベスト（石綿）", id_text: "Asbes — DILARANG", desc: "Mineral serat berbahaya yang dilarang karena menyebabkan kanker paru. Bangunan lama yang dicurigai asbes wajib disurvei sebelum dibongkar. Mandor:「アスベストが疑われる建物は素手で触るな」(jangan pegang tangan kosong)." },
  { id: 27, category: "hourei", source: "jac-ch2", type: "hukum", furi: "たいきおせんぼうしほう", jp: "大気汚染防止法", id_text: "UU Pencegahan Polusi Udara", desc: "UU pencegahan polusi udara. Bongkar gedung berisi asbes wajib lapor ke gubernur prefektur 14 hari sebelumnya. Mandor:「アスベスト解体は14日前に知事への届出が必要だ」(lapor gubernur 14 hari sebelum mulai)." },
  { id: 28, category: "setsubi_kougu", source: "jac-ch3", type: "konsep", furi: "らいふらいんこうじ", jp: "ライフライン工事", id_text: "Pekerjaan lifeline", desc: "Pekerjaan utilitas vital: listrik, gas kota, suplai air, drainase, dan telekomunikasi. Mandor:「ライフラインの工事中は近隣への影響に注意して」(perhatikan dampak ke sekitar saat pengerjaan utilitas)." },
  { id: 29, category: "sekou", source: "jac-ch3", type: "konsep", furi: "せつびこうじ", jp: "設備工事", id_text: "Pekerjaan peralatan", desc: "Meliputi peralatan AC, peralatan kebersihan suplai air & drainase, pekerjaan menjaga suhu, dan peralatan pemadam kebakaran." },
  { id: 30, category: "denki", source: "jac-ch3", type: "konsep", furi: "でんきこうじ", jp: "電気工事", id_text: "Pekerjaan listrik", desc: "Listrik dari pembangkit → gardu → tiang/bawah tanah → gedung. 'Sengatan listrik' adalah kecelakaan khas pekerjaan ini." },
  { id: 31, category: "haikan", source: "jac-ch3", type: "konsep", furi: "としがすこうじ", jp: "都市ガス工事", id_text: "Pekerjaan gas kota", desc: "Aliran gas kota: LNG → tangki → pipa bawah tanah → distribusi ke pabrik/rumah. Mandor:「ガス管の近くは火気厳禁です」(dilarang keras ada api di dekat pipa gas)." },
  { id: 32, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "きゅうはいすいこうじ", jp: "給排水工事", id_text: "Pekerjaan suplai air dan drainase", desc: "Suplai: air sungai → pemurnian → reservoir → pipa. Drainase: limbah gedung → pipa → instalasi pengolahan." },
  { id: 33, category: "tsushin", source: "jac-ch3", type: "konsep", furi: "つうしんこうじ", jp: "通信工事", id_text: "Pekerjaan telekomunikasi", desc: "Pembangunan jaringan telepon & internet menggunakan kabel logam atau serat optik. Mandor:「通信ケーブルは傷つけないよう注意して」(hati-hati jangan sampai kabel komunikasi rusak)." },
  { id: 34, category: "setsubi_kougu", source: "jac-ch3", type: "konsep", furi: "くうちょうせつびこうじ", jp: "空調設備工事", id_text: "Pekerjaan AC & pendingin udara", desc: "Pemasangan sistem pengatur suhu, kelembapan, dan pemurnian udara dalam ruangan. Mandor:「空調設備の試運転前に配管の確認をして」(periksa pipa sebelum uji coba sistem AC)." },
  { id: 35, category: "shoubou", source: "jac-ch3", type: "konsep", furi: "しょうぼうせつびこうじ", jp: "消防設備工事", id_text: "Pekerjaan peralatan pemadam kebakaran", desc: "Pemasangan sistem proteksi kebakaran: alarm, sprinkler, dan pompa pemadam. Mandor:「消防設備は定期点検が義務です」(inspeksi berkala sistem pemadam adalah kewajiban)." },
  { id: 36, category: "hoon", source: "jac-ch3", type: "konsep", furi: "ほおんほれいこうじ", jp: "保温保冷工事", id_text: "Pekerjaan isolasi termal panas & dingin", desc: "Memasang bahan isolasi termal pada saluran & pipa. 保温 (panas): mengurangi kehilangan panas & mencegah luka bakar dari pipa panas. 保冷 (dingin): mencegah kondensasi & kehilangan suhu dingin." },
  { id: 37, category: "haikan", source: "jac-ch3", type: "konsep", furi: "きゅうはいすいえいせいせつびこうじ", jp: "給排水衛生設備工事", id_text: "Pekerjaan sanitasi suplai air & drainase", desc: "Memasang peralatan untuk menjaga kebersihan lingkungan tempat tinggal menggunakan air dan air panas." },
  { id: 38, category: "setsubi_kougu", source: "jac-jitsugi2", type: "konsep", furi: "かしつきじょしつき", jp: "加湿器 vs 除湿器", id_text: "Pelembap udara vs Penyerap kelembapan", desc: "加湿器 = MENAMBAH kelembapan ke udara kering. 除湿器 = MENGURANGI kelembapan. 冷却コイル = koil pendingin." },
  { id: 39, category: "setsubi_kougu", source: "jac-jitsugi2", type: "konsep", furi: "ちくろこうじ", jp: "築炉工事（耐火物）", id_text: "Pekerjaan konstruksi tungku — bahan tahan api", desc: "Melapisi bagian dalam tungku/kiln yang suhu tinggi dengan BAHAN TAHAN API (耐火物). Perekat bata = 耐熱断熱煉瓦用モルタル. BUKAN 保温材/断熱材 biasa." },
  { id: 40, category: "haikan", source: "jac-jitsugi2", type: "konsep", furi: "まるだくとさしこみつぎてこうほう", jp: "丸ダクト", id_text: "Saluran udara bulat → sambungan selip/insert", desc: "丸ダクト (round duct): pakai 差し込み継手工法 (insert joint). 角ダクト (square duct): pakai 共板フランジ工法 (flange)." },
  { id: 41, category: "sekou", source: "jac-ch6", type: "konsep", furi: "じゅちゅういっぴんせいさん", jp: "受注一品生産", id_text: "Produksi pesanan satu-per-satu", desc: "Karakteristik khas konstruksi: setiap proyek dibuat sesuai permintaan klien dari awal, berbeda dari produksi pabrik." },
  { id: 42, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんばあじょん", jp: "コンバージョン", id_text: "Konversi bangunan", desc: "Memanfaatkan struktur bangunan yang sudah ada untuk diubah ke fungsi baru. Contoh: kantor → apartemen." },
  { id: 43, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "あとせこうあんかあ", jp: "あと施工アンカー", id_text: "Angkur pasca-cor", desc: "Angkur yang dipasang pada beton yang sudah mengeras. Ada 2 jenis: 金属系 (metal) dan 接着系 (adhesive/resin)." },
  { id: 44, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "けいりょうてっこつじゅりょうてっこつ", jp: "軽量鉄骨（LGS） vs 重量鉄骨", id_text: "Baja ringan (LGS <6mm) vs baja berat (≥6mm)", desc: "Baja ringan (軽量鉄骨/LGS): tebal <6mm — untuk rangka dinding/plafon. Baja berat (重量鉄骨): ≥6mm — struktur utama gedung." },
  { id: 45, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "ぶれすらあめんとらす", jp: "鉄骨構造の種類（ブレース・ラーメン・トラス）", id_text: "Struktur baja: brace / ramen / truss", desc: "①ブレース: diagonal brace. ②ラーメン: rigid joint kolom-balok → tahan gempa. ③トラス: susunan segitiga → atap/jembatan." },
  { id: 46, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "たてにげすいへいつまげ", jp: "建て逃げ方式 vs 水平積み上げ方式", id_text: "Pemasangan baja: mobile crane vs tower crane", desc: "①建て逃げ: mobile crane, dari belakang ke depan. ②水平積み上げ: tower crane, lantai per lantai → gedung pencakar langit." },
  { id: 47, category: "doboku_hoso", source: "jac-ch4", type: "konsep", furi: "てんあつ", jp: "転圧（てんあつ）", id_text: "Pemadatan dengan roller", desc: "Proses memadatkan tanah/aspal menggunakan roller. Digunakan dalam pekerjaan perkerasan jalan (舗装工事)." },
  { id: 48, category: "doboku_hoso", source: "jac-ch3", type: "konsep", furi: "ろしょうろばんひょうそう", jp: "路床・路盤・表層（舗装工事の層構造）", id_text: "Lapisan jalan: subgrade / base / surface", desc: "Dari bawah: ①路床 (subgrade, digali ±1m) ②路盤 (batu pecah, dipadatkan roller) ③表層 (aspal atas, tahan air)." },
  { id: 49, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "やりかたみずぬきみずもり", jp: "遣り方（やりかた）・水貫・水盛り", id_text: "Setting out bangunan — tiang & papan referensi", desc: "遣り方: rangka sementara tiang kayu + papan horizontal (水貫) untuk menentukan posisi & ketinggian bangunan. Di sipil disebut '丁張り'." },
  { id: 50, category: "sekou", source: "jac-jitsugi1", type: "konsep", furi: "せこうかんりしょていのひんしつ", jp: "施工管理", id_text: "Manajemen konstruksi — kualitas yang ditentukan", desc: "所定の品質。施工管理とは、施工計画に基づいて、施工者が、所定の【品質】の工事目的物を完成させるために必要な管理のことである。Kata kunci: 品質 (kualitas), bukan 環境 (lingkungan)." },
  { id: 51, category: "denki", source: "jac-ch5", type: "konsep", furi: "けんでんき", jp: "検電器", id_text: "Detektor tegangan", desc: "Alat untuk memeriksa apakah ada muatan listrik atau tidak. Ada untuk tegangan rendah dan tegangan tinggi." },
  { id: 52, category: "denki", source: "jac-ch5", type: "konsep", furi: "けんそうき", jp: "検相器", id_text: "Detektor fase", desc: "Alat cek urutan fase sistem 3-fase — menentukan arah rotasi motor. Mandor:「モーター接続前に検相器で確認して」(cek urutan fase sebelum sambung motor)." },
  { id: 53, category: "denki", source: "jac-ch5", type: "konsep", furi: "てすたあばにょうけい", jp: "テスター / 万用計", id_text: "Tester / Multimeter", desc: "Alat ukur voltase, arus, dan resistansi pada rangkaian listrik. Mandor:「テスターで断線していないか確認して」(cek putus-tidaknya rangkaian dengan tester)." },
  { id: 54, category: "denki", source: "jac-ch5", type: "konsep", furi: "くらんぷめえたあ", jp: "クランプメーター", id_text: "Clamp meter", desc: "Alat ukur arus listrik cukup dengan menjepit kabel tanpa memutus rangkaian. Mandor:「クランプメーターで負荷電流を測って」(ukur arus beban dengan clamp meter)." },
  { id: 55, category: "denki", source: "jac-ch5", type: "konsep", furi: "でんせんかん", jp: "電線管", id_text: "Conduit (pelindung kabel)", desc: "Pipa dari logam atau resin sintetis yang menampung kabel listrik di dalamnya. Ada pipa E, C, G, PF, CD, dll." },
  { id: 56, category: "denki", source: "jac-ch5", type: "konsep", furi: "ふれきしぶるかん", jp: "フレキシブル管", id_text: "Conduit fleksibel", desc: "Conduit fleksibel yang bisa ditekuk bebas — jenis logam dan resin (PF/CD). Mandor:「機器の接続部にはフレキを使って」(pakai flexible conduit di bagian koneksi alat)." },
  { id: 57, category: "denki", source: "jac-ch5", type: "konsep", furi: "ぷるぼっくす", jp: "プルボックス", id_text: "Pull box", desc: "Kotak junction untuk menghubungkan dan mencabangkan kabel — jenis logam dan resin. Mandor:「プルボックスのサイズを図面で確認して」(cek ukuran pull box di gambar kerja)." },
  { id: 58, category: "denki", source: "jac-ch5", type: "konsep", furi: "けえぷるらっく", jp: "ケーブルラック", id_text: "Rak kabel", desc: "Rak berbentuk tangga untuk mengelola berbagai jenis kabel sekaligus. Kait kabel digunakan jika jumlah kabel sedikit." },
  { id: 59, category: "denki", source: "jac-ch5", type: "konsep", furi: "っけえぷる", jp: "VVFケーブル", id_text: "Kabel VVF", desc: "Kabel listrik berisolasi vinil berbentuk datar untuk instalasi rumah/gedung. Mandor:「VVFは露出配線に使わないで」(jangan pakai VVF untuk kabel tampak permukaan)." },
  { id: 60, category: "denki", source: "jac-ch4", type: "konsep", furi: "あっちゃくたんし", jp: "圧着端子", id_text: "Terminal crimping", desc: "Terminal untuk menghubungkan kabel listrik ke peralatan. Dikencangkan dengan memberikan tekanan (crimping)." },
  { id: 61, category: "denki", source: "jac-jitsugi1", type: "konsep", furi: "ぶれえかあ", jp: "ブレーカー（NFB）", id_text: "Pemutus arus listrik (breaker)", desc: "Otomatis menghentikan pasokan listrik saat arus berlebih mengalir di sirkuit. NFB = No-Fuse Breaker." },
  { id: 62, category: "denki", source: "jac-ch5", type: "konsep", furi: "せっちぼう", jp: "接地棒", id_text: "Batang pentanahan (grounding rod)", desc: "Batang baja berlapis yang ditancapkan ke tanah untuk sistem pentanahan (grounding). Mandor:「接地棒は規定の深さまで打ち込んで」(tancapkan batang grounding sampai kedalaman yang ditentukan)." },
  { id: 63, category: "denki", source: "jac-ch5", type: "konsep", furi: "はんどほおる", jp: "ハンドホール", id_text: "Handhole", desc: "Kotak akses untuk kabel listrik dan komunikasi bawah tanah — lebih kecil dari manhole. Mandor:「ハンドホールの蓋はしっかり閉めて」(tutup rapat penutup handhole setelah selesai)." },
  { id: 64, category: "denki", source: "jac-ch3", type: "konsep", furi: "はいでんばん", jp: "配電盤", id_text: "Panel distribusi listrik", desc: "Perangkat untuk mencabangkan catu daya dan memasok listrik ke setiap perangkat. Ada papan mandiri dan papan dinding." },
  { id: 65, category: "denki", source: "jac-jitsugi1", type: "konsep", furi: "たんらく", jp: "短絡（たんらく）", id_text: "Hubungan arus pendek (short circuit)", desc: "2 kabel atau lebih bersentuhan TANPA melalui beban. Berbeda dari 漏電 (arus bocor) dan 感電 (sengatan listrik). Bisa menyebabkan kebakaran." },
  { id: 66, category: "denki", source: "jac-jitsugi1", type: "konsep", furi: "でんこうないふ", jp: "電工ナイフ", id_text: "Pisau listrik (electrician's knife)", desc: "Pisau untuk mengupas isolasi kabel. Bilah melengkung, ujung TUMPUL (mencegah merusak konduktor). Sering diuji lewat FOTO." },
  { id: 67, category: "tsushin", source: "jac-jitsugi2", type: "konsep", furi: "ひかりあいばあ", jp: "光ファイバー", id_text: "Serat optik", desc: "Serat tipis & ringan, kapasitas transmisi besar, rugi-rugi kecil (損失が小さい), non-induktif. Kelemahan: rentan goresan & tekukan." },
  { id: 68, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ひかりあいばあけえぷる", jp: "光ファイバーケーブル", id_text: "Kabel serat optik", desc: "Kabel serat optik yang dibundel — tersedia mulai 20 hingga 400 inti. Mandor:「光ファイバーは曲げ半径に注意して」(perhatikan radius tekukan kabel fiber optik)." },
  { id: 69, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "どじくけえぷる", jp: "同軸ケーブル", id_text: "Kabel koaksial", desc: "Kabel dengan konduktor di tengah, dilindungi isolator & konduktor luar. Digunakan untuk kabel antena TV." },
  { id: 70, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "うけえぷる", jp: "UTPケーブル", id_text: "Kabel UTP twisted pair", desc: "Kabel 2 konduktor yang dipilin berpasangan. Lebih murah & lembut dari koaksial. Digunakan untuk telepon atau jaringan." },
  { id: 71, category: "tsushin", source: "jac-jitsugi2", type: "konsep", furi: "ゆうちゃくせつぞくき", jp: "融着接続機", id_text: "Alat penyambung fusi serat optik", desc: "Mesin yang MELELEHKAN dan menyambungkan ujung 2 kabel serat optik." },
  { id: 72, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ひかりこねくた", jp: "光コネクタ", id_text: "Konektor optik", desc: "Bagian untuk menyambungkan kabel serat optik. Dapat dimasukkan & dilepas dengan tangan. Jenis: SC, FC, LC, MU." },
  { id: 73, category: "tsushin", source: "jac-jitsugi2", type: "konsep", furi: "おおちあちめどまいんれえとめて", jp: "OTDR", id_text: "Alat uji pulsa optik", desc: "Mengukur panjang jalur serat optik dan mendeteksi titik abnormal (rugi-rugi sambungan, pantulan)." },
  { id: 74, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "るうたあ", jp: "ルーター", id_text: "Router", desc: "Perangkat jaringan yang menghubungkan dan memisahkan beberapa jaringan berbeda. Mandor:「ルーターの設置場所を監督に確認して」(konfirmasi lokasi pemasangan router ke supervisor)." },
  { id: 75, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "すいちんぐはぶ", jp: "スイッチングハブ", id_text: "Switching hub", desc: "Perangkat relai jaringan yang memeriksa alamat dan mengirimkan data hanya ke perangkat yang diperlukan." },
  { id: 76, category: "tsushin", source: "jac-jitsugi2", type: "konsep", furi: "ゆうちゃく vs こねくた vs めかにかるすぷらいす", jp: "融着 vs コネクタ vs メカニカル", id_text: "3 metode penyambungan serat optik", desc: "①融着接続: MELELEHKAN ujung serat → permanen, rugi terkecil. ②コネクタ接続: konektor, bisa lepas-pasang. ③メカニカルスプライス: mekanis, lebih cepat dari fusion." },
  { id: 77, category: "tsushin", source: "jac-jitsugi2", type: "konsep", furi: "かんろ", jp: "管路（かんろ）", id_text: "Sistem jalur kabel bawah tanah", desc: "Menghubungkan manhole, handhole, とう道 (terowongan), dan 引上柱 (tiang pengangkat). Kedalaman di jalan raya >0.8m." },
  { id: 78, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "あいいばあかったあ", jp: "ファイバーカッター（光ファイバー用）", id_text: "Pemotong serat optik (presisi)", desc: "Memotong serat optik secara presisi, tegak lurus sempurna agar fusion bersih. Berbeda dari ファイバーカッター untuk kain/plastik." },
  { id: 79, category: "tsushin", source: "jac-jitsugi2", type: "konsep", furi: "てぼりあなほりけんちゅうしゃたんしんぼう", jp: "手掘り・穴掘建柱車・探針棒（埋設物確認）", id_text: "Gali manual + kendaraan tiang + probe rod", desc: "Sebelum menggali lubang untuk tiang listrik → gunakan 手掘り (gali manual) DAN 探針棒 (batang probe) untuk konfirmasi benda terpendam. 穴掘建柱車 = kendaraan khusus penggali & pendiri tiang." },
  { id: 80, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ひかりぱわあめえたあ", jp: "光パワーメーター", id_text: "Pengukur daya optik (optical power meter)", desc: "Mengukur kekuatan sinyal cahaya (daya) pada kabel serat optik. Berbeda dari OTDR yang mengukur panjang jalur & titik abnormal." },
  { id: 81, category: "tsushin", source: "jac-ch4", type: "konsep", furi: "きょうどうこう", jp: "共同溝（きょうどうこう）", id_text: "Terowongan utilitas bersama (common utility duct)", desc: "Saluran bawah tanah besar yang menampung BERBAGAI jenis kabel/pipa utilitas sekaligus (listrik, komunikasi, dll). Berbeda dari 管路 (kanro) yang menghubungkan manhole satu ke lainnya." },
  { id: 82, category: "haikan", source: "jac-ch5", type: "konsep", furi: "たんそこうこうかん", jp: "炭素鋼鋼管（SGP）", id_text: "Pipa baja karbon (SGP)", desc: "Pipa baja untuk uap, air, minyak, gas, dan udara. Ada tabung putih (berlapis) dan tabung hitam (tanpa lapisan). Sambungan ulir untuk 15A–100A." },
  { id: 83, category: "haikan", source: "jac-ch5", type: "konsep", furi: "こうしつえんかびにるかんう", jp: "硬質塩化ビニル管（VP/VU）", id_text: "Pipa PVC keras (VP/VU)", desc: "Pipa PVC abu-abu: VP=tebal, VU=tipis. Ringan dan halus tapi rentan benturan dan panas. Mandor:「VPとVUを間違えないように確認して」(pastikan tidak keliru antara VP dan VU)." },
  { id: 84, category: "haikan", source: "jac-ch5", type: "konsep", furi: "たいしょうげっきせいえんびかん", jp: "耐衝撃性塩ビ管（HIVP）", id_text: "Pipa HIVP (PVC tahan benturan)", desc: "Pipa PVC berwarna biru tua yang tahan benturan eksternal. Digunakan di tempat benturan besar dan daerah dingin." },
  { id: 85, category: "haikan", source: "jac-ch5", type: "konsep", furi: "だくたいるちゅうてつかん", jp: "ダクタイル鋳鉄管", id_text: "Pipa besi cor ulet", desc: "Grafit berbentuk bola (球状黒鉛) → kekuatan & ketangguhan lebih tinggi dari besi cor biasa. Relatif berat. Aliran utama sejak 1955." },
  { id: 86, category: "haikan", source: "jac-ch5", type: "konsep", furi: "どうかん", jp: "銅管", id_text: "Pipa tembaga", desc: "Pipa tembaga tanpa sambungan, digunakan untuk jalur refrigeran AC indoor-outdoor. Mandor:「銅管は傷つけないよう丁寧に扱って」(tangani pipa tembaga dengan hati-hati agar tidak lecet)." },
  { id: 87, category: "haikan", source: "jac-ch6", type: "konsep", furi: "しいるてえぷ", jp: "シールテープ", id_text: "Sealant tape", desc: "Pita untuk mencegah kebocoran pada sambungan ulir pipa. Digulung searah jarum jam, menyisakan 1 ulir, ~6-7 gulungan." },
  { id: 88, category: "haikan", source: "jac-jitsugi1", type: "konsep", furi: "ぱいぷかったあ", jp: "パイプカッター", id_text: "Pemotong pipa", desc: "Alat untuk memotong pipa baja, kuningan, tembaga. Roda pemotong menjepit dan memotong melingkar. Sering diuji lewat FOTO." },
  { id: 89, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ぱいぷれんち", jp: "パイプレンチ（ピレン）", id_text: "Kunci pipa (piren)", desc: "Tang pipa untuk mencengkeram dan memutar pipa bulat saat penyambungan. Mandor:「パイプレンチは正しい方向に使って」(gunakan pipe wrench ke arah yang benar)." },
  { id: 90, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ねじきりき", jp: "ねじ切り機", id_text: "Mesin ulir pipa (threading machine)", desc: "Mesin untuk membuat ulir pada pipa baja. JANGAN pakai sarung tangan saat threading!" },
  { id: 92, category: "haikan", source: "jac-ch5", type: "konsep", furi: "すりいぶ", jp: "スリーブ", id_text: "Selongsong (sleeve)", desc: "Tabung silinder dipasang pada dinding/lantai/balok untuk melewatkan pipa. Dibenamkan sebelum cor beton." },
  { id: 93, category: "haikan", source: "jac-ch5", type: "konsep", furi: "えるぼ", jp: "エルボ", id_text: "Siku (elbow)", desc: "Sambungan pipa yang mengubah arah aliran 45° atau 90°. Mandor:「エルボの向きを図面で確認してから取り付けて」(cek arah elbow di gambar sebelum pasang)." },
  { id: 94, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ちいず", jp: "チーズ（チー）", id_text: "Tee", desc: "Sambungan pipa tiga arah untuk membuat cabang aliran. Mandor:「チーズのサイズは配管径に合わせて」(sesuaikan ukuran tee dengan diameter pipa)." },
  { id: 95, category: "haikan", source: "jac-jitsugi2", type: "konsep", furi: "ぽりえちれんかんえせつごう", jp: "ポリエチレン管（EF接合）", id_text: "Pipa polietilen — sambungan EF (Electro Fusion)", desc: "Digunakan untuk pipa suplai air bersih dan pipa gas. Sambungan khas: EF接合 (Electro Fusion = fusi listrik). Berbeda dari SGP yang pakai ねじ接合." },
  { id: 96, category: "haikan", source: "jac-jitsugi1", type: "konsep", furi: "ねじせつごうあからあ", jp: "SGP ねじ接合", id_text: "Pipa SGP — sambungan ulir untuk 15A～100A", desc: "Metode penyambungan utama SGP = ねじ接合 (sambungan ulir), digunakan untuk ukuran 15A～100A. Di atas 100A → sambungan flensa/las." },
  { id: 97, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ぱいぷまんりき", jp: "パイプ万力（ぱいぷまんりき）", id_text: "Ragum pipa (pipe vise)", desc: "Alat penjepit/penahan pipa agar tidak bergerak saat dikerjakan (disambung, dipotong, dibuat ulir). Berbeda dari パイプレンチ yang untuk memutar/menyambung pipa." },
  { id: 98, category: "hoon", source: "jac-ch3", type: "konsep", furi: "ぐらすううるだんねつざい", jp: "グラスウール断熱材", id_text: "Bahan isolasi wol kaca", desc: "KACA dilebur → serat tipis. Fleksibel, tahan panas, tidak mudah terbakar. Tersedia bentuk tabung, sabuk, & pelat." },
  { id: 99, category: "hoon", source: "jac-ch3", type: "konsep", furi: "ろっくううるだんねつざい", jp: "ロックウール断熱材", id_text: "Bahan isolasi wol batu", desc: "Basalt/andesit dilebur → serat. Ketahanan api LEBIH BAIK dari wol kaca. Juga digunakan sebagai pengisi tahan api." },
  { id: 100, category: "hoon", source: "jac-ch5", type: "konsep", furi: "はっぽうすちろるだんねつざい", jp: "発泡スチロール断熱材 / ポリスチレンフォーム", id_text: "Bahan isolasi busa polistiren", desc: "Insulasi polistirena — tidak tahan suhu ≥70°C, umum dipakai untuk pipa air dan drainase. Mandor:「高温配管には発泡スチロールは使えません」(insulasi styrofoam tidak boleh untuk pipa suhu tinggi)." },
  { id: 101, category: "hoon", source: "jac-ch6", type: "konsep", furi: "れいばいかんひふくどうかん", jp: "冷媒管（被覆銅管）", id_text: "Pipa refrigeran (pipa tembaga berlapis)", desc: "Pipa yang membawa refrigeran antara unit indoor & outdoor AC. Ditutupi bahan isolasi termal tahan api." },
  { id: 102, category: "hoon", source: "jac-jitsugi2", type: "konsep", furi: "ぐらすううるろっくううる", jp: "グラスウール vs ロックウール", id_text: "Wol kaca (dari kaca) vs wol batu (dari basalt)", desc: "perbedaan kunci。グラスウール: dari KACA dilebur jadi serat. ロックウール: dari BASALT/batu vulkanik, tahan api lebih baik. Ujian tanya: 'kaca dilelehkan jadi serat' → グラスウール." },
  { id: 103, category: "hoon", source: "jac-jitsugi2", type: "konsep", furi: "らっきんぐかばあ", jp: "ラッキングカバー", id_text: "Penutup luar isolasi pipa (lagging cover)", desc: "Penutup finishing pada isolasi pipa yang TEREKSPOS DI LUAR RUANGAN (屋外露出). Melapisi 保温筒 dari cuaca. Untuk dalam ruangan tidak wajib." },
  { id: 104, category: "hoon", source: "jac-ch5", type: "konsep", furi: "けいさんかるしうむほおんざい", jp: "けい酸カルシウム保温材", id_text: "Bahan isolasi kalsium silikat", desc: "Bahan isolasi termal berbasis kalsium silikat. Digunakan untuk pipa/peralatan suhu tinggi. Bukan untuk pipa air biasa. Muncul sebagai opsi pengecoh di soal グラスウール vs ロックウール." },
  { id: 105, category: "shoubou", source: "jac-ch2", type: "konsep", furi: "しょうかいき", jp: "消火器", id_text: "Alat pemadam api (APAR)", desc: "Perangkat portabel untuk memadamkan api di tahap awal kebakaran. Dipasang di setiap lokasi konstruksi sesuai 消防法. Mandor:「消火器の場所と使い方を必ず覚えておけよ」(wajib tahu posisi dan cara pakai APAR)." },
  { id: 106, category: "shoubou", source: "jac-ch5", type: "konsep", furi: "すぷりんくらあせつび", jp: "スプリンクラー設備", id_text: "Peralatan sprinkler", desc: "Alat yang dipasang pada pipa pemadam dan memercikkan air otomatis dari plafon jika terjadi kebakaran." },
  { id: 107, category: "shoubou", source: "jac-jitsugi1", type: "konsep", furi: "おくがいしょうかいせんせつび", jp: "屋外消火栓設備", id_text: "Hidran kebakaran LUAR ruangan", desc: "Dipasang di LUAR gedung. Untuk pemadaman awal & mencegah api menyebar ke bangunan berdekatan (jangkauan lantai 1-2). Sering diuji lewat FOTO." },
  { id: 109, category: "shoubou", source: "jac-ch5", type: "konsep", furi: "ふんまつしょうかせつび", jp: "粉末消火設備", id_text: "Peralatan pemadam api bubuk", desc: "Menggunakan bahan pemadam bubuk. Cocok untuk kebakaran minyak dan kebakaran peralatan listrik berenergi." },
  { id: 110, category: "shoubou", source: "jac-jitsugi1", type: "konsep", furi: "おくがいおくないしょうかいせん", jp: "屋外消火栓 vs 屋内消火栓", id_text: "Hidran LUAR vs DALAM — perbedaan kunci", desc: "perbedaan kunci。屋外: di luar gedung, mencegah menyebar, lantai 1-2. 屋内: di dalam gedung, dioperasikan penghuni, No.1/No.1易/No.2. Ujian tampilkan FOTO → bedakan keduanya." },
  { id: 111, category: "anzen", source: "jac-ch2", type: "konsep", furi: "あんぜんだいいち", jp: "安全第一", id_text: "Keselamatan Utama (Safety First)", desc: "Prinsip dasar di lokasi konstruksi Jepang: keselamatan di atas segalanya. Papan \"Safety First\" dipasang di setiap lokasi. Mandor:「急いでても安全を後回しにするな」(meski buru-buru, jangan kesampingkan keselamatan)." },
  { id: 112, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ふるはあねすがたついらくせいしようきぐう", jp: "フルハーネス型墜落制止用器具", id_text: "Peralatan penahan jatuh jenis full harness", desc: "Wajib digunakan saat bekerja di ketinggian. Full harness lebih aman dari harness dada saja." },
  { id: 114, category: "anzen", source: "jac-ch2", type: "konsep", furi: "ついらくてんらく", jp: "墜落・転落", id_text: "Jatuh dari ketinggian / Terjatuh bergulir", desc: "Jatuh dari ketinggian adalah penyebab kematian terbanyak di konstruksi. Tahun 2021: 110 kasus dari 288 kematian total. Mandor:「高所作業では絶対にフルハーネスをつけてくれよ」(di ketinggian wajib pakai full harness)." },
  { id: 116, category: "anzen", source: "jac-ch6", type: "konsep", furi: "きゅうしいぢいえすいい", jp: "QCDSE", id_text: "5 Manajemen QCDSE", desc: "Q=Kualitas, C=Biaya (Cost), D=Jadwal/Waktu (Delivery), S=Keselamatan (Safety), E=Lingkungan (Environment)." },
  { id: 118, category: "anzen", source: "jac-ch6", type: "konsep", furi: "ごえむ", jp: "5M", id_text: "5M (metode pelaksanaan)", desc: "Men (Manusia), Materials (Material), Methods (Metode), Machinery (Mesin), Money (Uang)." },
  { id: 119, category: "anzen", source: "jac-ch7", type: "konsep", furi: "あんかあぽいんと", jp: "アンカーポイント", id_text: "Titik angkur (anchor point)", desc: "Titik pengait pada struktur untuk mengaitkan peralatan penahan jatuh saat bekerja di ketinggian." },
  { id: 120, category: "anzen", source: "jac-jitsugi1", type: "konsep", furi: "さんそけつぼう", jp: "酸素欠乏（さんそけつぼう）", id_text: "Kekurangan oksigen — bahaya di MANHOLE", desc: "Bahaya di ruang tertutup → MANHOLE. Perlu cek kadar oksigen sebelum masuk. Kerja di atas tiang/atap gedung TIDAK termasuk risiko ini." },
  { id: 121, category: "anzen", source: "jac-jitsugi1", type: "konsep", furi: "どどめ", jp: "土留め（どどめ）≥ 1.5m", id_text: "Penahan tanah — WAJIB jika galian ≥ 1.5m", desc: "Mencegah longsor tanah (土砂崩れ) pada pekerjaan galian. WAJIB jika kedalaman ≥1.5m. Berbeda dari 換気 (ventilasi) dan 排水 (drainase)." },
  { id: 122, category: "anzen", source: "jac-jitsugi2", type: "konsep", furi: "しんきにゅうじょうしゃきょういくしんにゅうしゃあんぜんえいせいきょういく", jp: "新規入場者教育 vs 新入者安全衛生教育", id_text: "K3 pekerja baru lokasi vs K3 rekrutan baru", desc: "①新規入場者教育 = untuk PENDATANG BARU ke LOKASI KERJA. ②新入者安全衛生教育 = untuk PEKERJA BARU yang baru DIREKRUT perusahaan. Keduanya wajib." },
  { id: 123, category: "anzen", source: "jac-jitsugi1", type: "konsep", furi: "さんだいさいがい", jp: "三大災害（さんだいさいがい）", id_text: "Tiga bencana besar konstruksi", desc: "①墜落・転落 (TERBANYAK) ②建設機械・クレーン災害 ③崩壊・倒壊. Menyumbang 40–70% kematian." },
  { id: 124, category: "anzen", source: "jac-ch6", type: "konsep", furi: "しぎょうまえてんけん", jp: "始業前点検（しぎょうまえてんけん）", id_text: "Pemeriksaan sebelum mulai kerja", desc: "WAJIB sebelum bekerja: ①Mesin ②Alat/perkakas ③Prosedur kerja. Banyak kecelakaan terjadi saat menangani alat/mesin." },
  { id: 125, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ばっくほうのあんぜん", jp: "バックホウ（油圧ショベル）の安全", id_text: "Keselamatan backhoe / excavator", desc: "Bahaya: ①激突 — tertabrak bucket ②はさまれ — terjepit bucket. Saat naik/turun ke truk: risiko terbalik. Wajib ada 誘導員 (pemandu)." },
  { id: 126, category: "anzen", source: "jac-ch4", type: "konsep", furi: "すぼり", jp: "素掘り（すぼり）", id_text: "Penggalian tanpa penahan (open cut)", desc: "Penggalian TANPA 土留め, diperbolehkan HANYA jika tanah benar-benar stabil. Berbeda dari galian ≥1.5m yang WAJIB pakai 土留め." },
  { id: 127, category: "anzen", source: "jac-ch3", type: "konsep", furi: "どらいわあくゑるぽいんとこうほう", jp: "ドライワーク（ウェルポイント工法）", id_text: "Pekerjaan kering — metode wellpoint (max 10m)", desc: "Pipa pompa ditancapkan ke tanah, air dipompa keluar dengan pompa vakum. Kedalaman max ≈10m. Lebih dalam → ディープウェル." },
  { id: 128, category: "anzen", source: "jac-jitsugi2", type: "konsep", furi: "ひろうぼうしてきせつなすいみんとしょくじ", jp: "疲労防止", id_text: "Pencegahan kelelahan — tidur & makan yang cukup", desc: "疲労がたまると事故につながるので、【適切な睡眠と食事をとること】を心がける。Kelelahan menyebabkan kecelakaan → perhatikan tidur & makan yang cukup." },
  { id: 129, category: "career", source: "jac-ch1", type: "konsep", furi: "けんせつきゃりああっぷしすてむ", jp: "建設キャリアアップシステム（CCUS）", id_text: "Sistem Kenaikan Karier Konstruksi", desc: "Sistem rekam karier pekerja konstruksi, 4 level (putih→biru→perak→emas). Level 2 butuh ≥645 hari kerja tercatat. Mandor:「CCUSカードは毎日タッチするのを忘れるな」(jangan lupa tap kartu CCUS setiap hari)." },
  { id: 130, category: "career", source: "jac-ch1", type: "konsep", furi: "もとうり", jp: "元請（ゼネコン）", id_text: "Kontraktor umum (general contractor)", desc: "Perusahaan yang menerima kontrak dari klien dan mengatur seluruh pekerjaan. Bertanggung jawab atas semua sub-kontraktor. Mandor:「ゼネコンからの指示は最優先で動けよ」(instruksi general contractor adalah prioritas)." },
  { id: 131, category: "career", source: "jac-ch2", type: "hukum", furi: "したうけせんもんこうじぎょうしゃ", jp: "下請（専門工事業者）", id_text: "Kontraktor khusus / sub-kontraktor", desc: "Kontraktor spesialis yang menerima subkontrak dari kontraktor utama. Bekerja sesuai instruksi 職長. Mandor:「職長の指示に従って確実に作業してくれよ」(ikuti instruksi mandor dan kerjakan dengan tepat)." },
  { id: 134, category: "career", source: "jac-gakka1", type: "konsep", furi: "ごえす", jp: "5S（整理・整頓・清掃・清潔・しつけ）", id_text: "5S: Pilah / Tata / Bersih / Higienis / Disiplin", desc: "Seiri=Pilah, Seiton=Tata, Seisou=Bersih, Seiketsu=Higienis, Shitsuke=DISIPLIN (item ke-5, sering ditanyakan)." },
  { id: 135, category: "career", source: "jac-gakka1", type: "konsep", furi: "ぱわあはらすめんと", jp: "パワー・ハラスメント（パワハラ）", id_text: "Pelecehan kekuasaan (Power Harassment)", desc: "Memanfaatkan keunggulan posisi untuk memberi tekanan melebihi batas wajar. Berbeda dari セクハラ." },
  { id: 136, category: "career", source: "jac-gakka2", type: "konsep", furi: "しかくのしゅるい", jp: "資格の種類：電気工事士・工事担任者・消防設備士", id_text: "Kualifikasi: listrik / telekomunikasi / pemadam", desc: "①電気工事士 = LISTRIK. ②工事担任者 = TELEKOMUNIKASI. ③消防設備士 = PEMADAM KEBAKARAN." },
  { id: 137, category: "career", source: "jac-ch2", type: "hukum", furi: "せくしゃるはらすめんと", jp: "セクシャル・ハラスメント（セクハラ）", id_text: "Pelecehan seksual (Sexual Harassment)", desc: "Tindakan atau ucapan seksual yang tidak diinginkan di tempat kerja. Berbeda dari パワハラ, keduanya dilarang keras. Mandor:「セクハラは厳しく対処する、相談してくれ」(pelecehan ditangani keras, konsultasikan masalah)." },
  { id: 138, category: "sekou", source: "jac-jitsugi1", type: "konsep", furi: "すいじゅんき", jp: "水準器（レベル）", id_text: "Waterpas / Level (instrumen survei)", desc: "Alat survei dengan teleskop untuk mengukur ketinggian/elevasi. Dipasang di atas tripod. Sering diuji lewat FOTO." },
  { id: 139, category: "sekou", source: "jac-ch5", type: "konsep", furi: "とらんしっと", jp: "トランシット", id_text: "Theodolit / Transit", desc: "Alat ukur sudut vertikal dan horizontal — saat ini umumnya versi digital. Mandor:「トランシットで通りと直角を確認して」(cek kelurusan dan sudut siku dengan transit)." },
  { id: 140, category: "sekou", source: "jac-ch5", type: "konsep", furi: "とおたるすてえしょん", jp: "トータルステーション", id_text: "Total station", desc: "Gabungan alat ukur jarak dan sudut elektronik dalam satu perangkat. Mandor:「トータルステーションで座標を確認して」(konfirmasi koordinat dengan total station)." },
  { id: 141, category: "sekou", source: "jac-ch5", type: "konsep", furi: "すみだし", jp: "墨出し（すみだし）", id_text: "Penandaan tinta / marking", desc: "Penandaan posisi dan ketinggian struktur di lokasi konstruksi. Pekerjaan terpenting yang butuh akurasi tinggi." },
  { id: 142, category: "sekou", source: "jac-ch5", type: "konsep", furi: "こんべっくす", jp: "コンベックス", id_text: "Meteran pita (convex rule)", desc: "Meteran pita logam tipis — nama resmi 'convex rule', di lapangan dipanggil 'konbe'. Mandor:「コンベックスで寸法を二度確認して」(ukur dimensi dua kali dengan meteran)." },
  { id: 143, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ふりこさげふり", jp: "振り子・下げ振り", id_text: "Bandul lot (plumb bob)", desc: "Pemberat berujung kerucut untuk memeriksa tegak lurusnya tiang. Prinsip: benang dari atas, cek jarak ke permukaan." },
  { id: 144, category: "sekou", source: "jac-ch5", type: "konsep", furi: "さんだあ", jp: "サンダー", id_text: "Sander (alat poles)", desc: "Alat listrik untuk ampelas permukaan datar — jenis getar, sabuk, dan putar. Mandor:「サンダーかける前に養生してください」(lakukan pelindungan area sebelum mengampelas)." },
  { id: 145, category: "sekou", source: "jac-jitsugi1", type: "konsep", furi: "すみつぼ", jp: "墨つぼ（すみつぼ）", id_text: "Wadah tinta / chalk line reel", desc: "Membuat garis lurus panjang dengan menarik benang bercelup tinta. Berbeda dari: 墨さし (kuas pendek), チョーク, レーザー墨出し器. Sering diuji lewat FOTO." },
  { id: 146, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ろくずみにげすみじずみ", jp: "墨出し用語：陸墨・逃げ墨・地墨", id_text: "Tinta horizontal / tinta geser / tinta lantai", desc: "①陸墨: garis referensi HORIZONTAL (ketinggian). ②逃げ墨: garis yang dipindah dari posisi asli karena terhalang. ③地墨: garis ditandai langsung di LANTAI." },
  { id: 147, category: "sekou", source: "jac-ch4", type: "konsep", furi: "べんちまーく", jp: "ベンチマーク（BM）・GL・FL", id_text: "BM = benchmark / GL = ground / FL = floor", desc: "BM: titik referensi ketinggian di lokasi. GL: ketinggian permukaan tanah. FL: ketinggian lantai jadi (1FL, 2FL, ...)." },
  { id: 148, category: "sekou", source: "jac-ch4", type: "konsep", furi: "とおりしんかべしんはしらしん", jp: "通り芯（とおりしん）・壁芯・柱芯", id_text: "Garis sumbu tengah — dinding dan kolom", desc: "通り芯: center line. 壁芯: center line dinding. 柱芯: center line kolom. Acuan penandaan posisi di lokasi." },
  { id: 149, category: "sekou", source: "jac-jitsugi2", type: "konsep", furi: "だいしゃ", jp: "台車（だいしゃ）", id_text: "Kereta dorong datar (platform cart)", desc: "Platform datar berkaki roda untuk mengangkut material dan peralatan berat di lokasi konstruksi. Di proyek: berbeda dari 一輪車 (satu roda), そり (sledge), ころ (roller)." },
  { id: 150, category: "sekou", source: "jac-ch5", type: "konsep", furi: "いちりんしゃ", jp: "一輪車（いちりんしゃ）", id_text: "Gerobak sorong satu roda (wheelbarrow)", desc: "Alat angkut dengan satu roda di depan dan dua gagang di belakang. Digunakan untuk mengangkut tanah, pasir, campuran beton di lokasi konstruksi. Berbeda dari 台車 (platform datar 4 roda)." },
  { id: 151, category: "hourei", source: "jac-ch2", type: "hukum", furi: "わりましちんぎんりつ", jp: "割増賃金率", id_text: "Lembur: biasa +25% / libur +35% / malam +25%", desc: "Tiga tingkat upah tambahan wajib sesuai UU. Batas lembur: 45 jam/bulan, 360 jam/tahun (berlaku April 2024). Mandor:「残業代は法律通りに払うから記録してくれ」(upah lembur dibayar sesuai UU, catat jam)." },
  { id: 152, category: "hourei", source: "jac-ch2", type: "hukum", furi: "つうきんさいがいぎょうむさいがい", jp: "通勤災害 vs 業務災害", id_text: "Kecelakaan perjalanan vs kecelakaan tempat kerja", desc: "通勤災害: kecelakaan saat perjalanan rumah↔kerja via rute wajar. 業務災害: akibat pekerjaan itu sendiri. Keduanya ditanggung 労災保険. Mandor:「通勤中の事故もすぐ報告してくれよ」(kecelakaan di perjalanan pun lapor)." },
  { id: 153, category: "career", source: "jac-ch2", type: "hukum", furi: "ぎのうけんてい／ぎのうし", jp: "技能検定 / 技能士", id_text: "Uji keterampilan / Teknisi berlisensi negara", desc: "Ujian sertifikasi nasional; lulus → dapat 合格証書 dan boleh menyebut diri 技能士. Ada 32 jenis di konstruksi, 5 tingkat. Mandor:「2級取ったら手当もつくし、CCUSも上がるぞ」(lulus level 2, ada tunjangan dan CCUS naik)." },
  { id: 154, category: "hourei", source: "jac-ch2", type: "hukum", furi: "とくていぎのうがいこくじんのこようほけん", jp: "特定技能外国人の雇用保険（失業給付）", id_text: "SSW asing bisa dapat tunjangan pengangguran", desc: "SSW yang kehilangan pekerjaan tidak wajib langsung pulang, bisa dapat tunjangan 雇用保険. Boleh tinggal selama aktif mencari kerja. Mandor:「仕事なくなってもすぐ帰国しなくていいぞ」(tidak harus langsung pulang)." },
  { id: 155, category: "hourei", source: "jac-ch2", type: "hukum", furi: "こようほけんのしきゅうようけん", jp: "雇用保険の支給要件（12ヶ月以上）", id_text: "Syarat tunjangan: ≥12 bln dalam 2 tahun terakhir", desc: "Syarat: menganggur dan mau bekerja, plus ≥12 bulan masa asuransi dalam 2 tahun terakhir. Tunjangan 45–80% upah, 90–360 hari. Mandor:「12ヶ月以上入ってれば給付もらえるよ」(masuk ≥12 bulan, bisa dapat tunjangan)." },
  { id: 156, category: "hourei", source: "jac-ch2", type: "hukum", furi: "すとれすへっく", jp: "ストレスチェック（50人以上の事業場）", id_text: "Cek stres — WAJIB perusahaan ≥50 orang, 1x/tahun", desc: "Perusahaan ≥50 karyawan wajib lakukan cek beban psikologis tiap tahun oleh dokter/perawat. Diatur 労働安全衛生法. Mandor:「ストレスチェックは必ず受けてくれよ」(wajib ikut stress check dari perusahaan)." },
  { id: 157, category: "hourei", source: "jac-ch2", type: "hukum", furi: "どろおんとうろくぎむ", jp: "ドローン登録義務（≥100g）", id_text: "Drone ≥100g WAJIB didaftarkan ke pemerintah", desc: "Drone berat ≥100g wajib didaftarkan sebagai pesawat tak berawak. Sering dipakai untuk survei (測量) di konstruksi. Mandor:「現場でドローン使う前に登録を確認しろよ」(pakai drone di lapangan, pastikan sudah terdaftar)." },
  { id: 158, category: "hourei", source: "jac-ch2", type: "hukum", furi: "こうくうしょうがいとう", jp: "航空障害灯（≥60m）", id_text: "Lampu hambatan penerbangan: wajib pada objek ≥60m", desc: "Bangunan, crane, atau struktur setinggi ≥60m wajib dipasangi lampu hambatan penerbangan, termasuk crane sementara. Mandor:「60メートル以上のクレーンには航空障害灯が必要だぞ」(crane ≥60m wajib pasang lampu hambatan)." },
  { id: 159, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ちんぎんしはらいのごげんそく", jp: "賃金支払いの5原則", id_text: "5 prinsip pembayaran upah (Labor Standards Act)", desc: "Lima prinsip pembayaran upah: ①tunai ②langsung ③penuh ④min. 1x/bulan ⑤tanggal tetap. Di lapangan: semua 5 harus terpenuhi. Mandor:「給料は毎月決まった日に全額渡すのが法律だよ」(gaji penuh tiap bulan, tanggal tetap)." },
  { id: 160, category: "hourei", source: "jac-ch2", type: "hukum", furi: "きゅうけいじかんのきてい", jp: "休憩時間の規定（6時間・8時間）", id_text: "Aturan istirahat: >6jam→45 mnt; >8jam→1 jam", desc: "Istirahat wajib di tengah jam kerja, diberikan serentak. Kerja >6 jam → 45 menit, >8 jam → 1 jam. Mandor:「8時間超えたら1時間休憩を取らせるぞ」(kerja lebih 8 jam, ambil 1 jam istirahat)." },
  { id: 161, category: "hourei", source: "jac-ch2", type: "hukum", furi: "かいこよこくさんじゅうにちまえ", jp: "解雇予告（かいこよこく）", id_text: "PHK wajib diumumkan 30 hari sebelumnya", desc: "Pemberi kerja wajib memberitahu 30 hari sebelum memecat; jika tidak, bayar ganti 30 hari upah. Mandor:「辞めてもらう時は30日前に必ず言うよ」(kalau harus berhenti, saya beritahu 30 hari sebelumnya)." },
  { id: 162, category: "hourei", source: "jac-ch2", type: "hukum", furi: "そうおんきせいほうていそうおんがたけんせつきかい", jp: "騒音規制法・低騒音型機械", id_text: "UU Kebisingan: wajib pilih mesin rendah bising", desc: "UU yang mengatur tingkat kebisingan dari konstruksi. Wajib pilih mesin 低騒音型 dan atur jadwal/zona bising. Mandor:「この現場では低騒音型の機械を選ぶように」(di lokasi ini pilih mesin rendah kebisingan)." },
  { id: 163, category: "hourei", source: "jac-ch2", type: "hukum", furi: "でんぱほうめんきょうがひつようなとらんしいばあ", jp: "電波法", id_text: "UU Gelombang Radio: transceiver butuh izin", desc: "UU yang mengatur penggunaan gelombang radio. Transceiver tanpa izin atau impor tak disetujui Jepang adalah ilegal. Mandor:「そのトランシーバー、免許あるか確認したか？」(transceiver itu sudah ada izinnya, sudah dicek?)." },
  { id: 164, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうさいほけんのよんきゅうふ", jp: "労災保険の4給付（療養・休業・遺族・介護）", id_text: "4 jenis tunjangan asuransi kecelakaan kerja", desc: "4 tunjangan 労災: biaya pengobatan penuh, ganti upah, ahli waris jika meninggal, dan perawatan jika cacat. Semua dijamin negara. Mandor:「怪我したら労災で全部面倒みてもらえるよ」(cedera, semua ditanggung asuransi kerja)." },
  { id: 165, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうさいほけんとくべつかにゅうせいど", jp: "労災保険の特別加入制度（一人親方・中小企業主）", id_text: "Jalur khusus asuransi kerja: kontraktor mandiri", desc: "労災保険 biasanya hanya untuk karyawan, tapi kontraktor mandiri (一人親方) boleh masuk lewat 特別加入制度. Mandor:「一人親方でも特別加入で労災に入れるぞ」(kontraktor mandiri pun bisa masuk asuransi kerja)." },
  { id: 166, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんせつろうどうしゃこようかいぜんほう", jp: "建設労働者雇用改善法", id_text: "UU Peningkatan Ketenagakerjaan Konstruksi", desc: "UU yang mendorong perbaikan kondisi kerja konstruksi. Rencana ke-10 (2021–2025) menargetkan CCUS dan batas lembur. Mandor:「CCUSカードは毎日忘れずタッチしてくれよ」(jangan lupa tap kartu CCUS setiap hari)." },
  { id: 167, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ちゅうしゃじょうほう", jp: "駐車場法（ちゅうしゃじょうほう）", id_text: "UU Perparkiran: lapor sebelum bangun/ubah parkir", desc: "UU yang mengatur pembangunan fasilitas parkir di perkotaan. Membangun atau memodifikasi parkir wajib lapor ke pemda sebelum mulai. Mandor:「駐車場工事は着工前に届出が要るぞ」(wajib lapor ke pemda)." },
  { id: 168, category: "hourei", source: "jac-ch2", type: "hukum", furi: "すいしつおだくぼうしほう", jp: "水質汚濁防止法", id_text: "UU Pencemaran Air: air beton wajib dinetralkan", desc: "UU yang mengatur kualitas air buangan. Air yang kontak beton sangat basa, wajib dinetralkan dengan CO₂ sebelum dibuang ke saluran. Mandor:「コンクリートの排水は中和してから流してくれよ」(air beton wajib dinetralkan dulu)." },
  { id: 169, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ばいしょうよていのきんし", jp: "賠償予定の禁止（ばいしょうよていのきんし）", id_text: "Dilarang tetapkan denda/ganti rugi di muka", desc: "Pemberi kerja dilarang mencantumkan klausul denda pemutusan di muka. Pekerja boleh menolak kontrak yang memuat ini. Mandor:「契約に罰金条項は違法だよ、サインするな」(klausul denda melanggar UU, jangan tanda tangan)." },
  { id: 170, category: "hourei", source: "jac-ch2", type: "hukum", furi: "きかいきんとうのげんそくきょうせいろうどうのきんし", jp: "機会均等の原則 / 強制労働の禁止", id_text: "Non-diskriminasi kebangsaan + dilarang kerja paksa", desc: "Dilarang membeda-bedakan upah berdasarkan kebangsaan/kepercayaan/status sosial, dan dilarang kerja paksa. Mandor:「国籍が違っても同じ条件で働いてもらうぞ」(beda kebangsaan pun kondisi kerja sama)." },
  { id: 171, category: "hourei", source: "jac-ch2", type: "hukum", furi: "かいこせいげんしょうびょうりょうようちゅうわかいこきんし", jp: "解雇制限", id_text: "Dilarang pecat saat sakit/cedera kerja + 30 hari", desc: "Pekerja yang sakit/cedera karena kerja tidak boleh dipecat selama pengobatan + 30 hari setelahnya. Berlaku otomatis sesuai UU. Mandor:「仕事中の怪我で休んでる間は解雇できないから安心しろ」(cedera kerja, tidak bisa dipecat)." },
  { id: 172, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうどうじょうけんのめいじろくこうもん", jp: "労働条件の明示", id_text: "6 hal wajib diberitahu pemberi kerja saat rekrut", desc: "6 hal wajib diberitahu tertulis: durasi kontrak, lokasi/jenis kerja, jam kerja, upah, libur, ketentuan resign/PHK. Mandor:「契約の時に条件は書面でもらってくれよ」(saat kontrak, minta kondisi kerja secara tertulis)." },
  { id: 173, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ちいきべつさいていちんぎん", jp: "地域別最低賃金（ちいきべつさいていちんぎん）", id_text: "Upah minimum berbeda per prefektur", desc: "Upah minimum ditetapkan per prefektur sesuai biaya hidup daerah. Berlaku untuk semua pekerja tanpa memandang jenis kontrak. Mandor:「最低賃金は毎年変わるから確認してくれよ」(upah minimum berubah tiap tahun, cek selalu)." },
  { id: 174, category: "career", source: "jac-ch2", type: "hukum", furi: "にんていくんれん", jp: "認定訓練（にんていくんれん）", id_text: "Pelatihan vokasi yang diakui gubernur prefektur", desc: "Pelatihan vokasi oleh pihak swasta yang diakui resmi gubernur prefektur; berbeda dari pelatihan pemerintah langsung. Mandor:「この研修は知事認定だから証書がもらえるぞ」(pelatihan diakui gubernur, dapat sertifikat)." },
  { id: 175, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ほうていきゅうじつまいしゅうすくなくともいっかい", jp: "法定休日", id_text: "Hari libur wajib: minimal 1 hari per minggu", desc: "Hari libur yang ditetapkan UU: minimal 1 hari per minggu wajib diberikan. Bekerja di hari ini → upah +35% (休日出勤). Mandor:「週に1日は必ず休んでくれよ、法律で決まってるから」(minimal 1 hari libur per minggu, aturan UU)." },
  { id: 176, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ゆうきゅうきゅうかのかいとりきんし", jp: "有給休暇の買い取り禁止", id_text: "Dilarang tukarkan cuti berbayar dengan uang", desc: "Pemberi kerja tidak boleh mengkonversi cuti berbayar menjadi uang tambahan. Cuti harus digunakan sebagai waktu istirahat. Mandor:「有給はお金に変えられないから、ちゃんと休んで使ってくれ」(cuti tidak bisa ditukar uang)." },
  { id: 177, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんこうしんだんていきねんいっかいとやといいれじ", jp: "健康診断", id_text: "Cek kesehatan: 1x/tahun + saat rekrut baru", desc: "Perusahaan wajib selenggarakan pemeriksaan kesehatan 1x/tahun dan saat rekrut baru. Biaya ditanggung perusahaan. Mandor:「年1回の健康診断は会社が出すから必ず受けてくれよ」(medical check-up setahun sekali, wajib ikut)." },
  { id: 178, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "ちすいりすい", jp: "治水（ちすい）vs 利水（りすい）", id_text: "Pengendalian banjir vs Pemanfaatan air", desc: "Dua tujuan utama bendungan (ダム). Chisui = menampung air saat hujan lebat agar sungai tidak meluap. Risui = menyediakan air stabil untuk pertanian, industri, dan PLTA." },
  { id: 179, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "ななとむこうほう", jp: "NATM（ナトム）工法", id_text: "Metode penggalian terowongan gunung", desc: "Metode terowongan gunung: bor/ledak batuan, semprotkan beton (吹付け), pasang penopang baja dan rock bolt. Mandor:「吹付け準備して」(siapkan beton semprot)." },
  { id: 180, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "しいるどとんねるせぐめんと", jp: "シールドトンネル・セグメント", id_text: "Terowongan shield / segmen beton/baja", desc: "Shield machine menggali dari 立坑, lalu segmen beton/baja dipasang di belakang mesin sebagai dinding. Cocok untuk tanah lunak. Mandor:「セグメント組み立てて」(rakit segmennya)." },
  { id: 181, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "すいしんとんねる", jp: "推進トンネル（すいしんトンネル）", id_text: "Terowongan jack-push / pipe jacking", desc: "Pipa prefabrikasi (コンクリート管・ダクタイル管・鋼管) didorong masuk ke tanah oleh jack dari shaft peluncur. Digunakan untuk infrastruktur perkotaan seperti saluran air, gas, listrik, dan komunikasi." },
  { id: 182, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "きょうりょうこうじかぶこうじょうぶこう", jp: "橋梁工事（下部工・上部工）", id_text: "Pekerjaan jembatan: struktur bawah & atas", desc: "下部工=pondasi penopang jembatan. 上部工=badan jembatan untuk kendaraan/pejalan kaki. Mandor:「下部工の検査入ります」(inspeksi struktur bawah)." },
  { id: 183, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "かいようどぼくこうじ", jp: "海洋土木工事（かいようどぼく）", id_text: "Pekerjaan sipil laut / offshore civil work", desc: "Pembangunan pelabuhan, bandara, terowongan bawah laut, jembatan laut, dan turbin angin di laut. Menggunakan kapal kerja (作業船) untuk mengeruk atau mengangkat material, serta penyelam (潜水士)." },
  { id: 184, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "しゅんせつこうじ", jp: "浚渫工事（しゅんせつ）", id_text: "Pengerukan dasar laut/sungai", desc: "Mengangkat lumpur dan pasir dari dasar laut atau sungai menggunakan kapal keruk (浚渫船) agar kapal dapat berlayar dengan aman di jalur pelayaran dan sandar di pelabuhan." },
  { id: 185, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "けえそん", jp: "ケーソン（防波堤工事）", id_text: "Caisson / kotak beton untuk pemecah gelombang", desc: "Kotak beton besar yang diletakkan di atas hamparan batu di dasar laut, lalu diisi pasir/kerikil untuk menstabilkan. Digunakan dalam pembuatan pemecah gelombang (防波堤)." },
  { id: 186, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくぶつのこうぞうしゅるい", jp: "建築物の構造種類（RC・S・SRC・木造・CB造）", id_text: "Jenis struktur: RC, S, SRC, kayu, blok beton", desc: "RC造=tulangan+beton, S造=baja, SRC造=baja+RC (terkuat), 木造=kayu, CB造=blok beton. Mandor:「ここはS造だから溶接確認して」(ini S造, cek las)." },
  { id: 187, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "ぼおりんぐちょうさしじそう", jp: "ボーリング調査・支持層（しじそう）", id_text: "Penyelidikan tanah / lapisan pendukung pondasi", desc: "Pengeboran tanah (ボーリング) untuk menemukan lapisan keras (支持層) tempat ujung tiang harus mencapai. Juga deteksi rintangan bawah tanah. Mandor:「支持層まで何mか確認して」(cek kedalaman lapisan keras)." },
  { id: 188, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "やまどめこうじしほこう", jp: "山留め工事（やまどめ）・支保工（しほこう）", id_text: "Pekerjaan penahan tanah / shoring", desc: "Dinding sementara di dalam tanah untuk cegah longsor saat penggalian, diperkuat strutting (支保工). Mandor:「山留めの切梁確認して」(cek strut penahan tanah)." },
  { id: 189, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "くいこうじばしょうちくいきせいくい", jp: "杭工事", id_text: "Pekerjaan tiang: cast-in-place vs precast", desc: "場所打ち杭=lubang digali, rangka tulangan dipasang, beton dicor di tempat. 既成杭=tiang pabrik (beton/baja/kayu) dipancang. Mandor:「既成杭の搬入確認して」(cek tiang pabrik masuk)." },
  { id: 190, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "たいしんせいしんめんしん", jp: "耐震・制振・免振（たいしん・せいしん・めんしん）", id_text: "Tahan gempa / kontrol getaran / isolasi gempa", desc: "耐震 = kolom/balok dibuat kokoh untuk menahan guncangan. 制振 = damper dipasang di bangunan untuk menyerap energi getaran. 免振 = isolator + damper di fondasi agar energi gempa tidak tersalur ke bangunan." },
  { id: 191, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "ねぎり", jp: "根切り（ねぎり）", id_text: "Galian pondasi bangunan", desc: "Penggalian tanah di lokasi pondasi bangunan agar struktur bawah tanah bisa dibangun. Berbeda dari galian umum — 根切り spesifik untuk menanam fondasi gedung." },
  { id: 192, category: "anzen", source: "jac-ch3", type: "konsep", furi: "はっぱ", jp: "発破（はっぱ）", id_text: "Peledakan / blasting", desc: "Peledakan batu menggunakan bahan peledak (火薬類) dalam pekerjaan tambang, terowongan, atau galian batu. Untuk mengerjakan peledakan, wajib memiliki lisensi 発破技士." },
  { id: 193, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "もりどきりど", jp: "盛り土（もりど）vs 切り土（きりど）", id_text: "Penimbunan vs penggalian untuk meratakan lahan", desc: "盛り土 = tanah ditimbun pada lahan miring atau tidak rata agar menjadi datar. 切り土 = tanah dipotong/digali agar permukaan menjadi rata. Keduanya adalah bagian dari pekerjaan tanah (土工作業)." },
  { id: 194, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "うめもどしさぎょう", jp: "埋め戻し作業（うめもどし）", id_text: "Pekerjaan pengurugan kembali", desc: "Setelah pekerjaan bawah tanah atau fondasi selesai, ruang kosong di sekitar struktur ditimbun kembali dengan tanah. Ini adalah tahap akhir dari pekerjaan galian." },
  { id: 195, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "さくせいこうじしゅるい", jp: "さく井工事の4種類（水源・観測・温泉・地熱）", id_text: "4 jenis pekerjaan pengeboran sumur", desc: "①水源井=air tanah. ②観測井=pantau penurunan tanah. ③温泉井=500〜1000m, bahaya gas. ④地熱井=±2000m, bahaya uap+panas. Mandor:「掘削深度の記録つけて」(catat kedalaman bor)." },
  { id: 196, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "ぢいぷうえる", jp: "ディープウェル（深井戸排水）", id_text: "Deep well dewatering / drainase sumur dalam", desc: "Metode pemompaan air tanah untuk galian di kedalaman >10m. Berbeda dari wellpoint (id:151) yang hanya efektif hingga ~10m. Untuk air tanah sangat dalam, ディープウェル adalah solusinya." },
  { id: 197, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "とびこうじのしゅるい", jp: "とび工事の種類", id_text: "Jenis pekerjaan tobi / rigger-scaffolder", desc: "足場とび=perancah, 鉄骨とび=rangka baja, 橋梁とび=jembatan, 重量とび=mesin berat, 送電とび=menara listrik, 町場とび=rumah. Mandor:「足場の点検してくれ」(cek perancah)." },
  { id: 198, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "てっきんつぎてこうじしゅるい", jp: "鉄筋継手工事の4種類（てっきんつぎて）", id_text: "4 metode penyambungan tulangan baja", desc: "①ガス圧接 = dipanaskan + ditekan (paling umum). ②溶接継手 = arc welding untuk diameter besar. ③機械式継手 = penyambung berulir (coupler). ④重ね接手 = ditumpuk lalu disatukan dengan beton (untuk tulangan tipis)." },
  { id: 199, category: "sekou", source: "jac-ch3", type: "konsep", furi: "ようせつぶんるいゆうせつあっせつろうせつ", jp: "溶接の3分類（融接・圧接・ろう接）", id_text: "3 kategori pengelasan: fusion / pressure / brazing", desc: "融接=material dilelehkan (arc/gas/laser). 圧接=dipanaskan+ditekan tanpa cair, contoh: ガス圧接 tulangan. ろう接=logam penghubung bersuhu leleh rendah sebagai lem. Mandor:「融接箇所の検査します」(inspeksi las lebur)." },
  { id: 200, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "かたわくこうじしほこう", jp: "型枠工事・支保工（かたわく・しほこう）", id_text: "Pekerjaan bekisting dan penopangnya", desc: "Cetakan kayu (型枠) melingkupi tulangan, beton dicor, diperkuat pipa baja luar (支保工). Setelah mengeras, dibongkar dan dipakai ulang. Mandor:「型枠の締め付け確認して」(cek pengencangan bekisting)." },
  { id: 201, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "れぢみくすどこんくりいとなまこんあっそう", jp: "レディミクスドコンクリート（生コン）", id_text: "Ready-mix concrete dan pemompaan beton", desc: "Beton berkualitas dari pabrik (生コン) dikirim truk molen (トラックアジテータ), lalu dipompa ke bekisting. Mandor:「生コン到着したら圧送開始して」(beton datang, mulai pompa)." },
  { id: 202, category: "sekou", source: "jac-ch3", type: "konsep", furi: "ばいぶれえたこんくりいとしめかため", jp: "バイブレータ（コンクリート締固め）", id_text: "Vibrator untuk pemadatan beton", desc: "Alat getar dimasukkan ke beton segar untuk hilangkan gelembung (気泡) dan pastikan beton isi sudut bekisting (締固め). Mandor:「バイブレータちゃんと入れて、気泡抜いて」(masukkan vibrator, keluarkan gelembung)." },
  { id: 203, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さかんこうじかべつちしっくいもるたる", jp: "左官工事（さかん）", id_text: "Pekerjaan plesteran tradisional Jepang", desc: "Gunakan kote (roskam) untuk oleskan 壁土, 漆喰 (kapur), atau モルタル ke dinding/lantai. Berbeda dari painting (塗装). Mandor:「左官さん、仕上げはいつですか」(kapan finishing plester)." },
  { id: 204, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ぼうすいこうじしゅるい", jp: "防水工事の5種類", id_text: "5 jenis pekerjaan waterproofing", desc: "①ウレタン=cairan, cocok area rumit. ②FRP=serat kaca+resin. ③シート=lembaran karet. ④アスファルト=tempel lembaran aspal. ⑤シーリング=sealant isi celah. Mandor:「プライマー塗ってから施工して」(oleskan primer dulu)." },
  { id: 205, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "みやだいく", jp: "宮大工（みやだいく）", id_text: "Tukang kayu kuil & shrine tradisional", desc: "Spesialis bangun/renovasi kuil (お寺) dan shrine (神社). Butuh ilmu jenis kayu dan sambungan kayu agar tahan ratusan tahun. Mandor:「仕口の加工、寸法確認して」(cek ukuran sambungan kayu)." },
  { id: 206, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "あまじまい", jp: "雨仕舞（あまじまい）", id_text: "Penanganan air hujan / rain detailing", desc: "Pengetahuan dan teknik konstruksi untuk mencegah air hujan masuk ke dalam bangunan melalui atap dan sambungan material. Merupakan kompetensi wajib dalam pekerjaan atap (屋根工事) dan panel baja (建築板金工事)." },
  { id: 207, category: "denki", source: "jac-ch3", type: "konsep", furi: "がいせんこうじないせんこうじ", jp: "外線工事 vs 内線工事（がいせん・ないせん）", id_text: "Instalasi listrik luar gedung vs dalam gedung", desc: "外線=hubungkan tiang/kabel ke gedung. 内線=listrik dalam gedung: grounding, panel, AC. Gedung besar butuh 電気工事士一種. Mandor:「内線の配線図もってきて」(bawa gambar kabel dalam gedung)." },
  { id: 208, category: "anzen", source: "jac-ch3", type: "konsep", furi: "たまがけいじょうわぎのうこうしゅう", jp: "玉掛け（たまがけ）", id_text: "Rigging (ikat beban crane): ≥1t wajib teknik", desc: "玉掛け=ikat beban ke kait crane. ≥1t wajib 技能講習. <1t cukup 特別教育. Kesalahan rigging bisa menyebabkan beban jatuh fatal. Mandor:「玉掛け資格ある人でやって」(kerjakan oleh pemegang sertifikat)." },
  { id: 209, category: "hourei", source: "jac-ch3", type: "konsep", furi: "しかくしゅるいこっかめんきょぎのうこうしゅうとくべつきょういく", jp: "資格の3種類：国家免許・技能講習・特別教育", id_text: "3 tingkat kualifikasi K3 konstruksi Jepang", desc: "①国家免許=lisensi negara (クレーン運転士 dll). ②技能講習修了証=lulus pelatihan terdaftar. ③特別教育=pelatihan khusus sebelum tugas berbahaya. Mandor:「この作業、技能講習持ってる人ですか」(punya sertifikat teknik?)." },
  { id: 210, category: "hourei", source: "jac-ch3", type: "konsep", furi: "はっぱぎしめんきょ", jp: "発破技士免許（はっぱぎし）", id_text: "Lisensi juru peledak / blaster license", desc: "Untuk peledakan (発破) di konstruksi/tambang, wajib lisensi negara 発破技士. Tugas: bor, pasang bahan peledak, sambung kawat, nyalakan, tangani gagal ledak. Mandor:「発破技士いますか」(ada juru peledak?)." },
  { id: 211, category: "sekou", source: "jac-ch3", type: "konsep", furi: "かいたいこうじあべすとたいさく", jp: "解体工事（かいたい）", id_text: "Pekerjaan pembongkaran bangunan + penanganan asbes", desc: "アスベスト対策。Sebelum bongkar, survei asbes (石綿) wajib. Jika ada, dibongkar prosedur khusus. Limbah (解体ガラ) dipilah: beton, besi, berbahaya. Mandor:「石綿調査の結果出ましたか」(hasil survei asbes keluar?)." },
  { id: 212, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "とそうこうじほうほうはけろおらあえあすぷれえ", jp: "塗装工事の3方法（はけ・ローラー・エアスプレー）", id_text: "3 metode cat: kuas / roller / semprotan", desc: "①はけ塗り=kuas, cocok bentuk apapun, hasil rapi. ②ローラー=efisien area luas. ③エアスプレー=cat dikabut kompresor, untuk area luas/sulit. Mandor:「外壁はローラーで仕上げて」(dinding luar pakai roller)." },
  { id: 213, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ぞおえんこうじしゅるい", jp: "造園工事の5種類", id_text: "5 jenis pekerjaan taman/lansekap", desc: "①植栽=tanam pohon. ②屋上緑化=hijau atap/dinding gedung. ③広場=lapangan. ④公園設備=gazebo, air mancur. ⑤緑地育成=perbaikan tanah+penyangga pohon. Mandor:「植栽の配置図確認して」(cek layout tanam pohon)." },
  { id: 214, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "けいてんこうじぼおどはりくろすはり", jp: "軽天工事（けいてん）・LGS", id_text: "Pekerjaan rangka LGS + papan gypsum + wallpaper", desc: "LGS (Light Gauge Steel/スタッド) untuk rangka dinding/plafon (軽天工事). Di atasnya papan gypsum (ボード貼り), sambungan dirapikan pate, lalu wallpaper (クロス貼り). Mandor:「LGSのピッチ確認して」(cek jarak rangka LGS)." },
  { id: 215, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "かばあこうほうさしかいしゅう", jp: "カバー工法（サッシ改修）", id_text: "Renovasi kusen tanpa bongkar rangka lama", desc: "カバー工法=pasang rangka baru DI ATAS rangka lama tanpa bongkar, lalu pasang sash baru. Hemat vs ganti total. Mandor:「カバー工法で行きましょう」(pakai metode cover saja)." },
  { id: 216, category: "anzen", source: "jac-ch3", type: "konsep", furi: "たいるはりこうじらっかりすくたしょくしゅれんけい", jp: "タイル張り工事", id_text: "Pekerjaan ubin: risiko jatuh & koordinasi lintas", desc: "Ubin jatuh dari ketinggian berpotensi fatal. Koordinasi pipa (配管) dan listrik wajib sebelum tempel ubin. Mandor:「配管確認してから貼って」(cek pipa dulu baru tempel ubin)." },
  { id: 217, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "いしこうじだいりいしみかげいしぎいし", jp: "石工事", id_text: "Pekerjaan batu: marmer, granit, batu artifisial", desc: "大理石=marmer, 御影石=granit, 擬石=batu tiruan dipasang ke bangunan (estetika, bukan struktur). Batu yang retak saat proses tidak bisa dipakai. Mandor:「大理石、割れないよう慎重に」(hati-hati jangan sampai marmer retak)." },
  { id: 218, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "かいさくとんねる", jp: "開削トンネル（かいさくトンネル）", id_text: "Cut-and-cover tunnel / terowongan gali-tutup", desc: "Tanah digali dari permukaan, terowongan dibangun dalam galian, lalu ditimbun kembali. Berbeda dari shield yang menggali horizontal. Mandor:「土留め支保工の点検して」(cek dinding penahan tanah)." },
  { id: 219, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "のりめんこうじもるたるふきつけしょくせいこうほう", jp: "法面工事（のりめん）", id_text: "Perkuatan lereng: semprotan mortar & revegetasi", desc: "①モルタル吹付け=mortar disemprot ke lereng untuk stabilisasi. ②植生工法=mat benih+pupuk ditempel agar tanaman tumbuh menahan tanah. Mandor:「吹付けの厚さ確認して」(cek ketebalan semprotan mortar)." },
  { id: 220, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "かせんかいがんこうぞうぶつぼうはていぼうちょうていごがんていぼうすいろ", jp: "河川・海岸の構造物", id_text: "Struktur sungai & pantai: tanggul, turap, saluran", desc: "防波堤=pecah gelombang pelabuhan. 防潮堤=tahan tsunami. 護岸=turap tepi sungai. 堤防=tanggul banjir. 水路=saluran irigasi/drainase. Mandor:「護岸の法面点検して」(cek lereng turap)." },
  { id: 221, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "てつどうこうじたしょくしゅしゅうやくこうじ", jp: "鉄道工事（てつどう）", id_text: "Pekerjaan rel: gabungan semua keahlian konstruksi", desc: "多職種集約工事。Pekerjaan kereta mencakup hampir SEMUA jenis konstruksi: 土木+電気設備+建築+spesialis. Ini yang membuat kereta jadi proyek paling kompleks. Mandor:「各職種の工程調整してくれ」(koordinasi jadwal semua profesi)." },
  { id: 222, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "じょうげすいどうこうじじょうすいじょうげすいしょりじょう", jp: "上下水道工事", id_text: "Instalasi air bersih & kotor: treatment plant", desc: "上水道: sungai→浄水場→pipa→rumah. 下水道: air kotor→下水処理場→sungai/laut. Termasuk pekerjaan lahan dan instalasi pipa. Mandor:「管の勾配ちゃんと確認して」(cek kemiringan pipa)." },
  { id: 223, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "さいがいふっきゅうこうじ", jp: "災害復旧工事（さいがいふっきゅう）", id_text: "Pekerjaan pemulihan bencana", desc: "Jepang rutin mengalami kerusakan akibat topan, hujan, gempa. 災害復旧=perbaiki fasilitas sipil (sungai, jalan, pelabuhan) yang rusak dengan cepat. Mandor:「早急に復旧工事に取り掛かれ」(segera mulai perbaikan)." },
  { id: 224, category: "hourei", source: "jac-ch3", type: "konsep", furi: "くれえんいどうしきくれえんしかくしきい", jp: "クレーン・移動式クレーン資格", id_text: "Lisensi crane: batas 5t dan 1t", desc: "クレーン: ≥5t→免許, 1〜5t→技能講習. 移動式: ≥5t→免許. 玉掛け: ≥1t→技能講習, <1t→特別教育. Angka kunci: 5t (免許) dan 1t (玉掛け). Mandor:「何トン吊りですか、資格確認して」(berapa ton angkat, cek lisensi)." },
  { id: 225, category: "hourei", source: "jac-ch3", type: "konsep", furi: "こうしょさぎょうしゃしかくきょうかい", jp: "高所作業車の資格境界", id_text: "Kendaraan ketinggian: ≥10m teknik, <10m khusus", desc: "作業床 ≥10m → 技能講習修了者. 作業床 <10m → 特別教育修了者. Angka kunci: 10m. Mandor:「高所作業車、10m以上なら技能講習ね」(≥10m butuh teknik)." },
  { id: 226, category: "hourei", source: "jac-ch3", type: "konsep", furi: "しゃりょうけいけんせつきかいしかくきょうかい", jp: "車両系建設機械の資格境界", id_text: "Alat berat: ≥3t teknik, <3t pendidikan khusus", desc: "Buldoser, backhoe, dll: 機体重量 ≥3t → 技能講習. <3t → 特別教育. Angka kunci: 3t. Berlaku mesin gali, angkut, bongkar. Mandor:「機体重量3t以上は技能講習持ってる人で」(≥3t harus bersertifikat)." },
  { id: 227, category: "hourei", source: "jac-ch3", type: "konsep", furi: "がすようせつさぎょうしゅにんしゃめんきょああくようせつさぎょうしゃとくべつきょういく", jp: "ガス溶接・アーク溶接の資格", id_text: "Las gas: lisensi / Las arc: pendidikan khusus", desc: "ガス溶接作業主任者=免許(negara). ガス溶接作業者=技能講習. アーク溶接作業者=特別教育. Hierarki: 主任者>作業者. Mandor:「ガス溶接の主任者は免許持ってますよね」(pengawas las gas punya lisensi?)." },
  { id: 228, category: "haikan", source: "jac-ch3", type: "konsep", furi: "れいとうくうきちょうわききこうじだいひょうきき", jp: "冷凍空気調和機器工事の代表機器", id_text: "Mesin utama dalam pekerjaan AC/refrigerasi", desc: "Termasuk: エアコン (rumah+komersial), 冷凍庫, パッケージ型/セパレート型空調, 業務用冷凍冷蔵庫, ショーケース, 輸送用冷凍ユニット. Pekerja perlu skill配管 (銅管加工) karena pekerjaan ini mencakup juga instalasi refrigerant piping." },
  { id: 229, category: "shoubou", source: "jac-ch3", type: "konsep", furi: "しょうぼうせつびぶんるいしょうかけいほうひなん", jp: "消防設備の3分類（消火・警報・避難）", id_text: "3 kategori peralatan pemadam kebakaran wajib UU", desc: "①消火設備=sprinkler, hidran. ②警報設備=detektor asap, alarm. ③避難設備=perosotan, tangga evakuasi. Ketiganya wajib dipasang dan dirawat per 消防法. Mandor:「消防設備の点検記録見せて」(tunjukkan catatan inspeksi pemadam)." },
  { id: 230, category: "setsubi_kougu", source: "jac-ch3", type: "konsep", furi: "かくしゅろのしゅるいちくろこうじしょうさい", jp: "各種炉の種類（築炉工事詳細）", id_text: "Jenis-jenis tungku dalam pekerjaan chikuro", desc: "焼却炉=incinerator. キューポラ=lebur besi. 焼鈍炉=ratakan logam. 脱臭炉=hilang bau gas. アルミ溶解炉=lebur alumunium. バイオマスボイラー=bakar kayu. 電気炉=induksi. Mandor:「炉の内壁点検して」(cek dinding tungku)." },
  { id: 231, category: "sekou", source: "jac-ch3", type: "konsep", furi: "きかいどこうこうじだいひょうきかいぶるどおざあゆあつしょべるほいいるろおだあ", jp: "機械土工事の代表機械", id_text: "Alat berat tanah: buldoser, excavator, loader", desc: "ブルドーザ=dorong tanah. 油圧ショベル=gali+muat ke dump truck. ホイールローダ=muat material. クラムシェル=gali bawah air. Mandor:「ショベルで掘って、すぐローダに積んで」(gali lalu muat)." },
  { id: 232, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "うめたてこうじがんぺきこうじ", jp: "埋立工事 vs 岸壁工事（うめたて・がんぺき）", id_text: "Reklamasi laut vs Konstruksi dermaga kapal", desc: "埋立=tanah pengerukan ditimbun ke laut untuk lahan baru (bandara, industri). 岸壁=dermaga kapal pakai sheet pile baja (鋼矢板) dan tiang. Mandor:「鋼矢板の打設確認して」(cek sheet pile)." },
  { id: 233, category: "hourei", source: "jac-ch3", type: "konsep", furi: "けんちくきじゅんほうたいしんきじゅんしんどきょうきょう", jp: "建築基準法の耐震基準", id_text: "Standar tahan gempa UU Bangunan: 5kuat & 6kuat-7", desc: "震度5強→機能保持(tetap berfungsi). 震度6強〜7→倒壊しない(tidak runtuh). Angka kunci: 5強 dan 6強〜7. Mandor:「耐震補強の設計確認して」(cek desain penguatan tahan gempa)." },
  { id: 234, category: "doboku_hoso", source: "jac-ch3", type: "konsep", furi: "ほうそうそうろしょうろばんきそうひょうそうあすふるといにっしゃあ", jp: "舗装の4層", id_text: "4 lapisan jalan: subgrade/base/binder/wearing", desc: "①路床=dasar terbawah. ②路盤=batu pecah dipadatkan. ③基層=aspal pertama (アスファルトフィニッシャー). ④表層=aspal atas, tahan air. Mandor:「路盤の締固め確認してから基層打って」(cek kepadatan base dulu)." },
  { id: 235, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "くいのざいりょうしゅるいきくいこうくいこんくりいとくい", jp: "杭の材料3種", id_text: "3 material tiang pondasi: kayu / baja / beton", desc: "木杭=kayu (tanah lunak). 鋼杭=baja (kuat, dalam). コンクリート杭=paling umum: 場所打ち atau 既成 (pabrik). Pilih per kondisi tanah, kedalaman支持層, kebisingan. Mandor:「支持層まで何mか報告して」(laporkan kedalaman keras)." },
  { id: 236, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんくりいとあっそうこうじやくちいむわあく", jp: "コンクリート圧送工事の3役チームワーク", id_text: "3 peran tim pengecoran: pompa/selang/pemadatan", desc: "①操作オペレータ=operasikan pompa. ②筒先作業員=arahkan ujung selang ke bekisting. ③土工作業員=operasikan バイブレータ (締固め). Harus sinkron karena 生コン mulai mengeras. Mandor:「3人ちゃんと連携してくれ」(3 orang harus sinkron)." },
  { id: 237, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さかんしあげとぎだしあらいだし", jp: "左官仕上げ", id_text: "Finishing plester: poles batu vs cuci permukaan", desc: "研ぎ出し=permukaan dipoles hingga rata mengkilap. 洗い出し=batu hias (種石) dicampur semen, ditempel, dicuci sikat agar batu menonjol. Butuh teknik tinggi. Mandor:「洗い出し仕上げ、丁寧にやって」(cuci permukaan teliti)." },
  { id: 238, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "ざいらいじくぐみこうほうもくぞうじゅうたく", jp: "在来軸組工法（ざいらいじくぐみ）", id_text: "Rangka kayu tradisional Jepang — metode dominan", desc: "Metode kayu paling umum di Jepang: kolom (柱) dan balok (梁) dirakit sebagai rangka struktural. 工務店 tangani semua: desain, kayu, konstruksi. Mandor:「柱と梁の接合部確認して」(cek sambungan kolom-balok)." },
  { id: 239, category: "setsubi_kougu", source: "jac-ch3", type: "konsep", furi: "だくとしゅるいはいえんくうちょうはいき", jp: "ダクトの3種類", id_text: "3 jenis duct: asap kebakaran/AC/pembuangan", desc: "排煙ダクト=buang asap kebakaran. 空調ダクト=distribusi udara AC. 排気ダクト=buang panas/bau mesin/toilet. Dibuat dari lembaran logam (建築板金工事). Mandor:「排煙ダクトの気密テストして」(tes kedap duct asap)." },
  { id: 240, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "たてぐのざいりょうしゅるいしゃったあじどうどあ", jp: "建具の材料種類 + シャッター・自動ドア", id_text: "Material kusen/pintu + shutter & pintu otomatis", desc: "建具=semua pemasangan di bukaan (pintu, jendela, fusuma, shoji). Material: 木製・アルミ・樹脂・鋼・ステンレス. Termasuk シャッター dan 自動ドア取付工事. Mandor:「建具の建て付け調整して」(sesuaikan pasang kusen/pintu)." },
  { id: 241, category: "hourei", source: "jac-ch3", type: "konsep", furi: "でんきこうじしいっしゅにしゅおおがたしせついっしゅ", jp: "電気工事士（一種・二種）", id_text: "Lisensi teknisi listrik: kelas 1 vs kelas 2", desc: "二種=rumah/kecil (600V以下). 一種=gedung besar, pabrik, tegangan tinggi — wajib. Kerja tanpa lisensi = pelanggaran hukum. Mandor:「高圧工事は一種持ちでやって」(tegangan tinggi harus kelas 1)." },
  { id: 242, category: "hourei", source: "jac-ch3", type: "konsep", furi: "こうじたんにんしゃでんきつうしんしゅにんぎじゅつしゃ", jp: "工事担任者・電気通信主任技術者", id_text: "Lisensi telekomunikasi: penanggung jawab & teknis", desc: "Kesalahan instalasi telekomunikasi bisa sebabkan gangguan jaringan masif. ①工事担任者 dan ②電気通信主任技術者 adalah lisensi wajib — bukan sekadar 特別教育. Mandor:「工事担任者の資格証確認させて」(lihat sertifikat penanggung jawab)." },
  { id: 243, category: "hourei", source: "jac-ch3", type: "konsep", furi: "ごんどらそうさとくべつきょういくこうそうびるがいへきさぎょう", jp: "ゴンドラ操作", id_text: "Gondola gedung tinggi → wajib pendidikan khusus", desc: "特別教育（高層ビルの外壁作業）。ゴンドラ=platform gantung untuk dinding luar gedung tinggi. Wajib 特別教育. Berbeda dari 高所作業車 yang berjalan di darat. Mandor:「ゴンドラ作業、特別教育受けてる人ですか」(sudah pelatihan khusus?)." },
  { id: 244, category: "hourei", source: "jac-ch3", type: "konsep", furi: "さんそけつぼうきけんさぎょうしゅにんしゃぎのうこうしゅうまんほおるちかどう", jp: "酸素欠乏危険作業主任者", id_text: "Pengawas kerja O₂ rendah → wajib pelatihan teknik", desc: "技能講習（マンホール・地下道）。Manhole/tunnel = risiko 酸素欠乏症 dan 硫化水素中毒. Pengawas (作業主任者) wajib 技能講習. Pekerja biasa wajib 特別教育. Mandor:「地下道に入る前、酸欠の確認して」(cek kadar oksigen sebelum masuk)." },
  { id: 245, category: "hourei", source: "jac-ch3", type: "konsep", furi: "いしわたあすべすととりあつかいさぎょうしゃとくべつきょういく", jp: "石綿（アスベスト）取り扱い作業者", id_text: "Pekerja asbes saat bongkar bangunan → khusus wajib", desc: "Bangunan lama mengandung 石綿 (asbes) dibongkar sangat hati-hati. Pekerja wajib 特別教育修了者 (石綿則第27条). Berbeda dari 石綿作業主任者 yang perlu 技能講習. Mandor:「石綿は飛散しないよう防護してくれ」(lindungi agar asbes tidak beterbangan)." },
  { id: 246, category: "hourei", source: "jac-ch3", type: "konsep", furi: "ゆうきようざいさぎょうしゅにんしゃぎのうこうしゅうしつないたんく", jp: "有機溶剤作業主任者", id_text: "Pengawas pelarut organik → wajib pelatihan teknik", desc: "技能講習（室内タンク等）。Bekerja dengan 有機溶剤 di ruang dalam/tangki bisa sebabkan keracunan. Pengawas wajib 技能講習. Berlaku kadar pelarut >5%. Mandor:「有機溶剤使う前に換気して」(ventilasi dulu)." },
  { id: 247, category: "doboku_haisui", source: "jac-ch3", type: "konsep", furi: "おんせんせいちねつせいふかさときけんせい", jp: "温泉井 vs 地熱井", id_text: "Sumur panas vs panas bumi: kedalaman & bahaya", desc: "温泉井=500〜1000m, bahaya: gas alam keluar saat bor → perlu izin. 地熱井=±2000m (terdalam), bahaya: 熱水・蒸気・有害物質 → keahlian tertinggi. Mandor:「掘削中はガス検知器つけといて」(pasang detektor gas selama pengeboran)." },
  { id: 248, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ふきつけうれたんせこうまえけんさっいたせこうちゅうかくにんかんかく", jp: "吹付けウレタン", id_text: "QC uretan semprot: uji papan + ukur ketebalan", desc: "Sebelum施工: semprotkan ke papan 450mm×450mm, cek kepadatan busa. Selama施工: tiap 4〜5m ukur ketebalan. Permukaan beton wajib bersih. Mandor:「施工前確認板、見せて」(tunjukkan papan uji)." },
  { id: 249, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんくりいとぶろっくぞうぞうてっきんもるたるほきょう", jp: "コンクリートブロック造（CB造）", id_text: "Blok beton: tulangan di rongga + mortar penguat", desc: "Blok beton berlubang disusun. Rongga diisi tulangan baja lalu dicor mortar, lebih kokoh dari bata. Untuk pagar, tembok penahan, bangunan kecil. Mandor:「ブロックの通り確認して」(cek kesejajaran blok)." },
  { id: 250, category: "sekou", source: "jac-ch4", type: "konsep", furi: "たてずみしあげずみ", jp: "立て墨（たてずみ）・仕上げ墨（しあげずみ）", id_text: "Garis referensi vertikal / Garis dimensi finishing", desc: "立て墨=garis vertikal di dinding/kolom. 仕上げ墨=referensi dimensi finishing dari sumbu/permukaan struktural. Mandor:「立て墨と仕上げ墨の位置を確認して」." },
  { id: 251, category: "sekou", source: "jac-ch4", type: "konsep", furi: "おやずみ", jp: "親墨（おやずみ）", id_text: "Garis induk / garis referensi utama", desc: "Garis referensi utama seperti 通り芯 (sumbu kolom/dinding) dan 陸墨 (horizontal) yang menjadi DASAR untuk pekerjaan墨出し di tahap berikutnya. Disebut 'induk' karena semua garis lain diturunkan dari sini." },
  { id: 252, category: "sekou", source: "jac-ch4", type: "konsep", furi: "かねをふるすみつけ", jp: "矩を振る（かねをふる）・墨付け（すみつけ）", id_text: "Buat sudut 90° / penandaan kayu untuk dipotong", desc: "矩を振る=membuat garis sudut 90° di tahap 墨出し. 墨付け=memberi tanda pengerjaan pada kayu struktural. Mandor:「矩と墨付けを正確にやれ」." },
  { id: 253, category: "sekou", source: "jac-ch4", type: "konsep", furi: "きじゅんずみ", jp: "基準墨（きじゅんずみ）", id_text: "Garis referensi dasar bangunan", desc: "Garis lurus horizontal/vertikal yang menjadi standar utama saat mendirikan bangunan. Dari garis ini, 通り芯 (sumbu kolom/dinding) diturunkan. Dibuat menggunakan墨つぼ tradisional atau laser墨出し器." },
  { id: 254, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "じなわばりみずいと", jp: "地縄張り（じなわばり）・水糸（みずいと）", id_text: "Penandaan pondasi di tanah / benang referensi", desc: "地縄張り=menandai posisi pondasi di tanah dengan tali. 水糸=benang horizontal direntangkan antar papan 水貫 sebagai referensi sumbu bangunan. Mandor:「地縄と水糸を確認してから掘れ」." },
  { id: 255, category: "sekou", source: "jac-ch4", type: "konsep", furi: "たかさきごう", jp: "FH・SL・CH（高さ記号）", id_text: "FH = tinggi tanah / SL = slab / CH = plafon", desc: "FH=Formation Height (tinggi tanah rencana). SL=Slab Level (tinggi permukaan slab). CH=Ceiling Height (jarak FL ke plafon). Melengkapi GL/FL/BM. Mandor:「FHとSLとCHを図面で確認して」." },
  { id: 256, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "もりどだんぎり", jp: "盛り土（もりど）・段切り（だんきり）", id_text: "Timbunan tanah / Pemotongan tangga pada lereng", desc: "盛り土 = menimbun tanah untuk meratakan lahan yang tidak rata atau miring. 段切り = memotong lahan miring secara bertingkat seperti tangga sebelum menimbun, agar timbunan tidak longsor." },
  { id: 257, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "ねきりよぼりすきとりとこづけ", jp: "根切り・余堀り・鋤取り・床付け", id_text: "Galian pondasi, galian lebih, perataan, dasar", desc: "根切り=gali hingga kedalaman pondasi. 余堀り=galian lebih untuk ruang kerja. 鋤取り=ratakan dasar. 床付け=finishing dasar secara presisi. Mandor:「床付けは丁寧にやれよ」." },
  { id: 258, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "うめもどしつきがためみずしめ", jp: "埋め戻し・突き固め・水締め", id_text: "Urugan balik / pemadatan manual / dengan air", desc: "埋め戻し=isi kembali tanah setelah pekerjaan bawah tanah. 突き固め=padatkan dengan ランマ. 水締め=tuang air sambil memadatkan. Mandor:「しっかり締め固めてくれ」." },
  { id: 259, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ようへきやいたこうやいた", jp: "擁壁・矢板・鋼矢板", id_text: "Dinding penahan tanah / papan turap / turap baja", desc: "擁壁=dinding penahan tanah. 矢板=papan penahan tanah. 鋼矢板=turap baja ujung alur sehingga bisa saling mengunci. Mandor:「鋼矢板の継ぎ目を確認して」." },
  { id: 260, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "のりめんじやまやまがくるやまどめ", jp: "法面・地山・山がくる・山留め", id_text: "Lereng galian / tanah alami / longsor / penahan", desc: "法面=permukaan miring galian. 地山=tanah kondisi alami. 山がくる=lereng LONGSOR — BAHAYA! 山留め=menahan tanah agar tidak runtuh. Mandor:「山留めが変形したらすぐ報告して」." },
  { id: 261, category: "sekou", source: "jac-ch4", type: "konsep", furi: "かまばみずかえまんぼう", jp: "釜場・水替え・万棒", id_text: "Lubang pompa / pemompaan galian / hitungan masuk", desc: "釜場=lubang di dasar galian tempat pompa dipasang. 水替え=pompa air yang menggenang. 万棒=hitung jumlah truk/orang yang masuk lokasi. Mandor:「釜場のポンプを動かしておけよ」." },
  { id: 262, category: "sekou", source: "jac-ch4", type: "konsep", furi: "じぎょうべたきそふうちんぐくいきそ", jp: "地業・ベタ基礎・フーチング・杭基礎", id_text: "Pekerjaan pondasi / 3 jenis pondasi utama", desc: "地業=pekerjaan di bawah slab pondasi. ベタ基礎=cor beton seluruh dasar. フーチング=hanya di titik beban. 杭基礎=pondasi tiang di tanah lunak. Mandor:「転圧後に捨てコンを打てよ」." },
  { id: 263, category: "sekou", source: "jac-ch4", type: "konsep", furi: "すらぶ", jp: "スラブ（構造スラブ・基礎スラブ・フラットスラブ）", id_text: "Slab (pelat lantai/pondasi/tanpa balok)", desc: "スラブ = pelat datar pada bangunan (lantai, pondasi, dll). 構造スラブ = slab yang menopang bangunan. 基礎スラブ = slab di bagian pondasi. フラットスラブ = slab tanpa balok (梁なし)." },
  { id: 264, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "きそめんしん", jp: "基礎免振（きそめんしん）", id_text: "Isolasi seismik pada pondasi", desc: "Sistem yang menyerap gaya horizontal gempa sehingga getaran berkurang sebelum masuk bangunan. Dipasang antara tanah dan pondasi. Mandor:「免振の点検は専門業者に任せてくれよ」." },
  { id: 265, category: "anzen", source: "jac-ch4", type: "konsep", furi: "あしばのしゅるいわくぐみたんかんくさびきんけつしき", jp: "足場の種類：枠組み・単管・くさび", id_text: "Jenis perancah: rangka / pipa tunggal / pasak", desc: "枠組み=rangka prefabrikasi. 単管=pipa tunggal, fleksibel. くさび緊結式=dikunci pasak, kuat dan cepat. Mandor:「足場の種類は作業内容に合わせて選んでくれ」." },
  { id: 266, category: "anzen", source: "jac-ch4", type: "konsep", furi: "さぎょうゆかかりがこい", jp: "作業床（さぎょうゆか）・仮囲い（かりがこい）", id_text: "Lantai kerja (perancah) / Pagar sementara lokasi", desc: "作業床=lantai perancah dari papan tempat pekerja berdiri. 仮囲い=pagar sementara lokasi dari jalan/lahan tetangga. Mandor:「作業床の隙間と仮囲いの固定を確認しろよ」." },
  { id: 267, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "はいきんかんかくあき", jp: "配筋・間隔（かんかく）・あき", id_text: "Pemasangan tulangan / jarak as-as / jarak bersih", desc: "配筋=mengatur dan merakit besi tulangan. 間隔=jarak center-to-center. あき=jarak BERSIH antar tulangan. Wajib dipenuhi sesuai standar. Mandor:「あきと間隔を図面通りに確認して」." },
  { id: 268, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "かぶりあつさ", jp: "かぶり厚さ", id_text: "Selimut beton (jarak tulangan ke permukaan beton)", desc: "Jarak antara permukaan LUAR besi tulangan ke permukaan beton yang menutupinya. Harus cukup tebal untuk melindungi tulangan dari korosi dan api. Termasuk hal yang selalu dicek dalam inspeksi kualitas." },
  { id: 269, category: "sekou", source: "jac-ch4", type: "konsep", furi: "すてこんくりいとすてこん", jp: "捨てコンクリート（すてコン）", id_text: "Beton lantai kerja (beton lean/blinding)", desc: "Beton tipis 5–10 cm dicor di atas 地業 sebelum tulangan dan bekisting dipasang. Membuat referensi ketinggian akurat dan permukaan rata. Mandor:「捨てコンの墨出しをしっかりやってくれ」." },
  { id: 270, category: "sekou", source: "jac-ch4", type: "konsep", furi: "けっそくはっかあ", jp: "結束（けっそく）・ハッカー", id_text: "Pengikatan tulangan / Alat pengikat kawat besi", desc: "結束=mengikat persilangan tulangan dengan kawat 結束線 menggunakan ハッカー. Cara ikat: たすき掛け atau 片だすき. Mandor:「ハッカーの使い方を覚えてくれよ」." },
  { id: 271, category: "sekou", source: "jac-ch4", type: "konsep", furi: "うちかさねうちつぎこおるどじょいんと", jp: "打ち重ね vs 打ち継ぎ", id_text: "Pengecoran di atas beton belum/sudah keras", desc: "打ち重ね=cor di atas beton BELUM keras; batas 150mnt (<25°C) atau 120mnt (≥25°C). Terlambat→コールドジョイント. 打ち継ぎ=cor di atas SUDAH keras. Mandor:「時間を守って打ち重ねろ」." },
  { id: 272, category: "anzen", source: "jac-ch4", type: "konsep", furi: "ぱんくかたわくほうかい", jp: "パンク（型枠崩壊）", id_text: "Pecahnya bekisting akibat tekanan beton", desc: "Bekisting pecah saat pengecoran karena 支保工 tidak kuat sehingga beton mengalir keluar. Berbahaya dan menyebabkan pemborosan besar. Mandor:「パンクしたらすぐ作業を止めて報告しろよ」." },
  { id: 273, category: "sekou", source: "jac-ch4", type: "konsep", furi: "おさまりとりあい", jp: "納まり（おさまり）・取合い（とりあい）", id_text: "Kerapian pemasangan / pertemuan dua elemen berbeda", desc: "納まり=keserasian tata letak elemen. 取合い=pertemuan dua elemen berbeda. Keduanya sering digunakan bersamaan. Mandor:「取合いの納まりが悪いから直してくれ」." },
  { id: 274, category: "sekou", source: "jac-ch4", type: "konsep", furi: "つらいちふろくめちがい", jp: "面一・不陸・目違い", id_text: "Rata sejajar / tidak rata / tepi tak sejajar", desc: "面一(つらいち)=dua permukaan dalam satu bidang rata. 不陸=permukaan bergelombang. 目違い=sambungan tile/papan yang tidak sejajar. Mandor:「面一になってるか確認してくれよ」." },
  { id: 275, category: "sekou", source: "jac-ch4", type: "konsep", furi: "だめてなおしてもどりだんどり", jp: "駄目・手直し・手戻り・段取り", id_text: "Pekerjaan sisa / koreksi / ulang / urutan kerja", desc: "駄目=pekerjaan terlewat saat hampir finishing. 手直し=koreksi sebagian. 手戻り=mengulang pekerjaan (buang waktu). 段取り=rencanakan urutan kerja. Mandor:「段取りして手戻りを減らせよ」." },
  { id: 276, category: "sekou", source: "jac-ch4", type: "konsep", furi: "たっぱうわばしたば", jp: "建端（たっぱ）・上端・下端", id_text: "Tinggi elemen / ujung atas / ujung bawah elemen", desc: "建端(たっぱ)=tinggi elemen. 上端=tepi atas elemen. 下端=tepi bawah elemen. Digunakan saat memberi instruksi pemasangan di lapangan. Mandor:「上端と下端の位置を確認してから取り付けて」." },
  { id: 277, category: "sekou", source: "jac-ch4", type: "konsep", furi: "いっけんいっしゃくいっすんひとつぼ", jp: "一間・一尺・一寸・一坪", id_text: "1 ken≈1.8m / 1 shaku≈30cm / 1 tsubo≈3.3m²", desc: "Satuan lama yang masih dipakai: 1間≈1.818m, 1尺≈30.3cm, 1寸≈3.03cm. 1坪=1間×1間≈3.3m². Muncul dalam gambar tradisional. Mandor:「この部屋は3坪くらいだ」." },
  { id: 278, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ぴっち", jp: "ピッチ（割り付けの間隔）", id_text: "Jarak pemasangan berulang / pitch antar elemen", desc: "Jarak antara elemen yang dipasang berulang: tulangan, baut, atau tile. Lebih umum dari 間隔. Contoh: ピッチ200mm. Mandor:「ピッチ200ミリで正確に並べてくれ」." },
  { id: 279, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "ぞうぞうぞうもくぞう", jp: "RC造・S造・SRC造・木造", id_text: "RC / S / SRC / kayu — 4 jenis struktur bangunan", desc: "RC造=beton bertulang. S造=baja. SRC造=baja+beton bertulang. 木造=kayu. Wajib dikenali untuk identifikasi pekerjaan SSW. Mandor:「この現場はRC造だから配筋が重要だ」." },
  { id: 280, category: "denki", source: "jac-ch4", type: "konsep", furi: "ぜつえんろうでんせっちああす", jp: "絶縁・漏電・接地・アース", id_text: "Isolasi listrik / kebocoran arus / grounding", desc: "絶縁=cegah arus bocor. 漏電=arus bocor — bahaya! 接地(アース)=hubungkan ke tanah untuk cegah感電. Mandor:「アースが取れているか確認してくれよ」." },
  { id: 281, category: "denki", source: "jac-ch4", type: "konsep", furi: "かくうはいせんまいせつはいせん", jp: "架空配線 vs 埋設配線", id_text: "Kabel via tiang listrik vs ditanam di tanah", desc: "架空配線=kabel via tiang listrik ke gedung. 埋設=kabel ditanam di tanah; 3 cara: 管路式, 直接埋設式, とう道. Mandor:「埋設方式だから掘削に注意して」." },
  { id: 282, category: "denki", source: "jac-ch4", type: "konsep", furi: "いんぺいはいかんろしゅつはいかん", jp: "隠ぺい配管 vs 露出配管", id_text: "Pipa tersembunyi di dinding/plafon vs terlihat", desc: "隠ぺい配管=pipa di dalam dinding, plafon, atau lantai. 露出配管=pipa tampak di permukaan. Pilihan tergantung estetika dan perawatan. Mandor:「この部屋は露出配管でいいから天井へ」." },
  { id: 283, category: "denki", source: "jac-ch4", type: "konsep", furi: "ていあつこうあつとくべつこうあつ", jp: "低圧・高圧・特別高圧（電圧の区分）", id_text: "3 kelas tegangan listrik Jepang — batas DC & AC", desc: "低圧: DC≤750V, AC≤600V. 高圧: DC/AC 750V–7000V. 特別高圧: >7000V. Menentukan syarat kualifikasi pekerja listrik. Mandor:「高圧部分には絶対に触れるな」." },
  { id: 284, category: "denki", source: "jac-ch4", type: "konsep", furi: "ちょくりゅうこうりゅう", jp: "直流（DC）vs 交流（AC）", id_text: "Arus searah vs Arus bolak-balik", desc: "直流(DC)=arus yang besar dan arahnya tidak berubah. 交流(AC)=arus yang berubah secara periodik. Listrik rumah tangga Jepang AC 100V. Mandor:「直流と交流を間違えないようにして」." },
  { id: 285, category: "denki", source: "jac-ch4", type: "konsep", furi: "えむぢいえふ", jp: "MDF（通信分配盤）", id_text: "Panel distribusi utama telekomunikasi gedung", desc: "Papan distribusi yang mengelola saluran komunikasi dari luar gedung ke dalam. Semua jalur masuk ke MDF dulu sebelum didistribusikan. Mandor:「MDFの配線は図面通りにやってくれ」." },
  { id: 286, category: "denki", source: "jac-ch4", type: "konsep", furi: "あいぢばあぱいぢこんるし", jp: "Φ（ファイ / パイ）", id_text: "Simbol diameter — dibaca PAI di konstruksi Jepang", desc: "Φ=simbol diameter. Secara matematik dibaca ファイ(fai), namun di konstruksi Jepang dibaca パイ(pai). Contoh: Φ50パイプ=pipa diameter 50mm. Mandor:「このパイプ、パイ50だから間違えるな」." },
  { id: 287, category: "denki", source: "jac-ch4", type: "konsep", furi: "つうでんあたるかしめるとぶおちる", jp: "通電・あたる・かしめる・飛ぶ/落ちる", id_text: "Ada arus / cek alat / crimp kabel / breaker trip", desc: "通電=arus aktif. あたる=cek dengan alat ukur. かしめる=crimp ujung kabel ke terminal. 飛ぶ/落ちる=breaker trip. Mandor:「ブレーカーが飛んだら原因確認してから復旧して」." },
  { id: 288, category: "setsubi_kougu", source: "jac-ch4", type: "konsep", furi: "くうちょうかんきはいえん", jp: "空調・換気・排煙", id_text: "AC/ventilasi udara / sirkulasi / pembuangan asap", desc: "空調=mengatur suhu, kelembapan, dan kualitas udara. 換気=ganti udara kotor dengan segar. 排煙=keluarkan asap saat kebakaran — K3 wajib. Mandor:「排煙ダクトは図面通りにしてくれ」." },
  { id: 289, category: "haikan", source: "jac-ch4", type: "konsep", furi: "おすいざつはいすい", jp: "汚水（おすい）・雑排水（ざつはいすい）", id_text: "Air limbah toilet / air limbah non-toilet", desc: "汚水=air buangan dari WC/toilet. 雑排水=air buangan dari kamar mandi, wastafel, dan dapur. Disalurkan terpisah sebelum diolah. Mandor:「汚水管と雑排水管を間違えないで接続してくれ」." },
  { id: 290, category: "haikan", source: "jac-ch4", type: "konsep", furi: "ろうえいしけんすいあつしけんまんすいしけん", jp: "漏洩試験（ろうえいしけん）：水圧試験・満水試験", id_text: "Uji kebocoran: uji tekanan air / uji penuh air", desc: "漏洩試験=uji kebocoran setelah pipa terpasang. 水圧試験=pipa suplai diberi tekanan. 満水試験=pipa drainase diisi penuh. Mandor:「試験前に全バルブを閉めてから加圧してくれ」." },
  { id: 291, category: "haikan", source: "jac-ch4", type: "konsep", furi: "らいにんぐぎゃくかんこうばい", jp: "ライニング・逆流・勾配", id_text: "Pelapisan pipa / aliran balik / kemiringan pipa", desc: "ライニング=melapisi permukaan dalam pipa pelindung. 逆流=cairan mengalir berlawanan arah. 勾配=kemiringan pipa agar air mengalir. Mandor:「勾配を確認してから配管固定してくれよ」." },
  { id: 292, category: "career", source: "jac-ch4", type: "konsep", furi: "ほうれんそうほうこくれんらくそうだん", jp: "ほうれんそう（報告・連絡・相談）", id_text: "Laporan / Komunikasi / Konsultasi — 3 pilar kerja", desc: "ほうれんそう=報告 (lapor ke atasan), 連絡 (sampaikan info/jadwal), 相談 (konsultasikan masalah). Sampaikan singkat dan jelas. Mandor:「問題があったらすぐ相談してくれよ」." },
  { id: 293, category: "career", source: "jac-ch4", type: "konsep", furi: "さぎょういんつめしょのるうる", jp: "作業員詰め所（さぎょういんつめしょ）のルール", id_text: "Aturan di ruang pekerja/ganti lokasi konstruksi", desc: "作業員詰め所=ruang ganti/istirahat pekerja. Aturan: merokok di tempat khusus, ポイ捨て禁止, helm di tempat ditentukan, barang di loker, cuci tangan, cek 掲示板. Mandor:「詰め所のルールを守ってくれよ」." },
  { id: 294, category: "sekou", source: "jac-ch4", type: "konsep", furi: "みつけみえがかりみえかくれ", jp: "見付け・見え掛かり・見え隠れ", id_text: "Tampak penuh / tampak sebagian / tampak bila gerak", desc: "見付け=permukaan yang sepenuhnya terlihat dari depan. 見え掛かり=tampak dari celah/sudut miring. 見え隠れ=tampak hanya saat sesuatu digeser. Mandor:「見付け部分は特に丁寧に仕上げてくれ」." },
  { id: 295, category: "sekou", source: "jac-ch4", type: "konsep", furi: "そりむくりろく", jp: "反り vs 起り・陸", id_text: "Melengkung cekung / cembung / horizontal sempurna", desc: "反り(そり)=melengkung CEKUNG. 起り(むくり)=melengkung CEMBUNG. 陸(ろく)=horizontal sempurna; 陸屋根=atap datar. Mandor:「この面が反っているから直してくれよ」." },
  { id: 296, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ころびにげ", jp: "転び（ころび）・逃げ（にげ）", id_text: "Elemen miring dari vertikal / toleransi dimensi", desc: "転び=kolom/dinding yang seharusnya tegak namun miring. 拝む=bangunan yang miring. 逃げ=toleransi dimensi yang SENGAJA diambil untuk menyerap kesalahan. Mandor:「柱が転んでいるから修正してくれ」." },
  { id: 297, category: "sekou", source: "jac-ch4", type: "konsep", furi: "みきるみきりざえなじみ", jp: "見切る・見切り材・馴染み", id_text: "Selesaikan sambungan / penutup / kerapatan", desc: "見切る=selesaikan sambungan dua pekerjaan finishing. 見切り材=material penutup sambungan. 馴染み=kerapatan sambungan. Mandor:「見切り材の馴染みが悪いから直してくれ」." },
  { id: 298, category: "sekou", source: "jac-ch4", type: "konsep", furi: "べたふかし", jp: "ベタ・ふかし（ふかす）", id_text: "Menutup seluruh permukaan / penebalan finishing", desc: "ベタ=menutupi seluruh permukaan tanpa celah (contoh: ベタ塗り). ふかし=finishing dibuat lebih tebal/maju dari desain awal. Mandor:「ここはふかして仕上げをそろえてくれ」." },
  { id: 299, category: "sekou", source: "jac-ch4", type: "konsep", furi: "とおりをみる", jp: "通り（とおり）を見る", id_text: "Mengecek kelurusan elemen", desc: "通り=kondisi lurus. 通りが悪い=bengkok. 通りを見る=memeriksa kelurusan dengan alat. Dipakai saat QC besi, dinding, kolom. Mandor:「柱の通りを見てくれよ、少し曲がってるぞ」." },
  { id: 300, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ひろいだし", jp: "拾い出し（ひろいだし）", id_text: "Perhitungan kebutuhan material dari gambar", desc: "Proses membaca gambar kerja untuk menghitung jumlah material dan tenaga kerja. Mirip quantity take-off. Mandor:「拾い出しをしてから材料を発注してくれよ」." },
  { id: 301, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ばしょううちうつだせつする", jp: "場所打ち（ばしょうち）・打つ／打設する（だせつ）", id_text: "Pengecoran di lokasi / istilah menuang beton", desc: "場所打ち=beton yang dicor langsung di lokasi, bukan precast. 打つ/打設する=terminologi untuk menuang beton ke dalam bekisting. Mandor:「打設前に型枠を確認して」." },
  { id: 302, category: "sekou", source: "jac-ch4", type: "konsep", furi: "のろあんこ", jp: "ノロ・アンコ", id_text: "Adukan semen encer / penyumbat sementara bekisting", desc: "ノロ=campuran semen+air sangat encer; juga bocoran beton dari celah bekisting. アンコ=pengisi di bekisting untuk membentuk cekungan. Mandor:「ノロが漏れないよう型枠を締めてくれ」." },
  { id: 303, category: "sekou", source: "jac-ch4", type: "konsep", furi: "てにょうくぎじまい", jp: "転用（てんよう）・釘仕舞", id_text: "Pemakaian ulang bekisting / pencabutan paku bekas", desc: "転用=memakai kembali bekisting di lokasi berbeda untuk hemat biaya. 釘仕舞=mencabut semua paku dari bekisting bekas agar bisa dipakai ulang. Mandor:「転用するなら釘仕舞をちゃんとやってくれ」." },
  { id: 304, category: "sekou", source: "jac-ch4", type: "konsep", furi: "はいごうねりまぜたんぴんぐ", jp: "配合・練り混ぜ・タンピング", id_text: "Rasio campuran beton / pengadukan / pemadatan slab", desc: "配合=perbandingan semen, pasir, kerikil, air. 練り混ぜ=mencampur hingga merata. タンピング=ketuk permukaan slab agar padat. Mandor:「配合は設計通りにして、タンピングも忘れずに」." },
  { id: 305, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "あそびたてかみ", jp: "あそび・建込み（たてこみ）", id_text: "Kelonggaran sambungan / mendirikan bekisting tegak", desc: "あそび=kelonggaran yang disengaja agar sambungan tidak terlalu kencang. 建込み=mendirikan bekisting sesuai garis 墨出し dan dikunci pada posisi. Mandor:「建込みは墨に合わせてあそびを確認してくれ」." },
  { id: 306, category: "denki", source: "jac-ch4", type: "konsep", furi: "はいせんりかくかんつう", jp: "配線・離隔・貫通", id_text: "Penarikan kabel / jarak pisah / melubangi dinding", desc: "配線=memasang dan merentangkan kabel. 離隔=jarak pemisahan wajib antar kabel berbeda jenis. 貫通=lubangi dinding/lantai untuk jalur kabel. Mandor:「離隔距離を守って配線してくれよ」." },
  { id: 307, category: "denki", source: "jac-ch4", type: "konsep", furi: "つうせんはいかんするすらぶはいかんしこむ", jp: "通線・配管する・スラブ配管・仕込む", id_text: "Tarik kabel / konduit / konduit slab / persiapan", desc: "通線=tarik kabel ke dalam konduit. 配管する=pasang konduit. スラブ配管=konduit ditanam dalam slab. 仕込む=persiapkan pekerjaan agar lancar. Mandor:「スラブ配管は打設前に仕込んでおいてくれ」." },
  { id: 308, category: "denki", source: "jac-ch4", type: "konsep", furi: "ひらいしんひらいき", jp: "避雷針 vs 避雷器", id_text: "Penangkal petir bangunan vs arrester alat", desc: "避雷針=perangkat di atap yang menangkap petir, alirkan arus ke tanah — lindungi BANGUNAN. 避雷器=lindungi PERALATAN dari lonjakan tegangan. Mandor:「避雷針と避雷器は違うから図面で確認してくれ」." },
  { id: 309, category: "denki", source: "jac-ch4", type: "konsep", furi: "ひふくいちじがわにじがわ", jp: "被覆・一次側・二次側", id_text: "Selubung kabel / sisi masuk / sisi keluar listrik", desc: "被覆=lapisan vinil/isolasi yang membungkus kawat inti. 一次側=sisi INPUT listrik. 二次側=sisi OUTPUT. Penting saat menghubungkan panel. Mandor:「一次側と二次側を間違えないよう接続してくれ」." },
  { id: 310, category: "denki", source: "jac-ch4", type: "konsep", furi: "まししめまあきんぐ", jp: "増し締め（ましじめ）・マーキング", id_text: "Pengencangan ulang baut / penandaan setelah itu", desc: "増し締め=kencangkan kembali baut/sekrup yang longgar secara berkala. マーキング=beri tanda pada baut setelah dikencangkan agar terlihat jika bergeser. Mandor:「増し締め後には必ずマーキングしてくれよ」." },
  { id: 311, category: "denki", source: "jac-ch4", type: "konsep", furi: "ふるせるふせる", jp: "振る・競る・伏せる", id_text: "Reroute pipa / hampir tabrakan / ujung slab", desc: "振る=ubah jalur pipa/kabel menghindari hambatan. 競る=dua elemen hampir bersentuhan. 伏せる=buat titik exit pipa konduit dari permukaan slab. Mandor:「競っているところを振って回避してくれ」." },
  { id: 312, category: "haikan", source: "jac-ch4", type: "konsep", furi: "えいせいせつびしにみず", jp: "衛生設備・死水", id_text: "Peralatan sanitasi / air stagnan dalam pipa", desc: "衛生設備=peralatan kebersihan pakai air: toilet, kamar mandi (BUKAN dapur). 死水=air diam lama dalam pipa/tangki — bisa terkontaminasi. Mandor:「定期的に水を流して死水対策をしてくれ」." },
  { id: 313, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ばりばりとり", jp: "バリ・バリ取り", id_text: "Gerinda sisa pemotongan / proses membuangnya", desc: "バリ=tonjolan sisa material di tepi produk logam/plastik akibat pemotongan. バリ取り=membersihkan バリ agar permukaan rata dan aman. Mandor:「パイプを切ったらバリ取りをして怪我防止しろ」." },
  { id: 314, category: "haikan", source: "jac-ch4", type: "konsep", furi: "ぶんきしんしゅくじゃばら", jp: "分岐・伸縮・蛇腹", id_text: "Percabangan pipa / memuai-menyusut / fleksibel", desc: "分岐=satu pipa terbagi dua. 伸縮=material memanjang/memendek akibat suhu. 蛇腹=konektor akordeon untuk menyerap 伸縮. Mandor:「長い配管には蛇腹を入れて伸縮に対応してくれ」." },
  { id: 315, category: "haikan", source: "jac-ch4", type: "konsep", furi: "しんさきはいかんようご", jp: "芯（しん）・先（さき）（配管用語）", id_text: "Garis sumbu pipa/duct / Ujung/end pipa", desc: "芯=garis tengah (center line) pipa atau duct — referensi pengukuran. 先=ujung/end dari pipa. Keduanya khas di konteks pekerjaan pipa. Mandor:「芯から先の長さを正確に測ってくれ」." },
  { id: 316, category: "anzen", source: "jac-ch4", type: "konsep", furi: "ふくそうのちゅうい", jp: "服装の注意（ふくそうのちゅうい）4項目", id_text: "4 pantangan pakaian di lokasi konstruksi", desc: "4 larangan: ①半袖・短パン禁止 ②上着前開け禁止 (tersangkut) ③袖まくり禁止 (lengan ke pergelangan) ④ポケット手禁止 (tak bisa menahan saat jatuh). Mandor:「服装を整えて入場してくれ」." },
  { id: 317, category: "career", source: "jac-ch4", type: "konsep", furi: "あとかたづけしょうかかくにん", jp: "後片付け・消火確認", id_text: "Beres-beres setelah kerja / konfirmasi api padam", desc: "Setelah kerja selesai WAJIB beres-beres dengan mindset mempersiapkan段取り untuk esok. Jika pakai api, pastikan padam sebelum pulang. Mandor:「帰る前に火の元を必ず確認してくれよ」." },
  { id: 318, category: "sekou", source: "jac-ch4", type: "konsep", furi: "すてざいりょう", jp: "捨て（すて）材料（ざいりょう）", id_text: "Material sacrificial untuk kelancaran konstruksi", desc: "捨て=material non-struktural untuk memudahkan 施工. Contoh: 捨てコン, 捨て板, 捨て石. Mandor:「捨てコンを打ってから墨出しをするんだよ」." },
  { id: 319, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "くいまさらいだんばね", jp: "杭間さらい・段跳ね", id_text: "Penggalian di antara tiang / angkat tanah bertahap", desc: "杭間さらい=saat 床付け, ratakan tanah di antara tiang pondasi. 段跳ね=galian dalam, tanah diangkat bertahap ke atas melalui undakan. Mandor:「杭間さらいは基礎工事に影響するからちゃんとやれ」." },
  { id: 320, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "やまずな", jp: "山砂（やまずな）", id_text: "Pasir gunung/daratan (berbeda dari pasir sungai)", desc: "Pasir dari daratan (bukan sungai). Daya serap air (保水性) lebih tinggi dari pasir sungai. Digunakan sebagai material urugan balik. Mandor:「山砂は保水性が高いから水締めをしっかりやってくれよ」." },
  { id: 321, category: "doboku_haisui", source: "jac-ch4", type: "konsep", furi: "きせいくいこうほうばしょううちこんくりいとくいこうほう", jp: "既成杭工法 vs 場所打ちコン杭工法", id_text: "Tiang prefabrikasi vs tiang beton cor di tempat", desc: "既成杭=tiang dibuat di pabrik lalu dipancang. 場所打ち杭=lubang dibor di lokasi lalu dicor. Pilihan tergantung kondisi tanah dan beban. Mandor:「杭工法は地質調査の結果で決めるんだ」." },
  { id: 322, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "こんくりいとぶろっくぞう", jp: "コンクリートブロック造（ぞう）", id_text: "Struktur bata/blok beton yang ditumpuk", desc: "Jenis struktur menggunakan blok beton yang ditumpuk. Dipakai untuk pagar, dinding pembatas, dan bangunan kecil. Berbeda dari RC造 yang dicor monolit. Mandor:「ブロック積みは目地を一直線にそろえてくれよ」." },
  { id: 323, category: "sekou", source: "jac-ch4", type: "konsep", furi: "おうすんぽう", jp: "追う（おう）・寸法（すんぽう）", id_text: "Mengukur berurutan dari referensi / ukuran/dimensi", desc: "追う=mengukur posisi berurutan dari titik referensi. 寸法=ukuran atau dimensi panjang. Keduanya istilah dasar pengukuran di lapangan. Mandor:「基準から追って寸法を確認してくれよ」." },
  { id: 324, category: "denki", source: "jac-ch4", type: "konsep", furi: "せつぞくけっせん", jp: "接続（せつぞく）・結線（けっせん）", id_text: "Menghubungkan / menyambung kabel komunikasi", desc: "接続=istilah umum menghubungkan dua hal. 結線=khusus untuk kabel komunikasi (通信線). 接続 untuk semua sambungan, 結線 lebih spesifik. Mandor:「通信線の結線は図面通りに正確にやってくれ」." },
  { id: 325, category: "denki", source: "jac-ch4", type: "konsep", furi: "ばいぶれえたあうちこみ", jp: "バイブレーター・打ち込み（うちこみ）", id_text: "Vibrator beton / menuang & memadatkan beton", desc: "打ち込み=menuang beton ke bekisting dan memadatkannya. バイブレーター=alat yang dimasukkan ke beton cair untuk menggetarkan dan hilangkan rongga udara. Mandor:「バイブレーターを入れながら打ち込んでくれ」." },
  { id: 326, category: "sekou", source: "jac-ch4", type: "konsep", furi: "つらかねおがむ", jp: "面（つら）・矩（かね）・拝む（おがむ）", id_text: "Permukaan elemen / sudut siku / elemen yang miring", desc: "面(つら)=permukaan elemen bangunan. 矩(かね)=sudut siku-siku 90°. 拝む=elemen yang seharusnya tegak namun miring. Mandor:「柱が拝んでいるから、矩を確認してくれよ」." },
  { id: 327, category: "career", source: "jac-ch4", type: "konsep", furi: "のかくていぎせいりせいとんせいそうせいけつしつけ", jp: "5Sの各定義：整理・整頓・清掃・清潔・しつけ", id_text: "5 definisi individual kegiatan 5S", desc: "5S: ①整理=pilah perlu vs tidak. ②整頓=letakkan di tempat ditentukan. ③清掃=bersih setelah kerja. ④清潔=pertahankan bersih. ⑤しつけ=aturan agar ①–④ dilaksanakan semua orang. Mandor:「5Sを毎日全員でやってくれ」." },
  { id: 328, category: "gaiyou", source: "jac-ch4", type: "konsep", furi: "おさきにしつれいします", jp: "お先に失礼します（おさきにしつれいします）", id_text: "Permisi, saya pulang lebih dulu", desc: "Diucapkan saat KAMU pulang lebih dulu dari rekan yang masih bekerja. Respons rekan: お疲れさまでした. Jangan ke atasan tanpa kalimat sopan. Mandor:「先に失礼します」→「お疲れさまでした！」." },
  { id: 329, category: "denki", source: "jac-ch4", type: "konsep", furi: "あつちゃくぺんちりんぐすりいぶ", jp: "圧着（あっちゃく）ペンチ・リングスリーブ", id_text: "Tang crimping / Selongsong sambungan kawat listrik", desc: "圧着ペンチ=tang khusus menekan terminal ke ujung kabel. リングスリーブ=selongsong logam cincin untuk menyambung kawat, lalu di-crimp. Mandor:「リングスリーブをきちんとかしめてくれよ」." },
  { id: 330, category: "anzen", source: "jac-ch4", type: "konsep", furi: "ぽいすてきんしがむをかみながらのさぎょうきんし", jp: "ポイ捨て禁止・ガムを噛みながらの作業禁止", id_text: "Dilarang buang sampah sembarangan / permen karet", desc: "ポイ捨て=buang sampah sembarangan — DILARANG. ガム禁止: ①risiko ポイ捨て ②jika benda jatuh mendadak bisa menggigit lidah. Mandor:「ガムを噛みながら作業するのは禁止だからな」." },
  { id: 331, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ろおどろおらあたいやろおらあしんどうろおらあ", jp: "ロードローラ・タイヤローラ・振動ローラ", id_text: "Mesin pemadat: road roller / tire roller", desc: "ロードローラ = rol besi (untuk subgrade/subbase jalan); タイヤローラ = rol karet (tanah biasa, aspal); 振動ローラ = rol besi bergetar (efek kuat meski ukuran kecil)." },
  { id: 332, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ほいいるろおだあ", jp: "ホイールローダ", id_text: "Wheel loader (tire dozer / tire shovel)", desc: "Mesin pemuat material (tanah, batu) ke truk menggunakan bucket besar di depan, bergerak dengan roda ban. Berbeda dari バックホウ yang menggali ke belakang." },
  { id: 333, category: "sekou", source: "jac-ch5", type: "konsep", furi: "たわあくれいんますとくらいんぐふろおあくらいみんぐ", jp: "タワークレーン", id_text: "Tower crane — 2 jenis naik ketinggian", desc: "マストクライング: kepala crane memanjat tiang (mast) yang diperpanjang. フロアークライミング: seluruh crane memanjat bangunan dari lantai ke lantai. Digunakan untuk gedung bertingkat tinggi." },
  { id: 334, category: "denki", source: "jac-ch5", type: "konsep", furi: "べんだあ", jp: "ベンダー", id_text: "Alat pembengkok pipa metal (conduit bender)", desc: "Digunakan untuk membengkokkan pipa logam (金属管) sesuai sudut yang diperlukan dalam pekerjaan instalasi listrik." },
  { id: 335, category: "denki", source: "jac-ch5", type: "konsep", furi: "しいぢいかんぴいえふかん", jp: "CD管 vs PF管", id_text: "CD (Combined Duct) vs PF (Plastic Flexible", desc: "CD管 = 非難燃性 (tidak tahan nyala api), khusus ditanam dalam beton (埋設用), berwarna oranye. PF管 = 難燃性 (tahan nyala api), untuk instalasi umum, tidak boleh ditanam dalam beton." },
  { id: 336, category: "denki", source: "jac-ch5", type: "konsep", furi: "しいかんうすこうでんせんかんじいかんあつこうでんせんかん", jp: "C管（薄鋼電線管）vs G管（厚鋼電線管）", id_text: "C = pipa baja tipis (ada ulir) vs G = pipa baja", desc: "C管 (薄鋼): lebih tipis, kuat terhadap benturan, untuk instalasi dalam ruangan. G管 (厚鋼): tebal, permukaan galvanis sehingga tahan cuaca (耐候性あり)." },
  { id: 337, category: "denki", source: "jac-ch5", type: "konsep", furi: "ぼいどかん", jp: "ボイド管", id_text: "Pipa kertas (void tube)", desc: "Pipa berbahan kertas yang ditanam sebelum pengecoran beton untuk membentuk lubang tembus di lantai, balok, atau dinding. Dilepas setelah beton mengeras." },
  { id: 338, category: "denki", source: "jac-ch5", type: "konsep", furi: "あうとれっとぼっくす", jp: "アウトレットボックス", id_text: "Outlet box — kotak percabangan kabel", desc: "Kotak yang digunakan untuk percabangan (分岐) dan penyambungan (接続) kabel dalam instalasi listrik. Berbeda dari プルボックス yang digunakan untuk menarik/menyambung kabel antar konduit panjang." },
  { id: 339, category: "denki", source: "jac-ch5", type: "konsep", furi: "あっちゃくぺんちたんしようあかりんぐすりいぶようき", jp: "圧着ペンチ（端子用=赤・リングスリーブ用=黄）", id_text: "Tang krimping — pegangan MERAH untuk terminal", desc: "Ada 2 jenis: pegangan merah = untuk圧着端子 (crimp terminal); pegangan kuning = untuk リングスリーブ (ring sleeve, menyambung beberapa kabel). Warna pegangan TIDAK boleh tertukar." },
  { id: 340, category: "denki", source: "jac-ch5", type: "konsep", furi: "りんぐすりいぶ", jp: "リングスリーブ", id_text: "Ring sleeve — komponen penyambung beberapa kabel", desc: "Komponen berbentuk cincin yang digunakan untuk menyambung beberapa kabel sekaligus. Kabel dimasukkan ke lubang cincin lalu dikrimping dengan 圧着ペンチ (pegangan kuning)." },
  { id: 341, category: "denki", source: "jac-ch5", type: "konsep", furi: "よびせん", jp: "呼び線（よびせん）", id_text: "Kabel panduan (guide wire) untuk menarik kabel", desc: "Kawat yang dimasukkan terlebih dahulu ke dalam pipa konduit. Kabel utama disambungkan ke ujung kawat panduan ini, kemudian ditarik melewati pipa." },
  { id: 342, category: "denki", source: "jac-ch5", type: "konsep", furi: "れえすゑえ", jp: "レースウェイ", id_text: "Raceway — rel distribusi listrik untuk memasang", desc: "Komponen penggantung lampu yang juga memiliki fungsi penyalur daya listrik (給電機能). Digantung dari baut gantung, digunakan di tempat tanpa plafon seperti gudang." },
  { id: 343, category: "denki", source: "jac-ch5", type: "konsep", furi: "つりぼるとぜんねじぼると", jp: "吊りボルト（全ねじボルト）", id_text: "Baut gantung (full-thread bolt)", desc: "Baut panjang berulir penuh tanpa kepala, dipasang pada insert yang tertanam di beton lantai. Digunakan untuk menggantung konduit, kabel rack, dan raceway." },
  { id: 344, category: "denki", source: "jac-ch5", type: "konsep", furi: "わいやあすとりっぱ", jp: "ワイヤーストリッパー", id_text: "Wire stripper — alat pengupas isolasi kabel", desc: "Alat untuk mengupas lapisan isolasi (被覆) kabel listrik tanpa merusak kawat di dalamnya. Sering dilengkapi ストリップゲージ untuk mengukur panjang kupasan." },
  { id: 345, category: "denki", source: "jac-ch5", type: "konsep", furi: "しいぶいけえぷるいいえむいいいいえふ", jp: "CVケーブル vs EM-EEF", id_text: "CV (cross-linked polyethylene) vs EM-EEF", desc: "EM-EEF = VVFケーブル dengan selubung polyethylene, tahan nyala lebih baik dari VVF biasa. CVケーブル = menggunakan 架橋ポリエチレン (cross-linked PE) sebagai isolator, ketahanan nyala LEBIH TINGGI dari EM-EEF." },
  { id: 346, category: "denki", source: "jac-ch5", type: "konsep", furi: "しいちいぶいしいちいいどうようでんせん", jp: "CT / VCT（移動用電線）", id_text: "CT (karet) / VCT (vinyl)", desc: "CT = selubung karet, tahan abrasi dan benturan, untuk kabel bergerak. VCT = selubung vinyl, tahan nyala api, lentur, dan tahan air — juga untuk kabel bergerak." },
  { id: 347, category: "denki", source: "jac-ch5", type: "konsep", furi: "さあまるりれえ", jp: "サーマルリレー", id_text: "Thermal relay — pemutus sirkuit berdasarkan suhu", desc: "Jenis relay yang memutus rangkaian listrik ketika suhu naik melampaui batas. Digunakan untuk melindungi motor listrik dari panas berlebih akibat beban lebih." },
  { id: 348, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "くろおじゃあ", jp: "クロージャ", id_text: "Closure — kotak sambungan kabel aerial di tiang", desc: "Kotak yang dipasang di tiang listrik untuk menyambung/mencabang inti kabel telekomunikasi aerial (架空配線). Melindungi sambungan dari cuaca. Warna: 光ファイバー closure = abu-abu, kabel metal = hitam." },
  { id: 349, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "つりせんめっせんじゃあわいやあ", jp: "つり線（メッセンジャーワイヤー）", id_text: "Suspension wire / messenger wire", desc: "Kawat baja yang dipasang di atas kabel telekomunikasi aerial agar kabel tidak menahan beban tarikannya sendiri. Juga disebut メッセンジャーワイヤー." },
  { id: 350, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ちょうせんきかくせんき", jp: "張線器（ちょうせんき）+ 掴線器（かくせんき）", id_text: "Penegang kawat + penjepit kawat", desc: "掴線器 = alat menjepit kawat gantung (つり線). 張線器 = dikombinasikan dengan 掴線器, menarik tuas untuk memberi tegangan pada kawat gantung agar tidak kendur." },
  { id: 351, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "せいりゅうきちくでんち", jp: "整流器 vs 蓄電池", id_text: "Rectifier (AC→DC) vs Baterai penyimpan energi", desc: "整流器 = mengubah arus bolak-balik (交流) menjadi arus searah (直流). 蓄電池 = menyimpan energi listrik dengan cara mengisi daya (充電). Keduanya digunakan dalam sistem telekomunikasi." },
  { id: 352, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "らんてすたあ", jp: "LANテスター", id_text: "LAN tester — alat uji kabel LAN (8 kawat", desc: "Alat untuk memeriksa 8 kawat di dalam kabel LAN apakah ada yang putus (断線) atau bersilang (交差). Dipasang di kedua ujung konektor modular kabel." },
  { id: 353, category: "haikan", source: "jac-ch5", type: "konsep", furi: "はいかんだくと", jp: "配管（はいかん）vs ダクト", id_text: "Pipa untuk air/gas vs Saluran udara", desc: "配管 = pipa untuk mengalirkan air atau gas. ダクト = saluran untuk mengalirkan udara. ダクト dibagi menjadi 角ダクト (kotak) dan 丸ダクト / スパイラルダクト (bundar)." },
  { id: 354, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ひゅうぶかったあぱいぷかったあ", jp: "チューブカッター vs パイプカッター", id_text: "Tube cutter (pipa tipis) vs Pipe cutter (pipa", desc: "チューブカッター = untuk memotong pipa tipis dari besi, baja, kuningan, tembaga, aluminium. パイプカッター = untuk pipa yang LEBIH TEBAL (baja, kuningan, tembaga, besi tempa, timbal)." },
  { id: 355, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ふれありんぐうつうる", jp: "フレアリングツール", id_text: "Flaring tool — alat melebar ujung pipa lunak", desc: "Alat untuk melebarkan (フレア加工) ujung pipa lunak seperti pipa tembaga agar dapat disambungkan. Digunakan dalam instalasi pendingin udara (AC)." },
  { id: 356, category: "haikan", source: "jac-ch5", type: "konsep", furi: "えきすぱんだあ", jp: "エキスパンダー（拡管器）", id_text: "Expander / — alat memperlebar ujung pipa tembaga", desc: "Alat untuk memperlebar (拡管) ujung pipa tembaga sehingga pipa lain dapat dimasukkan ke dalamnya untuk disambungkan. Berbeda dari フレアリングツール yang membuat flare berbentuk kerucut." },
  { id: 357, category: "haikan", source: "jac-ch5", type: "konsep", furi: "すいあつしけんきいてすとぽんぷ", jp: "水圧試験器（テストポンプ）", id_text: "Hydraulic pressure tester (test pump)", desc: "Alat ukur yang digunakan saat uji tekanan air (水圧試験) pada pipa air bersih (給水管) dan pipa air panas (給湯管) untuk memastikan tidak ada kebocoran." },
  { id: 358, category: "haikan", source: "jac-ch5", type: "konsep", furi: "たいねつせいこうしつえんかびにるかんかん", jp: "耐熱性硬質塩化ビニル管（HT管・HTVP管）", id_text: "Pipa PVC tahan panas (HT pipe)", desc: "Pipa PVC keras yang ditingkatkan ketahanan panasnya. Berwarna merah kecoklatan (赤茶色). Digunakan untuk pipa pendingin-pemanas, kolam air panas. Berbeda dari VP/VU (abu-abu) dan HIVP (biru tua)." },
  { id: 359, category: "haikan", source: "jac-ch6", type: "konsep", furi: "すいどうようこうしつえんかびにるらいにんぐこうかん", jp: "水道用硬質塩化ビニルライニング鋼管", id_text: "Pipa baja berlapis PVC untuk air bersih (VLP)", desc: "Pipa baja dilapisi PVC keras di dalamnya untuk mencegah korosi. Tahan karat (耐腐食性) dan bahan kimia. Di proyek: digunakan untuk jalur air bersih." },
  { id: 360, category: "haikan", source: "jac-ch5", type: "konsep", furi: "がすこっくまったんちゅうかん", jp: "ガスコック（末端 vs 中間）", id_text: "Kran gas: (ujung/terminal) vs (tengah/inline)", desc: "末端ガスコック = digunakan di ujung pipa saat menyambung ke kompor/water heater. 中間ガスコック = dipasang di tengah jalur pipa sebagai katup pengatur atau pemutus aliran gas." },
  { id: 361, category: "haikan", source: "jac-ch5", type: "konsep", furi: "がすもれけいほうき", jp: "ガス漏れ警報器", id_text: "Detektor kebocoran gas", desc: "Alat yang mendeteksi kebocoran gas dan mengeluarkan alarm untuk memberitahu bahaya. Dipasang di dapur atau ruangan bergas." },
  { id: 362, category: "haikan", source: "jac-ch5", type: "konsep", furi: "べんだんぱあ", jp: "弁（バルブ）vs ダンパー", id_text: "Katup/valve (pipa air) vs Damper (saluran udara)", desc: "弁（バルブ）= alat untuk menghentikan atau mengatur aliran CAIRAN/GAS di dalam pipa. ダンパー = alat untuk menghentikan atau mengatur aliran UDARA di dalam duct." },
  { id: 363, category: "haikan", source: "jac-ch5", type: "konsep", furi: "とらっぷ", jp: "トラップ（排水管）", id_text: "Perangkap bau (trap) pada pipa drainase", desc: "Bagian pada pipa drainase yang selalu berisi air untuk mencegah bau busuk (臭気) dan serangga kecil dari saluran pembuangan masuk ke dalam ruangan." },
  { id: 364, category: "haikan", source: "jac-ch5", type: "konsep", furi: "えいせいせつびきゅうはいすいえいせいせつびのろくぶにゃ", jp: "衛生設備（給排水衛生設備の6分野）", id_text: "Sanitasi / plumbing — 6 bidang: air bersih", desc: "給排水衛生設備 mencakup 6 bidang: 給水・排水・衛生器具・給湯・ガス・消火設備. Mandor:「どの設備工事か図面で確認してから始めて」(cek di gambar kerja bidang instalasi mana sebelum mulai)." },
  { id: 365, category: "sekou", source: "jac-ch5", type: "konsep", furi: "れいきゃくこいるおんすいこいる", jp: "冷却コイル vs 温水コイル", id_text: "Koil pendingin vs koil pemanas", desc: "冷却コイル = tabung berisi air dingin, dilewati udara untuk mendinginkan → digunakan saat 冷房 (AC pendingin). 温水コイル = tabung berisi air panas, memanaskan udara → digunakan saat 暖房 (pemanas)." },
  { id: 366, category: "shoubou", source: "jac-ch5", type: "konsep", furi: "みずふんむしょうかせつび", jp: "水噴霧消火設備", id_text: "Sistem pemadam kabut air", desc: "Menyemprotkan kabut air halus untuk memadamkan kebakaran. Digunakan di jalan, area parkir, dan tempat penyimpanan bahan mudah terbakar (指定可燃物)." },
  { id: 367, category: "shoubou", source: "jac-ch5", type: "konsep", furi: "あわしょうかせつび", jp: "泡消火設備", id_text: "Sistem pemadam busa — untuk kebakaran minyak", desc: "Digunakan untuk kebakaran minyak/oil yang tidak cocok dipadamkan dengan air. Bekerja dengan 2 cara: busa menutup permukaan api (窒息効果) + air dalam busa mendinginkan (冷却効果)." },
  { id: 368, category: "shoubou", source: "jac-ch5", type: "konsep", furi: "ふかあっせいがすしょうかせつび", jp: "不活性ガス消火設備", id_text: "Sistem pemadam gas inert", desc: "Menggunakan gas inert untuk mengurangi konsentrasi oksigen di udara (希釈) dan efek pendinginan (冷却). Tidak merusak peralatan, cocok untuk ruang server dan arsip." },
  { id: 369, category: "shoubou", source: "jac-ch5", type: "konsep", furi: "はろげんかぶつしょうかせつび", jp: "ハロゲン化物消火設備", id_text: "Sistem pemadam halogen", desc: "Menggunakan senyawa halogen (fluor, klor, brom) yang menghambat reaksi pembakaran. Efektif untuk kebakaran minyak, peralatan listrik aktif, komputer, perpustakaan, dan koleksi seni berharga." },
  { id: 370, category: "sekou", source: "jac-ch5", type: "konsep", furi: "どりるどらいばあいんぱくとどらいばあ", jp: "ドリルドライバー vs インパクトドライバー", id_text: "Drill driver vs Impact driver", desc: "ドリルドライバー: dapat mengatur kecepatan putar dan torsi, untuk memasang sekrup dan bor. インパクトドライバー: punya mekanisme pukul (ハンマー) sehingga torsi lebih besar, kecepatan & torsi tetap." },
  { id: 371, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ぢすくぐらいんだあこうそくがたていそくがた", jp: "ディスクグラインダー（高速型 vs 低速型）", id_text: "Angle grinder: disc kecepatan tinggi untuk", desc: "Mengganti disc sesuai kebutuhan: memotong pipa metal/beton → disc putaran TINGGI (高速トルク型). Mengamplas / menghaluskan permukaan → disc putaran RENDAH (低速トルク型)." },
  { id: 372, category: "anzen", source: "jac-ch5", type: "konsep", furi: "まるのこきっくばっく", jp: "丸のこ", id_text: "Gergaji sirkel — bahaya kickback (gerakan mundur", desc: "Gergaji sirkel berputar tinggi — bahaya キックバック: alat bisa mental balik tiba-tiba. Di proyek: cek safety cover sebelum pakai. Mandor:「カバーを確認してから使え」(cek pelindung dulu)." },
  { id: 373, category: "sekou", source: "jac-ch5", type: "konsep", furi: "こうそくせつだんきちっぷそおせつだんき", jp: "高速切断機 vs チップソー切断機", id_text: "High-speed cutter (mata gerinda) vs chip saw", desc: "チップソー切断機: menggunakan mata gergaji bundar (丸のこ刃), mata cepat aus. 高速切断機: menggunakan batu gerinda (砥石), mata jauh lebih tahan lama. Keduanya untuk memotong pipa metal, besi tulang, baja ringan." },
  { id: 374, category: "sekou", source: "jac-ch5", type: "konsep", furi: "けんすこっぷかくすこっぷてこきんし", jp: "剣スコップ vs 角スコップ（てこ禁止）", id_text: "Sekop runcing (menggali) vs Sekop rata (mengeruk)", desc: "剣スコップ: runcing, kaki bisa menginjak → gali tanah keras. 角スコップ: rata, tidak ada tempat injak → keruk tanah/aspal lunak. KEDUANYA dilarang sebagai tuas (てこ禁止)." },
  { id: 375, category: "sekou", source: "jac-ch5", type: "konsep", furi: "らんまばいぶろこんぱくたぷれえとこんぱくた", jp: "ランマ vs バイブロコンパクタ vs プレートコ", id_text: "Rammer (tumbuk kuat) vs Vibratory compactor", desc: "ランマ: tumbuk kuat → pemadat dalam. バイブロコンパクタ: getaran, jangkauan luas. プレートコンパクタ: plat besar → ratakan permukaan. Mandor:「ランマで締め固めて」(pampat pakai rammer)." },
  { id: 376, category: "sekou", source: "jac-ch5", type: "konsep", furi: "れえざあすみだしきあかれえざあみどりれえざあ", jp: "レーザー墨出し器（赤レーザー vs 緑レーザー）", id_text: "Laser level — garis acuan konstruksi: hijau lebih", desc: "Alat laser → garis acuan horizontal/vertikal di dinding, plafon, lantai. Laser HIJAU (緑) lebih jelas di tempat terang vs MERAH. Mandor:「緑レーザーで墨出しして」(tarik garis pakai laser hijau)." },
  { id: 377, category: "sekou", source: "jac-ch5", type: "konsep", furi: "すいへいき", jp: "水平器（すいへいき）", id_text: "Waterpass / spirit level", desc: "Alat genggam untuk memeriksa apakah permukaan horizontal atau vertikal dengan melihat gelembung udara di tabung (気泡管). BERBEDA dari 水準器/レベル yang merupakan alat survei besar untuk menentukan elevasi." },
  { id: 378, category: "sekou", source: "jac-ch5", type: "konsep", furi: "さしがねうらめんおもてめんのばい", jp: "さしがね（裏面 = 表面の√2 ≈ 1.414倍）", id_text: "Penggaris siku baja — sisi belakang = 1.414× sisi", desc: "Alat pengukur sudut siku-siku dari logam. Sisi depan (表面): skala meter biasa. Sisi belakang (裏面): skala 1.414× lebih besar dari depan, berguna menghitung diagonal papan kayu (teorema Pythagoras √2)." },
  { id: 379, category: "sekou", source: "jac-ch4", type: "konsep", furi: "みずいと", jp: "水糸（みずいと）", id_text: "Tali referensi — tidak mulur, untuk lurus & rata", desc: "Tali dari bahan tidak mudah mulur, direntangkan saat membangun pondasi atau pasang bata/blok untuk memastikan garis lurus dan ketinggian sama. Mandor:「水糸はピンと張ってから作業してくれ」." },
  { id: 380, category: "sekou", source: "jac-ch5", type: "konsep", furi: "たがねはつりさぎょう", jp: "たがね（ハツリ作業）", id_text: "Pahat (chisel) — digunakan untuk (memecah beton", desc: "Batang berbentuk pahat yang dipukul dengan palu. Fungsi: ①memotong logam tipis ②ハツリ作業 (memecah/melubangi beton atau mengeruk mortar lama). Jenisnya: 平たがね, コンクリートたがね, 目切りたがね." },
  { id: 381, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ばあるてこのげんり", jp: "バール（てこの原理）", id_text: "Linggis / crowbar — memanfaatkan prinsip tuas", desc: "Alat logam berbentuk L yang digunakan sebagai pengungkit. Ujung L punya alur untuk mencabut paku (釘抜き). Dapat mengangkat benda berat, mencungkil, membongkar bekisting. バール besar disebut 大バール." },
  { id: 382, category: "sekou", source: "jac-ch5", type: "konsep", furi: "へえんぶろっくればあほいすと", jp: "チェーンブロック vs レバーホイスト", id_text: "Chain block (untuk mengangkat berat) vs lever", desc: "チェーンブロック: dipasang di kaki tiga (三脚) untuk mengangkat beban berat naik-turun. レバーホイスト: prinsip sama tapi lebih KECIL, digunakan untuk mengencangkan muatan (contoh: mengamankan backhoe di atas truk)." },
  { id: 383, category: "sekou", source: "jac-ch5", type: "konsep", furi: "わいやあろおぷたまかけようだいつけよう", jp: "ワイヤーロープ（玉掛け用・台付け用）", id_text: "Wire rope — untuk (slinging beban ke crane) dan", desc: "Tali baja dengan kekuatan tarik tinggi, tahan benturan, dan fleksibel. 両端加工済み = 玉掛け用 (mengaitkan beban ke crane/hook). 台付け用 = untuk mengikat/mengamankan muatan di atas kendaraan." },
  { id: 384, category: "sekou", source: "jac-ch5", type: "konsep", furi: "しゃっくる", jp: "シャックル", id_text: "Shackle — penghubung wire rope", desc: "Alat penghubung berbentuk U berulir yang digunakan dalam operasi pengangkatan (玉掛け) untuk menyambungkan wire rope atau rantai dengan beban." },
  { id: 385, category: "sekou", source: "jac-ch5", type: "konsep", furi: "じゃっきねじしきはぐるましきゆあつしき", jp: "ジャッキ（ネジ式・歯車式・油圧式）", id_text: "Jack — mengangkat beban berat dengan tenaga", desc: "Alat untuk mengangkat benda sangat berat dengan tenaga minimal. Ada 3 prinsip: ①ネジ式 (ulir) ②歯車式 (roda gigi) ③油圧式 (hidrolik). キリンジャッキ = tipe khusus ulir untuk mengangkat secara vertikal." },
  { id: 386, category: "anzen", source: "jac-ch5", type: "konsep", furi: "はしごかくどやくどほじょうしゃひっす", jp: "はしご（角度 約75度・補助者必須）", id_text: "Tangga sandar — sudut ±75°", desc: "Tangga sandar harus diletakkan pada sudut sekitar 75°. Sudut terlalu tegak → bahaya jatuh ke belakang. Sudut terlalu landai → tangga bisa patah. Selalu bekerja bersama asisten yang memegang tangga." },
  { id: 387, category: "anzen", source: "jac-ch7", type: "konsep", furi: "きゃたつてんばんきんしまたぎきんし", jp: "脚立（きゃたつ）", id_text: "Tangga A — DILARANG berdiri/duduk di papan atas", desc: "天板禁止・またぎ禁止。Tangga lipat bentuk A. Tiga larangan: ①Dilarang DUDUK di papan atas (天板). ②Dilarang BERDIRI di papan atas. ③Dilarang bekerja sambil MENUNGGANGI (またぎ乗り) dua sisi." },
  { id: 388, category: "anzen", source: "jac-ch5", type: "konsep", furi: "ろおりんぐたわあいどうしきあしば", jp: "ローリングタワー（移動式足場）", id_text: "Rolling tower (scaffolding beroda)", desc: "Perancah bertingkat beroda (kastor di 4 sudut) untuk pekerjaan di ketinggian. Dapat dipindahkan. Memiliki standar keselamatan berdasarkan 労働安全衛生法. Berbeda dari 高所作業車 yang menggunakan kendaraan." },
  { id: 389, category: "sekou", source: "jac-ch5", type: "konsep", furi: "もんきいれんちうわあごにちからをかけてまわす", jp: "モンキーレンチ（上あごに力をかけて回す）", id_text: "Kunci inggris — putar ke arah RAHANG ATAS (upper", desc: "Kunci adjustable sesuai ukuran baut/mur. PENTING: gaya ke RAHANG ATAS (上あご) yang menyatu grip. Jika terbalik → rusak/cedera. Mandor:「上あごに力をかけて回せ」(putar tekan rahang atas)." },
  { id: 390, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ようじょうようぽりしいと", jp: "養生用ポリシート", id_text: "Polythene sheet untuk curing/proteksi", desc: "Lembaran film polyethylene tipis. Fungsi: ①mencegah kelembapan dari tanah saat pengecoran beton ②proteksi saat pengecatan ③melindungi dari hujan dan debu." },
  { id: 391, category: "anzen", source: "jac-ch5", type: "konsep", furi: "すいちょくようじょうねっとすいへいようじょうねっと", jp: "垂直養生ネット vs 水平養生ネット", id_text: "Jaring pengaman tegak (cegah material jatuh dari", desc: "垂直養生ネット = dipasang tegak di tepi perancah untuk mencegah material/benda terbang dari perancah. 水平養生ネット = dipasang horizontal untuk mencegah orang atau material jatuh dari tempat tinggi." },
  { id: 392, category: "sekou", source: "jac-ch5", type: "konsep", furi: "とろばことろぶね", jp: "トロ箱（トロ舟）", id_text: "Bak mortar (tro box/trough)", desc: "Bak kokoh berbentuk persegi panjang untuk mencampur dan mengaduk semen, mortar, atau beton. Juga disebut トロ舟 atau 舟. Material di dalamnya diaduk dengan alat pengaduk atau sekop." },
  { id: 393, category: "sekou", source: "jac-ch5", type: "konsep", furi: "くぎうちきこんぷれっしゃあしよう", jp: "釘打ち機（コンプレッサー使用）", id_text: "Nail gun (menggunakan compressor", desc: "Alat untuk memukul paku menggunakan tekanan udara dari kompresor (コンプレッサー). Jauh lebih cepat dari memukul paku manual dengan palu. Kompresor = mesin yang memampatkan udara." },
  { id: 394, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ふぉおくりふと", jp: "フォークリフト", id_text: "Forklift — kendaraan garpu hidrolik pemindah palet", desc: "Kendaraan dengan garpu (フォーク) naik-turun hidrolik untuk memindahkan palet/material. Di proyek: memindahkan tumpukan material dan bahan ke gudang." },
  { id: 395, category: "sekou", source: "jac-ch5", type: "konsep", furi: "おやづなきんちょうき", jp: "親綱緊張器（おやづなきんちょうき）", id_text: "Pengencang tali induk untuk pekerjaan ketinggian", desc: "Alat memasang tali induk (親綱) tempat kait harness pekerja agar tidak kendur. Di proyek: dipasang di atap atau scaffolding sebelum pekerja naik." },
  { id: 396, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ゆあつしょべる（ばっくほう）", jp: "油圧ショベル（バックホウ）", id_text: "Excavator / backhoe — mesin penggali utama", desc: "Mesin penggali dengan boom, arm, dan bucket; upper body berputar (旋回体). Di proyek: menggali galian pondasi dan parit. Mandor:「バックホウで掘削して」(gali pakai excavator)." },
  { id: 397, category: "sekou", source: "jac-ch5", type: "konsep", furi: "とらくたあしょべる", jp: "トラクターショベル", id_text: "Tractor shovel — bucket depan, ada tipe roda dan", desc: "Mesin bucket di depan untuk menyekop material ke dump truck. Tipe roda (ホイール) lebih lincah, tipe rantai (クローラ) untuk medan berat. Mandor:「ホイールローダで砂利を積んで」(muat kerikil pakai loader)." },
  { id: 398, category: "sekou", source: "jac-ch5", type: "konsep", furi: "とらっくくれいん vs くろおらくれいん", jp: "トラッククレーン vs クローラクレーン", id_text: "Truck crane (di truk) vs Crawler crane (di", desc: "トラッククレーン = crane di atas truk, mobile di jalan. クローラクレーン = bergerak dengan rantai, bisa di salju atau tanah tidak rata. Di proyek: pilih sesuai medan. Mandor:「クローラクレーンを手配して」(pesan crawler crane)." },
  { id: 399, category: "denki", source: "jac-ch5", type: "konsep", furi: "いいかん（ねじなしこうせいでんせんかん）", jp: "E管（ねじなし鋼製電線管）", id_text: "Konduit baja tanpa ulir (E19, E25 = diameter luar)", desc: "Pipa baja instalasi listrik TANPA ulir (ねじ無し). Ukuran dinyatakan diameter luar: E19=Ø19mm, E25=Ø25mm. Di proyek: jalur konduit dalam dinding atau plafon. Mandor:「E管を配管して」(pasang konduit E管)." },
  { id: 400, category: "denki", source: "jac-ch5", type: "konsep", furi: "かっぷりんぐ vs こんびねえしょんかっぷりんぐ", jp: "カップリング vs コンビネーションカップリング", id_text: "Coupling (konduit SEJENIS) vs Combination", desc: "カップリング = menyambung 2 konduit jenis SAMA. コンビネーションカップリング = menyambung konduit beda jenis (misal E管 ke PF管). Di proyek: pilih sesuai konduit yang disambung." },
  { id: 401, category: "denki", source: "jac-ch5", type: "konsep", furi: "だくたあちゃんねる（このじがただんめん）", jp: "ダクターチャンネル（コの字型断面）", id_text: "Daktar channel (profil C) — rel penopang cable", desc: "Rel berbentuk コ (C-channel) sebagai hanger untuk menopang cable rack, konduit, dan peralatan MEP dari plafon. Di proyek: dipasang sebelum kabel ditarik." },
  { id: 402, category: "denki", source: "jac-ch5", type: "konsep", furi: "だぶるなっと / さどる", jp: "ダブルナット / サドル", id_text: "Double nut (anti-kendur akibat getaran) / Saddle", desc: "ダブルナット = dua mur dipasang bersamaan agar tidak kendur akibat getaran. サドル = braket berbentuk U menempelkan konduit ke dinding/plafon. Di proyek: saddle dipasang tiap 1-1,5m." },
  { id: 403, category: "denki", source: "jac-ch5", type: "konsep", furi: "VVR（まるがた）vs VVF（ひらがた）", jp: "VVR（丸型）vs VVF（平型）", id_text: "VVF = kabel vinyl gepeng / VVR = kabel vinyl", desc: "VVF (Vinyl Vinyl Flat) = bentuk gepeng, umum untuk instalasi dinding. VVR (Vinyl Vinyl Round) = bentuk bundar, lebih fleksibel. Di proyek: VVF dominan untuk perumahan." },
  { id: 404, category: "denki", source: "jac-ch5", type: "konsep", furi: "りれえ vs さあまるりれえ", jp: "リレー vs サーマルリレー", id_text: "Relay (saklar sinyal listrik) vs Thermal relay", desc: "リレー = saklar dikontrol sinyal listrik kecil untuk rangkaian lebih besar. サーマルリレー = memutus sirkuit berdasarkan kenaikan suhu, proteksi motor listrik. Di proyek: thermal relay dipasang di panel motor." },
  { id: 405, category: "denki", source: "jac-ch5", type: "konsep", furi: "じこゆうちゃくてえぷ", jp: "自己融着テープ", id_text: "Self-fusing tape — menyatu sendiri saat", desc: "Pita yang ketika dililitkan sambil ditarik 2–3× akan menyatu sendiri antara permukaan atas dan bawah tanpa perekat. Di proyek: digunakan untuk pemasangan pipa air (水道管) mencegah kebocoran." },
  { id: 406, category: "denki", source: "jac-ch5", type: "konsep", furi: "さしこみこねくた / ちいがたこねくた", jp: "差し込みコネクタ / T型コネクタ", id_text: "Insert connector (colok langsung) / T-connector", desc: "差し込みコネクタ = sambungkan kabel hanya dengan memasukkan kawat inti, tanpa crimping. T型コネクタ = cabangkan kabel dari tengah kabel induk (母線). Di proyek: insert connector lebih cepat dipasang." },
  { id: 407, category: "denki", source: "jac-ch5", type: "konsep", furi: "でんこうどらむ", jp: "電工ドラム", id_text: "Extension cord reel — gulungan kabel perpanjang", desc: "Gulungan kabel untuk memperpanjang listrik di lokasi konstruksi. PENTING: kabel harus dikuluarkan sepenuhnya agar tidak panas berlebih akibat induktansi. Di proyek: wajib digelar penuh saat dipakai." },
  { id: 408, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ひかりふぁいばあゆうちゃくせつぞく（さんほうしき）", jp: "光ファイバー融着接続（3方式）", id_text: "Sambungan serat optik — 3 metode: fusion /", desc: "①融着接続: ujung serat dilelehkan & disatukan mesin, losses terkecil. ②メカニカルスプライス: sambungan mekanis tanpa pemanasan. ③コネクタ接続: pakai konektor, bisa dilepas. Di proyek: pasang 保護スリーブ SEBELUM splice." },
  { id: 409, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ひかりぱるすしけんき（OTDR）", jp: "光パルス試験機（OTDR）", id_text: "OTDR — alat ukur panjang jalur serat optik dan", desc: "Optical Time Domain Reflectometer. Mengukur: ①panjang total jalur serat ②rugi-rugi di titik sambungan (損失) ③lokasi kerusakan (反射). Di proyek: QC wajib setelah fusion splice." },
  { id: 410, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "じこしじけえぷる", jp: "自己支持ケーブル", id_text: "Self-supporting cable — kabel aerial terintegrasi", desc: "Kabel yang sudah memiliki kawat penopang (支持線) terintegrasi. Dipasang langsung ke tiang tanpa つり線 terpisah. Di proyek: instalasi kabel antar gedung atau tiang listrik." },
  { id: 411, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ぱいぷまんりき / ぱいぷねじきりき", jp: "パイプ万力 / パイプねじ切機", id_text: "Pipe vise (penjepit pipa) / Pipe threader (buat", desc: "パイプ万力 = ragum khusus pipa untuk mengamankan pipa saat dipotong/disambung. パイプねじ切機 = mesin membuat ulir (ねじ) di ujung pipa agar bisa disambung fitting." },
  { id: 412, category: "haikan", source: "jac-ch5", type: "konsep", furi: "めんとりき", jp: "面取り器", id_text: "Deburring tool / reamer — hilangkan sisa potongan", desc: "Alat menghilangkan sisa potongan (バリ) dari ujung pipa logam atau PVC setelah dipotong agar halus dan aman. Di proyek: wajib dilakukan sebelum menyambung pipa." },
  { id: 413, category: "haikan", source: "jac-ch5", type: "konsep", furi: "しいるざい（えきじょう / しいるてえぷ）", jp: "シール材（液状 / シールテープ）", id_text: "Sealant cair / PTFE tape — cegah kebocoran", desc: "シール材 = mencegah kebocoran di sambungan pipa berulir: ada tipe cair (液状) dan tape (PTFE). 塩ビ接着剤 = lem khusus pipa PVC. Di proyek: dipakai sebelum mengencangkan fitting." },
  { id: 414, category: "haikan", source: "jac-ch6", type: "konsep", furi: "はいかんようたんそこうこうかん（SGP / がすかん）", jp: "配管用炭素鋼鋼管（SGP / ガス管）", id_text: "SGP: putih (galvanis) vs hitam (tanpa lapisan)", desc: "Pipa baja karbon (SGP / Steel Gas Pipe) untuk uap, air, minyak, gas, udara. 白管 = berlapis seng/galvanis, tahan korosi. 黒管 = tanpa pelapisan. Di proyek: juga disebut ガス管." },
  { id: 415, category: "haikan", source: "jac-ch5", type: "konsep", furi: "こうしつぽりえんかびにるかん（VP vs VU）", jp: "硬質ポリ塩化ビニル管（VP管 vs VU管）", id_text: "Pipa PVC keras abu-abu: VP (tebal) vs VU (tipis)", desc: "VP管 = dinding tebal (厚肉管). VU管 = dinding tipis (薄肉管). Keduanya warna ABU-ABU, halus, ringan, mudah dikerjakan, tapi rapuh benturan & panas tinggi. Di proyek: VP untuk tekanan, VU untuk drainase." },
  { id: 416, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ねじこみしきかたんちゅうてつせいかんつぎて", jp: "ねじ込み式可鍛鋳鉄製管継手", id_text: "Fitting besi tempa berulir: elbow / tee / socket", desc: "Fitting untuk menyambung pipa berulir. エルボ = belok 90°. チーズ = percabangan 3 arah. ソケット = penyambung lurus. ニップル = penyambung pendek. Gunakan シール材 agar tidak bocor." },
  { id: 417, category: "haikan", source: "jac-ch5", type: "konsep", furi: "せきめんせめんとかん（あすべすとかん）", jp: "石綿セメント管（アスベスト管）", id_text: "Pipa asbes semen — TIDAK DIPRODUKSI LAGI", desc: "Pipa dari campuran asbes, semen, dan pasir kuarsa. Tahan korosi dan ringan, namun produksinya dihentikan karena menghirup serat asbes menyebabkan mesothelioma." },
  { id: 418, category: "shoubou", source: "jac-ch5", type: "konsep", furi: "おくないしょうかせんせつび（いちごう / いそうさせい / にごう）", jp: "屋内消火栓設備（1号 / 易操作 / 2号）", id_text: "Hidran dalam gedung: tipe 1 vs mudah dioperasikan", desc: "屋内消火栓 = pemadam kebakaran awal dalam gedung. 1号 = butuh 2 orang. 易操作性1号 = cukup 1 orang, daya sama dengan 1号. 2号 = 1 orang, kapasitas lebih kecil untuk gedung kecil." },
  { id: 419, category: "sekou", source: "jac-ch5", type: "konsep", furi: "れしぷろそお", jp: "レシプロソー", id_text: "Reciprocating saw — gergaji maju-mundur untuk", desc: "Gergaji elektrik dengan blade panjang bergerak maju-mundur. Berguna memotong di tempat sempit atau posisi sulit. Di proyek: memotong konduit lama atau rangka di area terbatas." },
  { id: 420, category: "sekou", source: "jac-ch5", type: "konsep", furi: "だぶるすこっぷ（ふかいあなほりよう）", jp: "ダブルスコップ（深い穴掘り用）", id_text: "Post hole digger — gali lubang dalam untuk tiang", desc: "Sekop dua bilah menjepit tanah, memungkinkan menggali lubang dalam dan sempit secara vertikal. Di proyek: memasang tiang listrik atau pancang. Mandor:「ダブルスコップで穴を掘って」(gali lubang pakai double shovel)." },
  { id: 421, category: "sekou", source: "jac-ch5", type: "konsep", furi: "つるはし", jp: "つるはし（鶴嘴）", id_text: "Pickaxe — untuk menggali tanah keras dan memecah", desc: "Alat kepala logam melengkung dua ujung, dipasang di gagang kayu. Di proyek: menggali tanah keras, batuan, atau memecah lapisan aspal. Mandor:「つるはしで掘り起こして」(gali/pecah pakai pickaxe)." },
  { id: 422, category: "doboku_doko", source: "jac-ch5", type: "konsep", furi: "たんぱあ vs たこ（じゅうりょうつきかため）", jp: "タンパー vs たこ（重量突き固め）", id_text: "Tamper (plat logam, hentakkan) vs Taco (beban", desc: "タンパー = plat datar logam di ujung gagang panjang, dihentakkan memadatkan aspal/tanah. たこ = beban masif dijatuhkan ke tanah untuk memadatkan dengan beratnya." },
  { id: 423, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ちょおくらいん vs すみつぼ", jp: "チョークライン vs 墨つぼ", id_text: "Chalk line (kapur, mudah bersih) vs Sumitsubo", desc: "Keduanya untuk menarik garis lurus panjang. チョークライン = serbuk kapur, mudah dibersihkan. 墨つぼ = tinta hitam tradisional (墨), lebih permanen untuk kayu dan beton. Di proyek: pilih sesuai kebutuhan." },
  { id: 424, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ぽんち（せんたあぽんち）", jp: "ポンチ（センターポンチ）", id_text: "Center punch — buat cekungan di logam sebagai", desc: "Alat batang runcing dipukul palu untuk membuat cekungan kecil di permukaan logam (マーキング). Di proyek: menandai titik bor agar mata bor tidak bergeser." },
  { id: 425, category: "sekou", source: "jac-ch5", type: "konsep", furi: "とらんしっと / せおどらいと", jp: "トランシット / セオドライト", id_text: "Transit / theodolite — ukur sudut horizontal &", desc: "Alat survei menggunakan teleskop untuk mengukur sudut horizontal dan vertikal dari titik referensi. Diletakkan di atas tripod. Di proyek: penentuan as bangunan dan peil." },
  { id: 426, category: "sekou", source: "jac-ch5", type: "konsep", furi: "おおがね", jp: "おおがね（大矩）", id_text: "Penggaris siku besar lapangan — rasio 3:4:5,", desc: "Segitiga siku besar untuk cek sudut 90° di lapangan. Dibuat dari 3 bahan dengan rasio 3:4:5 (teorema Pythagoras), dikenal sebagai 'サシゴ'. Di proyek: cek siku pondasi atau dinding." },
  { id: 427, category: "sekou", source: "jac-ch5", type: "konsep", furi: "はんまあのしゅるい", jp: "ハンマーの種類", id_text: "Jenis palu: karet, kayu, kayu besar, sledgehammer", desc: "ゴムハンマー: tidak merusak permukaan. 木づち: kepala kayu tradisional. かけや: 木づち besar untuk pasak kayu besar. 大ハンマー: gagang panjang untuk pancang atau pembongkaran. Di proyek: pilih sesuai material." },
  { id: 428, category: "sekou", source: "jac-ch5", type: "konsep", furi: "さんどぺえぱあ", jp: "サンドペーパー", id_text: "Amplas — nomor kecil = kasar, nomor besar = halus", desc: "Kertas amplas dengan partikel pasir/kaca. Nomor KECIL (#60) = kasar untuk material kasar. Nomor BESAR (#400) = halus untuk finishing. Ada 耐水ペーパー (tahan air) dan 布ペーパー (kain, lebih kuat)." },
  { id: 429, category: "sekou", source: "jac-ch5", type: "konsep", furi: "そけっとれんち / ぼっくすれんち / ろっかくれんち", jp: "ソケットレンチ / ボックスレンチ / 六角レンチ", id_text: "Socket wrench / Box wrench / Hex key (baut segi", desc: "ソケットレンチ = handle + kepala soket ganti-ganti. ボックスレンチ = soket menyatu dengan handle (L/T). 六角レンチ = batang heksagonal untuk baut berlubang segi enam. Di proyek: pilih sesuai baut." },
  { id: 430, category: "sekou", source: "jac-ch5", type: "konsep", furi: "もるたるみきさ vs こんくりいとみきさ", jp: "モルタルミキサ vs コンクリートミキサ", id_text: "Mortar mixer (semen+pasir) vs Concrete mixer", desc: "モルタルミキサ = mencampur semen, air, dan pasir → mortar. コンクリートミキサ = lebih kuat untuk beton. バッチミキサ = aduk satu batch per siklus. Di proyek: pilih sesuai campuran." },
  { id: 431, category: "sekou", source: "jac-ch5", type: "konsep", furi: "たあんぶっくる", jp: "ターンバックル", id_text: "Turnbuckle — pengencang kabel/kawat dengan", desc: "Alat logam berulir untuk mengencangkan atau memperpanjang tali, kabel, atau kawat dengan cara memutar badan tengahnya. Di proyek: mengatur tegangan kawat penopang scaffolding." },
  { id: 432, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ちるほおいる（しゅどうしきういんち）", jp: "チルホール（手動式ウインチ）", id_text: "Tirfor / come-along — winch manual tarik beban", desc: "Winch manual yang menarik wire rope melalui mekanisme lever. Di proyek: mengarahkan pohon saat ditebang atau menarik beban tanpa listrik. Mandor:「チルホールで引き寄せて」(tarik pakai tirfor)." },
  { id: 433, category: "sekou", source: "jac-ch5", type: "konsep", furi: "きりんじゃっき", jp: "キリンジャッキ", id_text: "Screw jack — angkat beban vertikal dengan prinsip", desc: "Jack yang menggunakan gaya dorong putaran ulir untuk mengangkat beban secara vertikal. Di proyek: juga digunakan dalam 山留め工事 untuk gaya horizontal pada penopang." },
  { id: 434, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ればあぶろっく", jp: "レバーブロック", id_text: "Lever block — angkat/kencangkan beban; juga untuk", desc: "Mengangkat atau mengencangkan beban via lever+rantai. Di proyek: 建て入れ直し = menegakkan kolom baja agar benar-benar vertikal (垂直を出す). Mandor:「レバーブロックで引っ張って鉄骨を起こして」(tegakkan baja pakai lever block)." },
  { id: 435, category: "anzen", source: "jac-ch5", type: "konsep", furi: "かはんしきさぎょうだい（のびうま）", jp: "可搬式作業台（伸び馬）", id_text: "Portable work platform 'nobima' — kaki teleskopik", desc: "Platform kerja 2 kaki yang bisa disesuaikan panjangnya dengan platform di atas, dilengkapi railing (手すり). Di proyek: kerja di ketinggian rendah-sedang dalam ruangan." },
  { id: 436, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ぶろああ（そうふうき）", jp: "ブロアー（送風機）", id_text: "Blower — kipas kuat untuk meniup debu, daun, dan", desc: "Alat elektrik menghasilkan aliran udara kencang untuk meniup dan mengumpulkan sampah ringan seperti daun, serbuk gergaji, atau debu konstruksi." },
  { id: 437, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ふぁん（そうふうき vs はいふうき）", jp: "ファン（送風機 vs 排風機）", id_text: "Fan: supply (dorong masuk) vs exhaust (keluar)", desc: "ファン = alat memberi energi ke udara dalam duct. 送風機 = mengirim udara dari luar ke dalam (supply). 排風機 = menghisap udara dari dalam ke luar (exhaust)." },
  { id: 438, category: "denki", source: "jac-ch5", type: "konsep", furi: "こんてすたあ", jp: "コンテスター", id_text: "Outlet tester — periksa polaritas dan arde pada", desc: "Alat dicolokkan ke stop kontak untuk memeriksa apakah kabel plus/minus tidak terbalik dan koneksi arde (earth/アース) sudah benar. Di proyek: cek setiap outlet setelah instalasi." },
  { id: 439, category: "denki", source: "jac-ch5", type: "konsep", furi: "でんどうはんまあ", jp: "電動ハンマー", id_text: "Electric hammer — melubangi dinding/slab untuk", desc: "Alat elektrik untuk menghaluskan/melubangi (はつる) dinding atau slab beton membuka jalur konduit. Di proyek: khusus pekerjaan はつり (demolisi parsial beton) saat instalasi listrik." },
  { id: 440, category: "denki", source: "jac-ch5", type: "konsep", furi: "まわしびき", jp: "廻し挽き（まわしびき）", id_text: "Keyhole saw — gergaji buat lubang di gypsum board", desc: "Gergaji panjang sempit untuk membuat lubang di papan gypsum atau triplek, misalnya untuk pemasangan saklar atau kotak instalasi. Di proyek: tidak bisa untuk material keras seperti beton." },
  { id: 441, category: "denki", source: "jac-ch5", type: "konsep", furi: "ぬりしろかばあ", jp: "塗代カバー", id_text: "Plaster ring — pelindung kotak tanam sebelum", desc: "Penutup dipasang pada kotak outlet yang akan ditanam dalam beton/plester saat konstruksi, melindungi kotak dari masuknya material. Di proyek: dilepas setelah beton mengeras." },
  { id: 442, category: "denki", source: "jac-ch5", type: "konsep", furi: "ぼっくすこねくた", jp: "ボックスコネクタ", id_text: "Box connector — penghubung konduit ke outlet box", desc: "Menyambungkan outlet box dengan konduit logam (E管/C管) atau PF管. Ada 2 tipe: ねじなし管用 dan PF管用. Di proyek: dipasang di sisi kotak, berbeda dari カップリング yang antar konduit." },
  { id: 443, category: "denki", source: "jac-ch5", type: "konsep", furi: "らじあすくらんぷ", jp: "ラジアスクランプ", id_text: "Radius clamp — sambungan listrik (grounding)", desc: "Fitting logam untuk menyambungkan secara listrik (電気的接続) antara outlet box baja dan konduit logam, memastikan kontinuitas grounding. Di proyek: wajib dipasang untuk keselamatan listrik." },
  { id: 444, category: "denki", source: "jac-ch5", type: "konsep", furi: "あっしゅくたんし vs あっちゃくたんし", jp: "圧縮端子 vs 圧着端子", id_text: "Terminal press (mesin) vs terminal crimping (tang)", desc: "圧縮端子 = dikencangkan mesin khusus (圧縮機) dengan tekanan besar. 圧着端子 = dikrimping dengan tang tangan (圧着ペンチ). Di proyek: 圧縮端子 untuk kabel besar, 圧着 untuk kabel kecil." },
  { id: 445, category: "denki", source: "jac-ch5", type: "konsep", furi: "ぼうたんし", jp: "棒端子", id_text: "Ferrule / pin terminal — ujung terminal berbentuk", desc: "Jenis 圧着端子 ujungnya berbentuk batang (棒状). Dimasukkan ke terminal klem atau blok terminal agar kabel tidak terurai, dikrimping pakai 圧着ペンチ. Di proyek: digunakan pada blok terminal panel." },
  { id: 446, category: "denki", source: "jac-ch5", type: "konsep", furi: "COS（ちぇんじおおばあすいっち）", jp: "COS（Change Over Switch）", id_text: "COS = Change Over Switch — saklar pemindah sumber", desc: "Saklar untuk memindahkan (切り換える) antara dua sumber daya, misal dari PLN ke generator saat pemadaman. Di proyek: dipasang di panel utama gedung." },
  { id: 447, category: "denki", source: "jac-ch5", type: "konsep", furi: "べるまうす", jp: "ベルマウス", id_text: "Bell mouth — corong pelindung kabel saat ditarik", desc: "Komponen berbentuk corong dipasang di ujung konduit/bukaan pipa saat menarik kabel, mencegah kabel tergores atau rusak saat penarikan (引き込み). Di proyek: wajib dipasang sebelum tarik kabel." },
  { id: 448, category: "denki", source: "jac-ch5", type: "konsep", furi: "ああすぼんどせん vs のんぼんどつぎて", jp: "アースボンド線 vs ノンボンド継手", id_text: "Earth bond wire (sambung grounding rack) vs", desc: "Saat menyambung dua cable rack, perlu sambungan listrik/grounding (電気的接続) menggunakan アースボンド線. Alternatif: gunakan ノンボンド継手 yang sudah menyediakan koneksi listrik sendiri tanpa kabel tambahan." },
  { id: 449, category: "denki", source: "jac-ch5", type: "konsep", furi: "えんどかばあ / すたっとばあ", jp: "エンドカバー / スタットバー", id_text: "End cover (penutup keluaran kabel) / Stud bar", desc: "エンドカバー = penutup di titik keluarnya kabel dari plafon. スタットバー = braket logam yang memanfaatkan tulangan dinding/slab untuk memasang kotak instalasi tanpa mengebor." },
  { id: 450, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "けえぷるくりだしき（かっしゃしき）", jp: "ケーブル繰り出し機（滑車式）", id_text: "Cable pay-out machine (katrol) — keluarkan kabel", desc: "Alat berbasis katrol (滑車) untuk mengeluarkan kabel dari drum secara mudah dan terkontrol, menghindari kerusakan akibat tarikan tidak merata. Di proyek: instalasi kabel aerial (架空配線)." },
  { id: 451, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "きんしゃ", jp: "金車（きんしゃ）", id_text: "Cable block / sheave — katrol di kawat gantung", desc: "Katrol kecil dipasang pada kawat gantung (つり線) selama penarikan kabel telekomunikasi aerial. Kabel diletakkan di atas roda agar ditarik mudah tanpa gesekan berlebih." },
  { id: 452, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ぽんぷ（はいかんないのみずをとおく・たかくへ）", jp: "ポンプ（配管内の水を遠く・高くへ）", id_text: "Pompa — beri energi air dalam pipa agar mengalir", desc: "Alat mekanis memberikan energi kepada air di sistem pipa agar mengalir ke tempat jauh atau dipompa ke lantai lebih tinggi. Di proyek: komponen utama distribusi air gedung." },
  { id: 453, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ねじげえじ", jp: "ねじゲージ", id_text: "Thread gauge — alat ukur kalibrasi ulir pipa dan", desc: "Alat pengukur untuk memeriksa ulir pada pipa (管) dan fitting (管継手) agar sesuai standar, memastikan sambungan tidak bocor. Di proyek: inspeksi QC sebelum pemasangan pipa berulir." },
  { id: 454, category: "sekou", source: "jac-ch5", type: "konsep", furi: "れえき vs じょれん", jp: "レーキ vs ジョレン", id_text: "Rake (meratakan tanah/aspal) vs Joren/hoe", desc: "レーキ = bergigi banyak untuk meratakan tanah atau kumpulkan daun (model tanpa gigi untuk aspal). ジョレン = mirip cangkul lebar untuk menggeser tanah atau puing. Di proyek: レーキ untuk finishing permukaan." },
  { id: 455, category: "sekou", source: "jac-ch5", type: "konsep", furi: "のこぎり", jp: "のこぎり（のこ）", id_text: "Gergaji — memotong kayu, logam, dan pipa", desc: "Alat dengan banyak mata pisau pada plat logam untuk memotong kayu, logam, dan pipa. Disingkat 'のこ' di lapangan. Di proyek: pilih jenis yang sesuai material yang dipotong." },
  { id: 456, category: "sekou", source: "jac-ch5", type: "konsep", furi: "くいきり（にっぱあ）vs ぺんち", jp: "くい切り（ニッパー）vs ペンチ", id_text: "Diagonal cutter (potong kawat) vs Pliers (bengkok", desc: "くい切り (ニッパー) = memotong kawat, tulangan kecil, atau kepala paku. ペンチ = membengkokkan dan memotong sekaligus dengan bagian bergigi dan pemotong. Di proyek: ニッパー untuk kawat halus, ペンチ serbaguna." },
  { id: 457, category: "sekou", source: "jac-ch5", type: "konsep", furi: "やすり + わいやあぶらし", jp: "やすり（金属用 / 木工用）+ ワイヤーブラシ", id_text: "Kikir (logam atau kayu) + Wire brush (bersihkan", desc: "やすり = kikir mengamplas logam atau kayu, berbagai jenis sesuai material. ワイヤーブラシ = sikat kawat keras untuk: ①bersihkan karat ②kupas cat ③bersihkan sumbatan pada mata kikir." },
  { id: 458, category: "sekou", source: "jac-ch5", type: "konsep", furi: "たっぴんぐねじ vs くぎのしゅるい", jp: "タッピングねじ vs 釘（くぎ）の種類", id_text: "Tapping screw (buat ulir sendiri) vs berbagai", desc: "タッピングねじ = sekrup yang membuat alur ulir sendiri saat dikencangkan, tak butuh pre-tap. 釘 = paku dipukul palu; berbagai jenis: スクリュー釘, コンクリート釘, ケーシング釘, トタン釘. Di proyek: pilih sesuai material." },
  { id: 459, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ふるい", jp: "ふるい", id_text: "Saringan/ayakan — pilah material berdasarkan", desc: "Rangka dengan jaring kawat untuk memisahkan material berdasarkan ukuran, misal memisahkan tanah halus dari kerikil hasil galian. Di proyek: dipakai sebelum penggunaan agregat." },
  { id: 460, category: "sekou", source: "jac-ch5", type: "konsep", furi: "うえす・ばけつ・ひしゃく", jp: "ウェス・バケツ・ひしゃく", id_text: "Kain lap oli / Ember zinc-plated / Centong air", desc: "ウェス = kain mengelap oli atau bahan kimia. バケツ = ember konstruksi dari pelat besi berlapis seng (亜鉛鉄板製) agar tahan lama. ひしゃく = alat bergagang mengambil air dari ember/bak." },
  { id: 461, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ぶるうしいと vs べにや（ようじょうざいりょう）", jp: "ブルーシート vs ベニヤ（養生材料）", id_text: "Blue sheet (proteksi dari cat/debu) vs Plywood", desc: "ブルーシート = lembaran biru plastik melindungi lantai dari tetesan cat atau debu. ベニヤ = plywood tipis di lantai mencegah goresan akibat material berat. Keduanya 養生材料." },
  { id: 462, category: "sekou", source: "jac-ch5", type: "konsep", furi: "そり vs ころ（じゅうりょうぶつのいどう）", jp: "そり vs ころ（重量物の移動）", id_text: "Sledge (tarik beban berat) vs Log rollers (geser", desc: "そり = rangka landai untuk menopang dan menarik beban berat. ころ = batang kayu/pipa bulat disusun di bawah benda berat untuk digeser memanfaatkan prinsip rolling." },
  { id: 463, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ほうき + ちりとり + ぶろああ", jp: "ほうき + ちりとり + ブロアー", id_text: "Sapu / Pengki (kumpulkan sampah) / Blower (tiup", desc: "ほうき = sapu untuk membersihkan lantai. ちりとり = pengki mengumpulkan sampah sapuan. ブロアー = penghasil angin kuat untuk meniup sampah ringan seperti daun atau serbuk." },
  { id: 464, category: "sekou", source: "jac-ch5", type: "konsep", furi: "かはんしきさぎょうだい vs きゃたつ vs ろおりんぐたわあ", jp: "可搬式作業台 vs 脚立 vs ローリングタワー", id_text: "3 alat kerja ketinggian: meja teleskopik / tangga", desc: "可搬式作業台: kaki disesuaikan + platform + railing. 脚立: tangga A — DILARANG berdiri di papan atas. ローリングタワー: perancah multi-lantai beroda (castor 4 sudut). Di proyek: pilih sesuai ketinggian dan luas area." },
  { id: 465, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ちゅうぶべんだあ（どうかんせんよう）", jp: "チューブベンダー（銅管専用）", id_text: "Tube bender — tekuk pipa tembaga (refrigerant AC)", desc: "Alat khusus membengkokkan pipa tembaga (銅管) tanpa membuatnya gepeng atau retak. Di proyek: penting dalam instalasi pipa refrigerant AC (冷媒配管). Berbeda dari ベンダー listrik untuk konduit logam." },
  { id: 466, category: "denki", source: "jac-ch5", type: "konsep", furi: "ばん", jp: "盤（ばん）", id_text: "Panel listrik: berdiri di lantai vs di dinding", desc: "盤 = panel distribusi listrik berisi breaker. 自立盤 = berdiri di lantai (pakai チャンネルベース). 壁掛け盤 = dipasang di dinding. Di proyek: penghubung dari sumber ke peralatan di setiap zona." },
  { id: 467, category: "denki", source: "jac-ch5", type: "konsep", furi: "あいぶい（おくないびにるぜつえんでんせん）", jp: "IV（屋内ビニル絶縁電線）", id_text: "IV wire = kawat berinsulasi PVC untuk instalasi", desc: "IV = Indoor PVC. Kawat listrik tunggal berinsulasi vinil untuk instalasi 屋内 (dalam ruangan). Bukan kabel berselubung — hanya insulasi tunggal, harus dalam konduit atau cable rack." },
  { id: 468, category: "denki", source: "jac-ch5", type: "konsep", furi: "ろしゅつぼっくす vs ろしゅつすいっちぼっくす", jp: "露出ボックス vs 露出スイッチボックス", id_text: "Surface-mount box (menempel dinding) vs", desc: "露出ボックス = kotak instalasi menempel di permukaan dinding, bukan ditanam. 露出スイッチボックス = khusus menyimpan saklar dan stopkontak secara surface-mount. Di proyek: dipakai di gedung industri atau ruang mesin." },
  { id: 469, category: "sekou", source: "jac-ch5", type: "konsep", furi: "しゅうじんき vs しゅうじんまるのこ", jp: "集塵機 vs 集塵丸のこ", id_text: "Dust collector vs Circular saw dengan penampung", desc: "集塵機 = mesin vakum khusus mengumpulkan debu halus (粉塵) saat memotong beton/keramik. 集塵丸のこ = gergaji sirkel dengan penampung debu: tipe ダストボックス atau disambung ke 集塵機 terpisah." },
  { id: 470, category: "anzen", source: "jac-ch3", type: "konsep", furi: "こうしょさぎょうしゃばすけっとたかさめえとるいじょう", jp: "高所作業車（バスケット高さ 2m以上）", id_text: "Aerial work platform (AWP): keranjang kerja ≥2m", desc: "Kendaraan dengan keranjang (バスケット) ke ≥2m via boom/scissor. ≥10m butuh 技能講習, <10m cukup 特別教育. Mandor:「高所作業車の点検記録見せて」(tunjukkan catatan inspeksi)." },
  { id: 471, category: "sekou", source: "jac-ch5", type: "konsep", furi: "でんどうぶろっくかったあ vs まるのこ", jp: "電動ブロックカッター vs 丸のこ", id_text: "Electric block cutter (beton/blok) vs Circular", desc: "電動ブロックカッター = khusus memotong material berbasis beton, blok, atau paving. 丸のこ = gergaji sirkel serba guna untuk kayu, logam, dan bahan umum. Di proyek: pilih sesuai material." },
  { id: 472, category: "sekou", source: "jac-ch5", type: "konsep", furi: "さげふり", jp: "下げ振り（さげふり）", id_text: "Plumb bob — bandul cek vertikalitas kolom dan", desc: "Bandul logam runcing digantung dengan tali untuk memeriksa apakah kolom/dinding tegak lurus (垂直). Dipasang pada 下げ振り保持器 di atas kolom, jarak tali ke permukaan diukur dari atas dan bawah." },
  { id: 473, category: "sekou", source: "jac-ch5", type: "konsep", furi: "だんぷとらっく", jp: "ダンプトラック", id_text: "Dump truck — angkut tanah/batu dengan bak yang", desc: "Kendaraan pengangkut tanah dan batuan dengan bak (荷台) yang bisa dimiringkan untuk membuang muatan. Di proyek: dikombinasikan dengan excavator atau wheel loader." },
  { id: 474, category: "denki", source: "jac-ch5", type: "konsep", furi: "VVF すとりっぱあ", jp: "VVFストリッパー", id_text: "VVF stripper — kupas selubung luar + isolasi inti", desc: "Alat khusus mengupas dua lapisan sekaligus pada kabel VVF: selubung luar (外装) dan insulasi inti kawat (芯線被覆). Berbeda dari ワイヤーストリッパー yang hanya satu lapisan." },
  { id: 475, category: "denki", source: "jac-ch5", type: "konsep", furi: "すとりっぷげえじ", jp: "ストリップゲージ", id_text: "Strip gauge — ukur panjang kupasan isolasi,", desc: "Gauge mengukur panjang kupasan isolasi kabel (被覆を剥き取る長さ). Dipasang menjadi satu pada ワイヤーストリッパー. Di proyek: memastikan panjang kupasan konsisten untuk sambungan yang benar." },
  { id: 476, category: "denki", source: "jac-ch5", type: "konsep", furi: "こんせんと（うめこみがた・ろしゅつがた）", jp: "コンセント（埋込型・露出型）", id_text: "Stopkontak: tanam (dinding) vs surface (menempel)", desc: "コンセント = stopkontak dinding 単相100V. 埋込型 = ditanam dalam dinding via mounting frame. 露出型 = menempel di permukaan dinding. Di proyek: 埋込 lebih umum di bangunan baru." },
  { id: 477, category: "denki", source: "jac-ch5", type: "konsep", furi: "やくもの", jp: "役物（やくもの）", id_text: "Fitting / aksesori bentuk khusus untuk posisi", desc: "Komponen berbentuk khusus (特殊な形状の部材) digunakan sesuai lokasi, misalnya konektor sudut atau sambungan khusus cable rack. Di proyek: diperlukan di titik belokan atau sudut instalasi." },
  { id: 478, category: "denki", source: "jac-ch5", type: "konsep", furi: "ふれどめ", jp: "振れ止め（ふれどめ）", id_text: "Anti-sway brace — penopang diagonal agar raceway", desc: "Penopang dipasang miring/diagonal (斜めに支持) agar レースウェイ tidak bergoyang. Dipasang antara raceway dan struktur bangunan. Di proyek: wajib di area gempa atau getaran." },
  { id: 479, category: "denki", source: "jac-ch5", type: "konsep", furi: "つりぼるとしじかなぐ", jp: "吊りボルト支持金具", id_text: "Hanging bolt bracket — pasang baut gantung ke", desc: "Fitting memungkinkan pemasangan 吊りボルト pada profil baja atau dek tanpa perlu melubangi (穴を開けることなく). Di proyek: mempercepat instalasi conduit dan cable rack." },
  { id: 480, category: "denki", source: "jac-ch4", type: "konsep", furi: "りいどたんし", jp: "リード端子（りーどたんし）", id_text: "Lead terminal — sambungan grounding rod dan kabel", desc: "Komponen yang menghubungkan 接地棒 (grounding rod) dengan 接地線 (kabel grounding). Junction point antara rod di tanah dan kabel ke panel. Mandor:「リード端子の圧着がしっかりできているか確認して」." },
  { id: 481, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "めたるけえぷる（どうじく・ついすとぺあ）", jp: "メタルケーブル（同軸・ツイストペア）", id_text: "Metal cable — kabel tembaga: coaxial dan twisted", desc: "Kabel telekomunikasi berbasis tembaga (銅) mengirim sinyal secara elektrik. Mencakup: ①同軸ケーブル = coaxial untuk antena TV. ②UTPツイストペア = untuk LAN/telepon." },
  { id: 482, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ふぁいばあほごすりいぶ", jp: "ファイバー保護スリーブ", id_text: "Fiber protection sleeve — pelindung titik fusion,", desc: "Sleeve pelindung titik sambungan 融着接続, dipanaskan agar mengerut. KRITIS: harus dimasukkan ke kabel SEBELUM fusion karena tidak bisa dimasukkan setelah selesai (後からでは挿入できない)." },
  { id: 483, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "ふぁいばあほるだ", jp: "ファイバーホルダ", id_text: "Fiber holder — dudukan serat optik saat jacket", desc: "Alat dudukan serat optik (光ファイバー) secara stabil saat dipasang ke ジャケットリムーバ, ファイバカッター, atau 融着接続器. Di proyek: mencegah serat bengkok atau patah. Mandor:「ファイバーホルダにセットしてから作業して」(pasang ke holder dulu)." },
  { id: 484, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "じゃけっとりむうば", jp: "ジャケットリムーバ", id_text: "Jacket remover — kupas selubung serat optik", desc: "Alat mengupas lapisan pelindung (被覆/jacket) ujung serat optik sebelum pemotongan dan fusion splice. Di proyek: pertama kali digunakan dalam rangkaian proses penyambungan serat." },
  { id: 485, category: "tsushin", source: "jac-ch5", type: "konsep", furi: "どうじくけえぷるちぇっかあ", jp: "同軸ケーブルチェッカー", id_text: "Coaxial cable checker — verifikasi kondisi", desc: "Alat memeriksa kondisi sambungan/konduktivitas (導通確認) kabel koaksial. Berbeda dari LANテスター yang memeriksa 8 kawat kabel LAN. Di proyek: QC setelah pemasangan kabel antena." },
  { id: 486, category: "haikan", source: "jac-ch5", type: "konsep", furi: "れいばいようどうかん", jp: "冷媒用銅管", id_text: "Pipa tembaga refrigerant — sirkulasi refrigerant", desc: "Pipa tanpa sambungan (継目無管) dari tembaga/paduan tembaga untuk mensirkulasikan refrigerant antara unit luar (室外機) dan dalam (室内機) AC. Di proyek: dibengkokkan pakai チューブベンダー." },
  { id: 487, category: "haikan", source: "jac-ch5", type: "konsep", furi: "えあふぃるたあ（くうちょう）", jp: "エアフィルター（空調）", id_text: "Air filter (AC/HVAC) — saring debu dan partikel", desc: "Komponen AC/HVAC menyaring debu dan partikel kecil dari udara sebelum masuk sistem. Di proyek: perlu dibersihkan berkala untuk menjaga efisiensi." },
  { id: 488, category: "haikan", source: "jac-ch3", type: "konsep", furi: "えいせいきぐせつび", jp: "衛生器具設備（えいせいきぐせつび）", id_text: "Sanitary fixtures: toilet, wastafel, sink, bak", desc: "Peralatan yang keluarkan/tampung/buang air. Meliputi: 蛇口(keran), 大便器(toilet), 小便器(urinoir), 洗面器(wastafel), 風呂(bak mandi), 流し(sink). Mandor:「衛生器具の取付完了しましたか」(pemasangan fixtures selesai?)." },
  { id: 489, category: "sekou", source: "jac-ch3", type: "konsep", furi: "といし", jp: "砥石（といし）", id_text: "Batu asah untuk pahat, ketam, dan alat tajam", desc: "Batu untuk mengasah logam atau batu (切削・磨く). Balok kecil (直方体) digunakan untuk mengasah のみ (pahat) atau かんな (ketam kayu) agar tetap tajam. Mandor:「のみの刃、砥石で研いどいて」(asah mata pahat pakai batu asah)." },
  { id: 490, category: "sekou", source: "jac-ch5", type: "konsep", furi: "どらいばあ（ぷらす・まいなす）", jp: "ドライバー（プラス・マイナス）", id_text: "Obeng — Phillips (+) dan flathead (−); pilih", desc: "Alat memutar sekrup (ネジ). プラス = Phillips, マイナス = flathead. Gunakan ukuran TEPAT agar alur tidak rusak (なめる). 電工用: grip besar dan bulat untuk genggaman kuat." },
  { id: 491, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ぼると・なっと・わっしゃあ", jp: "ボルト・ナット・ワッシャー", id_text: "Bolt + nut + washer — tiga komponen pengikat satu", desc: "ボルト (おねじ) + ナット (めねじ) = sepasang pengunci. ワッシャー dipasang di antara keduanya mencegah kerusakan permukaan dan mengurangi risiko kendor." },
  { id: 492, category: "sekou", source: "jac-ch6", type: "konsep", furi: "とちのせいやく", jp: "土地の制約（とちのせいやく）", id_text: "Karakteristik konstruksi: terikat pada lahan", desc: "Setiap proyek melekat pada lahan unik sehingga kondisi identik tidak pernah berulang; berbeda dari produksi pabrik. Di proyek: perencanaan harus menyesuaikan kondisi lahan spesifik." },
  { id: 493, category: "sekou", source: "jac-ch6", type: "konsep", furi: "しぜんじょうけんによるえいきょう", jp: "自然条件による影響", id_text: "Karakteristik konstruksi: dipengaruhi kondisi alam", desc: "Pekerjaan konstruksi umumnya di luar ruangan sehingga terpengaruh topografi, musim, dan cuaca — faktor yang tidak sepenuhnya bisa dikendalikan. Di proyek: jadwal menyesuaikan cuaca." },
  { id: 494, category: "sekou", source: "jac-ch6", type: "konsep", furi: "しゃかいてきせいやく", jp: "社会的制約（しゃかいてきせいやく）", id_text: "Karakteristik konstruksi: terikat regulasi sosial", desc: "Karena produksi di lokasi asli (現地生産), wajib memenuhi peraturan keselamatan dan lingkungan; hukum dan lingkungan sosial berbeda tiap lokasi. Di proyek: izin dan aturan warga sekitar." },
  { id: 495, category: "sekou", source: "jac-ch6", type: "konsep", furi: "せこうけいかく", jp: "施工計画（せこうけいかく）", id_text: "Rencana pelaksanaan konstruksi", desc: "Rencana berdasarkan dokumen desain untuk mengerjakan konstruksi: kualitas baik, biaya minimal, tepat waktu, nol kecelakaan, dan ramah lingkungan." },
  { id: 496, category: "sekou", source: "jac-ch6", type: "konsep", furi: "せこうようりょうしょ", jp: "施工要領書（せこうようりょうしょ）", id_text: "Dokumen prosedur pelaksanaan pekerjaan harian", desc: "Memuat detail teknis pelaksanaan pekerjaan: konfirmasi gambar, kondisi lapangan, urutan kerja, penempatan tenaga, serta persiapan alat dan material. Wajib dipahami sebelum memulai pekerjaan hari itu." },
  { id: 497, category: "career", source: "jac-ch6", type: "konsep", furi: "きゃりああっぷかあど・さぎょうめんきょ", jp: "キャリアアップカード・作業免許", id_text: "Kartu CCAS & izin kerja — wajib dibawa saat", desc: "Item konfirmasi sebelum施工: wajib memastikan pekerja membawa kartu CCAS (キャリアアップカード) dan semua lisensi/sertifikat yang diperlukan hari itu. Di proyek: dicek di morning briefing." },
  { id: 498, category: "anzen", source: "jac-ch6", type: "konsep", furi: "ひんしつかんり", jp: "品質管理（ひんしつかんり）", id_text: "Manajemen kualitas — Q dalam QCDSE", desc: "QCDSE の Q。Manajemen untuk memenuhi kualitas yang diminta pemberi kerja; mencakup inspeksi kualitas, uji material, uji konstruksi, serta kontrol dimensi dan bentuk sesuai rencana kualitas." },
  { id: 499, category: "anzen", source: "jac-ch6", type: "konsep", furi: "よさんのかんり", jp: "予算の管理（よさんのかんり）", id_text: "Manajemen biaya — C dalam QCDSE", desc: "QCDSE の C。Mengelola dana yang tersedia di lapangan (biaya material, tenaga kerja, biaya lapangan) agar tidak melampaui anggaran proyek yang ditetapkan." },
  { id: 500, category: "anzen", source: "jac-ch6", type: "konsep", furi: "こうていかんり", jp: "工程管理（こうていかんり）", id_text: "Manajemen jadwal — D dalam QCDSE", desc: "QCDSE の D。Koordinasi dengan kontraktor utama dan kontraktor lain agar pekerjaan selesai dalam batas waktu kontrak (工期内) tanpa keterlambatan." },
  { id: 501, category: "anzen", source: "jac-ch6", type: "konsep", furi: "あんぜんかんり", jp: "安全管理（あんぜんかんり）", id_text: "Manajemen keselamatan — S dalam QCDSE", desc: "QCDSE の S。Mencakup pencegahan jatuh, benda jatuh, dan penyakit akibat kerja; dilaksanakan melalui KY training harian, patroli, rapat keselamatan 5S, dan target nol kecelakaan (無事故・無災害)." },
  { id: 502, category: "anzen", source: "jac-ch6", type: "konsep", furi: "かんきょうほぜんかんり", jp: "環境保全管理（かんきょうほぜんかんり）", id_text: "Manajemen pelestarian lingkungan — E dalam QCDSE", desc: "QCDSE の E。Meminimalkan dampak kebisingan, getaran, dan pencemaran air akibat konstruksi; wajib mematuhi standar yang ditetapkan undang-undang dan peraturan daerah." },
  { id: 503, category: "sekou", source: "jac-ch6", type: "konsep", furi: "れえざあしょうしゃき", jp: "レーザー照射器", id_text: "Alat laser untuk sumidashi — penanda posisi dan", desc: "Memancarkan cahaya laser menggantikan 墨つぼ konvensional; memudahkan pengecekan sudut siku (直角) dan kerataan horizontal (水平) dengan cepat dan akurat. Mandor:「レーザーで墨を出して」(tandai posisi pakai laser)." },
  { id: 504, category: "sekou", source: "jac-ch6", type: "konsep", furi: "きじゅんすみ・おやすみ", jp: "基準墨・親墨（きじゅんすみ）", id_text: "3 jenis sumidashi: acuan / komponen / posisi", desc: "①基準墨・親墨 = posisi, ketinggian (GL/FL), dan通り芯 sebagai acuan utama. ②部材加工用墨付け = marking dimensi komponen. ③取付け位置出し = posisi pemasangan perangkat. Mandor:「基準墨を出してから始めて」(buat acuan garis dulu)." },
  { id: 505, category: "haikan", source: "jac-ch6", type: "konsep", furi: "Aこしょう vs Bこしょう", jp: "A呼称 vs B呼称", id_text: "Diameter nominal pipa: A (mm) vs B (inci)", desc: "A呼称 menyatakan diameter nominal pipa dalam mm; B呼称 dalam inci. Contoh: 25A = 1B. Di proyek: ねじ接合 digunakan untuk ukuran 15A–100A. Mandor:「25Aの配管を持ってきて」(ambil pipa ukuran 25A)." },
  { id: 506, category: "sekou", source: "jac-ch6", type: "konsep", furi: "ばんどそおかんせつだんき", jp: "バンドソー管切断機", id_text: "Mesin band saw pemotong pipa — hasil tegak lurus", desc: "Digunakan memotong pipa baja secara tegak lurus. Penyimpangan ≥1,0 mm berupa 斜め切れ (miring) atau 段切れ (bertangga) menjadi penyebab kebocoran air." },
  { id: 507, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ななめぎれ・だんぎれ", jp: "斜め切れ・段切れ ≥1.0mm", id_text: "Cacat potong pipa ≥1,0 mm → kebocoran air", desc: "斜め切れ = potongan miring; 段切れ = potongan bertangga. Keduanya menyebabkan kebocoran jika penyimpangan ≥1,0 mm. Di proyek: standar potongan 90° terhadap sumbu pipa." },
  { id: 508, category: "anzen", source: "jac-ch6", type: "konsep", furi: "ぐんてでのねじかこうぜったいきんし", jp: "軍手でのねじ加工は絶対禁止", id_text: "Sarung tangan kain saat mengulir pipa: DILARANG", desc: "Menggunakan 軍手 (sarung tangan kain) saat mengoperasikan mesin ulir sangat berbahaya — tangan bisa tersangkut dan tergulung mesin. Larangan mutlak (絶対にしてはいけない)." },
  { id: 509, category: "haikan", source: "jac-ch6", type: "konsep", furi: "しいるてえぷのまきかた", jp: "シールテープの巻き方", id_text: "Cara lilit seal tape: searah jarum jam, 6–7x,", desc: "時計回り6〜7巻き・1山残す。Gulung searah putaran pemasangan; mulai dari 1 ulir dari ujung, gulung 6–7 kali. Jika tape sampai ujung, potongan masuk pipa jadi penyumbat." },
  { id: 510, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ねじこみのこつ", jp: "ねじ込みのコツ", id_text: "Kunci pasang ulir: sisakan 2–2,5 ulir pakai wrench", desc: "2山〜2山半残す。Setelah dikencangkan tangan semaksimal mungkin, gunakan パイプレンチ dan hentikan saat masih tersisa 2–2,5 ulir (山). Mengencangkan berlebihan merusak ulir." },
  { id: 511, category: "haikan", source: "jac-ch6", type: "konsep", furi: "さびのあるねじはぜったいしようきんし", jp: "錆のあるねじは絶対使用禁止", id_text: "Ulir pipa berkarat: dilarang keras digunakan", desc: "Pipa atau fitting yang ulirnya berkarat (錆) tidak boleh digunakan dalam kondisi apapun; karat membuat sambungan tidak rapat dan bocor. Di proyek: periksa kondisi ulir sebelum pemasangan." },
  { id: 512, category: "sekou", source: "jac-ch6", type: "konsep", furi: "ねじげえじけんさたいみんぐぱたあん", jp: "ねじゲージ", id_text: "Thread gauge — 5 momen wajib inspeksi ulir pipa", desc: "検査タイミング5パターン。Wajib periksa: ①3 uliran pertama, ②setiap ukuran pipa berubah, ③per ~50 uliran (untuk 25A), ④saat lot/merek pipa berubah, ⑤saat チェーザ (mata potong) diganti." },
  { id: 513, category: "sekou", source: "jac-ch6", type: "konsep", furi: "へえざ", jp: "チェーザ（ねじ切り盤の切削工具）", id_text: "Chaser — mata potong pada mesin pengulir pipa", desc: "Komponen pada ねじ切り機 yang memotong ulir pada pipa; kondisinya mempengaruhi akurasi ulir. Setiap penggantian チェーザ wajib dilakukan pemeriksaan dengan ねじゲージ." },
  { id: 514, category: "haikan", source: "jac-ch6", type: "konsep", furi: "えきじょうしいるざい", jp: "液状シール剤（えきじょうシールざい）", id_text: "Sealant cair untuk sambungan ulir — perhatian K3", desc: "使用上の注意。Dioleskan merata ke ulir; jika terkena mata segera cuci air banyak dan ke dokter, jika terkena kulit cuci dengan sabun. Aduk rata sebelum digunakan. Simpan di tempat sejuk berventilasi." },
  { id: 515, category: "haikan", source: "jac-ch6", type: "konsep", furi: "がすようせつせつごうほう", jp: "ガス溶接接合法（ガスようせつせつごうほう）", id_text: "Las gas — untuk pipa diameter kecil", desc: "Tiga jenis: oksigen-asetilen (paling umum), oksigen-hidrogen, dan udara-asetilen. Banyak digunakan untuk pipa diameter kecil (小口径管)." },
  { id: 516, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ひふくああくようせつせつごうほう", jp: "被覆アーク溶接接合法（SMAW）", id_text: "Las busur tertutup (SMAW) — untuk pipa besar ≥100A", desc: "Elektroda berlapis fluks; fluks terbakar membentuk gas pelindung mencegah oksidasi logam cair. Di proyek: banyak digunakan untuk pipa ≥100A bersama atau sebagai alternatif las gas." },
  { id: 517, category: "haikan", source: "jac-ch6", type: "konsep", furi: "かいさきかこうがたがたれがたいがた", jp: "開先加工（かいさきかこう）", id_text: "Beveling ujung pipa sebelum pengelasan — 4 jenis", desc: "V型・Y型・レ型・I型。Pengerjaan ujung pipa setelah pemotongan untuk meningkatkan penetrasi las; tanpa 開先 terjadi penetrasi kurang (溶け込み不足). Empat jenis: V型、Y型、レ型、I型 (I型 disebut juga ドン付け開先)." },
  { id: 518, category: "haikan", source: "jac-ch6", type: "konsep", furi: "かりつけようせつ", jp: "仮付け溶接（かりつけようせつ）", id_text: "Tack welding — las ikat sebelum las penuh", desc: "Las pendek sebelum pengelasan utama (本溶接) untuk menstabilkan posisi dan mencegah distorsi atau pergeseran pada area bevel (開先部)." },
  { id: 519, category: "haikan", source: "jac-ch6", type: "konsep", furi: "めかにかるせつごうほうほう", jp: "メカニカル接合方法（メカニカルせつごうほうほう）", id_text: "Sambungan mekanis — tanpa las maupun ulir", desc: "Penyambungan menggunakan komponen mekanis: ハウジング管継手、MD継手、カップリング継手、NO-HUB継手. Disebut juga 機械的接合法." },
  { id: 520, category: "haikan", source: "jac-ch6", type: "konsep", furi: "のみこみのまあきんぐ", jp: "飲み込みのマーキング", id_text: "Marking kedalaman insersi pipa PVC ke fitting", desc: "Tanda di sisi pipa sepanjang kedalaman masuk ke fitting; jika tidak sampai tanda, panjang instalasi tidak sesuai dan bisa bocor. Di proyek: marking sebelum oleskan lem." },
  { id: 521, category: "haikan", source: "jac-ch6", type: "konsep", furi: "せっちゃくざいえんびかんよう", jp: "接着剤（塩ビ管用）の塗布手順（せっちゃくざい）", id_text: "Adhesif pipa PVC: urutan aplikasi yang benar", desc: "Oleskan dari sisi fitting dulu (bukan pipa), lalu pipa; dorong sekaligus penuh tenaga dan tahan ±10 detik tanpa melepaskan tekanan. Adhesif yang meluber segera dilap bersih sebelum mengeras." },
  { id: 522, category: "anzen", source: "jac-ch6", type: "konsep", furi: "らいにんぐこうかんのがすようだんぜったいきんし", jp: "ライニング鋼管のガス溶断絶対禁止", id_text: "DILARANG: potong pipa lining dengan oxy-acetylene", desc: "Pemotongan ライニング鋼管 dengan ガス溶断 atau panas tinggi adalah LARANGAN MUTLAK — panas merusak lapisan lining. Di proyek: gunakan band saw atau metal saw. Mandor:「ライニング管はバンドソーで切って」(potong pakai band saw)." },
  { id: 523, category: "haikan", source: "jac-ch6", type: "konsep", furi: "まくれ（ばり）とらいにんぐかんようりいま", jp: "まくれ（バリ）とライニング管用リーマ", id_text: "Burr pipa lining — buang pakai reamer khusus", desc: "Burr setelah pemotongan wajib dihilangkan dengan ライニング管用リーマ atau スクレーパ; jangan pakai reamer mesin ulir biasa karena merusak lapisan lining. Mandor:「ライニング管用リーマでバリを取って」(buang burr pakai reamer khusus)." },
  { id: 524, category: "haikan", source: "jac-ch6", type: "konsep", furi: "かんたんぼうしょくつぎて", jp: "管端防食継手（かんたんぼうしょくつぎて）", id_text: "Sambungan anti-korosi ujung pipa lining", desc: "Melindungi ujung potongan ライニング鋼管 dari korosi; sebelum dipasang, ujung pipa di-chamfer (面取り) sebesar 1/2–2/3 dari ketebalan lapisan塩ビ (塩ビ管肉厚)." },
  { id: 525, category: "anzen", source: "jac-ch6", type: "konsep", furi: "どうかんのせつだんにかのこぐらいんだあきんし", jp: "銅管の切断に金ノコ・グラインダー禁止", id_text: "DILARANG: potong pipa tembaga pakai gergaji", desc: "Memotong pipa tembaga (銅管) dengan 金ノコ atau グラインダー menghasilkan serbuk logam yang tertinggal di dalam pipa refrigeran. Di proyek: gunakan パイプカッター." },
  { id: 526, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ばりとりはどうかんをしたむきに", jp: "バリ取りは銅管を下向きに", id_text: "Buang burr pipa tembaga: ujung pipa menghadap", desc: "Saat menghilangkan burr dari ujung pipa tembaga dengan reamer/scraper, pipa wajib diarahkan ke bawah agar serbuk tidak masuk ke dalam pipa refrigeran." },
  { id: 527, category: "setsubi_kougu", source: "jac-ch6", type: "konsep", furi: "さいじんぐつうる（れいばいかんようしねんしゅうせい）", jp: "サイジングツール（冷媒管用真円修正）", id_text: "Sizing tool — koreksi kebulatan ujung pipa tembaga", desc: "Setelah バリ取り, ujung pipa tembaga wajib dikoreksi kebulatan (真円修正) sebelum flaring. Di proyek: pipa tidak bulat → flaring miring atau fitting tidak masuk." },
  { id: 528, category: "haikan", source: "jac-ch6", type: "konsep", furi: "さいしょうまげはんけいれいばいようひふくどうかん", jp: "最小曲げ半径（さいしょうまげはんけい）", id_text: "Radius tekukan minimum pipa tembaga refrigeran", desc: "冷媒用被覆銅管。手曲げ: dia. 6,35–12,7 mm → min 6× dia. luar; ≥15,88 mm → min 10× dia. luar. ベンダー曲げ: min 4× dia. luar. Di bawah batas ini → pipa penyok (扁平) atau retak (座屈)." },
  { id: 529, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ふれあせつごう", jp: "フレア接合（フレアせつごう）", id_text: "Sambungan flare pipa refrigeran tembaga", desc: "Ujung pipa tembaga dikembangkan menjadi bentuk terompet (フレア加工), lalu dikencangkan dengan フレアナット sehingga bagian flare tertekan dan berfungsi sebagai seal kedap refrigeran." },
  { id: 530, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ろうせつごう", jp: "ろう接合（ろうせつごう）", id_text: "Sambungan brazing pipa refrigeran tembaga", desc: "ろう材 dilelehkan ke celah sambungan tembaga; penting: bebas oksida/kotoran dan suhu brazing tepat. Setelah selesai dinginkan dengan kain basah, periksa ada tidaknya ピンホール atau ろう回り不良." },
  { id: 531, category: "hoon", source: "jac-ch6", type: "konsep", furi: "ほおんざいのしゅうしゅく（さいだいにぱあせんと）", jp: "保温材の収縮（最大2%）", id_text: "Penyusutan insulasi termal: maks 2% searah panjang", desc: "Insulasi menyusut hingga 2% searah panjang (≈8 cm per 4 m); celah akibat penyusutan menimbulkan kondensasi yang berpotensi jadi kecelakaan." },
  { id: 532, category: "hoon", source: "jac-ch6", type: "konsep", furi: "ほおんざいのけいじょういたじょうおびじょうつつじょう", jp: "保温材の形状", id_text: "Bentuk insulasi: lembaran / pita / selongsong", desc: "板状・帯状・筒状（ほおんざいのけいじょう）。板状(保温板) dan 帯状(保温帯) = untuk duct; 筒状(保温筒) = untuk pipa. Material utama: GW (glass wool), RW (rock wool), PS (polystyrene foam)." },
  { id: 533, category: "hoon", source: "jac-ch6", type: "konsep", furi: "ALGC / ALK", jp: "ALGC（アルミガラスクロス）/ ALK", id_text: "Penutup insulasi berbasis aluminium: ALGC dan ALK", desc: "Laminasi aluminium untuk membungkus insulasi di ruang tersembunyi atau garasi. ALGC = aluminium + glass cloth; ALK = aluminium + kraft paper; keduanya berfungsi sebagai penahan uap." },
  { id: 534, category: "hoon", source: "jac-ch6", type: "konsep", furi: "きっこうかなあみ", jp: "亀甲金網（きっこうかなあみ）", id_text: "Jaring kawat hexagonal — pengikat insulasi pipa", desc: "Jaring kawat berbentuk sarang lebah untuk mengikat dan menguatkan insulasi pipa di ruang mesin, garasi, atau gudang. Di proyek: gunakan 塩ビ亀甲金網 (berlapis PVC) untuk mencegah karat." },
  { id: 535, category: "haikan", source: "jac-ch6", type: "konsep", furi: "GXがただくたいるちゅうてつかん", jp: "GX形ダクタイル鋳鉄管", id_text: "Pipa ductile iron GX — tahan gempa besar", desc: "Jenis ダクタイル鋳鉄管 paling umum di Jepang; sambungannya memiliki fungsi伸縮 (tegang-susut) dan anti-lepas (離脱防止) sehingga tahan pergeseran tanah saat gempa. Mandor:「GX形を使って接合して」(sambung pakai pipa GX型)." },
  { id: 536, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ろっくりんぐ / ろっくりんぐほるだあ", jp: "ロックリング / ロックリングホルダ", id_text: "Lock ring & holder — anti-lepas pipa GX ductile", desc: "Saat pipa memanjang maksimum, tonjolan dalam pipa tertahan lock ring sehingga tidak bisa terlepas. Di proyek: wajib dicek posisinya visual dan tangan sebelum pemasangan." },
  { id: 537, category: "haikan", source: "jac-ch6", type: "konsep", furi: "かつざい", jp: "滑剤（かつざい）", id_text: "Pelumas khusus pemasangan pipa ductile iron GX", desc: "Dioleskan pada bagian dalam taper ゴム輪 dan permukaan luar ujung pipa dari garis putih ke ujungnya; jangan dioleskan ke dalam 受口 sebelum ゴム輪 dipasang." },
  { id: 538, category: "haikan", source: "jac-ch6", type: "konsep", furi: "EFせつごう（えれくとろふゅうじょん）", jp: "EF接合（エレクトロフュージョン）", id_text: "Sambungan electrofusion (EF) pipa polietilen", desc: "Kawat pemanas tertanam dalam fitting EF; setelah pipa dimasukkan dan diklem, controller dialirkan arus untuk melelehkan dan menyatukan resin." },
  { id: 539, category: "haikan", source: "jac-ch6", type: "konsep", furi: "EFせつごうのななめせつだんきょようげんど", jp: "EF接合の斜め切断許容限度", id_text: "Toleransi kemiringan potong pipa EF joint: ≤5 mm", desc: "Saat memotong pipa polietilen untuk EF接合, toleransi kemiringan potongan adalah 5 mm ke semua arah, tidak peduli ukuran pipa. Di proyek: gunakan alat potong mekanis." },
  { id: 540, category: "anzen", source: "jac-ch6", type: "konsep", furi: "こうそくといしたいぷのせつだんこうぐ", jp: "高速砥石タイプの切断工具", id_text: "DILARANG: pakai grinder potong pipa polietilen", desc: "Panas dari grinder dapat mendistorsi permukaan potongan pipa polietilen yang dipakai untuk EF接合. Di proyek: gunakan alat potong mekanis atau hand saw." },
  { id: 541, category: "anzen", source: "jac-ch6", type: "konsep", furi: "ちかまいせつぶつひょうじしいとのいろこおど", jp: "地下埋設物表示シートの色コード", id_text: "Kode warna lembar penanda utilitas bawah tanah", desc: "Dipasang antara utilitas dan permukaan tanah sebagai peringatan saat penggalian. Kode warna: 通信=赤, 高低圧電力=橙, 水道=青, 下水道=茶, ガス=緑. Mandor:「掘削前に埋設物表示シートを確認して」(cek lembar penanda sebelum gali)." },
  { id: 542, category: "anzen", source: "jac-ch6", type: "konsep", furi: "きそんまいせつかんしゅうへんごじゅっせんちいないはじんりきくっさく", jp: "既存埋設管周辺50cm以内は人力掘削", id_text: "Radius 50 cm dari utilitas bawah tanah: wajib", desc: "Dalam radius 50 cm dari utilitas yang sudah ada wajib beralih ke penggalian manual (人力). Kecelakaan oleh backhoe menyumbang lebih dari separuh insiden pemutusan utilitas." },
  { id: 543, category: "anzen", source: "jac-ch6", type: "konsep", furi: "さんそけつぼうきけんさぎょうしゅにんしゃ", jp: "酸素欠乏危険作業主任者", id_text: "Kepala kerja area rendah oksigen — wajib masuk", desc: "Yang boleh masuk manhole hanya pemegang 第一/二種酸素欠乏危険作業主任者技能講習 atau lulusan pendidikan khusus. Di proyek: O₂ harus ≥18%, H₂S ≤10 ppm setelah ventilasi. Mandor:「酸素濃度を計測してから入って」(ukur kadar oksigen dulu)." },
  { id: 544, category: "anzen", source: "jac-ch6", type: "konsep", furi: "りゅうかすいそのうど", jp: "硫化水素濃度（りゅうかすいそのうど）", id_text: "Batas konsentrasi H₂S di manhole: ≤10 ppm", desc: "Sebelum masuk manhole: O₂ harus ≥18% DAN H₂S ≤10 ppm. Jika ventilasi tidak memungkinkan, wajib pakai 呼吸用保護具. Wajib pakai 墜落制止用器具 meski ketinggian ≤2 m." },
  { id: 545, category: "sekou", source: "jac-ch6", type: "konsep", furi: "けがきはりでばいだ", jp: "ケガキ針 / デバイダ（けがきばり / デバイダ）", id_text: "Jarum garis / jangka — alat marking plat logam", desc: "ケガキ針 = jarum untuk menggambar garis tanda pada plat logam (digunakan bersama penggaris logam); デバイダ = jangka untuk menandai jarak atau radius yang sama. Lakukan marking satu kali semaksimal mungkin." },
  { id: 546, category: "sekou", source: "jac-ch6", type: "konsep", furi: "かなとこじょうばん", jp: "金床（アンビル）/ 定盤（じょうばん）", id_text: "Anvil / surface plate — landasan tekuk plat baja", desc: "Landasan baja keras untuk membengkokkan plat logam; sudut pinggir 定盤 digunakan sebagai tumpuan saat memukul plat dengan 影たがね + ハンマー untuk membentuk sudut yang diperlukan secara bertahap." },
  { id: 547, category: "haikan", source: "jac-ch2", type: "konsep", furi: "あんぐるふらんじこうほう", jp: "アングルフランジ工法（アングルフランジこうほう）", id_text: "Angle flange — sambungan duct kotak kuat", desc: "Sambungan duct kotak menggunakan flange sudut; kekuatan dan kerapatan tinggi, digunakan untuk 排煙ダクト. Mandor:「排煙ダクトはアングルフランジで接続してくれよ」(duct asap sambung pakai angle flange dengan benar)." },
  { id: 548, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ともいたふらんじこうほう", jp: "共板フランジ工法", id_text: "Shared-plate flange duct kotak, non-saluran asap", desc: "Flange dibuat dari bagian duct itu sendiri yang dilipat; empat sudut dikunci dengan klip khusus. Di proyek: lebih mudah dan cepat dari アングルフランジ工法; banyak dipakai untuk duct non-排煙." },
  { id: 549, category: "haikan", source: "jac-ch2", type: "konsep", furi: "すらいどおんふらんじこうほう", jp: "スライドオンフランジ工法", id_text: "Slide-on flange — kekuatan antara 2 metode lain", desc: "Flange siap pakai dimasukkan ke duct, dilas titik, dikencangkan baut + penjepit ラッツ di 4 sudut. Kekuatan antara 共板 dan アングル. Mandor:「四隅のラッツを忘れるな、気密性が落ちるぞ」(jangan lupa ラッツ di 4 sudut)." },
  { id: 550, category: "haikan", source: "jac-ch6", type: "konsep", furi: "まるだくとのふらんじこうほう", jp: "丸ダクトのフランジ工法", id_text: "Duct bulat: 75–100 mm plate flange, ≥200 mm angle", desc: "Sambungan duct spiral: diameter 75–100 mm → 板状プレートフランジ; diameter ≥200 mm → アングルフランジ. Di proyek: pilih sesuai diameter duct yang disambung. Mandor:「径に合わせてフランジを選んで」(pilih flange sesuai diameter)." },
  { id: 551, category: "denki", source: "jac-ch6", type: "konsep", furi: "PAS（こうあつきちゅうかいへいき）", jp: "PAS（高圧気中開閉器）", id_text: "PAS — sakelar udara tegangan tinggi di tiang", desc: "Dipasang di tiang listrik (架空配線); listrik 6600V melewati PAS sebelum masuk ke キュービクル gedung. Di proyek: untuk bekerja aman PAS harus dibuka (開放) terlebih dahulu." },
  { id: 552, category: "denki", source: "jac-ch6", type: "konsep", furi: "きゅうびくる", jp: "キュービクル", id_text: "Kubikl — panel penerima dan penurun tegangan 6600V", desc: "Mengubah tegangan 6600V menjadi 100V/200V; berisi 遮断器 (circuit breaker) dan 断路器 (disconnecting switch). Dipasang di dalam, bawah tanah, atau atap gedung. Wajib停電 saat dikerjakan." },
  { id: 553, category: "denki", source: "jac-ch6", type: "konsep", furi: "かっせん", jp: "活線（かっせん）", id_text: "Live line — jalur listrik masih bertegangan aktif", desc: "Kondisi kabel masih dialiri arus; bekerja pada sisi活線 (一次側) dapat menyebabkan sengatan atau loncatan busur (放電). Di proyek: semua pekerjaan wajib setelah停電 dikonfirmasi." },
  { id: 554, category: "denki", source: "jac-ch6", type: "konsep", furi: "ちらく", jp: "地絡（ちらく）", id_text: "Ground fault — arus bocor ke bumi", desc: "Arus mengalir ke tanah yang seharusnya terisolasi; terjadi misalnya karena polaritas grounding (アース) terpasang terbalik. Berbeda dari 短絡 (id:103) yang terjadi antar kabel bertegangan aktif." },
  { id: 555, category: "denki", source: "jac-ch6", type: "konsep", furi: "ろうでんとろうでんしゃだんき", jp: "漏電（ろうでん）と漏電遮断機（ろうでんしゃだんき）", id_text: "Arus bocor dan pemutus arus bocor (ELCB)", desc: "漏電 = arus mengalir ke jalur yang tidak seharusnya; menyebabkan sengatan dan kebakaran. 漏電遮断機 / 漏電警報器 otomatis memutus atau alarm saat terjadi漏電. Perlu waspada khusus saat renovasi." },
  { id: 556, category: "denki", source: "jac-ch6", type: "konsep", furi: "あっちゃくふりょうはつねつはっか", jp: "圧着不良", id_text: "Crimping buruk → panas berlebih → kebakaran", desc: "発熱・発火（あっちゃくふりょう）。圧着不良 menyebabkan 発熱・発火 (panas berlebih/kebakaran). Wajib crimp tepat di tengah sleeve (スリーブの真ん中) dan gunakan terminal yang sesuai ukuran kabel (許容電流にも注意)." },
  { id: 557, category: "anzen", source: "jac-ch6", type: "konsep", furi: "かくうせんのせつだんじこ", jp: "架空線の切断事故", id_text: "Kecelakaan pemotongan kabel overhead oleh alat", desc: "Terjadi saat boom alat berat, dump truck terangkat, atau saat loading/unloading tidak memperhatikan kabel overhead. Di proyek: pasang ケーブルカバー pada kabel di atas area kerja." },
  { id: 558, category: "anzen", source: "jac-ch6", type: "konsep", furi: "どうろしようきょかしょう", jp: "道路使用許可証", id_text: "Surat izin penggunaan jalan — wajib dibawa", desc: "作業責任者 wajib membawa surat ini; kondisi izin (jam kerja, syarat) harus dipatuhi. Wajib menempatkan 交通整理員, memasang fasilitas keselamatan, dan memastikan pejalan kaki bisa lewat." },
  { id: 559, category: "anzen", source: "jac-ch6", type: "konsep", furi: "かくうせつびのちじょうこう", jp: "架空設備の地上高", id_text: "Ketinggian kabel overhead di atas jalan raya: min", desc: "Untuk keselamatan lalu lintas, tinggi minimum kabel dan perangkat telekomunikasi di tiang di atas jalan raya adalah 5 m dari permukaan jalan. Di proyek: pastikan sebelum instalasi tiang." },
  { id: 560, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "しいしいぼっくす", jp: "C・C・BOX（シーシーボックス）", id_text: "CC-Box — saluran kabel berbentuk U di bawah jalan", desc: "Struktur beton bentuk U ditanam di bawah jalan untuk menampung kabel komunikasi, listrik, dan perangkat manajemen jalan; ditutup dengan penutup (ふた)." },
  { id: 561, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "どかぶり", jp: "土被り（どかぶり）", id_text: "Kedalaman tutup tanah di atas saluran kabel bawah", desc: "Jarak permukaan jalan ke bagian atas saluran (管路); berdasarkan 道路法施行令: di 車道 min 0,8 m, di 歩道 min 0,6 m. Di proyek: wajib dipenuhi saat pemasangan saluran." },
  { id: 562, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "かんろとまいせつぶつのりかくきょり", jp: "管路と埋設物の離隔距離", id_text: "Jarak aman saluran telekomunikasi dari utilitas", desc: "Paralel horizontal: kereta api=1,0 m↑, listrik=0,3 m↑, listrik tegangan sangat tinggi=0,6 m↑, air/gas/lain=0,3 m. Vertikal silang: kereta api=1,5 m↑, listrik/air/gas=0,15 m." },
  { id: 563, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "まんどれるつうかしけん", jp: "マンドレル通過試験", id_text: "Uji mandrel — verifikasi koneksi saluran bawah", desc: "Setelah pemasangan saluran: batang mandrel dimasukkan untuk memastikan saluran terhubung sempurna. Saluran >150 m → No.4 (Ø600 mm); jika tidak bisa lewat → pakai No.3." },
  { id: 564, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "きみつしけん（かんろふせつご）", jp: "気密試験（管路布設後）", id_text: "Uji kerapatan saluran: 49 kPa, 3 menit, ≤1,96 kPa", desc: "Setelah pemasangan saluran: tekanan dinaikkan ke 49 kPa, dibiarkan 3 menit; penurunan tekanan harus ≤1,96 kPa untuk lulus. Di proyek: dicatat dalam lembar inspeksi." },
  { id: 565, category: "setsubi_kougu", source: "jac-ch6", type: "konsep", furi: "たいかれんが / たいかだんねつれんが", jp: "耐火煉瓦 / 耐火断熱煉瓦", id_text: "Bata tahan api / bata insulasi tahan api", desc: "Dua jenis bata untuk築炉工事; perekatnya adalah mortar khusus tahan panas (耐熱断熱煉瓦用モルタル), bukan mortar biasa. Di proyek: digunakan untuk membangun tungku industri." },
  { id: 566, category: "setsubi_kougu", source: "jac-ch6", type: "konsep", furi: "ねっこうせいもるたる vs きこうせいもるたる", jp: "熱硬性モルタル vs 気硬性モルタル", id_text: "Mortar tahan api: mengeras panas vs mengeras udara", desc: "熱硬性モルタル = mengeras saat dipanaskan suhu tinggi; 気硬性モルタル = mengeras pada suhu ruangan di udara biasa. Keduanya perekat bata tahan api dalam築炉工事. Mandor:「熱硬性モルタルを使って積んで」(pakai mortar tahan panas)." },
  { id: 567, category: "setsubi_kougu", source: "jac-ch6", type: "konsep", furi: "れんがずみのろくげんそく", jp: "煉瓦積みの6原則", id_text: "6 aturan mutlak penyusunan bata tahan api", desc: "①Material benar. ②Dimensi tepat. ③Mortar merata. ④Pasangan selang-seling wajib. ⑤Bata ≤1/4 panjang tidak digunakan. ⑥Selalu horizontal & vertikal. Di proyek: langkah ④ sering dilupakan." },
  { id: 568, category: "shoubou", source: "jac-ch6", type: "konsep", furi: "こすいそうち", jp: "呼水装置（こすいそうち）", id_text: "Priming device — isi awal pompa pemadam kebakaran", desc: "Memastikan pompa pemadam terisi air sebelum beroperasi; wajib dipasang jika sumber air (水源) lebih rendah dari pompa. Tanpa ini pompa berputar kosong dan gagal memompa." },
  { id: 569, category: "shoubou", source: "jac-ch6", type: "konsep", furi: "すいおんじょうしょうぼうしようにがしはいかん", jp: "水温上昇防止用逃がし配管", id_text: "Pipa bypass pompa pemadam — cegah overheat", desc: "Mencegah pompa overheat saat berputar tanpa memompa air (sisi keluar tertutup); tanpa pipa ini pompa berhenti karena kepanasan dan tidak bisa memadamkan api." },
  { id: 570, category: "shoubou", source: "jac-ch6", type: "konsep", furi: "せいのうしけんそうちしょうぼうぽんぷ", jp: "性能試験装置（せいのうしけんそうち）", id_text: "Alat uji performa pompa pemadam kebakaran", desc: "消防ポンプ。Dipasang untuk memverifikasi bahwa pompa bekerja sesuai kapasitas yang ditetapkan (定められた通りの能力). Satu dari tiga perangkat khusus pompa pemadam (bersama呼水装置 dan逃がし配管)." },
  { id: 571, category: "shoubou", source: "jac-ch6", type: "konsep", furi: "ないめんらいにんぐこうかんのしようきんし", jp: "内面ライニング鋼管の使用禁止", id_text: "Pipa baja berlapis dalam DILARANG untuk pipa", desc: "Jika pipa pemadam tanpa air terkena panas api, lapisan lining meleleh dan mengeras sehingga air tidak bisa mengalir. Oleh karena itu pipa berlapis dalam dilarang digunakan untuk sistem pemadam." },
  { id: 572, category: "career", source: "jac-ch1", type: "konsep", furi: "せこうたいせい", jp: "施工体制（せこうたいせい）", id_text: "Struktur manajemen pelaksanaan konstruksi", desc: "Hierarki konstruksi: 発注者→監理者→ゼネコン→専門工事業者→職長→作業員. Proyek besar dipimpin ゼネコン, proyek kecil oleh 工務店. Mandor:「ゼネコンの現場監督の指示に従ってくれよ」(ikuti instruksi site supervisor dari GC)." },
  { id: 573, category: "career", source: "jac-ch1", type: "konsep", furi: "はっちゅうしゃ", jp: "発注者（はっちゅうしゃ）", id_text: "Pihak pemberi order konstruksi (klien)", desc: "Pihak yang memesan pekerjaan konstruksi (klien/owner). Bisa berupa kementerian, pemda, perusahaan swasta, atau perorangan. Mandor:「発注者の要求に応えるのが私たちの仕事だ」(memenuhi kebutuhan klien adalah pekerjaan kita)." },
  { id: 574, category: "career", source: "jac-ch1", type: "konsep", furi: "かんりしゃ", jp: "監理者（かんりしゃ）", id_text: "Pengawas konstruksi — memeriksa kesesuaian gambar", desc: "Teknisi yang memastikan pekerjaan sesuai gambar/blueprint. Posisi terpisah dari 設計者 maupun 現場監督. Mandor:「監理者から指摘があったらすぐ俺に報告してくれ」(ada koreksi dari pengawas, langsung lapor ke saya)." },
  { id: 575, category: "career", source: "jac-ch1", type: "konsep", furi: "せっけいしゃ", jp: "設計者（せっけいしゃ）", id_text: "Perancang / Desainer — membuat dokumen desain", desc: "Teknisi yang membuat dokumen desain untuk mewujudkan permintaan klien. Semua pekerjaan wajib sesuai 設計図書. Mandor:「図面に疑問があったら勝手に変えるな、確認が必要だ」(pertanyaan soal gambar, jangan ubah sendiri)." },
  { id: 576, category: "career", source: "jac-ch1", type: "konsep", furi: "ぜんこん", jp: "ゼネコン（工事全体をまとめる会社）", id_text: "General Contractor — perusahaan pemimpin proyek", desc: "Singkatan General Contractor; mengelola semua 専門工事業者 sebagai 元請け di proyek besar. Mandor:「ゼネコンからの指示は最優先で対応してくれよ」(instruksi dari general contractor diutamakan)." },
  { id: 577, category: "career", source: "jac-ch1", type: "konsep", furi: "げんばかんとく", jp: "現場監督（げんばかんとく）", id_text: "Pengawas lapangan (site supervisor)", desc: "Teknisi yang mengawasi pekerjaan di lokasi konstruksi. Berkoordinasi dengan 職長 yang meneruskan instruksi ke 技能者. Mandor:「今日の指示は朝のミーティングでもらうぞ」(instruksi hari ini dari site supervisor setiap pagi)." },
  { id: 578, category: "career", source: "jac-ch1", type: "konsep", furi: "せんもんこうじぎょうしゃ", jp: "専門工事業者（せんもんこうじぎょうしゃ）", id_text: "Kontraktor spesialis per jenis pekerjaan", desc: "Kontraktor spesialis yang menerima subkontrak dari ゼネコン. Contoh: 鉄筋工事, 型枠工事, とび工事. Mandor:「うちは配管専門だ、他の工事に口を出すな」(kita spesialis pipa, jangan ikut campur pekerjaan lain)." },
  { id: 579, category: "career", source: "jac-ch1", type: "konsep", furi: "しょくちょう", jp: "職長（しょくちょう）", id_text: "Mandor / Foreman — pemimpin langsung pekerja", desc: "Pemimpin langsung pekerja; menerima instruksi dari 現場監督 dan meneruskan ke 技能者. CCUS Lv3=シルバー setara 職長. Mandor:「作業中に疑問があれば、まず俺に聞けよ」(ada pertanyaan saat kerja, tanya ke saya dulu)." },
  { id: 580, category: "career", source: "jac-ch1", type: "konsep", furi: "ぎのうしゃ", jp: "技能者（ぎのうしゃ）", id_text: "Pekerja terampil / Skilled worker", desc: "Pekerja yang memiliki keahlian teknis di bidang konstruksi. CCUS Lv1=初級, Lv2=一人前, Lv3=職長級, Lv4=マネジメント. Mandor:「CCUSのレベルを上げたいなら資格を取れよ」(mau naik level CCUS, ambil sertifikat adalah cara terbaik)." },
  { id: 581, category: "career", source: "jac-ch1", type: "konsep", furi: "せしゅ", jp: "施主（せしゅ）", id_text: "Pemilik bangunan / klien pada proyek kecil", desc: "Pihak yang memesan bangunan untuk dibangun; istilah khas proyek kecil seperti rumah tinggal. Di proyek besar disebut 発注者. Mandor:「施主さんの要望を最優先に作業してくれよ」(utamakan keinginan pemilik rumah)." },
  { id: 582, category: "career", source: "jac-ch1", type: "konsep", furi: "こうむてん", jp: "工務店（こうむてん）", id_text: "Kontraktor lokal kecil untuk proyek rumah tinggal", desc: "Kontraktor kecil untuk proyek rumah tinggal, bertindak sebagai 元請け dari 施主. Mengelola berbagai 専門工事業者. Mandor:「近隣への挨拶も大事な仕事だ、忘れるな」(menyapa tetangga sekitar juga bagian dari pekerjaan kita)." },
  { id: 583, category: "career", source: "jac-ch1", type: "konsep", furi: "もとうけ", jp: "元請け（もとうけ）", id_text: "Kontraktor utama (prime contractor)", desc: "Pihak yang menerima kontrak langsung dari klien lalu memberi subkontrak ke spesialis. Proyek besar=ゼネコン, proyek kecil=工務店. Mandor:「元請けから指示が来たら最優先で動けよ」(instruksi dari kontraktor utama, gerak cepat)." },
  { id: 584, category: "career", source: "jac-ch1", type: "konsep", furi: "CCUSひょうかのさんきじゅん", jp: "CCUS評価の3基準", id_text: "3 kriteria CCUS: pengalaman/sertifikat/manajerial", desc: "Tiga kriteria evaluasi CCUS: ①hari kerja tercatat ②lisensi/sertifikat ③kemampuan manajerial. Level 2 butuh ≥645 hari. Mandor:「経験と資格を積んでCCUSレベルを上げろよ」(akumulasikan pengalaman dan sertifikat)." },
  { id: 585, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "しんきにゅうじょうしゃ", jp: "新規入場者（しんきにゅうじょうしゃ）", id_text: "Pekerja baru yang pertama masuk lokasi konstruksi", desc: "Pekerja yang baru pertama kali masuk lokasi konstruksi tertentu. Saat 全体朝礼 wajib sebut nama dan perusahaan dengan suara keras. Mandor:「名前と会社を大声で言えよ」(ucapkan nama dan perusahaan dengan keras di apel)." },
  { id: 586, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "あんぜんしょうわたちあんどこおる", jp: "安全唱和・タッチアンドコール（あんぜんしょうわ）", id_text: "Seruan keselamatan bersama + Touch-and-Call", desc: "Seruan keselamatan dan tumpuk tangan bersama di apel per jenis pekerjaan. Semua anggota menunjuk dan berseru untuk bangun kesatuan. Mandor:「全員で指差しして、ゼロ災で行こう、ヨシ！と言えよ」(semua tunjuk dan berseru bersama)." },
  { id: 587, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "ぜろさいでいこうよし", jp: "ゼロ災で行こう、ヨシ！！", id_text: "\"Zero kecelakaan, maju! Oke!!\" — slogan apel K3", desc: "Slogan 安全唱和 yang diucapkan sambil 指さし saat apel per jenis pekerjaan. Diakhiri seruan keras ヨシ!! untuk membangun kesatuan tim. Mandor:「全員で声を合わせて、ゼロ災で行こう、ヨシ！！」(serentak berseru bersama)." },
  { id: 588, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "かつどうすてっぷ", jp: "KY活動の4ステップ", id_text: "4 langkah KY: bahaya → solusi → target → serukan", desc: "4 langkah KY活動: ①identifikasi bahaya ②diskusi solusi (catat di KYボード) ③tetapkan target ④指差呼称 bersama \"○○○、ヨシ！\". Mandor:「KY活動は4ステップちゃんとやってくれよ」(lakukan KY活動 lengkap 4 langkah)." },
  { id: 589, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "ぼおどきけんよちかつどうひょう", jp: "KYボード（危険予知活動表）", id_text: "Formulir KY — lembar kegiatan prediksi bahaya", desc: "Formulir yang diisi saat KY活動: kolom titik bahaya dan solusi tim. Semua anggota 指差呼称 ke papan ini sambil berseru \"○○○、ヨシ！\". Mandor:「KYボードはちゃんと記入してから貼り出せよ」(isi KY board dengan benar sebelum dipasang)." },
  { id: 590, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "ぜんたいちょれいのこうもく", jp: "全体朝礼の6項目", id_text: "6 agenda apel pagi umum", desc: "Apel umum dengan 6 agenda: sapaan, senam radio, konfirmasi kerja, KY, cek keselamatan berpasangan, lalu \"ご安全に!\". Dipimpin 現場監督. Mandor:「全体朝礼は全員参加が基本だぞ」(apel pagi wajib dihadiri semua)." },
  { id: 591, category: "gaiyou", source: "jac-ch1", type: "konsep", furi: "あんぜんかくにんこうもく", jp: "安全確認の8項目", id_text: "8 item cek keselamatan berpasangan di akhir apel", desc: "Di akhir 全体朝礼, 2人1組 sambil bersuara: kanan/kiri/depan/belakang/atas/bawah/tali helm/seragam+nama. Mandor:「二人一組で確認し合うのが決まりだぞ」(konfirmasi berpasangan adalah aturannya)." },
  { id: 592, category: "career", source: "jac-ch1", type: "konsep", furi: "いったいかん", jp: "一体感（いったいかん）", id_text: "Rasa kesatuan tim di lokasi konstruksi", desc: "Rasa kesatuan yang terbentuk dari pekerja berbagai bidang yang bekerja sama. Dibangun melalui sapaan, apel, dan seruan keselamatan. Mandor:「現場はチームワークが大事だ、他の職種にも挨拶しろよ」(sapa juga pekerja bidang lain)." },
  { id: 593, category: "anzen", source: "jac-ch7", type: "konsep", furi: "てんとう", jp: "転倒（てんとう）", id_text: "Tersandung / Kehilangan keseimbangan di lantai", desc: "Jenis kecelakaan kerja: benda menghalangi → tersandung, atau kehilangan keseimbangan → jatuh di permukaan yang sama. Berbeda dari 墜落・転落 (jatuh dari ketinggian)." },
  { id: 594, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ひらいらっか", jp: "飛来・落下（ひらい・らっか）", id_text: "Benda melayang / jatuh menimpa pekerja dari atas", desc: "Jenis kecelakaan: material terlepas dari crane atau benda jatuh dari ketinggian menimpa pekerja. Penyebab: 玉掛け tidak sempurna, beban crane bergoyang." },
  { id: 595, category: "anzen", source: "jac-ch7", type: "konsep", furi: "げきとつされはさまれまきこまれ", jp: "激突され（げきとつされ）/ はさまれ・巻き込まれ", id_text: "Tertabrak alat berat / Terjepit atau terseret", desc: "激突され = tertabrak keras kendaraan berat atau bucket crane saat berputar (旋回中). はさまれ・巻き込まれ = terjepit antara mesin/material, atau terseret ke dalam bagian mesin. Keduanya banyak dalam 建設機械・クレーン災害." },
  { id: 596, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ゆうがいぶつせっしょく / おぼれる / かさい", jp: "有害物接触 / おぼれ / 火災", id_text: "Kontak bahan berbahaya / Tenggelam / Kebakaran", desc: "有害物との接触: zat kimia menyentuh kulit → gangguan kesehatan. おぼれ: jatuh ke saluran air saat 下水道工事 → tenggelam. 火災: kebakaran di lokasi konstruksi → terjebak asap/api. Ketiganya kecelakaan fatal." },
  { id: 597, category: "anzen", source: "jac-ch7", type: "konsep", furi: "たまがけ", jp: "玉掛け（たまがけ）", id_text: "Pengikatan beban crane (rigging/slinging)", desc: "Teknik mengikat material ke kait crane dengan wire rope atau sling sebelum diangkat. 玉掛けが不十分 → beban terlepas saat diangkat → 飛来・落下 fatal. Operator wajib punya sertifikat (技能講習 atau 特別教育)." },
  { id: 598, category: "anzen", source: "jac-ch7", type: "konsep", furi: "どどめくっさくふかさいじょうでげんそくひつよう", jp: "土留め（どどめ）", id_text: "Penahan tanah — wajib jika galian kedalaman ≥1.5m", desc: "Saat menggali parit untuk pipa (掘削工事), tanah bisa longsor menimbun pekerja. Jika kedalaman ≥1.5m: wajib gunakan 土留め, umumnya dengan 鋼矢板 (steel sheet pile). Mandor:「1." },
  { id: 599, category: "anzen", source: "jac-ch7", type: "konsep", furi: "こうやいた", jp: "鋼矢板（こうやいた）", id_text: "Sheet pile baja — material penahan tanah galian", desc: "土留めの代表材料。Lembaran baja yang dipancang vertikal di sisi galian untuk mencegah longsor tanah (崩壊). Metode utama 土留め pada galian dalam (≥1.5m) seperti pekerjaan pipa bawah tanah (管布設工事)." },
  { id: 600, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ほあんせつびゆどういん", jp: "保安設備・誘導員（ほあんせつび・ゆうどういん）", id_text: "Pengaman & pemandu lalu lintas — wajib kerja di", desc: "Saat bekerja di jalan umum (公道上): wajib pasang 囲い, 柵, ガード untuk cegah kendaraan masuk. Wajib tempatkan 誘導員 (traffic guide). Pekerja dilarang bekerja di luar 作業範囲 yang ditentukan." },
  { id: 601, category: "anzen", source: "jac-ch7", type: "konsep", furi: "きいろっくほうしきろおぷ", jp: "キーロック方式ロープ（移動用ロープの安全機構）", id_text: "Key-lock rope — tali lama tak bisa dilepas", desc: "Sistem keselamatan フルハーネス: melepas tali paling sering terjadi saat pindah titik. キーロック方式 = tali lama TIDAK BISA dilepas sebelum tali baru terpasang di titik berikutnya → mencegah jeda tanpa pengaman." },
  { id: 602, category: "anzen", source: "jac-ch7", type: "konsep", furi: "あんぜんせこうさいくるのすてっぷ", jp: "安全施工サイクルの8ステップ", id_text: "8 langkah siklus keselamatan harian konstruksi", desc: "①Apel pagi ②Safety meeting (KY, orientasi baru) ③Cek mesin & alat sebelum mulai ④Pengawasan saat bekerja ⑤Ronda keselamatan ⑥Koordinasi jadwal besok ⑦Bersih-bersih ⑧Cek kebakaran & bahaya saat tutup." },
  { id: 603, category: "anzen", source: "jac-ch7", type: "konsep", furi: "しんにゅうしゃあんぜんえいせいきょういくのはちこうもく", jp: "新入者安全衛生教育の8項目", id_text: "8 materi K3 wajib untuk rekrutan baru perusahaan", desc: "①Bahaya mesin & bahan ②APD & alat keselamatan ③Prosedur kerja ④Cek awal sebelum bekerja ⑤Penyakit akibat kerja ⑥Kebersihan & kerapian ⑦Tindakan darurat & evakuasi ⑧Materi K3 lainnya." },
  { id: 604, category: "anzen", source: "jac-ch7", type: "konsep", furi: "しんきにゅうじょうしゃきょういくしぼうのはんぶんがにゅうじょうしゅうかんいないじっしぷん", jp: "新規入場者教育", id_text: "Orientasi pekerja baru lokasi: 50% meninggal", desc: "死亡の半数が入場1週間以内。Kematian di lokasi konstruksi: separuhnya terjadi dalam 1 minggu pertama → maka 新規入場者教育 diwajibkan. Dilaksanakan oleh 職長 hari pertama masuk, durasi ±30 menit." },
  { id: 605, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ふるはあねすぎむたかさ", jp: "フルハーネス義務高さ", id_text: "Wajib full harness: >6.75m umum / >5m konstruksi", desc: "2022年1月施行: ketinggian >6.75m → semua sektor wajib full harness. Konstruksi lebih ketat: >5m sudah wajib karena risiko tinggi. Di proyek: pakai meskipun merasa tidak perlu." },
  { id: 606, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ほごめがね", jp: "保護メガネ（ほごめがね）", id_text: "Kacamata pelindung dari debu, percikan, dan sinar", desc: "Melindungi mata dari: debu logam/kayu (粉じん), percikan api las (火花), panas & asap, sinar laser/UV (有害光線). Di proyek: pilih jenis sesuai bahaya pekerjaan." },
  { id: 607, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ほごますくじんぱい", jp: "保護マスク・じん肺（ほごますく・じんぱい）", id_text: "Masker debu — cegah penyakit paru-paru (jinpai)", desc: "じん肺 = kerusakan paru akibat debu logam/batu jangka panjang saat las busur atau potong batu. Masker tersedia: 使い捨て式 dan フィルタ取換え式. Di proyek: wajib dipakai." },
  { id: 608, category: "anzen", source: "jac-ch7", type: "konsep", furi: "てぶくろきんしかいてんするはものしようじ", jp: "手袋（軍手）禁止", id_text: "DILARANG sarung tangan saat alat potong berputar", desc: "丸のこ, ボール盤, パイプねじ切機 dan alat berputar lain → sarung tangan (軍手) bisa tersangkut mata pisau → kecelakaan serius. Sarung tangan BOLEH untuk las, kimia, potong manual." },
  { id: 609, category: "anzen", source: "jac-ch7", type: "konsep", furi: "しいるどめんつきへるめっと / あんぜんぐつ", jp: "シールド面付きヘルメット / 安全靴", id_text: "Helm pelindung wajah (untuk las) / Sepatu safety", desc: "シールド面付きヘルメット = helm dengan pelindung wajah penuh untuk pekerjaan las — melindungi dari percikan api dan UV. 安全靴 = sepatu pelindung keras, perlengkapan dasar wajib semua lokasi." },
  { id: 610, category: "anzen", source: "jac-ch7", type: "konsep", furi: "あつさしすうまなつびもうしょび", jp: "WBGT（暑さ指数）・真夏日・猛暑日", id_text: "WBGT / Hari panas 30℃+ / Hari terik 35℃+", desc: "WBGT = indeks risiko 熱中症 dari 気象庁. 真夏日 = >30℃, 猛暑日 = >35℃. Di proyek: pasang kipas besar, jaring pelindung, mist, sediakan tempat istirahat ber-AC. Pada 猛暑日 bisa ubah jam kerja." },
  { id: 611, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ねちゅうしょうのしょうじょう", jp: "熱中症の症状（ねっちゅうしょうのしょうじょう）", id_text: "Gejala heatstroke — dari pusing hingga fatal", desc: "Bertahap: ①pusing/pingsan ②nyeri & kram otot ③keringat berlebih ④sakit kepala, mual, muntah ⑤gangguan kesadaran & kejang ⑥suhu tinggi → meninggal." },
  { id: 612, category: "anzen", source: "jac-ch7", type: "konsep", furi: "みどりじゅうじ / あんぜんえいせいき / きゅうきゅうばこ", jp: "緑十字 / 安全衛生旗 / 救急箱", id_text: "Palang Hijau / Bendera K3 / Kotak P3K", desc: "緑十字 (palang hijau di latar putih) = simbol K3, dipasang di helm dan 救急箱. 安全衛生旗 = gabungan 緑十字 (安全) + 白十字 (衛生), dikibarkan di lokasi. Di proyek: 救急箱 wajib tersedia berisi obat & alat P3K." },
  { id: 613, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ひゅうまんえらあしゅるい", jp: "ヒューマンエラー（12種類の概要）", id_text: "Human Error — 12 jenis penyebab kecelakaan manusia", desc: "Kesalahan manusia yang menyebabkan kecelakaan, penurunan kualitas, dan keterlambatan. 12 jenis: ①認知ミス ②不注意 ③意識低下 ④経験不足 ⑤慣れ手抜き ⑥集団欠陥 ⑦近道行動 ⑧連絡不足 ⑨場面本能 ⑩パニック ⑪心身低下 ⑫疲労." },
  { id: 614, category: "anzen", source: "jac-ch7", type: "konsep", furi: "はにんちみすふちゅういちゅういていか", jp: "ヒューマンエラー①〜③：認知ミス・不注意・注意低下", id_text: "HA 1–3: salah tangkap / kurang waspada / otomatis", desc: "①認知ミス = asumsi salah → salah baca instruksi. ②不注意 = terlalu fokus 1 hal → tidak waspada → jatuh ke lubang. ③注意低下 = pekerjaan monoton → bergerak tanpa berpikir (無意識の動作) → lalai tanpa sadar." },
  { id: 615, category: "anzen", source: "jac-ch7", type: "konsep", furi: "はけいけんぶそくなれによるてぬき", jp: "ヒューマンエラー④〜⑤：経験不足・慣れによる手抜き", id_text: "HA 4–5: kurang pengalaman / terbiasa → potong", desc: "④経験・知識不足 = tidak tahu cara benar gunakan alat, tidak bisa prediksi bahaya; KY活動 membantu belajar dari senior. ⑤慣れによる手抜き = makin terbiasa → skip prosedur. Kecelakaan sering saat hati mulai 緩む (lengah)." },
  { id: 616, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ひゅうまんえらあろくからはち", jp: "ヒューマンエラー⑥〜⑧", id_text: "HA 6–8: tekanan kelompok / shortcut / salah", desc: "⑥集団欠陥 = deadline menciptakan tekanan ambil jalan tidak aman — keselamatan tetap prioritas. ⑦近道行動 = demi efisiensi → skip langkah prosedur. ⑧連絡不足 = instruksi tidak jelas → pekerja bertindak salah." },
  { id: 617, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ひゅうまんえらあきゅうからじゅうに", jp: "ヒューマンエラー⑨〜⑫", id_text: "HA 9–12: refleks bahaya / panik / fisik menurun /", desc: "⑨場面本能 = refleks selamatkan diri → melempar alat → mengenai orang. ⑩パニック = terkejut → tindakan tidak aman. ⑪心身低下 = penuaan → fisik & penglihatan menurun tanpa disadari. ⑫疲労 = lelah → konsentrasi turun." },
  { id: 618, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ぱわあはらすめんとぼうしほうろうどうしさくそうごうすいしんほう", jp: "パワハラ防止法", id_text: "UU Anti-Harassment: kewajiban buat kebijakan", desc: "UU yang mewajibkan perusahaan buat kebijakan anti-パワハラ dan sediakan loket konsultasi. Berbeda dari sekedar definisi パワハラ. Mandor:「困ったら相談窓口を使えよ、会社が対処する」(kalau ada masalah, gunakan loket konsultasi)." },
  { id: 619, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ねんじゆうきゅうきゅうかのふよてえぶる", jp: "年次有給休暇の付与テーブル", id_text: "Tabel cuti: syarat 6 bln kerja + hadir ≥80%", desc: "Syarat: kerja ≥6 bulan + hadir ≥80%. Tabel: 0.5th→10hr, 1.5th→11hr ... ≥6.5th→20hr (maks). Diatur 労働基準法. Mandor:「6ヶ月経ったら有給が10日使えるぞ」(setelah 6 bulan, bisa pakai 10 hari cuti berbayar)." },
  { id: 620, category: "hourei", source: "jac-ch2", type: "hukum", furi: "あんぜんえいせいきょういくのとりがあやといいれじさぎょうないようへんこうじ", jp: "安全衛生教育の2トリガー", id_text: "2 wajib K3: saat rekrut + ganti isi pekerjaan", desc: "Pendidikan K3 wajib dua kali: ①saat rekrut baru ②saat isi pekerjaan berubah. Pekerjaan khusus butuh pelatihan tambahan. Mandor:「作業内容が変わったらK3教育をするぞ」(isi pekerjaan berubah, wajib pendidikan K3 dulu)." },
  { id: 621, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ろうどうしゃのせきむろうどうあんぜんえいせいほう", jp: "労働者の責務（ろうどうしゃのせきむ）", id_text: "Kewajiban PEKERJA menurut UU K3", desc: "UU K3 tidak hanya mengatur pengusaha — pekerja juga wajib mematuhi aturan K3. Mengabaikan APD pun bisa dipersalahkan. Mandor:「安全ルールを守るのは労働者の義務でもあるんだ」(mematuhi K3 adalah kewajiban pekerja juga)." },
  { id: 622, category: "anzen", source: "jac-ch2", type: "konsep", furi: "あんぜんきあんぜんえいせいき", jp: "安全旗 vs 安全衛生旗", id_text: "Bendera Keselamatan vs Bendera K3 — beda tujuan", desc: "安全旗: simbol 安全週間, dikibarkan hanya selama periode tersebut. 安全衛生旗: simbol K3 terpadu, dikibarkan permanen di lokasi. Mandor:「安全衛生旗は常に掲げておくものだよ」(安全衛生旗 harus selalu berkibar di lokasi kerja)." },
  { id: 623, category: "anzen", source: "jac-ch2", type: "konsep", furi: "ろうさいしぼうげにんらんきんぐいれいわねんどけんせつぎょう", jp: "労災死亡原因ランキング5位（令和3年度・建設業）", id_text: "Top 5 penyebab kematian konstruksi 2021 + angka", desc: "令和3年度 288 kematian konstruksi: ①墜落転落=110件 ②崩壊倒壊=31件 ③はさまれ=27件 ④交通事故=25件 ⑤激突され=19件. Dasar kewajiban フルハーネス. Mandor:「墜落が一番多い、高所は絶対フルハーネスを使えよ」(di ketinggian wajib full harness)." },
  { id: 624, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんせつぎょうほうのいつつのもくてき", jp: "建設業法の5つの目的", id_text: "5 tujuan UU Industri Konstruksi", desc: "5 tujuan 建設業法: ①kualitas usaha ②kontrak layak ③pelaksanaan tepat ④perlindungan pemesan ⑤pengembangan industri. Mandor:「建設業法は俺たちを守るためにある」(UU Konstruksi ada untuk melindungi kita)." },
  { id: 625, category: "hourei", source: "jac-ch2", type: "hukum", furi: "けんちくきじゅんほうたんたいきていしゅうだんきてい", jp: "建築基準法：単体 vs 集団規定", id_text: "UU Bangunan: peraturan individu vs kawasan kota", desc: "単体規定: standar bangunan itu sendiri (keselamatan, tahan gempa, dll). 集団規定: standar kawasan perkotaan (KDB, KLB, tinggi). Mandor:「建ぺい率と容積率は図面で確認してくれよ」(KDB dan KLB wajib dicek di gambar)." },
  { id: 626, category: "hourei", source: "jac-ch2", type: "hukum", furi: "はいきぶものしょりほうさんぎょうはいきぶものしゅうりょううんぱんきょかもとうけしたうけせきにんぶんたん", jp: "廃棄物処理法：産廃と責任分担", id_text: "UU Limbah: izin angkut + tanggung jawab kontraktor", desc: "Pengangkutan limbah industri butuh izin resmi. Kontraktor utama wajib buat manifest; sub-kontraktor bertanggung jawab penyimpanan. Mandor:「産廃は許可業者しか運べない、分別して保管して」(simpan sesuai jenis)." },
  { id: 627, category: "hourei", source: "jac-ch2", type: "hukum", furi: "げすいどうほうきんしはいすいのりゆうこうじげんばのはいすいしゅるい", jp: "下水道法：禁止排水の6理由 + 工事現場の排水種類", id_text: "UU Saluran Pembuangan: 6 larangan buang", desc: "6 alasan larangan buang ke saluran: merusak pipa, gas beracun, sumbat pipa, bahaya pekerja, ganggu pengolahan, sulit olah lumpur. Air beton wajib dinetralkan. Mandor:「コンクリートの排水は中和処理してから流してくれよ」." },
  { id: 628, category: "sekou", source: "jac-ch3", type: "konsep", furi: "けんせつこうじのさんだいぶんるい", jp: "建設工事の3大分類", id_text: "3 kategori besar pekerjaan konstruksi", desc: "①土木=alam: dam, jalan, terowongan, jembatan. ②建築=gedung: rumah, RS, sekolah. ③ライフライン・設備=infrastruktur: listrik, gas, air, AC, pemadam. Mandor:「土木か建築か、まず確認して」(konfirmasi jenis pekerjaan)." },
  { id: 629, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "だむこうじちすいりすい", jp: "ダム工事の目的：治水 vs 利水", id_text: "Tujuan bendungan: tahan banjir vs manfaatkan air", desc: "治水=tahan banjir: tampung air saat hujan besar, atur debit. 利水=manfaatkan air stabil untuk pertanian, industri, 水力発電. Jepang punya 3000+ bendungan. Mandor:「洪水吐きゲートの点検して」(cek pintu spillway bendungan)." },
  { id: 630, category: "doboku_doko", source: "jac-ch6", type: "konsep", furi: "とんねるのよんしゅるいこうほうでぶんるい", jp: "トンネルの4種類（工法で分類）", id_text: "4 jenis terowongan berdasarkan metode konstruksi", desc: "①山岳トンネル = NATM di batu keras gunung. ②開削トンネル = gali dari permukaan → bangun → timbun. ③シールドトンネル = mesin shield + segmen panel, tanah lunak. ④推進トンネル = pipa ditekan masuk tanah via dongkrak dari立坑." },
  { id: 631, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "なこうほうさんがくとんねるさんようそ", jp: "NATM工法（山岳トンネル）", id_text: "Metode NATM terowongan gunung — 3 elemen penyangga", desc: "NATM: gali gunung dengan peledakan/mesin. 3 penyangga: ①吹付けコンクリート=semprot beton ②鋼製支保工=rangka baja ③ロックボルト=baut pengikat batu. Mandor:「吹付け後にボルト打って」(pasang baut setelah semprot beton)." },
  { id: 632, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "しいるどとんねるこうほうたてこうせぐめんと", jp: "シールドトンネル工法（立坑・セグメント）", id_text: "Terowongan shield: tanah lunak & bawah bangunan", desc: "Prosedur: ①Bangun 立坑(poros vertikal) ②Shield menggali ③Pasang セグメント(panel beton/besi) di belakang mesin. Mandor:「セグメント組み立て確認して」(cek pemasangan segmen)." },
  { id: 633, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "きょうりょうこうじしゅるいとかぶこうじょうぶこう", jp: "橋梁工事：種類と下部工・上部工", id_text: "Pekerjaan jembatan: 6 jenis + 2 tahapan utama", desc: "Jenis: 桁橋・トラス・アーチ・ラーメン・斜張橋・吊橋. 下部工=fondasi penopang → 上部工=badan jembatan. Metode: ベント, ケーブルエレクション, 送り出し, フローティングクレーン. Mandor:「下部工の出来形検査入ります」(inspeksi fondasi jembatan)." },
  { id: 634, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "かいよどぼくこうじのとくちょとしゅよしせつ", jp: "海洋土木工事の特徴と主要施設", id_text: "Pekerjaan sipil laut: fasilitas & alat kerja utama", desc: "Bangun di laut/sungai: pelabuhan, bandara laut, jembatan laut, terowongan bawah laut. Alat: ①作業船=kapal kerja ②潜水士=penyelam ③alat ukur batimetri. Mandor:「作業船の位置確認してから開始して」(cek posisi kapal kerja)." },
  { id: 635, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくぶつのこうぞうごしゅるい", jp: "建築物の構造5種類", id_text: "5 jenis struktur bangunan dan karakteristiknya", desc: "RC造=tulangan+beton. S造=baja, untuk pabrik/komersial. SRC造=baja+RC, gedung tinggi. 木造=kayu, rumah biasa. CB造=blok beton+tulangan+mortar. Mandor:「ここはRC造、型枠と鉄筋の確認して」(cek bekisting dan tulangan RC)." },
  { id: 636, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくこうじのながれだいきぼびる", jp: "建築工事の流れ（大規模ビル・マンション）", id_text: "Urutan tahapan konstruksi gedung besar", desc: "①準備: pagar+borlog ②山留め: dinding cegah longsor ③杭: pancang ke支持層 ④土工: gali+残土 ⑤地下躯体: tulangan+cor ⑥地上躯体: baja+crane ⑦仕上げ: finishing. Mandor:「次は山留め確認からだ」(cek dinding penahan dulu)." },
  { id: 637, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "たいしんせいしんめんしんのさんしゅるい", jp: "耐震・制振・免振の3種類（地震対策）", id_text: "3 metode proteksi gempa: tahan/redam/isolasi", desc: "①耐震=perkuat kolom & balok. ②制振=pasang ダンパー kurangi goyangan. ③免振=pasang アイソレータ di fondasi, isolasi energi gempa. 震度5強=berfungsi, 6強〜7=tidak runtuh. Mandor:「免振装置の点検記録見せて」(tunjukkan catatan isolator)." },
  { id: 638, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "どこうじのさぎょうろくしゅるい", jp: "土工事の作業6種類", id_text: "6 jenis pekerjaan tanah", desc: "①掘削=gali tanah/batu (発破). ②積込み・運搬=muat残土. ③盛り土/切り土=tambah/potong tanah. ④埋め戻し=isi kembali. ⑤締固め=padatkan. ⑥法面=stabilisasi lereng. Mandor:「残土の運搬、記録つけて」(catat pengangkutan残土)." },
  { id: 639, category: "haikan", source: "jac-ch3", type: "konsep", furi: "ゑるぽいんとこうほうちかすいはいすいさいだいじゅめえとる", jp: "ウェルポイント工法（地下水排水・最大10m）", id_text: "Well point: dewatering maks 10m untuk kerja kering", desc: "Tancapkan banyak 揚水管 ke tanah, pompa vakum sedot air tanah via 集水管. Max efektif: 10m. Lebih dari 10m pakai ディープウェル. Juga menstabilkan 軟弱地盤. Mandor:「ウェルポイントの水位確認して」(cek ketinggian muka air sumur)." },
  { id: 640, category: "doboku_hoso", source: "jac-ch3", type: "konsep", furi: "ほそうこうじのよんそうこうぞうきそうをわすれずに", jp: "舗装工事の4層構造", id_text: "4 lapisan jalan beraspal — jangan lupa lapisan 3", desc: "①路床=dasar terbawah, digali±1m. ②路盤=batu pecah dipadatkan. ③基層=aspal pertama (アスファルトフィニッシャー). ④表層=aspal atas, tahan air. 基層 jangan terlupa! Mandor:「路盤後に基層打って」(base dulu lalu aspal ke-3)." },
  { id: 641, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "とびこうじのろくしゅるい", jp: "とび工事の6種類", id_text: "6 jenis pekerjaan tobi (ahli kerja ketinggian)", desc: "Pekerjaan tali baja di ketinggian. 6 jenis: 足場とび(perancah), 鉄骨とび(rangka baja), 橋梁とび(jembatan), 重量とび(mesin berat), 送電とび(menara listrik), 町場とび(rumah). Mandor:「足場の壁つなぎ確認して」(cek pengikat perancah)." },
  { id: 642, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "てっきんひつぎてのよんしゅるい", jp: "鉄筋継手の4種類", id_text: "4 jenis sambungan besi tulangan", desc: "4 sambungan tulangan: ①ガス圧接=panas+tekan (paling umum). ②溶接=las busur. ③機械式=besi berulir+coupler. ④重ね=tumpuk besi tipis, disatukan beton. Mandor:「ガス圧接の外観確認して」(cek visual sambungan)." },
  { id: 643, category: "sekou", source: "jac-ch3", type: "konsep", furi: "ようせつのさんだいぶんるいゆうせつあっせつろうせつ", jp: "溶接の3大分類：融接・圧接・ろう接", id_text: "3 kategori las: lelehkan / tekan / brazing", desc: "①融接=lelehkan material (arc/gas/laser) — paling umum. ②圧接=panas+tekan tanpa cair sempurna (ガス圧接tulangan). ③ろう接=logam penghubung suhu rendah sebagai lem. Mandor:「融接箇所の検査します」(inspeksi hasil las leleh)." },
  { id: 644, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "かたわくこうじとしほこうかたわくだいく", jp: "型枠工事と支保工（かたわく大工）", id_text: "Pekerjaan bekisting & perancah penopang beton cor", desc: "Cetakan kayu dibuat 型枠大工. Beton cair masuk: tekanan besar → perkuat 支保工 (pipa besi luar). Baca 加工図 dulu. Setelah mengeras, cetakan dibongkar, dipakai ulang. Mandor:「支保工の本数、図面通り確認して」(cek jumlah strut)." },
  { id: 645, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "こんくりいとあっそうこうじとさんしゃちいむわあく", jp: "コンクリート圧送工事と3者チームワーク", id_text: "Pengecoran beton dengan pompa: 3 peran sinkron", desc: "生コン dari pabrik → truk アジテータ → コンクリートポンプ車. 3 peran sinkron: ①オペレータ(pompa) ②筒先(selang) ③土工(締固めvibrator). Beton mengeras cepat, wajib koordinasi. Mandor:「3人連携、タイムロスなしで」(3 orang sinkron, tanpa tunda)." },
  { id: 646, category: "setsubi_kougu", source: "jac-ch3", type: "konsep", furi: "とそうこうじのさんこうほう", jp: "塗装工事の3工法", id_text: "3 metode pengecatan: kuas / roller / semprot udara", desc: "①はけ塗り=kuas, hasil paling rapi. ②ローラー=efisien untuk dinding luar. ③エアスプレー=cat dikabut kompresor, area luas/sulit. Pilih 塗料 sesuai jenis permukaan (素地). Mandor:「外壁はローラーで仕上げて」(dinding luar pakai roller)." },
  { id: 647, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さかんこうじととくしゅしあげとぎだしあらいだししっくい", jp: "左官工事（研ぎ出し・洗い出し・漆喰）", id_text: "Pekerjaan plester dinding + 2 teknik finishing", desc: "左官工事=oles 壁土/モルタル/漆喰 pakai こて. ①研ぎ出し=asah permukaan batu hingga mengkilap. ②洗い出し=種石+semen, sikat permukaan agar batu menonjol. Mandor:「漆喰の養生期間守ってください」(patuhi waktu pengeringan漆喰)." },
  { id: 648, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ふきつけうれたんだんねつこうじにせいぶん", jp: "吹付けウレタン断熱工事", id_text: "Insulasi semprot uretan keras: 2 komponen + QC", desc: "Semprot 硬質ウレタンフォーム ke bangunan. Bahan: ①ポリオール成分 + ②ポリイソシアネート. QC: sebelum=uji papan 450mm正方形, cek密度. Selama=cek ketebalan tiap 4〜5m. Mandor:「施工前確認板、見せてください」(tunjukkan papan uji dulu)." },
  { id: 649, category: "doboku_doko", source: "jac-ch3", type: "konsep", furi: "かいよどぼくのよんこうじしゅんせつうめたてがんぺきぼおはていけえそん", jp: "海洋土木の4工事", id_text: "4 pekerjaan sipil laut: keruk/reklamasi/dermaga", desc: "①浚渫=keruk dasar laut/sungai dengan 浚渫船. ②埋立=timbun tanah→lahan baru. ③岸壁=dermaga: sheet pile+tiang. ④防波堤=pemecah gelombang: batu+ケーソン(kotak beton). Mandor:「ケーソンの据付位置確認して」(cek posisi caisson)." },
  { id: 650, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ないそうしあげこうじぼおどくろすゆかかあてん", jp: "内装仕上げ工事（LGS・ボード・クロス・床）", id_text: "Finishing interior: LGS hingga wallpaper & lantai", desc: "①LGS/軽天=rangka baja ringan. ②ボード=papan gypsum+pate. ③クロス=wallpaper. ④塗装仕上げ=cat pengganti wallpaper. ⑤床仕上げ=ubin/karpet. ⑥カーテン工事=pasang tirai. Mandor:「LGSのピッチ、設計通りか確認して」(cek jarak LGS sesuai desain)." },
  { id: 651, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "さっしこうじとかばあこうほうきんぞくたてぐ", jp: "サッシ工事とカバー工法（金属建具の取付け）", id_text: "Pekerjaan sash logam + renovasi kusen metode cover", desc: "サッシ工事=pasang kusen logam: jendela aluminium, pintu, kasa nyamuk. Renovasi: カバー工法=pasang kusen baru DI ATAS lama tanpa bongkar → hemat biaya & waktu. Mandor:「カバー工法で対応します」(tangani dengan metode cover)." },
  { id: 652, category: "sekou", source: "jac-ch3", type: "konsep", furi: "かいたいこうじかいたいがらあすべすとたいさく", jp: "解体工事（解体ガラ・アスベスト対策）", id_text: "Pekerjaan bongkar: limbah & prosedur asbes", desc: "アスベスト対策。Bongkar bangunan tua, survei asbes wajib dulu. 解体ガラ dipilah (beton, besi, berbahaya) per 建設リサイクル法. Mandor:「石綿飛散防止処置してから始めて」(pasang pelindung asbes sebelum mulai)." },
  { id: 653, category: "career", source: "jac-ch3", type: "konsep", furi: "けんせつこうじのしかくさんしゅるい", jp: "建設工事の資格3種類", id_text: "3 tingkat kualifikasi konstruksi berdasarkan UU K3", desc: "①国家免許=lisensi negara tertinggi. ②技能講習修了証=lulus pelatihan terdaftar. ③特別教育=K3 sebelum tugas berbahaya. 作業主任者=pengawas wajib dipilih dari pemegang 技能講習. Mandor:「この作業の主任者はだれですか」(siapa pengawas?)." },
  { id: 654, category: "career", source: "jac-ch3", type: "konsep", furi: "くれえんいどうしきくれえんたまかけのしかくきじゅんかじゅうべつ", jp: "クレーン・移動式クレーン・玉掛け資格", id_text: "Kualifikasi crane & rigging berdasarkan kapasitas", desc: "クレーン: ≥5t免許, 1〜5t技能講習, <1t特別教育. 移動式: ≥5t免許. 玉掛け: ≥1t技能講習, <1t特別教育. Batas kunci: 5t (免許) dan 1t (玉掛け). Mandor:「何トンの荷物か確認して資格チェックして」(cek beban dan lisensi)." },
  { id: 655, category: "career", source: "jac-ch3", type: "konsep", furi: "しゃりょけいけんせつきかいこうしょさぎょうしゃおおとっくりふとのしかく", jp: "車両系・高所作業車・フォークリフト資格", id_text: "Kualifikasi alat berat: berat / tinggi / angkat", desc: "車両系: ≥3t技能講習, <3t特別教育. 高所作業車: ≥10m技能講習, <10m特別教育. フォーク: ≥1t技能講習, <1t特別教育. Mandor:「機体重量確認してから乗せて」(cek berat mesin sebelum operasikan)." },
  { id: 656, category: "career", source: "jac-ch3", type: "konsep", furi: "ようせつさんっけつはっぱあしばのしかくくぶん", jp: "溶接・酸欠・発破・足場の資格区分", id_text: "Kualifikasi las/O₂ rendah/peledakan/scaffolding", desc: "ガス溶接者=技能講習. ガス溶接主任者=免許. アーク溶接者=特別教育. 酸欠主任者=技能講習. 発破技士=免許(tertinggi). 足場主任者(≥5m)=技能講習. 石綿作業者=特別教育. Mandor:「作業前に資格証確認してから始めて」(cek sertifikat sebelum mulai)." },
  { id: 657, category: "kenchiku_kutai", source: "jac-ch3", type: "konsep", furi: "けんちくだいくこうじのしゅるいまちぞうさくみや", jp: "建築大工工事の種類（町大工・造作大工・宮大工）", id_text: "Jenis tukang kayu: rumah / finishing / kuil", desc: "①町大工=tukang kayu rumah tinggal biasa (paling umum). ②造作大工=pasang pintu, 障子, ふすま, interior. ③宮大工=kuil/shrine, teknik sambungan kayu tertinggi. Mandor:「造作大工さん、建具の取付お願いします」(pasang pintu/kusen)." },
  { id: 658, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "やねこうじかわらぶきあまじまいごしゅるい", jp: "屋根工事：瓦ぶきと雨仕舞い + 5種の屋根工事", id_text: "Pekerjaan atap: genteng, drainase hujan, 5 jenis", desc: "瓦=genteng tanah liat dibakar. 雨仕舞い=sistem alirkan air hujan, wajib dikuasai. 5 jenis: ふき替え, 重ねぶき, 漆喰補修, 雨どい交換, 屋根塗装. Mandor:「雨仕舞いの施工確認して、漏れないように」(cek sistem drainase, jangan bocor)." },
  { id: 659, category: "setsubi_kougu", source: "jac-ch3", type: "konsep", furi: "けんちくばんきんこうじのだくとさんしゅるいはいえんくうちょうはいき", jp: "建築板金工事のダクト3種（排煙・空調・排気）", id_text: "Pekerjaan plat logam: 3 jenis saluran udara (duct)", desc: "建築板金工事=proses pelat logam (potong, tekuk, sambung). 3 duct: ①排煙=asap kebakaran. ②空調=distribusi AC. ③排気=buang panas/bau. Termasuk atap logam, 外壁. Mandor:「ダクトの気密テスト完了しましたか」(tes kedap duct selesai?)." },
  { id: 660, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "いしこうじいしくだいりせきみかげいしぎいせき", jp: "石工事（石工・大理石・御影石・擬石）", id_text: "Pekerjaan batu: pasang batu alam/buatan", desc: "大理石(marmer), 御影石(granit), 擬石(tiruan) dipasang untuk estetika bukan struktur. Batu mahal → tidak boleh gagal. 乱形石 butuh pengalaman panjang. Mandor:「大理石、慎重に加工して」(proses marmer hati-hati)." },
  { id: 661, category: "gaiyou", source: "jac-ch4", type: "konsep", furi: "おはようございます", jp: "おはようございます（朝のあいさつの基本）", id_text: "Selamat pagi — salam dasar di pagi hari", desc: "Ucapkan kepada orang yang PERTAMA KALI ditemui di pagi hari. Fungsi ganda: ①memberi kesan baik kepada lawan bicara ②membuat lawan bicara bersemangat. Tidak perlu kenal — tetap ucapkan dengan semangat." },
  { id: 662, category: "gaiyou", source: "jac-ch4", type: "konsep", furi: "ごあんぜんに", jp: "ご安全に（建設現場専用のあいさつ）", id_text: "Semoga selamat — salam khas lokasi konstruksi", desc: "Ungkapan harapan agar selamat dan tidak kecelakaan. Digunakan saat akhir 朝礼 dan saat berpapasan dengan pekerja tugas berbahaya. Mandor:「では、今日もご安全に！」(semoga hari ini selamat semua!)." },
  { id: 663, category: "gaiyou", source: "jac-ch4", type: "konsep", furi: "おつかれさまです", jp: "おつかれさまです（感謝・労い", id_text: "Kerja keras ya — ungkapan penghargaan kerja keras", desc: "Ungkapan terima kasih dan penghargaan atas kerja keras. Bisa dipakai di mana saja. Yang sudah selesai: おつかれさまでした!. Mandor:「今日は大変だったね、おつかれさまでした！」." },
  { id: 664, category: "gaiyou", source: "jac-ch4", type: "konsep", furi: "ごくろさまおつかれさまちがい", jp: "ご苦労さま vs おつかれさまです", id_text: "Gokurosama ke atasan tidak sopan — pakai otsukare", desc: "ご苦労さま=kurang sopan untuk atasan. おつかれさまです=lebih sopan, bisa ke siapa saja. Jika atasan bilang ご苦労さま, jawab ありがとうございます！. Mandor:「上司にはおつかれさまですって言ってくれよ」." },
  { id: 665, category: "gaiyou", source: "jac-ch4", type: "konsep", furi: "しつれいしますみっつのばめん", jp: "失礼します（3つの場面での使い方）", id_text: "Permisi / maaf mengganggu — 3 situasi penggunaan", desc: "3 situasi: ①masuk ruangan ②menyela percakapan untuk hal mendesak ③pulang lebih dulu: お先に失礼します → dijawab お疲れさまでした. Mandor:「部屋に入る前に失礼しますって言ってくれよ」." },
  { id: 666, category: "gaiyou", source: "jac-ch4", type: "konsep", furi: "あぶないよけろ", jp: "危ない！よけろっ！（緊急の呼びかけ）", id_text: "Awas! Minggir! — seruan darurat saat bahaya datang", desc: "Saat seseorang tidak menyadari bahaya, orang sekitar berteriak 危ない！. Untuk benda jatuh: 危ない！よけろっ！. Dengar → LANGSUNG bereaksi tanpa pikir panjang. Mandor:「危ない！と言われたら迷わず動けよ！」." },
  { id: 667, category: "sekou", source: "jac-ch4", type: "konsep", furi: "すみだしきじゅんずみとおりしん", jp: "墨出し・基準墨・通り芯", id_text: "3 istilah dasar penandaan garis konstruksi", desc: "墨出し=menarik garis referensi konstruksi. 基準墨=garis lurus referensi utama bangunan. 通り芯=garis yang melewati titik tengah komponen. Mandor:「基準墨を正確に引いてから通り芯を出してくれ」." },
  { id: 668, category: "sekou", source: "jac-ch4", type: "konsep", furi: "にげずみろくずみたてずみじずみしあがずみ", jp: "逃げ墨・陸墨・立て墨・地墨・仕上げ墨（5種類の墨）", id_text: "5 jenis garis tinta konstruksi berdasarkan fungsi", desc: "逃げ墨=garis paralel dari referensi jika ada halangan. 陸墨=referensi ketinggian horizontal. 立て墨=garis vertikal. 地墨=garis di lantai. 仕上げ墨=garis dimensi finishing. Mandor:「逃げ墨は何センチか必ずメモして」." },
  { id: 669, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "かべしいんはしらしいんおやずみかねをふるすみつけ", jp: "壁芯・柱芯・親墨・矩を振る・墨付け", id_text: "5 istilah sumidashi — garis tengah & referensi", desc: "壁芯=garis tengah dinding. 柱芯=garis tengah kolom. 親墨=referensi untuk 墨出し berikutnya. 矩を振る=tarik garis sudut 90°. 墨付け=tanda pengerjaan pada kayu. Mandor:「壁芯と柱芯がずれていないか確認してくれ」." },
  { id: 670, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "やりかたみずぬきみずもりじなわはりみずいと", jp: "遣り方・水貫・水盛り・地縄張り・水糸", id_text: "5 istilah yarkata — pagar referensi pra-konstruksi", desc: "遣り方=pagar sementara pasak+papan untuk posisi & ketinggian bangunan. 水貫=papan horizontal. 水盛り=tentukan referensi horizontal. 地縄張り=tandai pondasi. 水糸=benang referensi. Mandor:「遣り方を絶対に動かすな」." },
  { id: 671, category: "sekou", source: "jac-ch4", type: "konsep", furi: "べんま", jp: "BM・GL・FH・FL・SL・CH（高さ基準6語）", id_text: "6 istilah referensi ketinggian — tanah ke plafon", desc: "BM=titik referensi ketinggian proyek. GL=tinggi tanah. FH=tinggi tanah rencana. FL=tinggi lantai jadi. SL=tinggi permukaan slab. CH=tinggi lantai ke plafon. Mandor:「全部の高さはBMからの+/-で確認してくれ」." },
  { id: 672, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "もりとだんぎりしめかためてんあつうめもどしつきがため", jp: "盛り土・段切り・締固め・転圧・埋戻し・突固め", id_text: "6 istilah operasi tanah dasar", desc: "盛り土=timbunan. 段切り=gali bertangga di lereng. 締固め=padatkan tanah. 転圧=padatkan dengan alat berat. 埋め戻し=isi kembali setelah pekerjaan bawah tanah. 突き固め=padatkan dengan ランマ. Mandor:「埋め戻しは締固めをしっかりやれよ」." },
  { id: 673, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "ろばんろしょうひょうそう", jp: "路盤・路床・表層（舗装土工事3語）", id_text: "3 lapisan perkerasan jalan — atas ke tanah dasar", desc: "表層=lapisan paling atas perkerasan aspal. 路盤=lapisan di atas 路床 menyebarkan beban. 路床=lapisan tanah dasar penopang perkerasan sekitar 1m dari permukaan. Mandor:「路盤の厚みを設計通りに確保してくれよ」." },
  { id: 674, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "じなわはりねぎりねいれながさすぼり", jp: "地縄はり・根切り・根入れ長さ・素掘り", id_text: "4 istilah pra/pasca penggalian pondasi", desc: "地縄はり=tandai batas pondasi di tanah. 根切り=gali dengan alat berat hingga dasar pondasi. 根入れ長さ=kedalaman pondasi ke ujung. 素掘り=galian tanpa 土留め jika tanah kokoh. Mandor:「根入れ長さが設計値に達しているか確認して」." },
  { id: 675, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "どどめようへきやいたこうやいたやまどめ", jp: "土留め・擁壁・矢板・鋼矢板・山留め（崩壊防止5語）", id_text: "5 istilah penahan tanah & pencegah longsor galian", desc: "土留め=menahan tanah agar tidak longsor. 擁壁=土留め berbentuk dinding. 矢板=papan penahan tanah. 鋼矢板=矢板 baja saling menyambung. 山留め=menahan tanah dengan 矢板. Mandor:「山留めの変形があれば報告して」." },
  { id: 676, category: "doboku_haisui", source: "jac-ch4", type: "konsep", furi: "ばしょうちうつ", jp: "場所打ち・打つ（打設）", id_text: "2 istilah pengecoran beton di lokasi kerja", desc: "場所打ち/現場打ち=mengecor beton langsung di lokasi, bukan precast. 打つ/打設する=terminologi untuk menuang beton ke dalam cetakan. Mandor:「コンクリートを打設する前に型枠を必ず確認して」." },
  { id: 677, category: "doboku_doko", source: "jac-ch4", type: "konsep", furi: "よぼりすきとりとこずけくいまさらいだんばね", jp: "余堀り・鋤取り・床付け・杭間さらい・段跳ね", id_text: "5 istilah presisi penggalian & dasar pondasi", desc: "余堀り=galian lebih untuk ruang kerja. 鋤取り=ratakan dasar galian. 床付け=finishing dasar secara presisi. 杭間さらい=bersihkan tanah di antara tiang. 段跳ね=angkat tanah bertahap ke atas. Mandor:「床付けは慎重にやれよ」." },
  { id: 678, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "じやまのりめんやまがくる", jp: "地山・法面・山がくる（自然地盤と崩壊危険）", id_text: "3 istilah tanah alami & bahaya lereng galian", desc: "地山=tanah dalam kondisi alami. 法面(のり)=permukaan miring pada galian. 山がくる=turap atau lereng RUNTUH/LONGSOR — sering jadi kecelakaan serius. Mandor:「法面が崩れそうなら作業を止めて報告してくれ」." },
  { id: 679, category: "haikan", source: "jac-ch4", type: "konsep", furi: "みずかえかまばやまずなみずしめまんぼう", jp: "水替え・釜場・山砂・水締め・万棒（排水・管理5語）", id_text: "5 istilah drainase & manajemen material lokasi", desc: "水替え=pompa air di dasar galian. 釜場=lubang untuk pompa penguras. 山砂=pasir daratan, serap air tinggi. 水締め=padatkan timbunan sambil siram air. 万棒=hitung truk/orang masuk. Mandor:「釜場のポンプを定期的に確認してくれよ」." },
  { id: 680, category: "sekou", source: "jac-ch4", type: "konsep", furi: "じぎょうきそちょくせつきそべたきそふうちんぐ", jp: "地業・基礎・直接基礎（ベタ基礎・フーチング）", id_text: "Pekerjaan tanah dasar & pondasi langsung", desc: "地業=lapisan di bawah slab pondasi (pasir/kerikil/捨てコン/tiang). 基礎=meneruskan beban ke tanah. ベタ基礎=cor seluruh dasar. フーチング=hanya di titik beban. Mandor:「転圧後に捨てコンを打てよ」." },
  { id: 681, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "くいきそすらぶくいじぎょうきそめんしん", jp: "杭基礎・スラブ・杭地業・基礎免振", id_text: "4 istilah pondasi tiang, slab & isolasi gempa", desc: "杭基礎=pondasi tiang untuk tanah lemah. スラブ=bagian datar bangunan. 杭地業=pekerjaan tiang pondasi. 基礎免振=sistem serap gaya gempa antara tanah dan pondasi. Mandor:「杭の打設記録を毎本記録してくれよ」." },
  { id: 682, category: "sekou", source: "jac-ch4", type: "konsep", furi: "あしばのしゅるいさぎょうゆかかりがこい", jp: "足場の種類・作業床・仮囲い（仮設工事3語）", id_text: "Jenis perancah, lantai kerja & pagar sementara", desc: "足場=lantai sementara untuk kerja di ketinggian (枠組み/単管/くさび). 作業床=lantai perancah dari 布板. 仮囲い=pembatas sementara lokasi ke jalan/lahan tetangga. Mandor:「作業床の点検を毎日してくれよ」." },
  { id: 683, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "はいきんひろいだしあそびあきかんかく", jp: "配筋・拾い出し・あそび・あき・間隔（鉄筋基本5語）", id_text: "5 istilah dasar pemasangan & perhitungan besi", desc: "配筋=tempatkan dan rakit besi tulangan. 拾い出し=hitung kebutuhan material dari gambar. あそび=toleransi. あき=jarak bersih antar tulangan. 間隔=jarak center-to-center. Mandor:「あきと間隔は設計図通りかチェックして」." },
  { id: 684, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "すてっこんけっそくかぶりあつさ", jp: "捨てコン・結束（ハッカー）・かぶり厚さ", id_text: "3 istilah presisi konstruksi beton bertulang", desc: "捨てコン=cor beton tipis 5–10cm sebagai referensi ketinggian. 結束=ikat persilangan tulangan dengan 結束線 pakai ハッカー. かぶり厚さ=jarak tulangan ke permukaan beton. Mandor:「かぶり厚さが設計値を満たしているか確認してくれ」." },
  { id: 685, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "たてこみのろあんこてんようぱんくくぎじまい", jp: "建込み・ノロ・アンコ・転用・パンク・釘仕舞", id_text: "6 istilah pekerjaan bekisting", desc: "建込み=dirikan bekisting. ノロ=bocoran beton dari sambungan. アンコ=pengisi agar beton tidak masuk ke alur. 転用=pakai ulang bekisting. パンク=bekisting jebol. 釘仕舞=cabut paku bekas. Mandor:「パンクしないよう支保工をしっかりしてくれよ」." },
  { id: 686, category: "sekou", source: "jac-ch4", type: "konsep", furi: "うちこみうちかさねひゃくごじゅうぷんひゃくにじゅうぷんおじょいんうちつぎ", jp: "打ち込み・打ち重ね・コールドジョイント・打ち継ぎ", id_text: "Pengecoran berlapis — batas waktu & sambungan", desc: "打ち込み=tuang beton ke bekisting. 打ち重ね=cor di atas beton BELUM keras (<25°C→150mnt, ≥25°C→120mnt). Terlambat→コールドジョイント. 打ち継ぎ=cor di atas SUDAH keras. Mandor:「時間オーバーでコールドジョイントにするなよ」." },
  { id: 687, category: "sekou", source: "jac-ch4", type: "konsep", furi: "しめかためたんぴんぐねりまぜはいごう", jp: "締固め・タンピング・練り混ぜ・配合", id_text: "4 istilah kualitas pengecoran beton", desc: "締固め=gunakan バイブレータ untuk getar beton, hilangkan rongga. タンピング=pukul permukaan slab agar padat. 練り混ぜ=campur semen dan agregat merata. 配合=perbandingan bahan beton. Mandor:「バイブレーターを入れながら締め固めてくれよ」." },
  { id: 688, category: "sekou", source: "jac-ch4", type: "konsep", furi: "おさまりとりあいあみつけみえがかりみえがくれ", jp: "納まり・取合い・見付け・見え掛かり・見え隠れ", id_text: "5 istilah kondisi finishing & keselarasan komponen", desc: "納まり=keseimbangan penempatan komponen. 取合い=pertemuan 2+ komponen. 見付け=permukaan tampak penuh dari depan. 見え掛かり=tampak dari celah. 見え隠れ=tampak saat digerakkan. Mandor:「取合いの納まりが悪いから図面と照合してくれ」." },
  { id: 689, category: "sekou", source: "jac-ch4", type: "konsep", furi: "とおりつらつらいちそりむくりろくふろく", jp: "通り・面一・反り・起り・陸・不陸", id_text: "6 istilah kelurusan, kerataan & kelengkungan", desc: "通り=kondisi lurus. 面一=dua permukaan rata sejajar. 反り=melengkung cekung. 起り=melengkung cembung. 陸=horizontal sempurna. 不陸=permukaan bergelombang. Mandor:「不陸があったらサンダーで修正してくれよ」." },
  { id: 690, category: "sekou", source: "jac-ch4", type: "konsep", furi: "めちがいおがむかねころびにげみきる", jp: "目違い・拝む・転び・逃げ・見切る", id_text: "5 istilah cacat konstruksi & penanganan sambungan", desc: "目違い=sambungan tidak rata. 拝む=elemen miring. 転び=kolom miring dari vertikal. 逃げ=toleransi dimensi yang sengaja diambil. 見切る=selesaikan sambungan dengan 見切り材. Mandor:「目違いと転びがないか最終確認してくれよ」." },
  { id: 691, category: "sekou", source: "jac-ch4", type: "konsep", furi: "なじみすてべたふかしてもどりだんどりてなおしだめ", jp: "駄目・手直し・手戻り・段取り・馴染み", id_text: "5 istilah kondisi pemasangan & proses kerja", desc: "駄目=bagian terlewat saat hampir selesai. 手直し=koreksi pekerjaan. 手戻り=pengerjaan ulang. 段取り=rencanakan urutan kerja. 馴染み=sambungan menempel sempurna. Mandor:「駄目直しはリストを作って確実に終わらせてくれ」." },
  { id: 692, category: "sekou", source: "jac-ch4", type: "konsep", furi: "ぴっちおうすんぽういっけんいっしゃくいっすんひとつぼ", jp: "ピッチ・追う・寸法・一間・一尺・一寸・一坪", id_text: "7 istilah ukuran termasuk satuan tradisional", desc: "ピッチ=jarak antar elemen berulang. 追う=ukur dari titik referensi. 寸法=dimensi panjang. 1間≈1.8m, 1尺≈30.3cm, 1寸≈3.03cm. 1坪=1間×1間≈3.3m². Mandor:「ピッチ300ミリで追って墨を出してくれよ」." },
  { id: 693, category: "kenchiku_kutai", source: "jac-ch4", type: "konsep", furi: "ぞうぞうぞうもくぞうぞう", jp: "RC造・S造・SRC造・木造・CB造", id_text: "5 singkatan struktur bangunan — definisi akronim", desc: "RC造=鉄筋コンクリート. S造=鉄骨. SRC造=鉄骨鉄筋コンクリート. 木造=kayu. CB造=blok beton ditumpuk. Mandor:「この現場はSRC造だから、鉄骨と配筋の両方が重要だ」." },
  { id: 694, category: "denki", source: "jac-ch4", type: "konsep", furi: "せつぞくはいせんりかくぜつえんかんつうかんろ", jp: "接続・配線・離隔・絶縁・貫通・管路", id_text: "6 istilah dasar listrik & telekomunikasi", desc: "接続=hubungkan (komunikasi: 結線). 配線=pasang kabel. 離隔=jarak pisah wajib. 絶縁=cegah arus bocor. 貫通=lubangi dinding/lantai. 管路=pipa untuk kabel. Mandor:「離隔距離を守って配線ルートを決めてくれよ」." },
  { id: 695, category: "denki", source: "jac-ch4", type: "konsep", furi: "まいせつさんしきかくうはいせん", jp: "埋設（3方式）・架空配線", id_text: "3 cara tanam kabel di tanah + kabel via tiang", desc: "埋設3方式: ①管路式=kubur pipa lalu masukkan kabel ②直接埋設式=kabel langsung tanam ③とう道=terowongan khusus. 架空配線=kabel via tiang listrik. Mandor:「管路式埋設は保護管の深さを守ってくれ」." },
  { id: 696, category: "denki", source: "jac-ch4", type: "konsep", furi: "はいかんするつうせんすらぶはいかんいんぺいろしゅつふせる", jp: "配管する・通線・スラブ配管・隠ぺい・露出・伏せる", id_text: "6 istilah pemasangan pipa kabel & manajemen jalur", desc: "配管する=pasang konduit. 通線=masukkan kabel ke konduit. スラブ配管=konduit di slab. 隠ぺい=pipa di dalam dinding. 露出=pipa tampak. 伏せる=buat exit pipa dari slab. Mandor:「スラブ配管は打設前に仕込み完了させてくれ」." },
  { id: 697, category: "denki", source: "jac-ch4", type: "konsep", furi: "かんでんろうでんせっちひらいしんひらいき", jp: "感電・漏電・接地（アース）・避雷針・避雷器", id_text: "5 istilah keselamatan listrik — bahaya & proteksi", desc: "感電=arus mengalir melalui tubuh. 漏電=listrik bocor. 接地/アース=hubungkan ke tanah cegah感電. 避雷針=lindungi bangunan dari petir. 避雷器=lindungi peralatan. Mandor:「アースが正しく施工されているか確認してくれよ」." },
  { id: 698, category: "denki", source: "jac-ch4", type: "konsep", furi: "たんらくていあつこうあつとくべつこうあつあっちゃくちょくりゅうこうりゅう", jp: "短絡・低圧・高圧・特別高圧・圧着・直流・交流", id_text: "7 istilah tegangan listrik & metode penyambungan", desc: "短絡/ショート=hubung singkat. 低圧: DC≤750V/AC≤600V. 高圧: 750V–7000V. 特別高圧: >7000V. 圧着=sambung dengan tekanan. 直流=arus tetap. 交流=arus periodik. Mandor:「圧着端子のサイズを確認してからかしめてくれよ」." },
  { id: 699, category: "denki", source: "jac-ch4", type: "konsep", furi: "てんめつひふくいちじがわにじがわまししめまあきんぐつうでん", jp: "点滅・被覆・一次側・増し締め・マーキング・通電", id_text: "6 istilah operasi & pemeliharaan pekerjaan listrik", desc: "点滅=nyala-mati bergantian. 被覆=isolasi vinil di kabel. 一次側/二次側=sisi masuk/keluar listrik. 増し締め=kencangkan baut kendur. マーキング=tanda setelah増し締め. 通電=listrik mengalir. Mandor:「増し締め後はマーキングしてくれよ」." },
  { id: 700, category: "denki", source: "jac-ch4", type: "konsep", furi: "あたるかしめるしこむふるせるとぶおちるぱい", jp: "あたる・かしめる・仕込む・振る・競る・Φ", id_text: "6 istilah slang khas pekerjaan listrik lapangan", desc: "あたる=cek dengan alat ukur. かしめる=crimp kabel. 仕込む=persiapkan pekerjaan. 振る=reroute pipa/kabel. 競る=dua benda hampir berbenturan. Φ(ぱい)=diameter. Mandor:「配管が競っていたら早めに振って対処してくれよ」." },
  { id: 701, category: "haikan", source: "jac-ch4", type: "konsep", furi: "くうちょうおんどしつどかんきはいえんえいせい", jp: "空調・温度・湿度・換気・排煙・衛生（設備基本6語）", id_text: "4 istilah dasar pekerjaan mekanikal & sanitasi", desc: "空調=mengatur suhu & kelembaban. 換気=ganti udara kotor dengan segar. 排煙=keluarkan asap saat kebakaran — K3 wajib. 衛生設備=toilet, kamar mandi (bukan dapur). Mandor:「換気量が設計通りか確認してくれよ」." },
  { id: 702, category: "haikan", source: "jac-ch4", type: "konsep", furi: "しにみずばりぎゃくりゅうぶんきしんしゅくじゃばららいにんぐ", jp: "死水・バリ・逆流・分岐・伸縮・蛇腹・ライニング", id_text: "7 istilah kondisi & material pipa/saluran", desc: "死水=air diam lama dalam pipa. バリ=sisa material di tepi produk. 逆流=aliran berlawanan. 分岐=pipa terbagi. 伸縮=memuai-menyusut. 蛇腹=konektor fleksibel. ライニング=lapisan dalam pipa. Mandor:「定期的に流して死水を防いでくれよ」." },
  { id: 703, category: "haikan", source: "jac-ch4", type: "konsep", furi: "ろうえいしけんすいあつしけんまんすいしけんこうばいおすいざつはいすい", jp: "漏洩試験・水圧試験・満水試験・勾配・汚水・雑排水", id_text: "6 istilah uji kebocoran & sistem drainase", desc: "漏洩試験=uji kebocoran (水圧/満水試験). 水圧試験=pipa suplai diberi tekanan. 満水試験=isi drainase penuh. 勾配=kemiringan. 汚水=air limbah toilet. 雑排水=air limbah dapur/kamar mandi. Mandor:「試験前に全バルブを確認してくれよ」." },
  { id: 704, category: "haikan", source: "jac-ch4", type: "konsep", furi: "しんさきつらせつびようご", jp: "芯・先・面（設備工事の3短語）", id_text: "3 istilah pendek bermakna teknis pekerjaan setsubi", desc: "芯(しん)=garis tengah pipa/duct. 先(さき)=ujung pipa. 面(つら)=permukaan flange. Kata pendek namun bermakna teknis spesifik di pekerjaan設備. Mandor:「芯から先までの寸法を正確に出してくれよ」." },
  { id: 705, category: "anzen", source: "jac-ch4", type: "konsep", furi: "ごえすかつどうせいりせいとんせいそうせいけつしつけ", jp: "5S活動（整理・整頓・清掃・清潔・しつけ）", id_text: "Program 5S — 5 kebiasaan lingkungan kerja aman", desc: "5S: ①整理=pisahkan perlu & tidak. ②整頓=tempatkan ditentukan. ③清掃=bersih setelah kerja. ④清潔=pertahankan bersih. ⑤しつけ=aturan agar ①–④ dilaksanakan disiplin. Mandor:「5Sを毎日全員でやってくれ」." },
  { id: 706, category: "anzen", source: "jac-ch4", type: "konsep", furi: "さぎょういんつめしょのろくるうる", jp: "作業員詰め所の6ルール", id_text: "6 aturan ruang istirahat pekerja lokasi konstruksi", desc: "詰め所=ruang ganti & istirahat pekerja. Aturan: merokok di tempat khusus, ポイ捨て禁止, helm di tempat ditentukan, barang di loker, cuci tangan, cek 掲示板. Mandor:「詰め所のルールを全員守ってくれよ」." },
  { id: 707, category: "anzen", source: "jac-ch4", type: "konsep", furi: "ふくそうのよんきんしじこうけんせつげんば", jp: "服装の4禁止事項（建設現場）", id_text: "4 larangan pakaian di lokasi konstruksi", desc: "4 larangan: ①半袖・短パン禁止 ②上着前開け禁止 (tersangkut) ③袖まくり禁止 (lengan ke pergelangan) ④ポケット手禁止 (tak bisa menahan saat jatuh). Mandor:「服装を整えて入場してくれよ」." },
  { id: 708, category: "career", source: "jac-ch4", type: "konsep", furi: "ほうれんそうほおこくれんらくそうだん", jp: "ほうれんそう（報告・連絡・相談）", id_text: "Hourensou — 3 pilar komunikasi efektif di kerja", desc: "ほうれんそう=報告 (lapor ke atasan), 連絡 (sampaikan info/jadwal), 相談 (konsultasikan masalah). Sampaikan singkat dan jelas. Mandor:「何かあったらすぐほうれんそうしてくれよ」." },
  { id: 709, category: "anzen", source: "jac-ch4", type: "konsep", furi: "あとかたずけさぎょうしゅうりょうごのぎむ", jp: "後片付け（作業終了後の義務・火の確認）", id_text: "Aturan beres-beres wajib setelah selesai bekerja", desc: "Setelah selesai bekerja WAJIB後片付け. Lakukan seolah段取り untuk esok hari. Jika menggunakan api, pastikan benar-benar padam sebelum pulang. Mandor:「帰る前に火の元を確認したか？確かめてくれよ」." },
  { id: 710, category: "hourei", source: "jac-ch2", type: "hukum", furi: "しょくぎょうのうりょくかいはつそくしんほう", jp: "職業能力開発促進法（技能検定）", id_text: "UU Pengembangan Kemampuan Kerja", desc: "UU yang meningkatkan kemampuan kerja melalui pelatihan dan sertifikasi. Lulus 技能検定 → dapat 合格証書 dan boleh sebut diri 技能士. Mandor:「技能士の資格を取れば手当もつくし、CCUSも上がるぞ」(sertifikat, ada tunjangan dan CCUS naik)." },
  { id: 711, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "どうろこうじ", jp: "道路工事", id_text: "Pekerjaan jalan", desc: "Membuat/memperbaiki jalan. Meliputi: aspal, rambu (標識), lampu lalu lintas, trotoar, marka, lanskap. Lebih banyak perbaikan jalan lama. Mandor:「舗装の厚さ、規定通りか確認して」(cek ketebalan aspal sesuai spec)." },
  { id: 712, category: "hourei", source: "jac-ch2", type: "hukum", furi: "ほうていろうどうじかん", jp: "法定労働時間（週40時間・1日8時間）", id_text: "Jam kerja legal", desc: "Jam kerja legal: max 8 jam/hari & 40 jam/minggu. Lembur butuh 36協定 dan dibayar upah tambahan: biasa +25%, libur +35%, malam +25%. Mandor:「8時間超えたら必ず記録してくれよ」(catat kalau lebih 8 jam)." },
  { id: 713, category: "kenchiku_shiage", source: "jac-ch3", type: "konsep", furi: "ひょうそうこうじ", jp: "表装工事（ひょうそうこうじ）", id_text: "Pekerjaan pelapis permukaan interior", desc: "Bagian 内装仕上げ工事, TIDAK termasuk LGS. Jenis: ①壁仕上げ (wallpaper/クロス). ②天井仕上げ (langit-langit, sulit). ③床仕上げ (ubin/karpet/tatami). ④塗装仕上げ. ⑤カーテン工事. Mandor:「クロス張りの前にパテ処理して」(dempul dulu sebelum wallpaper)." },
  { id: 714, category: "haikan", source: "jac-ch3", type: "konsep", furi: "はいかんこうじがいよう", jp: "配管工事（はいかんこうじ）の概要", id_text: "Gambaran umum pekerjaan pipa", desc: "Alirkan air/minyak/gas/uap via pipa logam. Meliputi: 給水, 排水, 消火, AC 冷媒管. 3 kemampuan dasar: ①切断 ②接合 ③組み立て. Mandor:「圧力テスト後、隠ぺいしてください」(tes tekanan dulu baru tutup pipa)." },
  { id: 715, category: "doboku_hoso", source: "jac-ch3", type: "konsep", furi: "どぼくこうじとくちょ", jp: "土木工事（どぼくこうじ）の特徴", id_text: "Karakteristik pekerjaan sipil", desc: "土木工事=berhadapan dengan alam (laut, sungai, gunung). Jenis: ダム, 河川, 道路, トンネル, 橋梁, 鉄道, 上下水道, 災害復旧. Berbeda dari 建築工事. Mandor:「河川工事の安全確認からだ」(mulai dari cek keselamatan kerja sungai)." },
  { id: 716, category: "denki", source: "jac-ch5", type: "konsep", furi: "かでんりゅうしゃだんき / ぶれえかあ / NFB", jp: "過電流遮断機 / ブレーカー / NFB", id_text: "Pemutus arus lebih — circuit breaker / NFB", desc: "Alat pengaman yang memutus suplai listrik secara otomatis saat arus berlebih mengalir. Disebut ブレーカー, versi modern tanpa sekring adalah NFB (No-Fuse Breaker)." },
  { id: 717, category: "sekou", source: "jac-ch5", type: "konsep", furi: "れべる（すいじゅんそくりょうき）/ れえざあれべる", jp: "レベル（水準測量機）/ レーザーレベル", id_text: "Alat ukur ketinggian — water level / laser level", desc: "レベル = alat survei ketinggian, dipasang di tripod, diatur manual. Versi otomatis: オートレベル. レーザーレベル = memancarkan laser untuk garis referensi horizontal/vertikal di dinding/plafon." },
  { id: 718, category: "sekou", source: "jac-ch5", type: "konsep", furi: "めじゃあ（まきじゃく）・じょうぎ", jp: "メジャー（巻き尺）・定規", id_text: "Meteran gulung / Penggaris (mistar lurus)", desc: "メジャー = pita ukur gulung; tipe baja tipis disebut コンベックス. 定規 = penggaris untuk menarik garis lurus; bahan: aluminium, stainless, atau bambu." },
  { id: 719, category: "denki", source: "jac-ch5", type: "konsep", furi: "はさみ・かったあないふ", jp: "はさみ・カッターナイフ", id_text: "Gunting / Cutter (pisau kater dengan mata patah)", desc: "はさみ = dua bilah menjepit untuk memotong. カッターナイフ = pisau dengan mata yang bisa dipatahkan untuk mempertahankan ketajaman; digunakan memotong pelindung, isolasi tape, dan bahan kemasan." },
  { id: 720, category: "sekou", source: "jac-ch5", type: "konsep", furi: "はんどみきさ・かくはんき", jp: "ハンドミキサ・かくはん機", id_text: "Pengaduk material — hand mixer / mesin pengaduk", desc: "ハンドミキサ = alat pengaduk genggam untuk cat, mortar, atau beton dalam ember. かくはん機 = sebutan umum mesin pengaduk, mencakup mortar mixer, concrete mixer, dan batch mixer." },
  { id: 721, category: "sekou", source: "jac-ch5", type: "konsep", furi: "ぶらし（よごれおとし）・すぽんじ", jp: "ブラシ（汚れ落とし）・スポンジ", id_text: "Sikat pembersih / Spons — bukan sikat kawat baja", desc: "ブラシ = sikat untuk menggosok kotoran; pada pekerjaan pemasangan batu, membersihkan sisa adukan (ノロ) yang meluap. スポンジ = busa untuk mengelap permukaan batu yang kotor akibat ノロ." },
  { id: 722, category: "haikan", source: "jac-ch5", type: "konsep", furi: "ぐらすうおる / ろっくうおる / ぽりすちれんふぉおむ", jp: "GW / RW / ポリスチレンフォーム", id_text: "3 jenis bahan insulasi termal: GW / RW / PS (foam)", desc: "①GW (グラスウール): serat kaca, ringan & murah, dipakai luas. ②RW (ロックウール): serat batu, tahan api lebih baik dari GW. ③PS (ポリスチレンフォーム): plastik busa untuk pipa air. Semua dipasang dalam 保温筒." },
  { id: 723, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ほおんこうじのばしょべつしあげしゅるい", jp: "保温工事の場所別仕上げ（4種類）", id_text: "Finishing insulasi pipa sesuai lokasi — 4 jenis", desc: "①天井内・隠蔽部: ALGC/ALK で包み固定（仕上材なし）。②屋内露出: 合成樹脂カバーまたはラッキング仕上材。③機械室・車庫・倉庫: ALGC/ALK + 鉄線 or 塩ビ亀甲金網。④屋外露出: ラッキングカバー（薄鉄板を板金加工）で覆う。湿気が多い屋外はポリエチレンフィルムで防湿も必要。" },
  { id: 724, category: "haikan", source: "jac-ch6", type: "konsep", furi: "だくとのほおんほれいこうじ", jp: "ダクトの保温保冷工事", id_text: "Insulasi termal duct — tanpa insulasi → kondensasi", desc: "Melilit insulasi pada duct meningkatkan efisiensi HVAC dan hemat energi. Tanpa insulasi, kondensasi terbentuk dan menyebabkan korosi serta jamur. Di proyek: dikencangkan pakai 鋲 atau tape ALGC." },
  { id: 725, category: "haikan", source: "jac-ch6", type: "konsep", furi: "さしこみつぎてこうほう（まるだくと）", jp: "差し込み継手工法（丸ダクト）", id_text: "Insert joint duct bulat — jangan pasang sekrup di", desc: "丸ダクト disambung dengan ニップル → kencangkan 2–3 baut → balut duct tape. PENTING: jangan pasang sekrup di bagian bawah duct agar tidak bocor jika ada air di dalam." },
  { id: 726, category: "haikan", source: "jac-ch6", type: "konsep", furi: "がすようせつのさんしゅるい", jp: "ガス溶接の3種類", id_text: "3 jenis las gas — paling umum: oksi-asetilen", desc: "①酸素アセチレン溶接 (paling umum) ②酸素水素溶接 ③空気アセチレン溶接. Banyak digunakan untuk pipa kecil (小口径管) dan dipakai bersama las busur tertutup. Mandor:「ガス溶接で小口径管を接合して」(las pipa kecil pakai las gas)." },
  { id: 727, category: "haikan", source: "jac-ch6", type: "konsep", furi: "こうしつえんかびにるかん（せっちゃくざいせつごう）", jp: "硬質塩化ビニル管（接着剤接合）", id_text: "Pipa PVC keras — tahan 10 detik setelah", desc: "継手挿入後10秒押さえ。Urutan: oleskan lem → masukkan sekaligus dengan tenaga → tahan 10 detik tanpa melepas tekanan → lap lem berlebih. Jika tidak ditahan, pipa terdorong keluar dan bocor." },
  { id: 728, category: "haikan", source: "jac-ch6", type: "konsep", furi: "こうしつえんかびにるかんのめんとり", jp: "硬質塩化ビニル管の面取り", id_text: "Chamfering pipa PVC — pipa air bersih: bevel luar", desc: "Setelah dipotong, bevel dalam dan luar agar pipa mudah masuk ke fitting. Untuk pipa air bersih/panas, chamfer luar harus lebih kuat karena lebih sulit masuk." },
  { id: 729, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ねじこみはいかん（つうすいはようじょうご）", jp: "ねじ込み配管（通水は養生後）", id_text: "Pipa ulir — aliri air hanya setelah curing time", desc: "Setelah シール剤 dan ねじ込み selesai, aliran air (通水) hanya boleh dilakukan setelah waktu curing yang cukup. Jika terlalu cepat, seal belum mengeras dan menyebabkan kebocoran." },
  { id: 730, category: "denki", source: "jac-ch6", type: "konsep", furi: "きゅうびくる（ろくせんろっぴゃっぼるとへんかん）", jp: "キュービクル（6600V変換）", id_text: "Cubicle — trafo 6600V menjadi 100V/200V", desc: "Listrik 6600V dari PLN masuk via PAS lalu ke キュービクル yang mengubah menjadi 100V/200V. Berisi 遮断器 dan 断路器. Di proyek: wajib dalam kondisi停電 saat dikerjakan." },
  { id: 731, category: "haikan", source: "jac-ch6", type: "konsep", furi: "EFせつごう（いんじけえたあかくにん）", jp: "EF接合（インジケーター確認）", id_text: "EF joint — selesai jika indikator menonjol kiri &", desc: "Konfirmasi keberhasilan EF接合: indikator EF socket harus menonjol (隆起) di kiri dan kanan. Setelah dingin, lepas klem dan catat di check sheet. Di proyek: langkah pemeriksaan wajib." },
  { id: 732, category: "haikan", source: "jac-ch6", type: "konsep", furi: "えせつごうばあこおどりいだあでゆうちゃくでえたよみこみ", jp: "EF接合", id_text: "EF joint — scan barcode untuk input data fusioning", desc: "EF接合の融着準備手順: ①コントローラーの電源プラグをコンセントに差し込む ②スイッチを入れる ③継手の端子に出力ケーブルを接続 ④コントローラーに付属のバーコードリーダーで融着データを読み込ませる → その後スタートボタンを押して通電開始。" },
  { id: 733, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "まんどれるつうかしけん", jp: "マンドレル通過試験", id_text: "Mandrel test: >150m No.4, ≤150m gagal → No.3", desc: "Saluran >150 m: wajib lewati mandrel No.4 (Ø600 mm). Saluran ≤150 m yang tidak bisa dilalui No.4: gunakan No.3. Tujuan: memastikan saluran terhubung sempurna setelah pemasangan." },
  { id: 734, category: "haikan", source: "jac-ch6", type: "konsep", furi: "GXがただくたいるちゅうてつかんのまがりはいかん", jp: "GX形ダクタイル鋳鉄管の曲げ配管", id_text: "Ductile iron GX — tekuk max 2°, dibagi ke", desc: "Setelah disambung, tiap pipa bisa ditekuk maksimal 2°. Di proyek: jangan tekuk di satu sambungan saja — bagi ke beberapa pipa untuk capai sudut yang diinginkan." },
  { id: 735, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "くろおじゃあのいろわけ", jp: "クロージャの色分け", id_text: "Closure: abu-abu untuk serat optik, hitam untuk", desc: "Closure = kotak sambungan/percabangan kabel di tiang listrik. Warna: abu-abu untuk serat optik (光ファイバー), hitam untuk kabel metal. Di proyek: pastikan tipe yang benar sebelum pemasangan." },
  { id: 736, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "でんせんきょうどうこう", jp: "電線共同溝", id_text: "Common utility duct — estetika kota & kemudahan", desc: "Fasilitas untuk memindahkan kabel tiang listrik ke bawah tanah. Tujuan: ①estetika kota ②kelancaran lalu lintas. Di proyek: wajib survei dan hati-hati terhadap utilitas yang sudah ada di bawah." },
  { id: 737, category: "tsushin", source: "jac-ch6", type: "konsep", furi: "でんちゅうをたてるてじゅんすてっぷ", jp: "電柱を建てる手順（5ステップ）", id_text: "5 langkah mendirikan tiang listrik", desc: "①電柱を建てる位置を確認 ②手掘りや探針棒（たんしんぼう）を使って埋設物（まいせつぶつ）を確認 ③手掘りと穴掘建柱車（あなほりけんちゅうしゃ）によって掘削 ④電柱を建てる ⑤埋め戻しをする。手順②で探針棒を使う点が試験で問われやすい。" },
  { id: 738, category: "haikan", source: "jac-ch6", type: "konsep", furi: "べんだあまげかこう（さいしょうまげはんけい）", jp: "ベンダー曲げ加工（最小曲げ半径）", id_text: "Bender bending — radius min 4x diameter luar pipa", desc: "Membengkokkan pipa tembaga refrigeran pakai bender: radius minimum = 4x diameter luar pipa (lebih kecil dari tekuk tangan). Di proyek: pilih bender sesuai tebal pipa agar tidak berkerut." },
  { id: 739, category: "haikan", source: "jac-ch6", type: "konsep", furi: "ろうづけごのかくにん", jp: "ろう付け後の確認", id_text: "Setelah brazing — dinginkan kain basah, cek", desc: "Setelah brazing pipa refrigeran: ①dinginkan dengan kain basah ②periksa pinhole dan ろう回り不良 (brazing tidak merata) secara visual. Di proyek: suhu brazing dan kebersihan permukaan wajib dipastikan." },
  { id: 740, category: "anzen", source: "jac-ch7", type: "konsep", furi: "さんだいさいがいついらくてんらくけんせつきかいくれええんほうかいとうかい", jp: "三大災害（さんだいさいがい）", id_text: "3 Bencana Besar Konstruksi — 40–70% kecelakaan", desc: "①墜落・転落 (terbanyak, saat kerja di ketinggian) ②建設機械・クレーン災害 (激突され, はさまれ) ③崩壊・倒壊災害. Ketiganya menyumbang 4–7割 kematian di konstruksi. Di luar itu: kecelakaan lalu lintas." },
  { id: 741, category: "anzen", source: "jac-ch7", type: "konsep", furi: "がいこくじんろうどうしゃのしぼうさいがいけんせつぎょうがもっともおおい", jp: "外国人労働者の死亡災害", id_text: "Kecelakaan fatal TKA — sektor konstruksi terbanyak", desc: "厚生労働省データ（令和2・3年度）: 外国人労働者の死亡災害発生件数は建設業が最も多い（製造業・その他より多い）。事故の型別では墜落・転落が最多、続いて交通事故（道路）。建設業で働く外国人は特にこのリスクに注意が必要。" },
  { id: 742, category: "anzen", source: "jac-ch7", type: "konsep", furi: "ほうかいとうかいさいがいのけんせつとくゆうれいかせつでんちゅうせきさいでんちゅう", jp: "崩壊・倒壊災害の建設特有例", id_text: "Tiang sementara roboh / tiang di truk rubuh →", desc: "Contoh 崩壊・倒壊 pada pekerjaan listrik: ①仮設電柱 patah & rubuh ②tiang listrik di atas truk ambruk menimpa pekerja. Pada galian air: tanah longsor menimbun (≥1.5m → wajib 土留め)." },
  { id: 743, category: "anzen", source: "jac-ch7", type: "konsep", furi: "きかいせっちこうじのしぼうじこおおがたきかいのてんとうによるしたじき", jp: "機械設置工事の死亡事故", id_text: "Pasang mesin besar — mesin terbalik, pekerja", desc: "Karakteristik kecelakaan fatal 機械設置工事: mesin besar terbalik (転倒) menimpa pekerja. Saat menangani beban berat, tindakan pencegahan terbalik (転倒防止措置) wajib dilakukan." },
  { id: 744, category: "anzen", source: "jac-ch7", type: "konsep", furi: "じょうげすいどうこうじのしゅるいのじこりすく", jp: "上下水道工事の3種類の事故リスク", id_text: "3 risiko saluran air: longsor, tersandung, backhoe", desc: "①Tanah longsor di galian → tertimbun (≥1.5m: wajib 鋼矢板). ②Tersandung kabel atau amblas di tepi galian → jatuh. ③Backhoe berputar menabrak atau mundur → tertabrak (wajib ada 誘導員 khusus)." },
  { id: 745, category: "anzen", source: "jac-ch7", type: "konsep", furi: "しんきにゅうじょうしゃきょういくのはちこうもく", jp: "新規入場者教育の8項目", id_text: "8 materi wajib orientasi pekerja baru di lapangan", desc: "[1]混在作業場所の状況 [2]危険有害箇所と立入禁止区域 [3]混在作業場所での作業相互の連絡・調整 [4]災害発生時の避難の方法 [5]指揮命令系統 [6]担当する作業内容と労働災害防止対策 [7]安全衛生に関する規程 [8]基本方針・目標など。死亡の半数近くが入場1週間以内に発生するため義務化。実施時間: 30分程度。" },
  { id: 746, category: "career", source: "jac-gakka1", type: "konsep", furi: "せんもんこうじぎょうしゃかんのちいむわあく", jp: "専門工事業者間のチームワーク", id_text: "Kerja tim antar kontraktor spesialis", desc: "Untuk memajukan konstruksi dengan lancar, kerja tim (チームワーク) antar kontraktor spesialis sangat penting. Masing-masing sub-kontraktor bekerja sesuai jadwal dan berkoordinasi ketat." },
  { id: 747, category: "kenchiku_kutai", source: "jac-gakka1", type: "konsep", furi: "てっこつこうじ", jp: "鉄骨工事（てっこつこうじ）", id_text: "Pekerjaan struktur baja (steel frame)", desc: "Membangun rangka bangunan menggunakan baja: kolom (柱), balok (梁), dan elemen diagonal. Struktur baja: ブレース, ラーメン構造, トラス. Berbeda dari 鉄筋工事 (tulangan beton)." },
  { id: 748, category: "kenchiku_kutai", source: "jac-gakka1", type: "konsep", furi: "こんくりいとだせつこうじ", jp: "コンクリート打設工事（コンクリートだせつこうじ）", id_text: "Pekerjaan pengecoran beton", desc: "Menuangkan beton cair (生コン) ke dalam bekisting (型枠). Alur: muat → pompa → tuang → padatkan (バイブレータ) → finishing. Tim 3 peran: 筒先, 振動機操作, 補助. Mandor:「バイブレータでしっかり締め固めて」(padatkan beton pakai vibrator)." },
  { id: 749, category: "kenchiku_shiage", source: "jac-gakka2", type: "konsep", furi: "くたい", jp: "躯体（くたい）", id_text: "Struktur utama bangunan", desc: "Bagian struktural bangunan: 基礎 (pondasi) + 柱 (kolom) + 梁 (balok) + 壁面 (dinding) + 床 (lantai). = tulang/kerangka utama. BUKAN: 内装仕上げ (finishing dalam), 建具 (kusen pintu/jendela), 屋根 (atap)." },
  { id: 750, category: "doboku_doko", source: "jac-gakka2", type: "konsep", furi: "しきならしさぎょう", jp: "敷き均し作業（しきならしさぎょう）", id_text: "Pekerjaan penghamparan dan perataan material", desc: "Menyebarkan dan meratakan material (aspal, agregat, tanah) secara merata menggunakan mesin paver/finisher. Di proyek: berbeda dari 盛り土 (menumpuk tanah) dan 積み込み (memuat)." },
  { id: 751, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "はいかん", jp: "配管", id_text: "Perpipaan / pipa", desc: "Sistem pipa untuk mengalirkan fluida (air, gas, refrigeran, dll)." },
  { id: 752, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "まいせつ", jp: "埋設", id_text: "Instalasi bawah tanah", desc: "Pemasangan pipa/kabel di bawah permukaan tanah. Di proyek: wajib catat posisi di gambar teknik. Mandor:「埋設管の位置を図面に記録して」(catat posisi pipa di gambar)." },
  { id: 753, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ちか", jp: "地下", id_text: "Bawah tanah", desc: "Area di bawah permukaan tanah. 地下配管 = pipa bawah tanah. Di proyek: pastikan kedalaman sesuai standar. Mandor:「地下配管の深さを確認して」(cek kedalaman pipa bawah tanah)." },
  { id: 754, category: "haikan", source: "vocab-general", type: "vocab", furi: "とうけつ", jp: "凍結", id_text: "Pembekuan", desc: "Air/fluida dalam pipa membeku di cuaca dingin → pipa bisa pecah." },
  { id: 756, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "しんくうびき", jp: "真空引き", id_text: "Pemvakuman", desc: "Proses mengeluarkan udara & uap air dari pipa refrigeran sebelum mengisi refrigeran." },
  { id: 757, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "かんたん", jp: "管端", id_text: "Ujung pipa", desc: "Bagian ujung pipa/selang. シーリング材を充填する = isi sealant di ujung pipa." },
  { id: 758, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "がすはいかん", jp: "ガス配管", id_text: "Perpipaan gas", desc: "Sistem pipa untuk mengalirkan gas kota. Wajib uji kebocoran setelah sambungan." },
  { id: 759, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "せつぞく", jp: "接続", id_text: "Penyambungan / koneksi", desc: "Menghubungkan dua bagian pipa atau kabel. Di proyek: setiap sambungan harus dicek kebocorannya. Mandor:「接続部の漏れを確認して」(cek kebocoran di titik sambungan)." },
  { id: 760, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "せつぞくぶ", jp: "接続部", id_text: "Bagian sambungan", desc: "Titik di mana dua pipa atau komponen bertemu. Di proyek: titik sambungan paling rentan bocor. Mandor:「接続部をしっかり締め付けて」(kencangkan bagian sambungan)." },
  { id: 763, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "かんかく", jp: "間隔", id_text: "Jarak / interval", desc: "Jarak antar saddle penyangga pipa. Jika terlalu jauh → lendutan (たわみ)." },
  { id: 764, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "たわみ", jp: "たわみ", id_text: "Lendutan / defleksi", desc: "Pipa melengkung ke bawah akibat beratnya sendiri. Terjadi jika interval saddle terlalu lebar." },
  { id: 766, category: "haikan", source: "vocab-general", type: "vocab", furi: "りゅうりょう", jp: "流量", id_text: "Laju aliran / debit", desc: "Jumlah fluida yang mengalir per satuan waktu. Satuan: m³/h, L/min." },
  { id: 767, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "ほおんざい", jp: "保温材", id_text: "Material insulasi panas", desc: "Bahan yang membungkus pipa panas agar panas tidak hilang ke lingkungan." },
  { id: 768, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "だんねつざい", jp: "断熱材", id_text: "Material insulasi termal", desc: "Bahan pencegah perpindahan panas. Dipakai pada pipa panas & dingin." },
  { id: 770, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "しーりんぐざい", jp: "シーリング材", id_text: "Bahan sealant / penyegel", desc: "Material yang digunakan untuk menutup celah dan mencegah masuknya air/udara." },
  { id: 771, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "ぜつえんてーぷ", jp: "絶縁テープ", id_text: "Selotip insulasi listrik", desc: "Pita perekat untuk mengisolasi kabel listrik. Berbeda fungsi dari sealant." },
  { id: 772, category: "hoon", source: "vocab-general", type: "vocab", furi: "あぶら", jp: "油", id_text: "Minyak / oli", desc: "Jika menempel pada sambungan 冷媒管 → シール性が低下 (kemampuan seal menurun)." },
  { id: 773, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "たいこうせい", jp: "耐候性", id_text: "Ketahanan cuaca", desc: "Kemampuan material bertahan terhadap sinar UV, hujan, dan perubahan suhu di luar ruangan." },
  { id: 774, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "あつさ", jp: "厚さ", id_text: "Ketebalan", desc: "Tebal material insulasi. Jika 断熱材 terlalu tipis → 結露 (kondensasi) sering terjadi." },
  { id: 775, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "とうけつぼうし", jp: "凍結防止", id_text: "Pencegahan pembekuan", desc: "Kombinasi 保温材 + 電熱線 untuk mencegah pipa bawah tanah membeku." },
  { id: 776, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "けつろ", jp: "結露", id_text: "Kondensasi / embun", desc: "Air mengembun pada permukaan pipa dingin karena suhu lebih rendah dari titik embun udara." },
  { id: 777, category: "anzen", source: "vocab-general", type: "vocab", furi: "たはつ", jp: "多発", id_text: "Sering terjadi / berulang", desc: "Kejadian yang terjadi berulang-ulang. 結露が多発 = kondensasi sering terjadi." },
  { id: 778, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "すいぶん", jp: "水分", id_text: "Kandungan air / kelembapan", desc: "Jika 真空引き tidak tuntas → 水分が残る → pipa refrigeran rusak dari dalam. Di proyek: wajib vakum hingga tuntas. Mandor:「真空引きをしっかりやって」(lakukan pemvakuman dengan tuntas)." },
  { id: 779, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "こしょう", jp: "故障", id_text: "Kerusakan / gangguan", desc: "Kegagalan fungsi peralatan. Refrigeran yang lembab → 内部故障. Di proyek: pemvakuman yang tidak sempurna menyebabkan kerusakan. Mandor:「故障を防ぐために真空引きを確実に」(vakum tuntas untuk mencegah kerusakan)." },
  { id: 780, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "もれ", jp: "漏れ", id_text: "Kebocoran", desc: "Cairan atau gas yang keluar dari tempat yang seharusnya tertutup." },
  { id: 781, category: "anzen", source: "vocab-general", type: "vocab", furi: "さび", jp: "錆", id_text: "Karat", desc: "Oksidasi pada permukaan logam. Pipa berkarat → wajib 洗浄 & 防錆処理 sebelum konstruksi." },
  { id: 782, category: "anzen", source: "vocab-general", type: "vocab", furi: "れっか", jp: "劣化", id_text: "Degradasi / kemunduran", desc: "Material melemah seiring waktu. Sinar UV menyebabkan 劣化 pada kabel di luar ruangan." },
  { id: 783, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "ふちゃく", jp: "付着", id_text: "Menempel / melekat", desc: "油が付着する = minyak menempel. Pada 冷媒管接続部 → シール性が低下する. Di proyek: bersihkan bagian sambungan sebelum memasang. Mandor:「接続部の油を拭き取ってから取り付けて」(bersihkan minyak dulu)." },
  { id: 784, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "しんにゅう", jp: "侵入", id_text: "Masuk / infiltrasi", desc: "水が侵入する = air masuk ke dalam. Di proyek: ujung konduit wajib ditutup dengan sealant. Mandor:「管端にシーリング材を充填して水の侵入を防いで」(isi sealant di ujung konduit)." },
  { id: 785, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "たわみはっせい", jp: "たわみ発生", id_text: "Timbulnya lendutan", desc: "Ketika jarak saddle terlalu lebar, pipa melengkung ke bawah." },
  { id: 786, category: "anzen", source: "vocab-general", type: "vocab", furi: "いおん", jp: "異音", id_text: "Suara abnormal", desc: "Suara tidak normal pada sistem pipa/mesin. Membuka katup terlalu cepat → aliran mendadak → 異音." },
  { id: 787, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "ひーとろす", jp: "ヒートロス", id_text: "Heat loss (kehilangan panas)", desc: "Panas yang terbuang keluar dari sistem insulasi melalui celah 断熱材." },
  { id: 788, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "すきま", jp: "隙間", id_text: "Celah / gap", desc: "Celah pada material insulasi tempat panas bisa bocor keluar → ヒートロス." },
  { id: 789, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "あつりょくしけん", jp: "圧力試験", id_text: "Uji tekanan", desc: "Pengujian pipa dengan memberikan tekanan di atas tekanan kerja untuk mengecek kebocoran." },
  { id: 790, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "がすもれしけん", jp: "ガス漏れ試験", id_text: "Uji kebocoran gas", desc: "Wajib dilakukan setiap kali menyambung pipa gas. Menggunakan air sabun atau detektor gas." },
  { id: 791, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "もれけんさ", jp: "漏れ検査", id_text: "Inspeksi kebocoran", desc: "Pemeriksaan setelah pengelasan. Wajib dilakukan untuk memastikan sambungan kedap." },
  { id: 792, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "あんぜんかくにん", jp: "安全確認", id_text: "Pemeriksaan keamanan", desc: "Langkah verifikasi bahwa kondisi sudah aman sebelum/sesudah pekerjaan." },
  { id: 793, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "かくにん", jp: "確認", id_text: "Konfirmasi / pengecekan", desc: "Memastikan suatu hal sudah benar. 施工前に確認する = periksa sebelum mulai konstruksi." },
  { id: 794, category: "haikan", source: "vocab-general", type: "vocab", furi: "きろく", jp: "記録", id_text: "Pencatatan / dokumentasi", desc: "埋設配管の位置を図面に記録する = catat lokasi pipa bawah tanah di gambar teknik." },
  { id: 795, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "ぼうし", jp: "防止", id_text: "Pencegahan", desc: "凍結防止、感電防止、結露防止 — istilah pencegahan sering muncul di soal ujian." },
  { id: 796, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "こうしょさぎょう", jp: "高所作業", id_text: "Pekerjaan di ketinggian", desc: "Pekerjaan di atas 2m dari lantai/tanah. Bahaya utama: 落下 (jatuh) dan 感電 (kesetrum)." },
  { id: 797, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "らっか", jp: "落下", id_text: "Jatuh", desc: "Bahaya utama pekerjaan di ketinggian. Wajib pakai harness & jaring pengaman." },
  { id: 798, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "そうおん", jp: "騒音", id_text: "Kebisingan", desc: "Bahaya yang juga perlu diperhatikan, tapi bukan bahaya utama di 高所溶接作業." },
  { id: 799, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "きけん", jp: "危険", id_text: "Bahaya", desc: "危険予知活動 (KY活動) = kegiatan identifikasi bahaya sebelum bekerja." },
  { id: 800, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "あーす", jp: "アース", id_text: "Grounding / pentanahan", desc: "Menghubungkan peralatan listrik ke tanah. Tujuan utama: 感電防止 (mencegah sengatan listrik)." },
  { id: 801, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "しょち", jp: "処置", id_text: "Tindakan penanganan", desc: "Langkah yang diambil untuk mengatasi/mencegah masalah. 水侵入を防ぐための処置." },
  { id: 802, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "しようちゅうし", jp: "使用中止", id_text: "Menghentikan penggunaan", desc: "Jika kabel 電動工具 panas → segera hentikan penggunaan (使用を中止する)." },
  { id: 803, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "せこうほうほう", jp: "施工方法", id_text: "Metode konstruksi", desc: "Cara/prosedur pelaksanaan pekerjaan konstruksi. Di proyek: ditentukan berdasarkan dokumen desain dan spesifikasi. Mandor:「施工方法を確認してから始めて」(cek metode kerja dulu sebelum mulai)." },
  { id: 805, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ほおん", jp: "保温", id_text: "Retensi panas / insulasi panas", desc: "Menjaga suhu pipa/peralatan panas agar tidak dingin. 保温 ≠ 断熱 (断熱 lebih umum)." },
  { id: 806, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ようせつ", jp: "溶接", id_text: "Pengelasan", desc: "Menyambung logam dengan panas tinggi. Setelah selesai → wajib 漏れ検査." },
  { id: 807, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ついかせこう", jp: "追加施工", id_text: "Pekerjaan tambahan", desc: "Pekerjaan konstruksi yang ditambahkan setelah konstruksi utama. 屋外保温の追加施工." },
  { id: 808, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "じゅうてん", jp: "充填", id_text: "Pengisian / penyumbatan", desc: "管端にシーリング材を充填する = isi sealant di ujung pipa konduit. Di proyek: mencegah air masuk ke dalam konduit. Mandor:「管端にシーリング材を充填して」(isi sealant di ujung pipa)." },
  { id: 809, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "はっせい", jp: "発生", id_text: "Timbul / terjadi", desc: "錆が発生した = karat timbul. 異音が発生する = suara abnormal terjadi. Di proyek: karat di dalam pipa harus dibersihkan sebelum konstruksi. Mandor:「錆が発生したら施工前に洗浄して」(cuci dulu jika ada karat)." },
  { id: 810, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "せんじょう", jp: "洗浄", id_text: "Pembersihan", desc: "配管内面に錆が発生した場合 → 施工前に洗浄と防錆処理が必要. Di proyek: karat dalam pipa harus dibereskan sebelum mulai. Mandor:「施工前に配管内を洗浄して防錆処理をして」(cuci dan anti-karat sebelum pasang)." },
  { id: 811, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ぼうせいしょり", jp: "防錆処理", id_text: "Perawatan anti-karat", desc: "Proses melapisi permukaan logam untuk mencegah karat. Dilakukan setelah pembersihan pipa." },
  { id: 812, category: "sekou", source: "vocab-general", type: "vocab", furi: "へいよう", jp: "併用", id_text: "Penggunaan bersamaan", desc: "Menggunakan dua hal sekaligus. 保温材と電熱線を併用する = pakai insulasi + kawat pemanas bersamaan." },
  { id: 813, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ぼうすいかばー", jp: "防水カバー", id_text: "Penutup anti-air", desc: "Penutup tahan air untuk melindungi insulasi pipa di luar ruangan dari hujan." },
  { id: 815, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "でんきせつび", jp: "電気設備", id_text: "Peralatan listrik", desc: "Sistem & peralatan yang berhubungan dengan listrik. アース取付が義務." },
  { id: 816, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "でんどうこうぐ", jp: "電動工具", id_text: "Alat listrik (power tool)", desc: "Alat kerja yang ditenagai listrik. Jika kabel panas saat dipakai → segera 使用中止." },
  { id: 817, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "でんげん", jp: "電源", id_text: "Sumber daya / power supply", desc: "Sumber listrik untuk peralatan. 電源を強くする = memperkuat daya (bukan solusi jika kabel panas)." },
  { id: 818, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "しがいせん", jp: "紫外線", id_text: "Sinar ultraviolet (UV)", desc: "Sinar UV dari matahari menyebabkan 劣化 (degradasi) pada kabel dan material di luar ruangan." },
  { id: 819, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "ふくすう", jp: "複数", id_text: "Beberapa / jamak", desc: "複数の電線を束ねて配管に通す場合 = saat memasukkan beberapa kabel dalam satu konduit." },
  { id: 820, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "ねつがこもる", jp: "熱がこもる", id_text: "Panas terperangkap", desc: "Bahaya memasukkan banyak kabel dalam satu konduit → panas menumpuk → risiko kebakaran." },
  { id: 821, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ふじゅうぶん", jp: "不十分", id_text: "Tidak mencukupi / kurang", desc: "真空引きを不十分に行った場合 = jika pemvakuman dilakukan secara tidak mencukupi." },
  { id: 822, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ふそく", jp: "不足", id_text: "Kekurangan / kurang", desc: "勾配不足が原因で起こる問題 = masalah yang terjadi akibat kemiringan pipa kurang." },
  { id: 823, category: "career", source: "vocab-lifeline", type: "vocab", furi: "あんてい", jp: "安定", id_text: "Stabil", desc: "圧力試験の結果が安定しない場合の原因 = penyebab hasil uji tekanan tidak stabil." },
  { id: 824, category: "career", source: "vocab-lifeline", type: "vocab", furi: "げんいん", jp: "原因", id_text: "Penyebab", desc: "Faktor yang menyebabkan masalah. 圧力不安定の原因 = 漏れの有無 (ada tidaknya kebocoran)." },
  { id: 825, category: "career", source: "vocab-general", type: "vocab", furi: "きゅうへん", jp: "急変", id_text: "Perubahan mendadak", desc: "バルブを開いた直後に流量が急変する → 異音発生の原因. Di proyek: buka katup perlahan agar aliran tidak tiba-tiba berubah. Mandor:「バルブはゆっくり開いて」(buka katup perlahan-lahan)." },
  { id: 826, category: "career", source: "vocab-general", type: "vocab", furi: "ちょくご", jp: "直後", id_text: "Segera setelah", desc: "バルブを開いた直後 = segera setelah katup dibuka. 直後 = langsung setelah." },
  { id: 827, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ないめん", jp: "内面", id_text: "Permukaan dalam", desc: "配管の内面に錆が発生した場合 = ketika karat muncul di permukaan dalam pipa." },
  { id: 828, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ないぶ", jp: "内部", id_text: "Bagian dalam / interior", desc: "内部に水分が残り故障する = kelembapan tersisa di bagian dalam → menyebabkan kerusakan." },
  { id: 829, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ずめん", jp: "図面", id_text: "Gambar teknik / denah", desc: "埋設配管の位置を将来確認するために、施工時に図面に記録する. Di proyek: gambar teknik adalah acuan utama. Mandor:「埋設配管の位置を必ず図面に記録して」(catat posisi pipa terpendam di gambar)." },
  { id: 830, category: "career", source: "vocab-supplementary", type: "vocab", furi: "しーるせい", jp: "シール性", id_text: "Kemampuan penyegelan (sealing)", desc: "Kemampuan sambungan untuk tidak bocor. 油が付着すると→シール性が低下する. Di proyek: bersihkan bagian sambungan sebelum memasang. Mandor:「油を拭いてからシールして」(bersihkan minyak sebelum menyegel)." },
  { id: 831, category: "career", source: "vocab-lifeline", type: "vocab", furi: "おんど", jp: "温度", id_text: "Suhu / temperatur", desc: "Besaran fisik panas suatu benda. Muncul sebagai pengecoh: '温度が一定になる', '温度の変化'." },
  { id: 832, category: "career", source: "vocab-lifeline", type: "vocab", furi: "うむ", jp: "有無", id_text: "Ada tidaknya / keberadaan", desc: "漏れの有無を確認する = periksa ada tidaknya kebocoran. Penyebab hasil uji tekanan tidak stabil." },
  { id: 833, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "ざいりょう", jp: "材料", id_text: "Material / bahan", desc: "Bahan yang digunakan dalam konstruksi. 材料の色 sering muncul sebagai pengecoh di soal ujian." },
  { id: 834, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "こーど", jp: "コード", id_text: "Kabel / kord (power tool)", desc: "Kabel listrik pada 電動工具. コードが熱くなる = kabel terasa panas → tanda bahaya → 使用中止." },
  { id: 835, category: "career", source: "vocab-general", type: "vocab", furi: "げんしょう", jp: "現象", id_text: "Fenomena / gejala", desc: "Kejadian atau gejala fisik. 断熱材の隙間から熱が漏れる現象 = fenomena panas bocor dari celah insulasi." },
  { id: 836, category: "career", source: "vocab-lifeline", type: "vocab", furi: "じゅうりょう", jp: "重量", id_text: "Berat / massa", desc: "Beban fisik suatu objek. Sering muncul sebagai pilihan pengecoh: '重量が増える' (berat bertambah)." },
  { id: 837, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "あつりょくけい", jp: "圧力計", id_text: "Manometer / alat ukur tekanan", desc: "Alat untuk mengukur tekanan fluida dalam pipa. Berbeda dari 圧力試験 (uji tekanan). 破損 = rusak." },
  { id: 838, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "ていか", jp: "低下", id_text: "Penurunan / penurun fungsi", desc: "シール性が低下する = kemampuan sealing menurun. Terjadi bila 冷媒管接続部 terkena 油." },
  { id: 839, category: "career", source: "vocab-lifeline", type: "vocab", furi: "いち", jp: "位置", id_text: "Posisi / lokasi", desc: "埋設配管の位置を図面に記録する = catat posisi pipa terpendam di gambar teknik agar bisa dilacak kelak." },
  { id: 840, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "はそん", jp: "破損", id_text: "Kerusakan / pecah", desc: "圧力計の破損 = manometer rusak. Muncul sebagai pengecoh penyebab 異音 saat katup dibuka." },
  { id: 841, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "ぶりっじ", jp: "ブリッジ", id_text: "Bridge (jembatan termal)", desc: "Istilah pengecoh di soal Q10. Fenomena bocornya panas melalui material yang menghubungkan sisi panas & dingin. Jawaban benar Q10 adalah ヒートロス." },
  { id: 842, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "さーまるぎゃっぷ", jp: "サーマルギャップ", id_text: "Thermal gap (celah termal)", desc: "Istilah pengecoh di soal Q10. Bukan istilah standar konstruksi Jepang. Jawaban benar Q10 adalah ヒートロス bukan サーマルギャップ." },
  { id: 843, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "でんせん", jp: "電線", id_text: "Kabel listrik / kawat", desc: "Kawat penghantar listrik. Berbeda dari 電線管（konduit pelindung）. 電線を複数束ねて通す = memasukkan banyak kabel sekaligus → panas terperangkap." },
  { id: 844, category: "career", source: "vocab-lifeline", type: "vocab", furi: "おくがい", jp: "屋外", id_text: "Luar ruangan / outdoor", desc: "Di luar gedung. 屋外配線 = kabel luar ruangan（rentan UV）. 屋外で配管保温を行う場合 = saat insulasi pipa di luar ruangan → wajib tambah 防水カバー." },
  { id: 845, category: "career", source: "vocab-lifeline", type: "vocab", furi: "しゅるい", jp: "種類", id_text: "Jenis / tipe", desc: "冷媒の種類 = jenis refrigeran. Muncul sebagai pengecoh di Q4. Penyebab 結露 多発 bukan jenis refrigeran, melainkan ketipisan 断熱材." },
  { id: 846, category: "career", source: "vocab-lifeline", type: "vocab", furi: "もくてき", jp: "目的", id_text: "Tujuan / maksud", desc: "アースを取る主な目的 = tujuan utama pemasangan grounding. Jawaban: 感電防止 (mencegah sengatan listrik)." },
  { id: 847, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "じょうしょう", jp: "上昇", id_text: "Kenaikan / peningkatan", desc: "温度上昇防止 = mencegah kenaikan suhu. Muncul sebagai pengecoh di Q13 (tujuan アース). Tujuan アース bukan mencegah 温度上昇, melainkan 感電防止." },
  { id: 848, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "そくてい", jp: "測定", id_text: "Pengukuran / pengujian", desc: "騒音測定 = pengukuran kebisingan. Muncul sebagai pengecoh di Q8 (安全確認 gas). Jawaban benar Q8 adalah ガス漏れ試験, bukan 騒音測定." },
  { id: 849, category: "career", source: "vocab-lifeline", type: "vocab", furi: "けっか", jp: "結果", id_text: "Hasil / hasil akhir", desc: "圧力試験の結果が安定しない場合 = jika hasil uji tekanan tidak stabil → kemungkinan ada 漏れ (kebocoran)." },
  { id: 850, category: "career", source: "vocab-lifeline", type: "vocab", furi: "へんか", jp: "変化", id_text: "Perubahan", desc: "温度の変化 = perubahan suhu（pengecoh Q6）. 色の変化 = perubahan warna（pengecoh Q19）. Kedua-duanya bukan penyebab utama dalam soal terkait." },
  { id: 851, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ながれ", jp: "流れ", id_text: "Aliran (fluida)", desc: "流れが悪くなる = aliran memburuk. Terjadi akibat 勾配不足（kemiringan pipa tidak cukup）→ fluida tidak mengalir lancar → bisa menggenang." },
  { id: 852, category: "career", source: "vocab-lifeline", type: "vocab", furi: "もんだい", jp: "問題", id_text: "Masalah / persoalan", desc: "勾配不足が原因で起こる問題 = masalah yang timbul akibat kemiringan pipa kurang. Kunci: 流れが悪くなる (aliran memburuk)." },
  { id: 853, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ぺんきぬり", jp: "ペンキ塗り", id_text: "Pengecatan dengan cat biasa", desc: "Pengecoh di Q11. Jika pipa berkarat, solusinya bukan hanya cat biasa (ペンキ塗り) — harus 洗浄＋防錆処理 (cuci + anti-karat) sebelum konstruksi." },
  { id: 854, category: "career", source: "vocab-general", type: "vocab", furi: "いろ", jp: "色", id_text: "Warna", desc: "Pengecoh paling sering di soal — muncul 6x: バルブの色(Q4)、材料の色(Q6)、色を塗る(Q15)、色検査(Q16)、色をそろえる(Q18)、色が変わる(Q20). Warna tidak pernah jadi jawaban benar." },
  { id: 855, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "ふえる", jp: "増える", id_text: "Bertambah / meningkat", desc: "Pengecoh yang muncul 4x: 流量が増える(Q2,Q17)、重量が増える(Q14,Q20). Selalu jadi pengecoh — bukan jawaban benar di soal manapun." },
  { id: 856, category: "career", source: "vocab-lifeline", type: "vocab", furi: "いってい", jp: "一定", id_text: "Tetap / konstan", desc: "温度が一定になる = suhu menjadi konstan. Pengecoh Q2 — bukan efek dari 真空引き yang tidak tuntas. Efek nyatanya: 水分が残り故障する." },
  { id: 857, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "とりつけ", jp: "取り付け", id_text: "Pemasangan / instalasi", desc: "防水カバー取り付け = pemasangan penutup anti-air. Jawaban benar Q12 — pekerjaan tambahan saat insulasi pipa di luar ruangan." },
  { id: 858, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "こうかん", jp: "交換", id_text: "Penggantian / tukar", desc: "圧力計交換 = mengganti manometer. Pengecoh Q12 — bukan pekerjaan tambahan yang dibutuhkan saat insulasi pipa luar ruangan." },
  { id: 859, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "とそう", jp: "塗装", id_text: "Pengecatan / pelapisan", desc: "色塗装 = pengecatan warna. Pengecoh Q12 — bukan tindakan tambahan standar untuk insulasi pipa di luar ruangan." },
  { id: 860, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "あがる", jp: "上がる", id_text: "Naik / meningkat", desc: "流量が上がる = debit aliran naik. Pengecoh Q14 — minyak pada sambungan 冷媒管 tidak menyebabkan debit naik, melainkan シール性が低下する." },
  { id: 861, category: "career", source: "vocab-general", type: "vocab", furi: "おと", jp: "音", id_text: "Suara / bunyi", desc: "音検査 = inspeksi suara. Pengecoh Q16 — inspeksi wajib setelah pengelasan bukan 音検査 melainkan 漏れ検査 (inspeksi kebocoran)." },
  { id: 862, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "へる", jp: "減る", id_text: "Berkurang / menurun", desc: "騒音が減る = kebisingan berkurang. Pengecoh Q17 — jarak saddle terlalu lebar tidak mengurangi kebisingan, melainkan menyebabkan たわみ (lendutan)." },
  { id: 863, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ながさ", jp: "長さ", id_text: "Panjang / panjangnya", desc: "長さをそろえる = menyamakan panjang kabel. Pengecoh Q18 — saat memasukkan banyak kabel dalam konduit, yang penting bukan panjang tapi agar 熱がこもらない (panas tidak terperangkap)." },
  { id: 864, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "かわる", jp: "変わる", id_text: "Berubah", desc: "色が変わる = warna berubah. Pengecoh Q20 — kemiringan pipa kurang (勾配不足) tidak menyebabkan warna berubah, melainkan 流れが悪くなる (aliran memburuk)." },
  { id: 865, category: "career", source: "vocab-lifeline", type: "vocab", furi: "あさい", jp: "浅い", id_text: "Dangkal", desc: "配管を浅く埋める = kubur pipa dangkal-dangkal. Pengecoh Q1 — pipa bawah tanah yang dangkal justru lebih rentan membeku. Harus pakai 保温材＋電熱線." },
  { id: 866, category: "career", source: "vocab-general", type: "vocab", furi: "はだか", jp: "裸", id_text: "Tanpa pelindung / telanjang", desc: "裸のまま埋める = kubur pipa tanpa pelindung apapun. Pengecoh Q1 — cara terburuk untuk pipa bawah tanah di cuaca dingin. Wajib pakai 保温材＋電熱線." },
  { id: 867, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "ちゅうい", jp: "注意", id_text: "Perhatian / kewaspadaan", desc: "特に注意するべき危険 = bahaya yang perlu diwaspadai khususnya. Muncul di Q5 (高所溶接). 注意する = memperhatikan / waspada." },
  { id: 868, category: "career", source: "vocab-general", type: "vocab", furi: "こくしょく", jp: "黒色", id_text: "Warna hitam", desc: "黒色テープで覆う = tutup dengan selotip hitam. Pengecoh Q7 — selotip hitam bukan pelindung UV yang tepat. Yang benar: 耐候性カバーを使用する." },
  { id: 869, category: "career", source: "vocab-general", type: "vocab", furi: "けいさん", jp: "計算", id_text: "Perhitungan / kalkulasi", desc: "流量計算 = menghitung debit aliran. Pengecoh Q8 — sebelum mengoperasikan pipa gas bukan saatnya hitung debit, yang wajib adalah ガス漏れ試験 dulu." },
  { id: 870, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ひやす", jp: "冷やす", id_text: "Mendinginkan / mengompres", desc: "コードを水で冷やす = dinginkan kabel dengan air. Pengecoh Q9 — JANGAN lakukan ini! Kabel panas → segera 使用を中止する. Air bisa menyebabkan korsleting." },
  { id: 871, category: "career", source: "vocab-lifeline", type: "vocab", furi: "つよい", jp: "強い", id_text: "Kuat / keras", desc: "電源を強くする = perkuat/naikkan daya listrik. Pengecoh Q9 — JANGAN dilakukan saat kabel panas. Justru memperburuk kondisi → kebakaran. Solusi: 使用中止." },
  { id: 872, category: "career", source: "vocab-general", type: "vocab", furi: "しょうらい", jp: "将来", id_text: "Masa depan / kelak", desc: "将来確認するために = agar bisa diketahui di masa depan. Konteks Q15: posisi pipa bawah tanah dicatat di 図面 agar bisa dilacak kelak." },
  { id: 873, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ひろい", jp: "広い", id_text: "Lebar / luas", desc: "サドル間隔が広すぎる = jarak saddle terlalu lebar. Konteks Q17 — penyebab たわみが発生する (lendutan terjadi). Interval saddle harus sesuai spesifikasi pipa." },
  { id: 874, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "そろえる", jp: "そろえる", id_text: "Menyamakan / menyelaraskan", desc: "色をそろえる = samakan warna (Q18 pengecoh). 長さをそろえる = samakan panjang (Q18 pengecoh). Kedua-duanya bukan hal yang diutamakan saat banyak kabel masuk konduit." },
  { id: 875, category: "career", source: "vocab-general", type: "vocab", furi: "さい", jp: "際", id_text: "Pada saat / ketika", desc: "〜する際（さい）= pada saat melakukan〜. 配管を埋設する際 = pada saat pemasangan pipa. Mirip 時（とき）tapi lebih formal. Sering muncul di teks soal." },
  { id: 876, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ばあい", jp: "場合", id_text: "Dalam kasus / apabila", desc: "〜の場合（ばあい）= dalam kasus〜 / apabila〜. Muncul di hampir semua soal sebagai frasa syarat: 結露が多発する場合、コードが熱くなる場合, dll." },
  { id: 877, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "まく", jp: "巻く", id_text: "Membelit / melilit", desc: "絶縁テープで巻く = balut dengan selotip insulasi. Pengecoh Q3 — selotip insulasi (絶縁テープ) bukan untuk waterproofing. Yang benar: シーリング材を充填する." },
  { id: 878, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ふとい", jp: "太い", id_text: "Tebal / gemuk (kabel)", desc: "電線を太くする = ganti kabel lebih tebal. Pengecoh Q3 — ketebalan kabel tidak mencegah air masuk ke konduit. Yang benar: 管端にシーリング材を充填する." },
  { id: 879, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "おおう", jp: "覆う", id_text: "Menutup / menyelimuti", desc: "黒色テープで覆う = tutup dengan selotip hitam. Pengecoh Q7. 耐候性カバーで覆う = tutup dengan pelindung tahan cuaca → metode benar pencegahan UV." },
  { id: 880, category: "career", source: "vocab-supplementary", type: "vocab", furi: "みじかい", jp: "短い", id_text: "Pendek", desc: "電線を短く切る = potong kabel lebih pendek. Pengecoh Q7 — memotong kabel tidak ada hubungannya dengan pencegahan degradasi UV. Yang benar: 耐候性カバー." },
  { id: 881, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "きる", jp: "切る", id_text: "Memotong", desc: "電線を短く切る = potong kabel lebih pendek. Pengecoh Q7. Juga terkait 使用を中止する (hentikan, bukan potong) pada Q9." },
  { id: 882, category: "career", source: "vocab-lifeline", type: "vocab", furi: "よぶ", jp: "呼ぶ", id_text: "Menyebut / memanggil", desc: "何と呼びますか = disebut apa? Pola pertanyaan nama/istilah. Muncul di Q10: 断熱材の隙間から熱が漏れる現象は何と呼びますか → ヒートロス." },
  { id: 883, category: "career", source: "vocab-lifeline", type: "vocab", furi: "おもな", jp: "主な", id_text: "Utama / terutama", desc: "主な目的（おもなもくてき）= tujuan utama. Muncul di Q13: アースを取る主な目的は何ですか → 感電防止. 主に = terutama, 主な = yang utama." },
  { id: 884, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "せこうじ", jp: "施工時", id_text: "Saat konstruksi / waktu pengerjaan", desc: "施工時（せこうじ）に行うこと = yang dilakukan saat konstruksi. Konteks Q15: posisi pipa bawah tanah dicatat di 図面 saat施工時." },
  { id: 885, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "さぎょうご", jp: "作業後", id_text: "Setelah pekerjaan", desc: "溶接作業後（さぎょうご）= setelah pekerjaan pengelasan. Konteks Q16: 溶接作業後に必ず行うべき検査 = inspeksi wajib setelah las → 漏れ検査." },
  { id: 886, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ぬる", jp: "塗る", id_text: "Mengecat / melapisi", desc: "色を塗る = mengecat dengan warna. Pengecoh Q15 — mengecat pipa bukan cara untuk menandai posisi pipa bawah tanah. Yang benar: 図面に記録する." },
  { id: 887, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "つける", jp: "付ける", id_text: "Memasang / menempelkan", desc: "圧力計を付ける = pasang manometer. Pengecoh Q15 — memasang manometer bukan cara untuk menandai posisi pipa bawah tanah. Yang benar: 図面に記録する." },
  { id: 888, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "たばねる", jp: "束ねる", id_text: "Mengikat / membundel", desc: "電線を複数束ねて配管に通す = memasukkan banyak kabel yang dibundel ke dalam konduit. Konteks Q18: bahaya 熱がこもる (panas terperangkap) bila terlalu banyak." },
  { id: 889, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "とおす", jp: "通す", id_text: "Melewatkan / meneruskan", desc: "配管に通す = melewatkan melalui konduit/pipa. Konteks Q18: 電線を配管に通す場合の注意点 = hal yang diperhatikan saat kabel dimasukkan ke konduit." },
  { id: 890, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ひらく", jp: "開く", id_text: "Membuka", desc: "バルブを開いた直後 = segera setelah katup dibuka. Konteks Q19: membuka katup terlalu cepat → 流量が急変 → 異音が発生する. バルブはゆっくり開くべき." },
  { id: 891, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "せこうまえ", jp: "施工前", id_text: "Sebelum konstruksi", desc: "施工前に何を行いますか = apa yang dilakukan sebelum konstruksi? Konteks Q11: jika pipa berkarat → 施工前に洗浄と防錆処理を行う. 施工前 = sebelum mulai pengerjaan konstruksi." },
  { id: 892, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ちゅういてん", jp: "注意点", id_text: "Poin perhatian / hal yang perlu diperhatikan", desc: "注意点は何ですか = apa yang perlu diperhatikan? Konteks Q18: 電線を複数束ねて配管に通す場合の注意点 → 熱がこもらないようにする. Beda dari 注意（ちゅうい）= peringatan umum." },
  { id: 893, category: "career", source: "vocab-lifeline", type: "vocab", furi: "かならず", jp: "必ず", id_text: "Wajib / pasti / selalu", desc: "必ず行うべき = yang wajib dilakukan. Kata kunci soal prosedur wajib. Muncul di Q8 (ガス配管接続→ガス漏れ試験必ず) dan Q16 (溶接作業後→漏れ検査必ず). 必ず = tidak boleh dilewati." },
  { id: 894, category: "career", source: "vocab-lifeline", type: "vocab", furi: "まず", jp: "まず", id_text: "Pertama-tama / langkah pertama", desc: "まず行うべきことは何ですか = apa yang pertama harus dilakukan? Muncul di Q4 (まず確認すべき点 → 断熱材の厚さ) dan Q9 (まず行うべきこと → 使用を中止する). まず = urutan prioritas utama." },
  { id: 895, category: "career", source: "vocab-lifeline", type: "vocab", furi: "とくに", jp: "特に", id_text: "Khususnya / terutama", desc: "特に注意するべき危険は何ですか = bahaya apa yang khususnya perlu diwaspadai? Muncul di Q5 (高所溶接 → 特に注意 = 落下). 特に = kata penekanan untuk hal paling penting/prioritas." },
  { id: 896, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "うめる", jp: "埋める", id_text: "Mengubur / menanam (pipa)", desc: "配管を埋める = mengubur pipa (di bawah tanah). Muncul sebagai opsi Q1: 浅く埋める (kubur dangkal — pengecoh), 裸のまま埋める (kubur tanpa pelindung — pengecoh). Yang benar: 保温材＋電熱線を併用して埋める." },
  { id: 897, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ふせぐ", jp: "防ぐ", id_text: "Mencegah / melindungi dari", desc: "〜を防ぐ = mencegah〜. Muncul di Q3: 電線管に水が侵入するのを防ぐための処置, dan Q7: 紫外線劣化を防ぐ方法. 防止（ぼうし）= pencegahan (kata benda); 防ぐ = mencegah (kata kerja)." },
  { id: 898, category: "career", source: "vocab-lifeline", type: "vocab", furi: "おこなう", jp: "行う", id_text: "Melakukan / melaksanakan", desc: "〜を行う = melaksanakan〜. Kata kerja paling sering di soal ujian. 施工を行う = melaksanakan konstruksi, 検査を行う = melakukan inspeksi, 処置を行う = mengambil tindakan. Formal version of する." },
  { id: 899, category: "career", source: "vocab-lifeline", type: "vocab", furi: "かんがえられる", jp: "考えられる", id_text: "Yang dapat diperkirakan / kemungkinan", desc: "考えられる原因 = penyebab yang mungkin / dapat diperkirakan. Muncul di Q6: 圧力試験の結果が安定しない場合、考えられる原因はどれですか → 漏れの有無. Bentuk potensial pasif dari 考える（かんがえる）." },
  { id: 900, category: "career", source: "vocab-lifeline", type: "vocab", furi: "しようちゅう", jp: "使用中", id_text: "Saat digunakan / sedang digunakan", desc: "使用中（しようちゅう）= sedang dipakai / dalam penggunaan. Konteks Q9: 電動工具使用中にコードが熱くなる場合 = saat power tool sedang digunakan dan kabelnya panas. 〜中 = sedang berlangsung." },
  { id: 901, category: "career", source: "vocab-lifeline", type: "vocab", furi: "べき", jp: "べき", id_text: "Seharusnya / harus dilakukan", desc: "動詞 + べき = seharusnya melakukan〜 / wajib〜. Muncul di banyak soal: 必ず行うべき検査, まず行うべきこと, 注意するべき危険. 〜すべき = 〜するべき (harus/seharusnya). Kata kunci soal prosedur wajib." },
  { id: 902, category: "career", source: "vocab-lifeline", type: "vocab", furi: "おこる", jp: "起こる", id_text: "Terjadi / timbul", desc: "Kata kerja PALING SERING di soal — muncul di Q2,Q14,Q17,Q19,Q20 sebagai '何が起こりますか'. 起こる = terjadi (intransitif); 起こす = menyebabkan (transitif). Hafal polanya: 〜すると何が起こりますか = jika〜, apa yang terjadi?" },
  { id: 903, category: "career", source: "vocab-lifeline", type: "vocab", furi: "のこる", jp: "残る", id_text: "Tersisa / tertinggal", desc: "水分が残り故障する = kelembapan tersisa → menyebabkan kerusakan. Konteks Q2: pemvakuman tidak tuntas → 水分が残る (kelembapan tertinggal di dalam pipa refrigeran). 残る = tersisa; 残す = menyisakan (transitif)." },
  { id: 904, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "しけん", jp: "試験", id_text: "Uji / pengujian (tekanan/teknis)", desc: "圧力試験（Q6）= uji tekanan. ガス漏れ試験（Q8）= uji kebocoran gas. 試験 = pengujian terhadap batas/standar teknis. Berbeda dari 検査（けんさ）= inspeksi kondisi visual/kebocoran pasca-konstruksi." },
  { id: 905, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "けんさ", jp: "検査", id_text: "Inspeksi / pemeriksaan", desc: "漏れ検査（Q16）= inspeksi kebocoran — WAJIB setelah pengelasan. 色検査 & 音検査 = pengecoh Q16. 検査 = pemeriksaan kondisi pasca-pekerjaan. Berbeda dari 試験（しけん）= pengujian teknis terhadap standar/tekanan." },
  { id: 906, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "さぎょう", jp: "作業", id_text: "Pekerjaan / operasi kerja", desc: "高所作業（Q5）= pekerjaan di ketinggian. 溶接作業後（Q16）= setelah pekerjaan pengelasan. 作業中 = sedang bekerja. 作業員（さぎょういん）= pekerja/operator. Lebih spesifik dari 工事（pekerjaan konstruksi besar）." },
  { id: 907, category: "career", source: "vocab-lifeline", type: "vocab", furi: "ほうほう", jp: "方法", id_text: "Cara / metode", desc: "施工方法（Q1）= metode konstruksi. 防ぐ方法（Q7）= cara mencegah. 〜のための方法/〜する方法 = cara untuk〜. Sering menjadi kata kunci pertanyaan 'bagaimana caranya'. Beda dari 施工方法（metode khusus konstruksi）." },
  { id: 908, category: "hoon", source: "vocab-lifeline", type: "vocab", furi: "こうじ", jp: "工事", id_text: "Pekerjaan konstruksi", desc: "保冷工事（Q4）= pekerjaan insulasi dingin. 工事 = pekerjaan konstruksi secara umum (berskala proyek). Lebih besar dari 作業（さぎょう）= operasi kerja harian. 工事中 = sedang dalam konstruksi." },
  { id: 909, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "あんぜん", jp: "安全", id_text: "Aman / keselamatan", desc: "安全確認（Q8）= pemeriksaan keamanan. 安全管理 = manajemen K3. 安全第一 = safety first. 安全 = kondisi aman/safety. Kata dasar yang sering kombinasi: 安全確認、安全管理、安全帯（ハーネス）." },
  { id: 910, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "せこう", jp: "施工", id_text: "Pelaksanaan konstruksi", desc: "Kata dasar dari: 施工方法（cara konstruksi）, 施工前（sebelum konstruksi）, 施工時（saat konstruksi）, 追加施工（konstruksi tambahan）, 施工後（setelah konstruksi）. 施工する = melaksanakan konstruksi." },
  { id: 911, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "とる", jp: "取る", id_text: "Mengambil / memasang / mendapatkan", desc: "アースを取る（Q13）= memasang grounding. 取り付け（とりつけ）= pemasangan（Q12）. 取る banyak makna kontekstual: mengambil, memasang, mendapatkan. Perhatikan bentuk: 取り付ける = memasang (lebih spesifik)." },
  { id: 912, category: "career", source: "vocab-jac", type: "vocab", furi: "せいり", jp: "整理", id_text: "Pilah / sortir", desc: "整理 = menyortir/memilah barang. S pertama dari 5S. Di proyek: barang tidak perlu disingkirkan dari area kerja. Mandor:「いらないものは整理して」(pilah dan singkirkan yang tidak perlu)." },
  { id: 913, category: "career", source: "vocab-jac", type: "vocab", furi: "せいとん", jp: "整頓", id_text: "Tata / rapikan", desc: "例: 工具を決めた場所に整頓する。→ Taruh alat di tempat yang sudah ditentukan." },
  { id: 914, category: "career", source: "vocab-jac", type: "vocab", furi: "せいそう", jp: "清掃", id_text: "Bersihkan / sapu", desc: "例: 毎日作業後に清掃する。→ Bersihkan area kerja setelah selesai setiap hari." },
  { id: 915, category: "career", source: "vocab-jac", type: "vocab", furi: "せいけつ", jp: "清潔", id_text: "Jaga kebersihan / higienis", desc: "例: 作業員詰め所を清潔に保つ。→ Jaga ruang pekerja tetap bersih dan sehat." },
  { id: 916, category: "career", source: "vocab-jac", type: "vocab", furi: "しつけ", jp: "しつけ", id_text: "Disiplin / kebiasaan baik", desc: "例: 5Sの5つ目はしつけ。→ Elemen ke-5 dari 5S = disiplin menjaga aturan." },
  { id: 917, category: "career", source: "vocab-jac", type: "vocab", furi: "ちーむわーく", jp: "チームワーク", id_text: "Kerja tim", desc: "例: 専門業者間のチームワークが大切。→ Kunci lancarnya konstruksi multi-kontraktor." },
  { id: 918, category: "career", source: "vocab-jac", type: "vocab", furi: "ゆういせい", jp: "優位性", id_text: "Keunggulan / superioritas posisi", desc: "例: 職場の優位性を利用したいじめ＝パワハラ。→ Memanfaatkan jabatan untuk menekan orang lain." },
  { id: 919, category: "career", source: "vocab-jac", type: "vocab", furi: "くつう", jp: "苦痛", id_text: "Penderitaan / tekanan", desc: "例: 精神的な苦痛を与える行為はパワハラ。→ Tindakan yang menyebabkan penderitaan mental = pelecehan." },
  { id: 920, category: "career", source: "vocab-jac", type: "vocab", furi: "ろうどうしゃ", jp: "労働者", id_text: "Pekerja / tenaga kerja", desc: "例: 労働者の安全を守る法律＝労働安全衛生法。→ UU yang melindungi keselamatan pekerja." },
  { id: 921, category: "career", source: "vocab-jac", type: "vocab", furi: "じぎょうぬし", jp: "事業主", id_text: "Pemberi kerja / majikan", desc: "例: 労災保険の保険料は事業主が払う。→ Premi asuransi kecelakaan kerja ditanggung majikan." },
  { id: 922, category: "career", source: "vocab-jac", type: "vocab", furi: "ししつ", jp: "資質", id_text: "Kualitas / kompetensi / mutu SDM", desc: "例: 建設業法の目的は業者の資質の向上。→ Tujuan UU Konstruksi = tingkatkan mutu pelaku usaha." },
  { id: 923, category: "career", source: "vocab-jac", type: "vocab", furi: "はいざい", jp: "廃材", id_text: "Material limbah / sisa bongkaran", desc: "例: 廃材の適切な処理は建設リサイクル法で定める。→ Penanganan limbah material diatur UU Daur Ulang Konstruksi." },
  { id: 924, category: "career", source: "vocab-jac", type: "vocab", furi: "さいていげん", jp: "最低限", id_text: "Minimum / batas paling rendah", desc: "例: 建築基準法は最低限のルールを定める。→ UU Standar Bangunan menetapkan aturan minimum." },
  { id: 925, category: "career", source: "vocab-jac", type: "vocab", furi: "けいげん", jp: "軽減", id_text: "Pengurangan / mitigasi", desc: "例: 消防法は火災の被害を軽減する目的。→ UU Pemadam bertujuan memitigasi kerugian kebakaran." },
  { id: 926, category: "career", source: "vocab-jac", type: "vocab", furi: "あんか", jp: "安価", id_text: "Murah / terjangkau", desc: "例: 水道法は安価な水の供給を目指す。→ UU Air Bersih bertujuan menyediakan air dengan harga terjangkau." },
  { id: 927, category: "career", source: "vocab-jac", type: "vocab", furi: "ぎのうこうしゅう", jp: "技能講習", id_text: "Pelatihan wajib sebelum operasikan mesin berat", desc: "例: 車両系建設機械3t以上は技能講習が必要。→ Alat berat ≥3t wajib ikut pelatihan keterampilan." },
  { id: 928, category: "career", source: "vocab-jac", type: "vocab", furi: "とくべつきょういく", jp: "特別教育", id_text: "Pendidikan khusus (wajib K3)", desc: "例: アーク溶接は特別教育が必要。→ Las busur wajib ikut pendidikan khusus K3." },
  { id: 929, category: "career", source: "vocab-jac", type: "vocab", furi: "めんきょ", jp: "免許", id_text: "Lisensi / SIM / izin resmi negara", desc: "免許 = lisensi resmi dari negara. Las gas, crane, dan listrik memerlukan lisensi. Di proyek: pekerja tanpa lisensi tidak boleh mengoperasikan alat. Mandor:「免許を持っているか確認して」(pastikan punya lisensi)." },
  { id: 930, category: "sekou", source: "vocab-jac", type: "vocab", furi: "じゅんびこうじ", jp: "準備工事", id_text: "Pekerjaan persiapan", desc: "例: 着工前に準備工事を行う。→ Sebelum mulai konstruksi, lakukan pekerjaan persiapan terlebih dahulu." },
  { id: 931, category: "doboku_doko", source: "vocab-jac", type: "vocab", furi: "やりかた", jp: "遣り方", id_text: "Batter board / rangka referensi", desc: "例: 遣り方で建物の位置・水平を確認する。→ Batter board dipakai untuk menentukan posisi & level bangunan." },
  { id: 932, category: "doboku_doko", source: "vocab-jac", type: "vocab", furi: "ねきり", jp: "根切り", id_text: "Penggalian fondasi", desc: "例: 基礎のために根切りを行う。→ Gali tanah untuk pemasangan fondasi bangunan." },
  { id: 933, category: "haikan", source: "vocab-jac", type: "vocab", furi: "うめもどし", jp: "埋戻し", id_text: "Urugan kembali / backfill", desc: "例: 配管設置後に埋戻しを行う。→ Setelah pipa terpasang, uruk kembali tanah di atasnya." },
  { id: 934, category: "kenchiku_kutai", source: "vocab-jac", type: "vocab", furi: "やまどめ", jp: "山留め", id_text: "Penahan tanah / earth retaining", desc: "例: 深い掘削では山留めが必要。→ Untuk galian dalam, wajib pasang sistem penahan tanah." },
  { id: 935, category: "sekou", source: "vocab-general", type: "vocab", furi: "しゅんこう", jp: "竣工", id_text: "Selesai konstruksi / serah terima", desc: "例: 竣工検査に合格したら引き渡し。→ Setelah lulus inspeksi akhir, bangunan diserahkan ke pemilik." },
  { id: 936, category: "sekou", source: "vocab-general", type: "vocab", furi: "ちゃっこう", jp: "着工", id_text: "Mulai konstruksi / groundbreaking", desc: "例: 着工から竣工まで18ヶ月かかった。→ Dari mulai konstruksi sampai selesai butuh 18 bulan." },
  { id: 937, category: "sekou", source: "vocab-jac", type: "vocab", furi: "こうき", jp: "工期", id_text: "Periode konstruksi / durasi proyek", desc: "例: 工期を守るには工程管理が重要。→ Untuk tepat waktu, manajemen jadwal konstruksi itu krusial." },
  { id: 938, category: "doboku_doko", source: "vocab-jac", type: "vocab", furi: "しめがため", jp: "締固め", id_text: "Pemadatan tanah / compaction", desc: "例: 盛り土は転圧機で締固める。→ Tanah urukan dipadatkan menggunakan mesin pemadat." },
  { id: 939, category: "doboku_doko", source: "vocab-jac", type: "vocab", furi: "だんきり", jp: "段切り", id_text: "Pemotongan bertangga di lereng", desc: "例: 急な斜面に盛り土するとき段切りを行う。→ Saat mengurug lereng curam, potong bertangga agar tidak longsor." },
  { id: 940, category: "doboku_hoso", source: "vocab-jac", type: "vocab", furi: "ろしょう", jp: "路床", id_text: "Subgrade / lapisan tanah dasar jalan", desc: "例: 路床の上に路盤材を敷く。→ Di atas subgrade, hampar material lapis pondasi jalan." },
  { id: 941, category: "sekou", source: "vocab-jac", type: "vocab", furi: "おしど", jp: "押土", id_text: "Mendorong tanah (bulldozer)", desc: "例: ブルドーザで土砂を押土する。→ Bulldozer dipakai untuk mendorong timbunan tanah." },
  { id: 942, category: "sekou", source: "vocab-jac", type: "vocab", furi: "うんぱん", jp: "運搬", id_text: "Pengangkutan / transport material", desc: "例: ダンプカーで土砂を運搬する。→ Truk dump dipakai untuk mengangkut tanah galian." },
  { id: 943, category: "doboku_hoso", source: "vocab-jac", type: "vocab", furi: "しきならし", jp: "敷き均し", id_text: "Penghamparan & perataan", desc: "例: アスファルトをフィニッシャーで敷き均す。→ Aspal dihampar dan diratakan menggunakan mesin finisher." },
  { id: 944, category: "sekou", source: "vocab-jac", type: "vocab", furi: "くったい", jp: "躯体", id_text: "Struktur utama bangunan", desc: "例: 躯体＝基礎・柱・梁・壁・床。→ Kutai = pondasi + kolom + balok + dinding + lantai." },
  { id: 945, category: "sekou", source: "vocab-jac", type: "vocab", furi: "ないそう", jp: "内装", id_text: "Finishing interior", desc: "例: 躯体工事の後に内装仕上げを行う。→ Setelah struktur selesai, baru pekerjaan finishing interior." },
  { id: 946, category: "kenchiku_kutai", source: "vocab-jac", type: "vocab", furi: "かたわく", jp: "型枠", id_text: "Bekisting / formwork", desc: "例: 型枠にコンクリートを打設する。→ Tuang beton ke dalam bekisting untuk membentuk struktur." },
  { id: 947, category: "haikan", source: "vocab-jac", type: "vocab", furi: "しほこう", jp: "支保工", id_text: "Perancah penyangga / shoring", desc: "例: 型枠を鉄パイプで支保工する。→ Perkuat bekisting menggunakan perancah dari pipa baja." },
  { id: 948, category: "sekou", source: "vocab-jac", type: "vocab", furi: "ようじょう", jp: "養生", id_text: "Perawatan beton / curing", desc: "例: コンクリート打設後は養生が必要。→ Setelah pengecoran, beton perlu dirawat agar mengeras sempurna." },
  { id: 949, category: "kenchiku_kutai", source: "vocab-jac", type: "vocab", furi: "てっきん", jp: "鉄筋", id_text: "Tulangan baja / rebar", desc: "例: 鉄筋はコンクリートの引張力を補う。→ Tulangan baja menambah kekuatan tarik pada beton." },
  { id: 950, category: "kenchiku_kutai", source: "vocab-jac", type: "vocab", furi: "くぎじまい", jp: "釘仕舞", id_text: "Mencabut paku (daur ulang bekisting)", desc: "例: 型枠解体後に釘仕舞をして再利用する。→ Setelah bekisting dibongkar, cabut paku agar bisa dipakai ulang." },
  { id: 951, category: "kenchiku_kutai", source: "vocab-jac", type: "vocab", furi: "てんよう", jp: "転用", id_text: "Penggunaan ulang / reuse bekisting", desc: "例: 型枠の転用回数を記録する。→ Catat berapa kali bekisting sudah dipakai ulang." },
  { id: 952, category: "sekou", source: "vocab-general", type: "vocab", furi: "つぼ", jp: "坪", id_text: "Tsubo — satuan luas (≈3.3 m²)", desc: "例: 1坪＝約3.3m²。→ Satuan luas tradisional Jepang, masih dipakai di properti." },
  { id: 953, category: "sekou", source: "vocab-general", type: "vocab", furi: "しゃく", jp: "尺", id_text: "Shaku — satuan panjang (≈30.3 cm)", desc: "Satuan panjang tradisional Jepang. 1尺 ≈ 30.3 cm. 10寸＝1尺, 10尺＝1丈. Di proyek: sering muncul di gambar tua. Mandor:「1尺は約30センチと覚えて」(ingat 1 shaku ≈ 30 cm)." },
  { id: 954, category: "sekou", source: "vocab-general", type: "vocab", furi: "すん", jp: "寸", id_text: "Sun — satuan panjang (≈3.03 cm)", desc: "例: 1寸＝約3.03cm＝1尺の1/10。→ Sering muncul di gambar teknik bangunan tradisional Jepang." },
  { id: 955, category: "sekou", source: "vocab-jac", type: "vocab", furi: "いっけん", jp: "一間", id_text: "1 Ken — satuan panjang (≈1.818 m)", desc: "例: 柱の間隔は一間（約1.82m）が基本。→ Jarak antar kolom standar bangunan Jepang = 1 ken." },
  { id: 956, category: "haikan", source: "vocab-jac", type: "vocab", furi: "かんろ", jp: "管路", id_text: "Jalur pipa / conduit path", desc: "例: マンホール間を結ぶのが管路。→ Jalur pipa yang menghubungkan antar manhole." },
  { id: 957, category: "haikan", source: "vocab-jac", type: "vocab", furi: "まいせつぶつ", jp: "埋設物", id_text: "Utilitas bawah tanah / buried utilities", desc: "例: 穴を掘る前に埋設物を確認する。→ Sebelum menggali, periksa dulu ada tidaknya pipa/kabel bawah tanah." },
  { id: 958, category: "haikan", source: "vocab-jac", type: "vocab", furi: "たてこう", jp: "立坑", id_text: "Shaft vertikal / sumur akses", desc: "例: 推進工事の発進立坑をジャッキで掘る。→ Shaft vertikal dipakai sebagai titik start konstruksi jacking." },
  { id: 959, category: "haikan", source: "vocab-jac", type: "vocab", furi: "きょうどうこう", jp: "共同溝", id_text: "Saluran utilitas bersama", desc: "例: 電気・ガス・水道を共同溝にまとめる。→ Listrik, gas, air bersih dikumpulkan dalam 1 saluran bawah tanah." },
  { id: 960, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "どかぶり", jp: "土被り", id_text: "Kedalaman penimbunan / cover tanah", desc: "例: 車道の管路の土被りは0.8m以上。→ Pipa di bawah jalan harus tertanam minimal 0.8m." },
  { id: 961, category: "haikan", source: "vocab-general", type: "vocab", furi: "ぼうせい", jp: "防錆", id_text: "Anti-karat / rust prevention", desc: "例: 配管施工前に洗浄と防錆処理を行う。→ Sebelum pasang pipa berkarat, bersihkan dan beri lapisan anti-karat." },
  { id: 962, category: "denki", source: "vocab-jac", type: "vocab", furi: "ぜつえん", jp: "絶縁", id_text: "Insulasi listrik", desc: "例: 電気が他の部分に流れないよう絶縁する。→ Cegah arus mengalir ke bagian lain dengan insulasi." },
  { id: 963, category: "denki", source: "vocab-jac", type: "vocab", furi: "せっち", jp: "接地", id_text: "Pentanahan / grounding", desc: "例: 感電防止のため電気設備にアース(接地)を取る。→ Pasang grounding di peralatan listrik untuk cegah sengatan." },
  { id: 964, category: "denki", source: "vocab-jac", type: "vocab", furi: "ろうでん", jp: "漏電", id_text: "Kebocoran listrik", desc: "例: 漏電は感電・火災の原因になる。→ Kebocoran listrik bisa menyebabkan sengatan dan kebakaran." },
  { id: 965, category: "denki", source: "vocab-jac", type: "vocab", furi: "たんらく", jp: "短絡", id_text: "Korsleting / short circuit", desc: "例: 2本以上の電線が負荷なしに接触すると短絡。→ Dua kabel bersentuhan tanpa beban = korsleting." },
  { id: 966, category: "anzen", source: "vocab-jac", type: "vocab", furi: "ついらく", jp: "墜落", id_text: "Jatuh dari ketinggian (orang)", desc: "例: 建設業の三大災害の1位は墜落・転落。→ Jatuh dari ketinggian = penyebab kecelakaan terbesar di konstruksi." },
  { id: 967, category: "anzen", source: "vocab-jac", type: "vocab", furi: "さんそけつぼう", jp: "酸素欠乏", id_text: "Kekurangan oksigen", desc: "例: マンホール内は酸素欠乏に注意が必要。→ Di dalam manhole, waspadai kondisi kekurangan oksigen." },
  { id: 968, category: "anzen", source: "vocab-jac", type: "vocab", furi: "どどめ", jp: "土留め", id_text: "Penahan tanah / soil retaining", desc: "例: 掘削深さ1.5m以上では土留めが必要。→ Galian lebih dari 1.5m wajib pasang penahan tanah." },
  { id: 969, category: "anzen", source: "vocab-jac", type: "vocab", furi: "かんき", jp: "換気", id_text: "Ventilasi / sirkulasi udara", desc: "例: マンホール作業前に換気を行う。→ Sebelum masuk manhole, pastikan ada ventilasi yang cukup." },
  { id: 970, category: "sekou", source: "vocab-jac", type: "vocab", furi: "せこうかんり", jp: "施工管理", id_text: "Manajemen pelaksanaan konstruksi", desc: "例: 施工管理＝品質・工程・原価・安全・環境の管理。→ Construction management = kelola kualitas, jadwal, biaya, K3, lingkungan." },
  { id: 971, category: "sekou", source: "vocab-jac", type: "vocab", furi: "ひんしつ", jp: "品質", id_text: "Kualitas / mutu", desc: "例: 施工管理の4大管理のひとつが品質管理。→ Salah satu dari 4 manajemen konstruksi = quality control." },
  { id: 972, category: "sekou", source: "vocab-jac", type: "vocab", furi: "こうてい", jp: "工程", id_text: "Jadwal / tahapan proses", desc: "例: 工程表で工事の進捗を管理する。→ Gunakan bagan jadwal untuk pantau kemajuan konstruksi." },
  { id: 973, category: "gaiyou", source: "vocab-jac", type: "vocab", furi: "ごあんぜんに", jp: "ご安全に", id_text: "Semoga selamat / stay safe", desc: "例: 工事現場での挨拶は「ご安全に」。→ Sapaan khas di lokasi konstruksi = semoga selamat bekerja." },
  { id: 974, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "おつかれさまです", jp: "お疲れ様です", id_text: "Terima kasih sudah bekerja keras", desc: "例: 現場でも事務所でもすれ違ったときに使える。→ Bisa dipakai di mana saja — di lapangan, kantor, atau lorong." },
  { id: 975, category: "gaiyou", source: "vocab-jac", type: "vocab", furi: "あぶない", jp: "危ない", id_text: "Bahaya! / Awas!", desc: "例: まわりの人が「危ない！」と叫んだらすぐ反応。→ Jika orang sekitar berteriak 'bahaya!', segera bereaksi." },
  { id: 976, category: "sekou", source: "vocab-core", type: "vocab", furi: "しようしょ", jp: "仕様書", id_text: "Dokumen spesifikasi teknis", desc: "例: 施工は仕様書に従って行う。→ Pelaksanaan konstruksi harus sesuai spesifikasi teknis." },
  { id: 977, category: "sekou", source: "vocab-core", type: "vocab", furi: "けんちく", jp: "建築", id_text: "Bangunan / konstruksi gedung", desc: "例: 建築工事＝住宅・ビルなどの建物を作る工事。→ Pekerjaan membangun rumah, gedung, dll." },
  { id: 978, category: "doboku_hoso", source: "vocab-core", type: "vocab", furi: "どぼく", jp: "土木", id_text: "Teknik sipil / infrastruktur", desc: "例: 土木工事＝道路・ダム・橋など。→ Pekerjaan jalan, bendungan, jembatan, dll." },
  { id: 979, category: "sekou", source: "vocab-core", type: "vocab", furi: "かいたい", jp: "解体", id_text: "Pembongkaran / demolition", desc: "例: 解体工事ではアスベストに注意する。→ Dalam pekerjaan bongkar, waspadai material asbes." },
  { id: 980, category: "sekou", source: "vocab-core", type: "vocab", furi: "きそ", jp: "基礎", id_text: "Fondasi / pondasi", desc: "例: 建物の基礎は躯体の一部。→ Fondasi adalah bagian dari struktur utama bangunan." },
  { id: 981, category: "sekou", source: "vocab-general", type: "vocab", furi: "はしら", jp: "柱", id_text: "Kolom / pilar", desc: "Kolom vertikal menopang beban bangunan. 柱は建物の垂直荷重を支える. Di proyek: kolom baja dipasang tegak lurus, dicek dengan plumb bob. Mandor:「柱が垂直か確認して」(cek apakah kolom tegak lurus)." },
  { id: 982, category: "sekou", source: "vocab-general", type: "vocab", furi: "はり", jp: "梁", id_text: "Balok struktural", desc: "例: 梁は柱と柱をつなぐ水平部材。→ Balok = elemen horizontal yang menghubungkan kolom ke kolom." },
  { id: 983, category: "sekou", source: "vocab-general", type: "vocab", furi: "ゆか", jp: "床", id_text: "Lantai", desc: "例: 地墨は床など水平面に直接つける墨。→ Garis lantai (jizumi) ditarik langsung di permukaan horizontal." },
  { id: 984, category: "sekou", source: "vocab-core", type: "vocab", furi: "すみだし", jp: "墨出し", id_text: "Penarikan garis referensi / layout marking", desc: "例: 壁の位置を墨出しで確認する。→ Posisi dinding ditentukan dengan menarik garis referensi." },
  { id: 985, category: "sekou", source: "vocab-core", type: "vocab", furi: "にげずみ", jp: "逃げ墨", id_text: "Garis referensi offset", desc: "例: 仕上げ面から500mm逃げた位置に逃げ墨を引く。→ Garis offset dari permukaan finishing, biasanya 500mm." },
  { id: 986, category: "sekou", source: "vocab-core", type: "vocab", furi: "じずみ", jp: "地墨", id_text: "Garis lantai / floor marking", desc: "例: 床に直接つける墨を地墨という。→ Garis yang ditarik langsung di lantai = garis lantai." },
  { id: 987, category: "doboku_doko", source: "vocab-core", type: "vocab", furi: "みずもり", jp: "水盛り", id_text: "Penentuan level air / water leveling", desc: "例: 水盛りで水平基準を出す。→ Tentukan level horizontal menggunakan metode air." },
  { id: 988, category: "haikan", source: "vocab-core", type: "vocab", furi: "せつごう", jp: "接合", id_text: "Penyambungan / joint", desc: "例: 鉄管はねじ接合、ポリエチレン管はEF接合。→ Pipa baja = sambungan ulir; pipa PE = sambungan EF." },
  { id: 989, category: "denki", source: "vocab-core", type: "vocab", furi: "でんちゅう", jp: "電柱", id_text: "Tiang listrik / utility pole", desc: "例: 電柱を建てる前に埋設物を確認する。→ Sebelum pasang tiang listrik, cek utilitas bawah tanah." },
  { id: 990, category: "denki", source: "vocab-core", type: "vocab", furi: "まんほーる", jp: "マンホール", id_text: "Manhole", desc: "例: マンホール内は酸素欠乏と有害ガスに注意。→ Di dalam manhole, waspadai kekurangan oksigen dan gas berbahaya." },
  { id: 993, category: "anzen", source: "vocab-core", type: "vocab", furi: "さいがい", jp: "災害", id_text: "Kecelakaan / bencana kerja", desc: "例: 建設業の三大災害＝墜落・機械・温度接触。→ 3 kecelakaan terbesar di konstruksi = jatuh, mesin, suhu ekstrem." },
  { id: 994, category: "anzen", source: "vocab-core", type: "vocab", furi: "きけんよちかつどう", jp: "危険予知活動", id_text: "Kegiatan prediksi bahaya / KY", desc: "例: 作業前にKYで危険を予測し対策を立てる。→ Sebelum kerja, prediksi bahaya (KY) dan tentukan tindakan pencegahan." },
  { id: 995, category: "career", source: "vocab-core", type: "vocab", furi: "げんばかんとく", jp: "現場監督", id_text: "Pengawas lapangan / site supervisor", desc: "例: 現場監督は品質・安全・工程を管理する。→ Site supervisor mengelola kualitas, K3, dan jadwal di lapangan." },
  { id: 998, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "おんすいかん", jp: "温水管", id_text: "Pipa air panas", desc: "Pipa untuk mengalirkan air panas dari boiler/water heater ke titik penggunaan." },
  { id: 999, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かいへいべん", jp: "開閉弁", id_text: "Katup buka-tutup (gate valve)", desc: "Katup untuk membuka dan menutup aliran fluida sepenuhnya. 機能: 流れを開閉する." },
  { id: 1000, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "はいすいろ", jp: "排水路", id_text: "Saluran pembuangan air", desc: "Saluran untuk mengalirkan air limbah/buangan keluar dari area kerja atau bangunan." },
  { id: 1001, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "きゅうすいこう", jp: "給水口", id_text: "Lubang suplai air / water inlet", desc: "Titik masuk air bersih ke dalam sistem perpipaan gedung. Di proyek: posisi inlet dicatat di gambar teknik. Mandor:「給水口の位置を確認して」(cek posisi inlet air bersih)." },
  { id: 1003, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ちちゅうかん", jp: "地中管", id_text: "Pipa bawah tanah", desc: "Pipa yang ditanam di bawah permukaan tanah. Perlu perhatian kedalaman untuk cegah 凍結." },
  { id: 1004, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "てんじょうかん", jp: "天井管", id_text: "Pipa langit-langit / ceiling pipe", desc: "Pipa yang dipasang di atas plafon/langit-langit ruangan. Di proyek: wajib dipasang insulasi agar tidak kondensasi. Mandor:「天井管に保温材を巻いて」(balut pipa langit-langit dengan insulasi)." },
  { id: 1005, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "しすいせん", jp: "止水栓", id_text: "Keran penutup air / stopcock", desc: "Keran untuk menghentikan aliran air. 役割: 水の流れを止める. Di proyek: dicek fungsinya sebelum serah terima. Mandor:「止水栓を閉めてから作業して」(tutup keran air sebelum mulai kerja)." },
  { id: 1006, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "すいへいき", jp: "水平器", id_text: "Waterpass / spirit level", desc: "Alat pengukur kerataan/kelurusan horizontal. Digunakan saat memasang pipa dan peralatan." },
  { id: 1007, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "きゅうとうかん", jp: "給湯管", id_text: "Pipa air panas (suplai)", desc: "Pipa yang menyalurkan air panas ke keran, shower, dll. Berbeda dari 温水管 (lebih umum)." },
  { id: 1008, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かんきせん", jp: "換気扇", id_text: "Kipas ventilasi / exhaust fan", desc: "Kipas untuk mengeluarkan udara kotor dari ruangan. 目的: 汚れた空気を排出する." },
  { id: 1009, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "はいきこう", jp: "排気口", id_text: "Lubang pembuangan udara", desc: "Lubang tempat udara kotor keluar dari sistem ventilasi. Di proyek: posisi dan ukurannya harus sesuai gambar. Mandor:「排気口の位置を確認して取り付けて」(cek posisi lubang buang lalu pasang)." },
  { id: 1010, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "きゃたつ", jp: "脚立", id_text: "Tangga lipat (stepladder)", desc: "Tangga yang bisa berdiri sendiri, dilipat saat tidak digunakan. Untuk pekerjaan di ketinggian sedang." },
  { id: 1011, category: "sekou", source: "vocab-general", type: "vocab", furi: "はしご", jp: "梯子", id_text: "Tangga (ladder)", desc: "Tangga panjang yang disandarkan ke dinding. Untuk akses ke tempat tinggi." },
  { id: 1012, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ぱいぷれんち", jp: "パイプレンチ", id_text: "Kunci pipa (pipe wrench)", desc: "Kunci khusus bergigi untuk memutar dan mengencangkan pipa besi/baja." },
  { id: 1013, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "もんきーれんち", jp: "モンキーレンチ", id_text: "Kunci inggris (adjustable wrench)", desc: "Kunci yang bisa disesuaikan bukaannya untuk berbagai ukuran baut dan mur." },
  { id: 1014, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "うすいかん", jp: "雨水管", id_text: "Pipa pembuangan air hujan", desc: "Pipa untuk mengalirkan air hujan dari atap ke saluran drainase. 役割: 雨水を排水する." },
  { id: 1015, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "れいきゃくとう", jp: "冷却塔", id_text: "Menara pendingin (cooling tower)", desc: "Peralatan untuk mendinginkan air sirkulasi sistem AC. 役割: 循環水を冷やす." },
  { id: 1016, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かんきこう", jp: "換気口", id_text: "Lubang ventilasi", desc: "Lubang pada dinding/langit-langit untuk sirkulasi udara segar." },
  { id: 1017, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ほーす", jp: "ホース", id_text: "Selang (hose)", desc: "Pipa fleksibel untuk mengalirkan air atau fluida. Terbuat dari karet atau PVC." },
  { id: 1018, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "れいふうかん", jp: "冷風管", id_text: "Pipa udara dingin / cold air duct", desc: "Saluran yang mengalirkan udara dingin dari AC ke ruangan. Di proyek: wajib diinsulasi mencegah kondensasi. Mandor:「冷風管の断熱材を確認して」(cek insulasi pipa udara dingin)." },
  { id: 1019, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "おんぷうかん", jp: "温風管", id_text: "Pipa udara panas / hot air duct", desc: "Saluran yang mengalirkan udara panas dari pemanas ke ruangan." },
  { id: 1020, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "ちちゅうけーぶる", jp: "地中ケーブル", id_text: "Kabel bawah tanah", desc: "Kabel listrik yang ditanam di bawah tanah, biasanya dalam konduit pelindung." },
  { id: 1021, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "ちじょうけーぶる", jp: "地上ケーブル", id_text: "Kabel di atas tanah", desc: "Kabel listrik yang dipasang di permukaan tanah atau di atas permukaan." },
  { id: 1022, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "かくうけーぶる", jp: "架空ケーブル", id_text: "Kabel udara / overhead cable", desc: "Kabel listrik yang dibentangkan di atas tiang (電柱). Paling umum di jalanan Jepang." },
  { id: 1023, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ぐりる", jp: "グリル", id_text: "Grill (penutup ventilasi)", desc: "Penutup berlubang pada saluran udara/ventilasi untuk mengatur arah aliran udara." },
  { id: 1024, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "てんじょうない", jp: "天井内", id_text: "Bagian dalam plafon / ceiling space", desc: "Ruang tersembunyi di atas plafon tempat pipa, kabel, dan duct dipasang." },
  { id: 1025, category: "setsubi_kougu", source: "vocab-general", type: "vocab", furi: "しゃこ", jp: "車庫", id_text: "Garasi", desc: "Tempat parkir kendaraan dalam bangunan. Perlu ventilasi khusus (換気) karena gas buang." },
  { id: 1026, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "おくがいろしゅつぶぶん", jp: "屋外露出部分", id_text: "Bagian terbuka di luar ruangan", desc: "Area di mana pipa/kabel terekspos langsung ke cuaca luar. Perlu perlindungan anti-UV dan anti-air." },
  { id: 1027, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "おくないろしゅつぶぶん", jp: "屋内露出部分", id_text: "Bagian terbuka di dalam ruangan", desc: "Area di mana pipa/kabel terlihat langsung di dalam ruangan (tidak tersembunyi di plafon/dinding)." },
  { id: 1028, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "かつざいのとふ", jp: "滑剤の塗布", id_text: "Pengolesan pelumas", desc: "Melumasi bagian sambungan pipa agar mudah dimasukkan. Langkah penting dalam pemasangan pipa ductile." },
  { id: 1029, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "さしくちのそうにゅう", jp: "挿し口の挿入", id_text: "Memasukkan spigot", desc: "Proses memasukkan ujung spigot pipa ke dalam socket pipa lain. Bagian dari penyambungan pipa DIP." },
  { id: 1030, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ごむわのせっと", jp: "ゴム輪のセット", id_text: "Pemasangan cincin karet", desc: "Memasang o-ring/gasket karet pada alur pipa sebelum penyambungan. Fungsi: mencegah kebocoran." },
  { id: 1031, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ごむわのいち", jp: "ゴム輪の位置", id_text: "Posisi cincin karet", desc: "Memastikan cincin karet berada pada posisi yang benar di alur pipa. Posisi salah = kebocoran." },
  { id: 1032, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "ゆうちゃくじゅんび", jp: "融着準備", id_text: "Persiapan fusi (EF welding)", desc: "Langkah-langkah persiapan sebelum proses electrofusion welding pada pipa polietilen." },
  { id: 1033, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ゆうちゃくめんのせいそう", jp: "融着面の清掃", id_text: "Membersihkan permukaan fusi", desc: "Membersihkan area yang akan difusi dari kotoran/minyak agar sambungan sempurna." },
  { id: 1034, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "いーえふそけっと", jp: "EFソケット", id_text: "Soket EF (electrofusion socket)", desc: "Fitting elektrofusi yang memiliki kawat pemanas internal. Digunakan untuk menyambung pipa polietilen." },
  { id: 1035, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "こんとろーら", jp: "コントローラ", id_text: "Pengontrol (controller)", desc: "Alat pengontrol yang mengatur proses fusi, suhu, atau operasi mesin." },
  { id: 1036, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "いんじけーた", jp: "インジケータ", id_text: "Indikator", desc: "Alat penunjuk status atau kondisi. Contoh: indikator tekanan, suhu, atau daya." },
  { id: 1037, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "すいどうはいすいようぽりえちれんかん", jp: "水道配水用ポリエチレン管", id_text: "Pipa polietilen distribusi air", desc: "Pipa PE khusus untuk jaringan distribusi air bersih. Disambung dengan metode EF (electrofusion)." },
  { id: 1038, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ばんきんのかこう", jp: "板金の加工", id_text: "Pengolahan pelat logam", desc: "Proses memotong, menekuk, dan membentuk lembaran logam untuk ducting atau cladding." },
  { id: 1039, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "けがき", jp: "ケガキ", id_text: "Kegaki (marking layout lines)", desc: "Teknik menggaris pada permukaan logam untuk panduan pemotongan/penekukan. Alat: スクライバー." },
  { id: 1040, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かくだくとのせつぞく", jp: "角ダクトの接続", id_text: "Sambungan duct bersudut", desc: "Cara menyambung saluran udara berbentuk kotak/persegi. Metode: アングルフランジ工法 atau 共板フランジ工法." },
  { id: 1041, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "だくとのせつぞくほうほう", jp: "ダクト接続方法", id_text: "Metode sambungan duct/saluran", desc: "Cara-cara menyambung saluran udara (ducting). Termasuk metode flange dan metode tanpa flange." },
  { id: 1042, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "あんぐるふらんじ", jp: "アングルフランジ", id_text: "Flensa bersudut (angle flange)", desc: "Tipe flange dari besi siku yang dipasang di tepi duct untuk penyambungan dengan baut." },
  { id: 1043, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "わっしゃー", jp: "ワッシャー", id_text: "Ring / washer", desc: "Cincin logam tipis yang dipasang di bawah mur/baut untuk mendistribusikan tekanan." },
  { id: 1044, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "なっと", jp: "ナット", id_text: "Mur (nut)", desc: "Komponen baut berkepala segi enam dengan ulir dalam. Dipasangkan dengan ボルト." },
  { id: 1045, category: "doboku_doko", source: "vocab-lifeline", type: "vocab", furi: "くっさく", jp: "掘削", id_text: "Penggalian / excavation", desc: "Proses menggali tanah untuk pemasangan pipa atau kabel bawah tanah." },
  { id: 1046, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "かんのまいせつこうじ", jp: "管の埋設工事", id_text: "Pekerjaan menanam pipa", desc: "Pekerjaan membenamkan pipa ke dalam tanah, termasuk penggalian, pemasangan, dan penimbunan kembali." },
  { id: 1047, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "こうあつ・ていあつ", jp: "高圧・低圧", id_text: "Tegangan tinggi dan rendah", desc: "Klasifikasi tegangan listrik. 高圧: di atas 600V. 低圧: 600V ke bawah. Penting untuk keselamatan." },
  { id: 1048, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "かばー", jp: "カバー", id_text: "Cover / penutup", desc: "Penutup pelindung untuk pipa, kabel, atau peralatan. Contoh: cable cover, duct cover." },
  { id: 1049, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "おんすいき", jp: "温水器", id_text: "Pemanas air / water heater", desc: "Alat untuk memanaskan air sebelum dialirkan ke keran panas. Di proyek: perlu dicek suhu dan tekanannya. Mandor:「温水器の圧力と温度を確認して」(cek tekanan dan suhu water heater)." },
  { id: 1050, category: "haikan", source: "vocab-general", type: "vocab", furi: "ふうかん", jp: "風管", id_text: "Duct / saluran udara", desc: "Saluran untuk mengalirkan udara dalam sistem HVAC. Terbuat dari logam atau fiberglass." },
  { id: 1051, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "そうこ", jp: "倉庫", id_text: "Gudang", desc: "Tempat menyimpan barang/material. Perlu ventilasi dan penerangan yang memadai." },
  { id: 1052, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "きかいしつ", jp: "機械室", id_text: "Ruang mesin / mechanical room", desc: "Ruang khusus tempat mesin-mesin besar (boiler, chiller, pompa) dipasang." },
  { id: 1053, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "きゃっぷ", jp: "キャップ", id_text: "Cap / penutup ujung pipa", desc: "Tutup yang dipasang di ujung pipa untuk menutup aliran. Di proyek: dipasang saat pengujian tekanan. Mandor:「テスト前にキャップを取り付けて」(pasang cap sebelum uji tekanan)." },
  { id: 1054, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "こっく", jp: "コック", id_text: "Keran kecil / cock valve", desc: "Katup kecil untuk mengatur aliran, lebih kecil dari バルブ. Di proyek: buka perlahan untuk hindari water hammer. Mandor:「コックはゆっくり開いて」(buka keran perlahan-lahan)." },
  { id: 1055, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "ばりとり", jp: "バリ取り", id_text: "Deburring / hilangkan gerinda", desc: "Proses menghilangkan sisa potongan tajam (gerinda) pada logam setelah dipotong." },
  { id: 1056, category: "sekou", source: "vocab-lifeline", type: "vocab", furi: "めんをとる", jp: "面を取る", id_text: "Chamfering / buat chamfer", desc: "Proses menghaluskan tepi tajam pipa/logam dengan sudut 45° menggunakan cutter atau reamer. Di proyek: dilakukan setelah pemotongan pipa. Mandor:「切断後は必ず面取りをして」(chamfer setelah memotong)." },
  { id: 1057, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "しんえんしゅうせい", jp: "真円修正", id_text: "Koreksi kebulatan pipa", desc: "Proses mengembalikan bentuk pipa yang oval/penyok menjadi bulat sempurna." },
  { id: 1058, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "かんかこう", jp: "管加工", id_text: "Pengolahan/pemrosesan pipa", desc: "Semua proses pengerjaan pipa: potong, tekuk, chamfer, deburring, dll." },
  { id: 1059, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かりつけようせつ", jp: "仮付溶接", id_text: "Tack welding / las titik sementara", desc: "Pengelasan titik sementara untuk menahan posisi pipa sebelum las penuh." },
  { id: 1060, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かいさきかこう", jp: "開先加工", id_text: "Bevel preparation / pengolahan ujung las", desc: "Membuat sudut bevel pada ujung pipa agar hasil las penetrasi sempurna." },
  { id: 1061, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "てまげかこう", jp: "手曲げ加工", id_text: "Hand bending / tekuk manual", desc: "Menekuk pipa dengan tangan tanpa mesin. Untuk pipa kecil dan tipis." },
  { id: 1062, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "べんだーまげかこう", jp: "ベンダー曲げ加工", id_text: "Bender bending / tekuk mesin", desc: "Menekuk pipa menggunakan mesin bender. Untuk pipa besar atau tebal." },
  { id: 1063, category: "anzen", source: "vocab-lifeline", type: "vocab", furi: "てんけん", jp: "点検", id_text: "Pengecekan rutin / routine inspection", desc: "Pemeriksaan rutin berkala pada peralatan dan instalasi. Di proyek: wajib dilakukan sebelum mulai bekerja. Mandor:「作業前に点検を忘れないで」(jangan lupa cek rutin sebelum kerja)." },
  { id: 1064, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かんとつぎてのそうにゅう・こてい", jp: "管と継手の挿入・固定", id_text: "Memasukkan & mengencangkan pipa-fitting", desc: "Proses memasukkan pipa ke fitting lalu mengencangkan/memfiksasi sambungan." },
  { id: 1065, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ちじょうかん", jp: "地上管", id_text: "Pipa di atas tanah", desc: "Pipa yang dipasang di permukaan tanah, bukan dikubur. Di proyek: perlu perlindungan anti-UV dan anti-benturan. Mandor:「地上管は保護カバーをつけて」(pasang cover pelindung di pipa atas tanah)." },
  { id: 1066, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "れいきゃくき", jp: "冷却器", id_text: "Cooler / alat pendingin", desc: "Alat atau perangkat untuk mendinginkan fluida atau udara. Di proyek: perlu dicek kapasitas dan kondisi kerjanya. Mandor:「冷却器の動作を確認して」(cek kondisi kerja alat pendingin)." },
  { id: 1067, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "てこうぐ", jp: "手工具", id_text: "Perkakas tangan (hand tools)", desc: "Alat kerja yang dioperasikan dengan tangan tanpa motor/listrik. Contoh: obeng, palu, tang." },
  { id: 1068, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "さんろスイッチ", jp: "3路スイッチ", id_text: "Saklar dua arah (two-way switch)", desc: "Saklar yang bisa mengontrol satu lampu dari 2 lokasi berbeda. Sering dipasang di tangga atau koridor panjang." },
  { id: 1069, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "よんろスイッチ", jp: "4路スイッチ", id_text: "Saklar empat arah (four-way switch)", desc: "Saklar tambahan yang dipasang di antara 2 buah 3路スイッチ. Memungkinkan kontrol dari 3+ lokasi." },
  { id: 1070, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "たんきょくスイッチ", jp: "単極スイッチ", id_text: "Saklar tunggal (single-pole switch)", desc: "Saklar paling sederhana — nyala/mati dari 1 lokasi saja. Di proyek: dipasang di dekat pintu masuk ruangan. Mandor:「単極スイッチの位置を確認して取り付けて」(cek posisi lalu pasang saklar tunggal)." },
  { id: 1071, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "テープまき", jp: "テープ巻き", id_text: "Gulungan isolasi (tape winding)", desc: "Proses membalut sambungan kabel dengan selotip isolasi. Di proyek: wajib dilakukan setiap sambungan kabel listrik. Mandor:「テープ巻きをしっかりして絶縁して」(balut rapi agar terisolasi dengan baik)." },
  { id: 1072, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "ほごテープ", jp: "保護テープ", id_text: "Pita pelindung (protective tape)", desc: "Pita untuk melindungi kabel/pipa dari gesekan atau kerusakan fisik. Berbeda dari 絶縁テープ." },
  { id: 1073, category: "denki", source: "vocab-lifeline", type: "vocab", furi: "けっそくバンド", jp: "結束バンド", id_text: "Cable tie / pengikat kabel", desc: "Tali plastik untuk mengikat dan merapikan kumpulan kabel listrik." },
  { id: 1074, category: "denki", source: "vocab-general", type: "vocab", furi: "しせん", jp: "支線", id_text: "Jalur percabangan (branch line)", desc: "Kabel cabang yang menyalurkan listrik dari 幹線 ke peralatan individual." },
  { id: 1075, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "きゅうきファン", jp: "吸気ファン", id_text: "Kipas isap (intake fan)", desc: "Kipas yang menghisap udara dari luar ke dalam ruangan. Berbeda dari 排気ファン (exhaust fan)." },
  { id: 1076, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "ぼうしんゴム", jp: "防振ゴム", id_text: "Karet anti-getar (vibration damper)", desc: "Karet yang dipasang di bawah mesin AC/kompresor untuk menyerap getaran." },
  { id: 1077, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "きゅうおんざい", jp: "吸音材", id_text: "Material penyerap suara", desc: "Bahan yang menyerap gelombang suara untuk mengurangi kebisingan di dalam ruangan." },
  { id: 1078, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "くうきせいじょうき", jp: "空気清浄機", id_text: "Pembersih udara (air purifier)", desc: "Alat untuk memurnikan udara di ruangan dengan menyaring debu & partikel." },
  { id: 1079, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "さぎょうとう", jp: "作業灯", id_text: "Lampu kerja (work light)", desc: "Lampu portabel untuk menerangi area kerja gelap di lokasi konstruksi." },
  { id: 1080, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "そうすいポンプ", jp: "送水ポンプ", id_text: "Pompa air bersih (water supply pump)", desc: "Pompa untuk mengalirkan air bersih ke sistem distribusi gedung." },
  { id: 1081, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "はいすいポンプ", jp: "排水ポンプ", id_text: "Pompa air limbah (drainage pump)", desc: "Pompa untuk mengalirkan air limbah/kotor dari gedung ke saluran pembuangan." },
  { id: 1082, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "れいきゃくポンプ", jp: "冷却ポンプ", id_text: "Pompa pendingin (cooling pump)", desc: "Pompa untuk mengalirkan air pendingin di sistem AC sentral atau chiller. Di proyek: perlu dicek putaran dan tekanannya. Mandor:「冷却ポンプの圧力を確認して」(cek tekanan pompa pendingin)." },
  { id: 1083, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "おんすいじゅんかんポンプ", jp: "温水循環ポンプ", id_text: "Pompa sirkulasi air panas", desc: "Pompa untuk mensirkulasikan air panas di sistem pemanas gedung." },
  { id: 1084, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ポリブテンかん", jp: "ポリブテン管", id_text: "Pipa polibuten (polybutene pipe)", desc: "Pipa plastik fleksibel, tahan korosi, dipakai untuk suplai air panas & dingin." },
  { id: 1085, category: "haikan", source: "vocab-general", type: "vocab", furi: "なまりかん", jp: "鉛管", id_text: "Pipa timah (lead pipe)", desc: "Pipa dari timah, dulu dipakai untuk suplai air. Sekarang jarang dipakai karena bahaya kesehatan." },
  { id: 1086, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "きゅうすいたんく", jp: "給水タンク", id_text: "Tangki air bersih (water supply tank)", desc: "Tangki penampung air bersih di gedung, biasanya di atap atau ruang bawah tanah." },
  { id: 1087, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "パイプバンド", jp: "パイプバンド", id_text: "Pipe band / pengikat pipa", desc: "Pengikat logam untuk memfiksasi pipa ke dinding atau langit-langit." },
  { id: 1088, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "モップ", jp: "モップ", id_text: "Mop / alat pel", desc: "Alat pembersih lantai, digunakan untuk membersihkan lokasi kerja." },
  { id: 1089, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "たらい", jp: "たらい", id_text: "Baskom (basin)", desc: "Wadah besar untuk mencuci atau menampung air di lokasi konstruksi. Di proyek: digunakan untuk cuci tangan dan peralatan. Mandor:「たらいを使って道具を洗って」(gunakan baskom untuk cuci peralatan)." },
  { id: 1090, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "はしごきゃたつ", jp: "梯子脚立", id_text: "Tangga lipat (folding ladder)", desc: "Tangga yang bisa dilipat, digunakan untuk pekerjaan di ketinggian rendah." },
  { id: 1091, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ゴムパッド", jp: "ゴムパッド", id_text: "Bantalan karet (rubber pad)", desc: "Bantalan karet untuk peredam atau alas anti-selip pada peralatan." },
  { id: 1092, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "シートガスケット", jp: "シートガスケット", id_text: "Gasket lembaran (sheet gasket)", desc: "Gasket berbentuk lembaran untuk mencegah kebocoran pada sambungan flensa." },
  { id: 1093, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "かんしょうざい", jp: "緩衝材", id_text: "Material peredam benturan (cushioning material)", desc: "Bahan untuk melindungi peralatan atau pipa dari benturan fisik." },
  { id: 1094, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "だんさだい", jp: "段差台", id_text: "Platform bertingkat (step platform)", desc: "Platform kecil bertingkat sebagai pijakan untuk pekerjaan di ketinggian rendah." },
  { id: 1095, category: "tsushin", source: "vocab-lifeline", type: "vocab", furi: "ひかりケーブルちちゅうはいせん", jp: "光ケーブル地中配線", id_text: "Pengabelan kabel optik bawah tanah", desc: "Pemasangan kabel serat optik di dalam tanah melalui 管路 atau 共同溝." },
  { id: 1096, category: "haikan", source: "vocab-lifeline", type: "vocab", furi: "かしつき", jp: "加湿器", id_text: "Humidifier / pelembab udara", desc: "Alat untuk menambah kelembaban udara ruangan. Bagian dari sistem HVAC." },
  { id: 1097, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "すぷりんくらーへっど", jp: "スプリンクラーヘッド", id_text: "Kepala sprinkler pemadam api", desc: "例: スプリンクラーヘッドは火災時に熱で溶栓が溶けて自動放水する。→ Kepala sprinkler meleleh saat suhu tinggi dan memancarkan air secara otomatis. Ada dua jenis: 開放型 (terbuka) dan 閉鎖型 (tertutup)." },
  { id: 1098, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "かいほうがたすぷりんくらー", jp: "開放型スプリンクラー", id_text: "Sprinkler jenis terbuka (open)", desc: "例: 開放型スプリンクラーは舞台や劇場など広い空間に使われる。→ Sprinkler terbuka digunakan di panggung atau ruang besar; semua kepala menyembur serentak saat katup utama dibuka." },
  { id: 1099, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "へいさがたすぷりんくらー", jp: "閉鎖型スプリンクラー", id_text: "Sprinkler jenis tertutup (closed)", desc: "例: 閉鎖型スプリンクラーは感熱部が溶けた箇所だけ放水する。→ Sprinkler tertutup hanya menyembur di kepala yang terkena panas; paling umum digunakan di gedung bertingkat." },
  { id: 1100, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "さどうしきかんちき", jp: "差動式感知器", id_text: "Detektor panas diferensial", desc: "例: 差動式感知器は温度が急激に上昇したときに作動する。→ Detektor diferensial aktif ketika suhu naik dengan cepat; cocok untuk ruangan yang suhunya normal stabil." },
  { id: 1101, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "ていおんしきかんちき", jp: "定温式感知器", id_text: "Detektor suhu tetap (fixed-temperature)", desc: "例: 定温式感知器は設定温度（例：60℃）に達すると作動する。→ Detektor suhu tetap aktif saat mencapai suhu yang sudah ditentukan; cocok untuk dapur atau ruang boiler." },
  { id: 1102, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "こうでんしきかんちき", jp: "光電式感知器", id_text: "Detektor asap fotoelektrik", desc: "例: 光電式感知器は煙が光の通路を遮ることで作動する。→ Detektor fotoelektrik mendeteksi asap yang menghalangi sinar cahaya; efektif untuk asap pekat dari api membara lambat." },
  { id: 1103, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "いおんかしきかんちき", jp: "イオン化式感知器", id_text: "Detektor asap ionisasi", desc: "例: イオン化式感知器は微小な煙粒子でも早期に感知できる。→ Detektor ionisasi mendeteksi partikel asap halus sejak dini; sensitif terhadap api nyala terbuka yang cepat menyebar." },
  { id: 1104, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "じどうかさいほうちせつび", jp: "自動火災報知設備", id_text: "Sistem alarm kebakaran otomatis", desc: "例: 自動火災報知設備は感知器・発信機・受信機・ベルで構成される。→ Sistem ini terdiri dari detektor, tombol manual, panel penerima, dan bel; wajib dipasang di gedung tertentu sesuai 消防法." },
  { id: 1105, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "かんこうき", jp: "緩降機", id_text: "Alat turun perlahan / slow descender", desc: "例: 緩降機はロープを体に巻いて窓から安全に降下する避難器具だ。→ Alat evakuasi yang memungkinkan pengguna turun dari jendela secara perlahan dengan tali; digunakan satu orang per waktu." },
  { id: 1106, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "ひなんはしご", jp: "避難はしご", id_text: "Tangga evakuasi darurat", desc: "例: 避難はしごは窓に取り付けて外壁を伝って降りる避難器具だ。→ Tangga evakuasi dipasang di jendela untuk turun menyusuri dinding luar gedung saat lift tidak bisa digunakan." },
  { id: 1107, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "きゅうじょぶくろ", jp: "救助袋", id_text: "Kantong/seluncur evakuasi darurat", desc: "例: 救助袋は布製の袋状トンネルに入って建物外に脱出する器具だ。→ Berbentuk terowongan kain; penghuni masuk ke dalam dan meluncur turun ke titik aman di luar gedung." },
  { id: 1108, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "ぼうかど", jp: "防火戸", id_text: "Pintu tahan api (fire door)", desc: "例: 防火戸は火災時に自動閉鎖して延焼を防ぐ構造を持つ。→ Pintu tahan api menutup otomatis saat kebakaran untuk menghambat penyebaran api dan asap antar zona; bagian dari 防火区画." },
  { id: 1109, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "ぼうかだんぱー", jp: "防火ダンパー", id_text: "Fire damper (katup pemadam di ducting)", desc: "例: 防火ダンパーはダクトが防火区画を貫通する部分に設置する。→ Dipasang di titik duct yang menembus dinding tahan api; menutup otomatis saat sensor meleleh akibat panas untuk mencegah api merambat lewat ducting." },
  { id: 1110, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "れんけつさんすいせつび", jp: "連結散水設備", id_text: "Sistem sprinkler terhubung (siamese)", desc: "例: 連結散水設備は地下街などで消防隊が外部から送水する設備だ。→ Digunakan di area bawah tanah; unit pemadam memompakan air dari luar ke jaringan pipa dalam gedung melalui sambungan siamese." },
  { id: 1111, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "れんけつそうすいかん", jp: "連結送水管", id_text: "Pipa suplai air terhubung (standpipe)", desc: "例: 連結送水管は11階以上の高層建築に設置義務がある。→ Standpipe yang memungkinkan petugas pemadam menyambungkan selang di setiap lantai; wajib di gedung tinggi sesuai peraturan 消防法." },
  { id: 1112, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "しょうかぽんぷ", jp: "消火ポンプ", id_text: "Pompa pemadam kebakaran", desc: "例: 消火ポンプは加圧送水装置として屋内消火栓やスプリンクラーに水を供給する。→ Pompa pemadam menyuplai air bertekanan ke sistem hidran dan sprinkler; dilengkapi 性能試験装置 untuk pengujian berkala." },
  { id: 1113, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "ひじょうとう", jp: "非常灯", id_text: "Lampu darurat (emergency light)", desc: "例: 非常灯は停電時でも自動点灯して室内を照らす照明設備だ。→ Lampu yang menyala otomatis saat listrik padam; wajib dipasang di koridor dan tangga darurat agar penghuni bisa bergerak aman." },
  { id: 1114, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "ゆうどうとう", jp: "誘導灯", id_text: "Lampu penunjuk jalur evakuasi", desc: "例: 誘導灯は「EXIT」や矢印マークで避難方向を示す緑色の照明だ。→ Lampu hijau bertanda panah atau EXIT yang memandu penghuni menuju pintu darurat; berbeda dari 非常灯 yang berfungsi sebagai penerangan umum." },
  { id: 1115, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "はっしんき", jp: "発信機", id_text: "Tombol alarm kebakaran manual", desc: "例: 発信機は人が火災を発見した際に手動で押して警報を鳴らす装置だ。→ Manual call point; ditekan oleh orang yang melihat api untuk mengaktifkan alarm; biasanya berwarna merah dan dipasang di koridor tiap lantai." },
  { id: 1116, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "じゅしんき", jp: "受信機", id_text: "Panel penerima alarm kebakaran", desc: "例: 受信機は感知器や発信機からの信号を受けて警報を表示・発報する中枢装置だ。→ Panel utama sistem alarm kebakaran yang menampilkan lokasi kebakaran dan mengaktifkan bel; biasanya di ruang penjaga gedung." },
  { id: 1117, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "はいえんせつび", jp: "排煙設備", id_text: "Sistem pembuangan asap kebakaran", desc: "例: 排煙設備は火災時に煙を屋外に排出して避難経路を確保する設備だ。→ Sistem exhaust asap yang menjaga koridor tetap bersih dari asap selama evakuasi; terdiri dari damper, kipas, dan shaft khusus asap." },
  { id: 1118, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "ふんまつしょうかき", jp: "粉末消火器", id_text: "Tabung pemadam bubuk kering (portable)", desc: "例: 粉末消火器はABC火災すべてに対応できる万能型の携帯消火器だ。→ Tabung pemadam portabel berisi bubuk kering; efektif untuk kebakaran kelas A (padat), B (cair/gas), dan C (listrik)." },
  { id: 1119, category: "shoubou", source: "vocab-exam", type: "vocab", furi: "しょうぼうようすい", jp: "消防用水", id_text: "Cadangan air untuk pemadam kebakaran", desc: "例: 消防用水は敷地内に一定量の水を貯留しておく消防設備の一種だ。→ Tangki atau kolam cadangan air yang wajib tersedia di lokasi tertentu; digunakan sebagai sumber air alternatif saat pasokan PDAM tidak cukup." },
  { id: 1120, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "ぼうかくかく", jp: "防火区画", id_text: "Zona tahan api / fire compartment", desc: "例: 防火区画は耐火構造の壁・床・防火戸で建物を区切った区域だ。→ Gedung dibagi menjadi zona-zona tahan api untuk membatasi penyebaran api; diatur dalam 建築基準法 berdasarkan luas lantai dan fungsi bangunan." },
  { id: 1121, category: "shoubou", source: "vocab-supplementary", type: "vocab", furi: "たいかこうぞう", jp: "耐火構造", id_text: "Struktur / konstruksi tahan api", desc: "例: 耐火構造は一定時間火熱に耐えられる壁・柱・床などの建築構造だ。→ Konstruksi yang mampu menahan panas api selama waktu tertentu tanpa runtuh; standar ditetapkan dalam 建築基準法 untuk gedung bertingkat dan fasilitas publik." },
  { id: 1122, category: "hoon", source: "vocab-exam", type: "vocab", furi: "ろっくうーる", jp: "ロックウール", id_text: "Rock wool / wol batu", desc: "例: ロックウールはグラスウールより耐熱温度が高く、約600℃まで使用できる。→ Rock wool tahan panas lebih tinggi dari glass wool, bisa digunakan hingga ±600°C. Terbuat dari basalt/batu terak, lebih berat tapi lebih tahan api." },
  { id: 1123, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "びーずほうぽりすちれんふぉーむ", jp: "ビーズ法ポリスチレンフォーム", id_text: "EPS / styrofoam bead method", desc: "例: ビーズ法ポリスチレンフォーム（EPS）は発泡ビーズを型に入れて成形した断熱材だ。→ EPS dibentuk dari butiran polistirena yang dipanaskan dalam cetakan. Ringan dan murah, tapi daya serap air lebih tinggi dibanding XPS." },
  { id: 1124, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "おしだしほうぽりすちれんふぉーむ", jp: "押出法ポリスチレンフォーム", id_text: "XPS / extruded polystyrene foam", desc: "例: 押出法ポリスチレンフォーム（XPS）は連続押出成形のため、吸水率が低く床断熱に多用される。→ XPS diproduksi dengan ekstrusi kontinu sehingga berstruktur sel tertutup rapat, tahan air, dan kuat tekan tinggi." },
  { id: 1125, category: "hoon", source: "vocab-exam", type: "vocab", furi: "こうしつうれたんふぉーむ", jp: "硬質ウレタンフォーム", id_text: "Rigid urethane foam (board/panel)", desc: "例: 硬質ウレタンフォームボードは熱伝導率が非常に低く、薄くても高い断熱性能を発揮する。→ Papan busa uretan keras memiliki nilai λ sangat rendah (~0.022 W/mK), efisien untuk ruang sempit. Beda dengan吹付けウレタン yang disemprotkan di tempat." },
  { id: 1126, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ふぇのーるふぉーむ", jp: "フェノールフォーム", id_text: "Phenolic foam / busa fenolik", desc: "例: フェノールフォームは断熱材の中で最も熱伝導率が低い部類に入り、難燃性も高い。→ Busa fenolik termasuk insulasi dengan λ terendah (~0.020 W/mK) dan sangat tahan api. Digunakan pada bangunan berperforma tinggi dan pipa suhu tinggi." },
  { id: 1127, category: "hoon", source: "vocab-exam", type: "vocab", furi: "ぱーらいとほおんざい", jp: "パーライト保温材", id_text: "Perlite insulation material", desc: "例: パーライト保温材は膨張させた真珠岩を原料とし、高温配管や機器の保温に使われる。→ Insulasi perlit terbuat dari obsidian/batu vulkanik yang dipanaskan hingga mengembang." },
  { id: 1128, category: "hoon", source: "vocab-exam", type: "vocab", furi: "がいそうざい", jp: "外装材", id_text: "Jacketing material / material pelapis luar", desc: "例: 保温材の外装材には、アルミ・亜鉛鉄板・ステンレスなどが使われる。→ Material penutup luar lapisan insulasi pipa/duct untuk melindungi dari cuaca dan benturan fisik." },
  { id: 1129, category: "hoon", source: "vocab-exam", type: "vocab", furi: "あるみがいそう", jp: "アルミ外装", id_text: "Aluminum jacketing (outer cladding)", desc: "例: 屋外露出配管の保温仕上げには、軽量で耐候性のあるアルミ外装が多く採用される。→ Jacketing aluminium ringan dan tahan karat, umum dipakai pada pipa outdoor." },
  { id: 1130, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ぼうしつそう", jp: "防湿層", id_text: "Vapor barrier layer", desc: "例: 冷水管の保冷工事では、外部からの湿気侵入を防ぐため防湿層を設ける。→ Lapisan penghalang uap dipasang pada sistem insulasi pipa dingin untuk mencegah uap air masuk ke dalam insulasi yang menyebabkan kondensasi dan korosi." },
  { id: 1131, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ぼうろこうじ", jp: "防露工事", id_text: "Anti-condensation insulation work", desc: "例: 冷房ダクトや冷水配管には結露防止のために防露工事が必要だ。→ Pekerjaan insulasi khusus yang bertujuan mencegah pembentukan embun (kondensasi) pada permukaan pipa/duct dingin. Berbeda dengan 保温工事 yang fokus pada retensi panas." },
  { id: 1132, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "しんしゅくつぎてかばー", jp: "伸縮継手カバー", id_text: "Expansion joint cover", desc: "例: 配管の伸縮継手部分には、熱膨張に対応できる伸縮継手カバーを取り付ける。→ Cover khusus yang dipasang pada sambungan ekspansi pipa, dirancang untuk mengikuti gerakan termal." },
  { id: 1133, category: "hoon", source: "vocab-exam", type: "vocab", furi: "ほおんとう", jp: "保温筒", id_text: "Pre-formed pipe insulation section", desc: "例: 保温筒は配管の外径に合わせて半円形に成形された保温材で、2枚合わせて取り付ける。→ Insulasi pipa berbentuk silinder yang sudah dicetak setengah lingkaran, dipasang memeluk pipa." },
  { id: 1134, category: "hoon", source: "vocab-exam", type: "vocab", furi: "ほおんたい", jp: "保温帯", id_text: "Insulation band / blanket strip", desc: "例: バルブやフランジなど複雑な形状の箇所には保温筒の代わりに保温帯を巻き付けて施工する。→ Strip insulasi fleksibel (blanket) yang dililitkan pada bagian pipa tidak beraturan seperti valve, fitting, dan flensa yang tidak bisa memakai 保温筒" },
  { id: 1135, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "あえんてっせん", jp: "亜鉛鉄線", id_text: "Galvanized binding wire", desc: "例: 保温筒を固定するために亜鉛鉄線で一定間隔に巻き縛りを行う。→ Kawat besi berlapis seng digunakan untuk mengikat lapisan insulasi pipa agar tidak bergeser sebelum dipasang jacketing." },
  { id: 1136, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ねつでんどうりつ", jp: "熱伝導率", id_text: "Thermal conductivity (λ value)", desc: "例: 熱伝導率（λ値）が低いほど断熱性能が高く、フェノールフォームはλ≈0.020 W/mKと非常に低い。→ Nilai λ (lambda) menunjukkan seberapa mudah panas berpindah melalui material. Makin kecil λ, makin baik insulasinya. Satuan: W/(m·K)." },
  { id: 1137, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ねつていこう", jp: "熱抵抗", id_text: "Thermal resistance (R-value)", desc: "例: 熱抵抗（R値）は保温材の厚さを熱伝導率で割った値で、大きいほど断熱性能が高い。→ Nilai R = tebal material ÷ λ. Makin besar R, makin baik kemampuan menghambat aliran panas. Digunakan untuk menghitung kebutuhan ketebalan insulasi." },
  { id: 1138, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ねつかんりゅうりつ", jp: "熱貫流率", id_text: "Overall heat transfer coefficient (U-value)", desc: "例: 熱貫流率（U値）は壁や床全体の断熱性能を示す値で、省エネ設計の基準に使われる。→ Nilai U menunjukkan total perpindahan panas melalui seluruh lapisan dinding/lantai/atap (termasuk insulasi). Makin kecil U, makin hemat energi." },
  { id: 1139, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ほおんあつさけいさん", jp: "保温厚さ計算", id_text: "Insulation thickness calculation", desc: "例: 保温厚さ計算では、流体温度・外気温度・熱伝導率・許容熱損失を考慮して必要な保温厚さを求める。→ Perhitungan ketebalan insulasi yang diperlukan berdasarkan suhu fluida, suhu ambient, nilai λ material, dan batas kehilangan panas yang diizinkan." },
  { id: 1140, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "けつろぼうし", jp: "結露防止", id_text: "Condensation prevention (measures)", desc: "例: 冷水管では表面温度が露点を下回らないよう、十分な厚さの保冷材で結露防止を行う。→ Upaya mencegah terbentuknya embun pada permukaan pipa/duct dingin dengan memastikan suhu permukaan insulasi tetap di atas titik embun (dew point) ruangan." },
  { id: 1141, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "たいねつおんど", jp: "耐熱温度", id_text: "Heat resistance temperature (max service temp)", desc: "例: 保温材を選定する際は、配管流体の温度が保温材の耐熱温度を超えないことを確認する。→ Suhu maksimum yang dapat ditahan material insulasi tanpa mengalami degradasi. Contoh: GW ±350°C, RW ±600°C, EPS ±80°C." },
  { id: 1142, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "きゅうすいりつ", jp: "吸水率", id_text: "Water absorption rate", desc: "例: 保温材の吸水率が高いと断熱性能が著しく低下するため、屋外や多湿環境では低吸水率の材料を選ぶ。→ Persentase air yang dapat diserap material insulasi. Insulasi basah kehilangan performa drastis karena air menghantar panas jauh lebih baik." },
  { id: 1143, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ほかんつうかんすいしょり", jp: "防火区画貫通処理", id_text: "Fire compartment penetration sealing", desc: "例: 保温した配管が防火区画を貫通する場合、貫通部に耐火充填材や耐火カバーを設けなければならない。→ Penyegelan wajib pada titik pipa berinsulasi yang menembus dinding/lantai tahan api (防火区画)." },
  { id: 1144, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ほおんせこうてじゅん", jp: "保温施工手順", id_text: "Insulation installation procedure", desc: "例: 保温施工手順は一般に①下地確認→②保温材取付→③結束線固定→④防湿層施工→⑤外装仕上げの順で行う。→ Prosedur pemasangan insulasi: (1) cek permukaan pipa bersih & bebas karat, (2) pasang保温筒/保温帯, (3) ikat dengan亜鉛鉄線, (4) pasang防湿層 jika perlu, (5)" },
  { id: 1145, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ぽりえちれんふぉーむ", jp: "ポリエチレンフォーム", id_text: "Polyethylene foam insulation", desc: "例: ポリエチレンフォームは軽くて柔軟性が高く、冷媒配管や給水管の防露・保冷に広く使われる。→ Busa polietilena (PE foam) fleksibel dan ringan, cocok untuk pipa AC (冷媒管) dan pipa air dingin." },
  { id: 1146, category: "hoon", source: "vocab-exam", type: "vocab", furi: "ほれいこうじ", jp: "保冷工事", id_text: "Cold insulation work / refrigeration insulation", desc: "例: 保冷工事では、外部からの熱侵入を防ぐとともに、結露による腐食も防止しなければならない。→ Pekerjaan insulasi khusus untuk pipa/peralatan bersuhu rendah (pipa chiller, AC, freezer)." },
  { id: 1147, category: "denki", source: "vocab-exam", type: "vocab", furi: "ぶんでんばん", jp: "分電盤", id_text: "Panel distribusi / breaker box", desc: "例: 分電盤には主幹ブレーカーと複数の分岐ブレーカーが設置されている。→ Panel distribusi berisi breaker utama dan breaker-breaker cabang untuk tiap sirkuit." },
  { id: 1148, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "へんあつき", jp: "変圧器", id_text: "Transformator / trafo", desc: "例: 変圧器は高圧の電力を低圧に変換して建物内の機器に供給する。→ Transformator mengubah tegangan tinggi ke rendah untuk menyuplai daya ke peralatan dalam gedung." },
  { id: 1149, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "じゃんくしょんぼっくす", jp: "ジャンクションボックス", id_text: "Kotak sambungan / junction box", desc: "例: 電線の分岐・接続はジャンクションボックス内で行い、蓋をして保護する。→ Percabangan dan sambungan kabel dilakukan di dalam junction box, lalu ditutup untuk perlindungan." },
  { id: 1150, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "せっちていこう", jp: "接地抵抗", id_text: "Resistansi grounding / tahanan pembumian", desc: "例: D種接地工事では接地抵抗値が100Ω以下でなければならない。→ Untuk grounding jenis D, nilai resistansi pembumian tidak boleh melebihi 100Ω." },
  { id: 1151, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "ぶっしんぐ", jp: "ブッシング", id_text: "Bushing / pelindung ujung konduit", desc: "例: 電線管の管端にブッシングを取り付け、通線時に電線の被覆が傷つかないようにする。→ Bushing dipasang di ujung konduit untuk melindungi isolasi kabel saat penarikan." },
  { id: 1152, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "でんりょくりょうけい", jp: "電力量計", id_text: "KWh meter / meteran listrik", desc: "例: 電力量計は消費電力量（kWh）を積算計測する機器で、電気料金の算定に使われる。→ KWh meter mengakumulasi total konsumsi listrik dan digunakan sebagai dasar perhitungan tagihan." },
  { id: 1153, category: "denki", source: "vocab-general", type: "vocab", furi: "かんせん", jp: "幹線", id_text: "Kabel feeder utama", desc: "例: 幹線は引込口から主分電盤までを結ぶ主電力供給ラインである。→ Feeder utama adalah jalur suplai daya primer yang menghubungkan titik masukan hingga panel utama." },
  { id: 1154, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "ぶんきかいろ", jp: "分岐回路", id_text: "Sirkuit cabang / branch circuit", desc: "例: 分岐回路は分電盤から各コンセントや照明器具へ電力を分配する個別の回路である。→ Branch circuit adalah sirkuit individual yang mendistribusikan daya dari panel ke stop kontak atau lampu." },
  { id: 1155, category: "denki", source: "vocab-exam", type: "vocab", furi: "たんそう", jp: "単相", id_text: "Fase tunggal / single phase", desc: "例: 家庭用電源は単相2線式（100V）または単相3線式（100V/200V）が標準である。→ Listrik rumah tangga umumnya menggunakan single phase 2 kawat (100V) atau 3 kawat (100V/200V)." },
  { id: 1156, category: "denki", source: "vocab-general", type: "vocab", furi: "さんそう", jp: "三相", id_text: "Tiga fase / three phase", desc: "例: 大型モーターや工場設備には三相3線式200Vまたは400Vが使用される。→ Motor besar dan peralatan industri menggunakan listrik tiga fase 200V atau 400V." },
  { id: 1157, category: "denki", source: "vocab-exam", type: "vocab", furi: "きょようでんりゅう", jp: "許容電流", id_text: "Ampasitas / arus maksimum yang diizinkan", desc: "例: 電線の許容電流を超えると絶縁被覆が過熱し、火災の原因となる。→ Jika arus melebihi ampasitas kabel, isolasi akan kepanasan dan dapat menyebabkan kebakaran." },
  { id: 1158, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "ぜつえんていこうそくてい", jp: "絶縁抵抗測定", id_text: "Pengukuran resistansi isolasi (tes megger)", desc: "例: 竣工検査では絶縁抵抗測定を行い、電路の絶縁状態に異常がないことを確認する。→ Saat inspeksi akhir, tes megger dilakukan untuk memverifikasi bahwa isolasi sirkuit dalam kondisi baik." },
  { id: 1159, category: "denki", source: "vocab-general", type: "vocab", furi: "がいし", jp: "碍子", id_text: "Insulator listrik (porselen/keramik)", desc: "例: 碍子は電線を構造物に固定しながら電気的に絶縁するための部品である。→ Insulator berfungsi menjaga kabel tetap pada posisinya sekaligus memisahkannya secara elektrik dari struktur." },
  { id: 1160, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "はいせんようしゃだんき", jp: "配線用遮断器", id_text: "MCB / pemutus sirkuit kabel", desc: "例: 配線用遮断器は過電流・短絡時に回路を遮断するが、漏電には反応しない点に注意する。→ MCB memutus sirkuit saat arus lebih atau korsleting, namun tidak bereaksi terhadap kebocoran arus (butuh ELCB)." },
  { id: 1161, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "けーぶるとれい", jp: "ケーブルトレイ", id_text: "Cable tray (jalur kabel dasar tertutup)", desc: "例: ケーブルトレイは底が閉じた形状で、ケーブルラックより防塵・防水性に優れる。→ Cable tray memiliki dasar tertutup sehingga lebih tahan debu dan cipratan air dibanding cable ladder." },
  { id: 1162, category: "denki", source: "vocab-exam", type: "vocab", furi: "ていあつ", jp: "低圧", id_text: "Tegangan rendah (AC ≤600V / DC ≤750V)", desc: "例: 電気設備技術基準では交流600V以下・直流750V以下を低圧と定義している。→ Standar teknis instalasi listrik mendefinisikan tegangan rendah sebagai AC ≤600V atau DC ≤750V." },
  { id: 1163, category: "denki", source: "vocab-exam", type: "vocab", furi: "こうあつ", jp: "高圧", id_text: "Tegangan tinggi (AC 600V–7000V)", desc: "例: 交流600Vを超え7000V以下の電圧を高圧といい、工場やビルの受電設備に使われる。→ Tegangan AC di atas 600V hingga 7000V disebut tegangan tinggi, digunakan di panel penerimaan pabrik dan gedung." },
  { id: 1165, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "せっちこうじのしゅるい", jp: "接地工事の種類", id_text: "Grounding A/B/C/D — nilai resistansi berbeda-beda", desc: "例: A種（10Ω以下）・C種（10Ω以下）・D種（100Ω以下）の接地抵抗値が試験頻出。→ Nilai resistansi grounding jenis A (≤10Ω), C (≤10Ω), dan D (≤100Ω) sering muncul dalam soal ujian." },
  { id: 1166, category: "denki", source: "vocab-exam", type: "vocab", furi: "せいぎょけーぶる", jp: "制御ケーブル", id_text: "Kabel kontrol / sinyal", desc: "例: 制御ケーブルは動力ケーブルと分離して配線し、電磁ノイズによる誤作動を防ぐ。→ Kabel kontrol harus dipisah dari kabel daya untuk mencegah gangguan sinyal akibat interferensi elektromagnetik." },
  { id: 1167, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "あーすくらんぷ", jp: "アースクランプ", id_text: "Klem grounding / penjepit kabel bumi", desc: "例: アースクランプで接地線を接地棒にしっかりと固定し、良好な接地接続を確保する。→ Klem grounding menghubungkan kabel bumi ke batang grounding secara kuat dan andal." },
  { id: 1168, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "のっくあうと", jp: "ノックアウト", id_text: "Knockout / bukaan pre-cetak pada panel listrik", desc: "例: 配電盤や金属ボックスのノックアウト部分を打ち抜いて、電線管引き込み口を設ける。→ Bagian knockout pada panel dilepas untuk membuat lubang masuknya konduit kabel." },
  { id: 1169, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "でんせんのしきべつしょく", jp: "電線の識別色", id_text: "Kode warna identifikasi kabel listrik", desc: "例: 単相3線式では黒・赤（非接地側）と白（接地側中性線）が識別色の基本となる。→ Pada sistem single phase 3 kawat, hitam & merah untuk fasa aktif dan putih untuk netral (grounded)." },
  { id: 1170, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "ひきこみせん", jp: "引込線", id_text: "Kabel masukan dari tiang ke gedung (service drop)", desc: "例: 引込線は電力会社の電柱から建物の引込口まで引き渡される電線で、電力会社の管轄である。→ Kabel masukan ditarik dari tiang listrik ke gedung dan menjadi tanggung jawab perusahaan listrik." },
  { id: 1171, category: "denki", source: "vocab-exam", type: "vocab", furi: "でんきこうじし", jp: "電気工事士", id_text: "Teknisi listrik berlisensi — tingkat 1 dan 2", desc: "例: 第二種電気工事士は一般用電気工作物（交流600V以下）の電気工事を行える国家資格である。→ Lisensi teknisi listrik tingkat 2 memungkinkan pengerjaan instalasi listrik tegangan rendah (AC ≤600V)." },
  { id: 1172, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "しきりべん", jp: "仕切弁", id_text: "Gate valve / katup pintu geser", desc: "例: 仕切弁は全開か全閉で使用し、流量調節には適さない。→ Gate valve dipakai posisi buka penuh atau tutup penuh; tidak cocok untuk mengatur debit aliran." },
  { id: 1173, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "たまがたべん", jp: "玉形弁", id_text: "Globe valve / katup bola bulat", desc: "例: 玉形弁は流量調節に適しているが、圧力損失が大きい。→ Globe valve cocok untuk mengatur aliran, namun kerugian tekanannya besar dibanding gate valve." },
  { id: 1174, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ボールバルブ", jp: "ボールバルブ", id_text: "Ball valve / katup bola putar", desc: "例: ボールバルブはレバー1回転で全開・全閉でき、操作が簡単だ。→ Ball valve dapat dibuka/ditutup penuh hanya dengan memutar tuas 90°; mudah dioperasikan." },
  { id: 1175, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "バタフライバルブ", jp: "バタフライバルブ", id_text: "Butterfly valve / katup kupu-kupu", desc: "例: バタフライバルブは大口径ダクトや冷水配管の流量制御によく使われる。→ Butterfly valve sering dipakai pada pipa berdiameter besar untuk pengendalian debit air dingin." },
  { id: 1176, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ぎゃくしべん", jp: "逆止弁", id_text: "Check valve / katup non-balik", desc: "例: 逆止弁はポンプ出口に設置し、逆流を防止する。→ Check valve dipasang di sisi keluar pompa untuk mencegah aliran balik saat pompa berhenti." },
  { id: 1177, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "あんぜんべん", jp: "安全弁", id_text: "Safety / relief valve — katup pengaman tekanan", desc: "例: 安全弁は設定圧力を超えると自動的に開き、圧力を逃がす。→ Safety valve terbuka otomatis saat tekanan melebihi nilai seting, membuang kelebihan tekanan." },
  { id: 1178, category: "haikan", source: "vocab-exam", type: "vocab", furi: "フランジせつごう", jp: "フランジ接合", id_text: "Sambungan flange / flange joint", desc: "例: フランジ接合はボルト・ナットで締め付け、ガスケットで気密を保つ。→ Sambungan flange diikat baut-mur dan disekat gasket; mudah dibongkar pasang untuk perawatan." },
  { id: 1179, category: "haikan", source: "vocab-exam", type: "vocab", furi: "ソケットせつごう", jp: "ソケット接合", id_text: "Sambungan soket / socket joint", desc: "例: 塩ビ管のソケット接合では、接着剤を均一に塗布してから素早く挿入する。→ Pada sambungan soket pipa PVC, oleskan lem merata lalu masukkan pipa dengan cepat sebelum lem mengering." },
  { id: 1180, category: "haikan", source: "vocab-exam", type: "vocab", furi: "グルーブドせつごう", jp: "グルーブド接合", id_text: "Sambungan grooved / Victaulic joint", desc: "例: グルーブド接合はパイプ端に溝を加工し、カップリングとガスケットで接合するため、工期が短い。→ Sambungan grooved menggunakan alur di ujung pipa dan coupling; pengerjaan lebih cepat dibanding las." },
  { id: 1181, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ストレーナー", jp: "ストレーナー", id_text: "Strainer / saringan kotoran pipa", desc: "例: ストレーナーはポンプや機器の前に設置し、異物を取り除いて機器を保護する。→ Strainer dipasang sebelum pompa atau peralatan untuk menyaring kotoran dan melindungi komponen." },
  { id: 1182, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "レデューサー", jp: "レデューサー", id_text: "Reducer / reduser perbedaan diameter pipa", desc: "例: 異径管をつなぐときはレデューサー（径違い継手）を使用する。→ Saat menyambung pipa berbeda diameter, gunakan reducer; tersedia tipe konsentrik dan eksentrik." },
  { id: 1183, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ユニオン", jp: "ユニオン", id_text: "Union / sambungan pipa yang dapat dilepas", desc: "例: ユニオンはバルブや機器の前後に設け、取り外しを容易にする継手だ。→ Union dipasang di sisi masuk/keluar katup agar peralatan mudah dibongkar saat pemeliharaan." },
  { id: 1184, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ゆーボルト", jp: "Uボルト", id_text: "U-bolt / penjepit pipa berbentuk U", desc: "例: Uボルトは配管を支持するために使われ、適切な締め付けトルクで固定する。→ U-bolt digunakan sebagai penjepit pipa pada dudukan; kencangkan sesuai torsi yang ditentukan agar tidak merusak pipa." },
  { id: 1185, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "つりバンド", jp: "吊りバンド", id_text: "Pipe hanger band / penggantung pipa", desc: "例: 吊りバンドは天井スラブから吊りボルトで下げ、水平配管を支持する。→ Hanger band digantung dari pelat beton lewat baut gantung untuk menopang pipa horizontal di langit-langit." },
  { id: 1186, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ぼうしんつぎて", jp: "防振継手", id_text: "Anti-vibration joint / sambungan peredam getaran", desc: "例: ポンプ出口には防振継手を設け、振動が配管に伝わるのを防ぐ。→ Pasang anti-vibration joint di sambungan keluar pompa untuk mencegah getaran merambat ke jaringan pipa." },
  { id: 1187, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かとうつぎて", jp: "可とう継手", id_text: "Flexible joint / sambungan pipa fleksibel", desc: "例: 可とう継手は地震時の変位や温度変化による伸縮を吸収する。→ Flexible joint menyerap perpindahan saat gempa dan ekspansi-kontraksi akibat perubahan suhu pada sistem perpipaan." },
  { id: 1188, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "つうきかん", jp: "通気管", id_text: "Vent pipe / pipa ventilasi saluran air", desc: "例: 通気管は排水管内の空気圧を調整し、トラップの封水が破れないようにする。→ Pipa vent menstabilkan tekanan udara dalam pipa drainase agar air di dalam trap tidak tersedot habis." },
  { id: 1189, category: "haikan", source: "vocab-exam", type: "vocab", furi: "よびけい", jp: "呼び径", id_text: "Nominal diameter / ukuran nominal pipa", desc: "例: 呼び径25Aの鋼管は外径34mm、実際の内径は25mmより若干異なる。→ Pipa baja 25A berarti ukuran nominal 25 mm; diameter sebenarnya sedikit berbeda tergantung standar A atau B." },
  { id: 1190, category: "haikan", source: "vocab-exam", type: "vocab", furi: "きみつしけん", jp: "気密試験", id_text: "Air tightness test / uji kebocoran udara", desc: "例: ガス配管の気密試験では、設定圧力で所定時間保持し、圧力降下がないか確認する。→ Pada pipa gas, lakukan uji tekanan udara pada tekanan yang ditentukan dan pantau apakah ada penurunan tekanan." },
  { id: 1191, category: "haikan", source: "vocab-exam", type: "vocab", furi: "きゅうすいかん", jp: "給水管", id_text: "Pipa suplai air bersih", desc: "例: 給水管は水道本管から分岐し、各器具へ水を供給する。→ Pipa suplai air bersih bercabang dari jaringan utama PDAM dan mendistribusikan air ke setiap fixture bangunan." },
  { id: 1192, category: "haikan", source: "vocab-exam", type: "vocab", furi: "はいすいかん", jp: "排水管", id_text: "Pipa drainase / buangan air limbah", desc: "例: 排水管は適切な勾配（一般的に1/100）を確保して詰まりを防ぐ。→ Pipa drainase harus dipasang dengan kemiringan memadai (umumnya 1/100) agar aliran lancar dan tidak mampet." },
  { id: 1193, category: "haikan", source: "vocab-exam", type: "vocab", furi: "ニップル", jp: "ニップル", id_text: "Nipple / sambungan pendek berulir dua sisi", desc: "例: ニップルは両端に雄ねじが切ってあり、ソケットや機器との短距離接続に使う。→ Nipple memiliki ulir jantan di kedua ujungnya; dipakai untuk menyambung dua fitting yang berdekatan." },
  { id: 1194, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "はいかんず", jp: "配管図", id_text: "Gambar diagram perpipaan / piping diagram", desc: "例: 配管図を正しく読むことで、バルブの位置や流れの方向を把握できる。→ Dengan membaca gambar perpipaan dengan benar, kita bisa memahami posisi katup dan arah aliran dalam sistem." },
  { id: 1195, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "かんしじかなぐ", jp: "管支持金具", id_text: "Pipe support bracket / dudukan penopang pipa", desc: "例: 管支持金具の間隔は管径と材質によって異なり、施工基準で定められている。→ Jarak antara dudukan pipa ditentukan berdasarkan diameter dan material pipa sesuai standar pemasangan." },
  { id: 1196, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "すいげきさよう", jp: "水撃作用", id_text: "Water hammer / hentakan air (pukulan palu air)", desc: "例: ポンプの急停止でバルブを急閉すると水撃作用が発生し、配管を損傷させることがある。→ Water hammer terjadi saat pompa mendadak berhenti atau katup ditutup tiba-tiba, menimbulkan lonjakan tekanan yang bisa merusak pipa." },
  { id: 1197, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "おーえぬゆー（ひかりかいせんしゅうたんそうち）", jp: "ONU（光回線終端装置）", id_text: "Perangkat terminasi fiber optik sisi pelanggan", desc: "例: ONUはFTTHで光信号を電気信号に変換する装置だ。→ ONU adalah perangkat FTTH yang mengubah sinyal cahaya menjadi sinyal listrik di sisi pelanggan." },
  { id: 1198, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "おーえるてぃー（ひかりかにゅうしゃせんしゅうたんそうち）", jp: "OLT（光加入者線終端装置）", id_text: "Perangkat terminasi optik sisi ISP/sentral", desc: "例: OLTは局舎側に設置され、スプリッターを介して複数のONUを管理する。→ OLT dipasang di sisi sentral dan mengelola banyak ONU melalui splitter." },
  { id: 1199, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "しんぐるもーどふぁいばー", jp: "シングルモードファイバー", id_text: "Fiber optik mode tunggal, untuk jarak jauh", desc: "例: シングルモードファイバーは芯径約9μmで、長距離幹線通信に使われる。→ SMF berdiameter inti sekitar 9μm, digunakan untuk komunikasi trunk jarak jauh." },
  { id: 1200, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "まるちもーどふぁいばー", jp: "マルチモードファイバー", id_text: "Fiber optik multi-mode, untuk jarak dekat", desc: "例: マルチモードファイバーは芯径50または62.5μmで、構内LAN配線に用いられる。→ MMF berdiameter inti 50 atau 62.5μm, umum dipakai untuk kabel LAN dalam gedung." },
  { id: 1201, category: "tsushin", source: "vocab-exam", type: "vocab", furi: "えすしーこねくた", jp: "SCコネクタ", id_text: "Konektor fiber optik tipe SC (push-pull)", desc: "例: SCコネクタはプッシュプル式でワンタッチ着脱でき、ONU接続によく使われる。→ Konektor SC bertipe push-pull, mudah dipasang dan dilepas, sering dipakai pada sambungan ONU." },
  { id: 1202, category: "tsushin", source: "vocab-exam", type: "vocab", furi: "えるしーこねくた", jp: "LCコネクタ", id_text: "Konektor fiber optik tipe LC, lebih kecil dari SC", desc: "例: LCコネクタはSCより小型で高密度実装が可能なため、データセンターのスイッチに多用される。→ LC lebih kecil dari SC dan memungkinkan kepadatan tinggi, banyak dipakai di switch data center." },
  { id: 1203, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "えすてぃーこねくた", jp: "STコネクタ", id_text: "Konektor fiber optik tipe ST (bayonet/putar)", desc: "例: STコネクタはバヨネット式で回して固定するタイプで、配線盤への接続に古くから使われてきた。→ Konektor ST dikunci dengan memutar seperti bayonet, dahulu banyak digunakan untuk panel distribusi fiber." },
  { id: 1204, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "はんしゃそんしつ", jp: "反射損失", id_text: "Rugi daya akibat pantulan sinyal optik", desc: "例: OTDRで測定すると、コネクタ接続部では反射損失が大きく現れ、波形にスパイクが出る。→ Saat diukur dengan OTDR, sambungan konektor menunjukkan nilai refleksi tinggi berupa lonjakan pada grafik." },
  { id: 1205, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "そうにゅうそんしつ", jp: "挿入損失", id_text: "Rugi sisip akibat penyambungan komponen optik", desc: "例: コネクタや融着部の挿入損失が規定値を超えると、伝送距離が短くなり通信品質が低下する。→ Jika rugi sisip pada konektor atau sambungan fusion melebihi batas, jarak transmisi berkurang dan kualitas komunikasi menurun." },
  { id: 1206, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "でっどぞーん", jp: "デッドゾーン", id_text: "Zona buta OTDR (area tak terukur setelah refleksi)", desc: "例: OTDRのデッドゾーン内は測定不能なため、光コネクタ直後の損失は正確に読み取れない。→ Area dalam dead zone OTDR tidak dapat diukur, sehingga rugi tepat setelah konektor optik tidak terbaca dengan akurat." },
  { id: 1207, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "ぱっちぱねる", jp: "パッチパネル", id_text: "Panel distribusi dan penghubung kabel jaringan", desc: "例: パッチパネルにLANケーブルを接続し、スイッチとの配線を一か所にまとめて整理する。→ Kabel LAN dari berbagai titik disambungkan ke patch panel untuk merapikan kabel menuju switch dalam satu lokasi." },
  { id: 1208, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "えすてぃーぴーけーぶる", jp: "STPケーブル", id_text: "Kabel twisted pair berpelindung (shielded)", desc: "例: STPケーブルはシールドが電磁ノイズを遮断するため、工場などノイズの多い環境で使われる。→ STP memiliki pelindung EMI yang memblokir gangguan elektromagnetik, cocok untuk lingkungan pabrik yang banyak noise." },
  { id: 1209, category: "tsushin", source: "vocab-exam", type: "vocab", furi: "つうしんらっく", jp: "通信ラック", id_text: "Rak perangkat telekomunikasi standar 19 inci", desc: "例: 通信ラックは19インチ規格が主流で、スイッチ・パッチパネル・サーバーを搭載できる。→ Rak telekomunikasi umumnya berstandar 19 inci, mampu menampung switch, patch panel, dan server." },
  { id: 1210, category: "tsushin", source: "vocab-exam", type: "vocab", furi: "つうしんきゃびねっと", jp: "通信キャビネット", id_text: "Kabinet tertutup untuk perangkat telekomunikasi", desc: "例: 屋外設置の通信キャビネットは防水・防塵（IP55以上）構造が必要だ。→ Kabinet telekomunikasi untuk pemasangan luar ruangan harus memiliki konstruksi tahan air dan debu (IP55 ke atas)." },
  { id: 1211, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "あいでぃーえふ（ちゅうかんはいせんばん）", jp: "IDF（中間配線盤）", id_text: "Panel distribusi kabel tingkat lantai/zona", desc: "例: 大型ビルではMDFから引き出した幹線をIDFで各フロアの端末へ分岐させる。→ Di gedung besar, kabel trunk dari MDF didistribusikan via IDF ke setiap terminal di masing-masing lantai." },
  { id: 1212, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "せっちたんしばん", jp: "接地端子盤", id_text: "Panel terminal grounding perangkat komunikasi", desc: "例: 通信機器室の接地端子盤に各機器のアース線を集結させ、一点接地を確保する。→ Kabel grounding semua perangkat komunikasi dikumpulkan di panel terminal grounding guna memastikan single-point earthing." },
  { id: 1213, category: "tsushin", source: "vocab-exam", type: "vocab", furi: "ほあんき", jp: "保安器", id_text: "Pelindung jalur masuk telepon (arrester/protector)", desc: "例: 保安器は雷サージや過電流から屋内の通信機器を保護するために引き込み口に設置される。→ Hoaan-ki dipasang di titik masuk kabel untuk melindungi peralatan komunikasi dalam gedung dari lonjakan petir dan arus lebih." },
  { id: 1214, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "たんしだい", jp: "端子台", id_text: "Terminal block / blok penghubung kabel", desc: "例: 端子台に複数の電線をねじで固定し、通信回路を分岐・接続する。→ Beberapa kabel diikat dengan sekrup pada terminal block untuk membagi dan menyambungkan rangkaian komunikasi." },
  { id: 1215, category: "tsushin", source: "vocab-general", type: "vocab", furi: "せいたん", jp: "成端", id_text: "Terminasi ujung kabel (pengakhiran ujung kabel)", desc: "例: 光ケーブルの成端作業では、コネクタ取り付けと端面研磨を丁寧に行う必要がある。→ Dalam pekerjaan terminasi kabel fiber, pemasangan konektor dan pemolesan permukaan ujung serat harus dilakukan dengan teliti." },
  { id: 1216, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "しんせんたいしょう", jp: "心線対照", id_text: "Identifikasi / pelacakan pasangan inti kabel", desc: "例: 心線対照器を使って、多心ケーブルのどの心線がどの端末に対応しているかを確認する。→ Alat pelacak inti kabel digunakan untuk memastikan inti mana di dalam kabel multi-core yang terhubung ke terminal mana." },
  { id: 1217, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "ひかりけーぶるのまげはんけい", jp: "光ケーブルの曲げ半径", id_text: "Radius tikungan minimum kabel fiber optik", desc: "例: 光ケーブルの曲げ半径を規定値以下にすると光損失が急増し、最悪断線する恐れがある。→ Jika radius tikungan kabel fiber lebih kecil dari nilai minimum, rugi cahaya melonjak dan serat berisiko putus." },
  { id: 1218, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "かてごりーごいーけーぶる", jp: "Cat5eケーブル", id_text: "Kabel UTP Cat5e, mendukung hingga 1 Gbps", desc: "例: Cat5eケーブルはギガビットイーサネット（1000BASE-T）に対応し、一般オフィスLANに広く使われる。→ Kabel Cat5e mendukung Gigabit Ethernet (1000BASE-T) dan banyak digunakan untuk LAN kantor umum." },
  { id: 1219, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "かてごりーろくけーぶる", jp: "Cat6ケーブル", id_text: "Kabel UTP Cat6, mendukung 10 Gbps jarak dekat", desc: "例: Cat6ケーブルはCat5eより高周波ノイズに強く、短距離なら10ギガビットイーサネットにも対応できる。→ Kabel Cat6 lebih tahan noise frekuensi tinggi dari Cat5e dan mampu mendukung 10GbE pada jarak pendek." },
  { id: 1220, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "ひかりすぷりったー", jp: "光スプリッター", id_text: "Pembagi sinyal optik pasif untuk jaringan PON", desc: "例: PONシステムでは光スプリッターで1本の光ファイバーを複数の加入者向けに分岐させる。→ Dalam sistem PON, splitter optik membagi satu fiber menjadi jalur untuk banyak pelanggan sekaligus." },
  { id: 1221, category: "tsushin", source: "vocab-supplementary", type: "vocab", furi: "ぽん（じゅどうひかりねっとわーく）", jp: "PON（受動光ネットワーク）", id_text: "Passive Optical Network, jaringan fiber pasif", desc: "例: FTTHサービスの多くはOLTとONUを光スプリッターで接続するPON方式を採用している。→ Sebagian besar layanan FTTH menggunakan sistem PON yang menghubungkan OLT dan ONU melalui splitter optik." },
  { id: 1222, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "わくぐみあしば", jp: "枠組足場", id_text: "Scaffolding rangka (perancah pabrikasi)", desc: "例: 枠組足場は、建設工事で最も一般的に使われる仮設足場の一種です。→ Scaffolding rangka adalah jenis perancah sementara yang paling umum di proyek konstruksi. Terbuat dari panel baja pabrikasi yang dipasang vertikal dan horizontal." },
  { id: 1223, category: "anzen", source: "vocab-exam", type: "vocab", furi: "たんかんあしば", jp: "単管足場", id_text: "Scaffolding pipa tunggal", desc: "例: 単管足場は鋼管とクランプを組み合わせて組み立てる足場です。→ Scaffolding pipa tunggal dirakit dari pipa baja yang disambung dengan klem. Fleksibel untuk berbagai bentuk bangunan." },
  { id: 1224, category: "anzen", source: "vocab-exam", type: "vocab", furi: "くさびきんけつしきあしば", jp: "くさび緊結式足場", id_text: "Scaffolding sistem baji / wedge-lock", desc: "例: くさび緊結式足場は、ハンマー一本で組み立て・解体ができる足場です。→ Scaffolding sistem baji dapat dipasang dan dibongkar hanya dengan satu palu. Lebih cepat dari scaffolding pipa tunggal." },
  { id: 1225, category: "anzen", source: "vocab-exam", type: "vocab", furi: "あんぜんねっと", jp: "安全ネット", id_text: "Jaring pengaman (safety net)", desc: "例: 高所作業では、安全ネットを設置して作業員の墜落を防ぎます。→ Saat kerja di ketinggian, safety net dipasang untuk mencegah pekerja jatuh. Wajib dipasang di bawah area kerja yang berisiko." },
  { id: 1226, category: "anzen", source: "vocab-exam", type: "vocab", furi: "てすり", jp: "手すり", id_text: "Pegangan tangan / guardrail", desc: "例: 作業床の端には、高さ85cm以上の手すりを設けなければなりません。→ Di tepi platform kerja, guardrail setinggi minimal 85 cm wajib dipasang. Berfungsi mencegah pekerja jatuh dari tepi." },
  { id: 1227, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "なかさん", jp: "中さん", id_text: "Mid-rail / rel tengah scaffolding", desc: "例: 手すりと幅木の間に中さんを取り付けて、作業員の転落を防ぎます。→ Mid-rail dipasang di antara guardrail atas dan toe board untuk mencegah pekerja tergelincir jatuh. Posisi sekitar 35–50 cm dari platform." },
  { id: 1228, category: "anzen", source: "vocab-general", type: "vocab", furi: "はばき", jp: "巾木", id_text: "Toe board / papan pengaman bawah", desc: "例: 巾木を足場の端に設置することで、工具や資材の落下を防げます。→ Toe board dipasang di bagian bawah tepi scaffolding untuk mencegah alat dan material jatuh ke bawah. Tinggi minimal 10 cm." },
  { id: 1229, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "しょうこうせつび", jp: "昇降設備", id_text: "Fasilitas naik-turun (tangga/stairway)", desc: "例: 足場には、作業員が安全に昇降できる昇降設備を設けることが義務です。→ Scaffolding wajib dilengkapi fasilitas naik-turun agar pekerja dapat mengakses ketinggian dengan aman. Termasuk tangga tetap dan tangga portable." },
  { id: 1230, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "さんそのうどけい", jp: "酸素濃度計", id_text: "Alat ukur kadar oksigen", desc: "例: 密閉空間に入る前に、酸素濃度計で酸素濃度が18%以上あることを確認します。→ Sebelum memasuki ruang tertutup, konfirmasi kadar oksigen minimal 18% dengan oksimeter. Kadar di bawah 18% = bahaya kekurangan oksigen." },
  { id: 1231, category: "anzen", source: "vocab-exam", type: "vocab", furi: "りゅうかすいそ", jp: "硫化水素", id_text: "Hidrogen sulfida (H₂S)", desc: "例: 硫化水素は腐卵臭のある無色の有毒ガスで、下水道や地下工事で発生しやすいです。→ Hidrogen sulfida adalah gas beracun tak berwarna berbau telur busuk, mudah muncul di pekerjaan saluran dan bawah tanah. Batas aman: di bawah 10 ppm." },
  { id: 1232, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "ゆうがいがすけんちき", jp: "有害ガス検知器", id_text: "Detektor gas berbahaya", desc: "例: 密閉空間作業前に有害ガス検知器を使って、一酸化炭素や硫化水素の濃度を測ります。→ Sebelum kerja di ruang tertutup, ukur konsentrasi CO dan H₂S menggunakan detektor gas berbahaya. Wajib dilakukan sebelum pekerja masuk." },
  { id: 1233, category: "anzen", source: "vocab-exam", type: "vocab", furi: "そうきますく", jp: "送気マスク", id_text: "Respirator suplai udara / airline mask", desc: "例: 酸素欠乏や有毒ガスが発生する環境では、送気マスクを着用して作業します。→ Di lingkungan kekurangan oksigen atau bergas beracun, gunakan respirator suplai udara." },
  { id: 1234, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "ろっくあうとたぐあうと", jp: "ロックアウト・タグアウト", id_text: "Lockout-Tagout (LOTO) — prosedur pengamanan energi", desc: "例: 設備のメンテナンス中は、ロックアウト・タグアウトを実施して誤作動を防ぎます。→ Saat perawatan alat, terapkan prosedur LOTO untuk mencegah mesin menyala tidak sengaja. Energi dikunci (lock) dan diberi tanda peringatan (tag)." },
  { id: 1235, category: "anzen", source: "vocab-exam", type: "vocab", furi: "さぎょうしゅにんしゃ", jp: "作業主任者", id_text: "Pengawas kerja (mandated supervisor)", desc: "例: 足場組立や酸欠危険作業など、特定の危険作業には作業主任者の選任が法律で義務付けられています。→ Untuk pekerjaan berbahaya tertentu seperti pemasangan scaffolding atau ruang oksigen rendah, penunjukan pengawas kerja bersertifikat diwajibkan oleh" },
  { id: 1236, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "つーるぼっくすみーてぃんぐ", jp: "ツールボックスミーティング", id_text: "Toolbox meeting (TBM) / rapat singkat keselamatan", desc: "例: 毎朝の作業開始前にツールボックスミーティングで当日の危険ポイントを確認します。→ Setiap pagi sebelum kerja dimulai, bahaya hari itu dikonfirmasi bersama dalam toolbox meeting. Biasanya berlangsung 5–15 menit di lokasi kerja." },
  { id: 1237, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "あんぜんとうばん", jp: "安全当番", id_text: "Petugas keselamatan harian (giliran)", desc: "例: 安全当番は、当日の現場の安全状態を巡回して確認し、記録する役割を担います。→ Petugas keselamatan harian bertugas berkeliling mengecek dan mencatat kondisi keamanan lapangan. Dilakukan secara bergilir oleh anggota tim." },
  { id: 1238, category: "anzen", source: "vocab-exam", type: "vocab", furi: "あんぜんぱとろーる", jp: "安全パトロール", id_text: "Patroli inspeksi keselamatan", desc: "例: 安全パトロールでは、ヘルメット未着用や足場の異常など危険箇所を点検します。→ Dalam patroli keselamatan, dicek hal-hal seperti helm tidak dipakai atau scaffolding tidak normal. Dilakukan oleh pengawas atau tim K3 secara berkala." },
  { id: 1239, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "さぎょうてじゅんしょ", jp: "作業手順書", id_text: "Manual prosedur kerja (SOP)", desc: "例: 作業手順書には、作業の流れ・使用機材・注意事項・緊急時の対応が記載されています。→ Manual prosedur kerja memuat alur pekerjaan, peralatan yang digunakan, peringatan keselamatan, dan langkah darurat." },
  { id: 1240, category: "anzen", source: "vocab-exam", type: "vocab", furi: "ついらくせいしようきぐ", jp: "墜落制止用器具", id_text: "Alat pencegah jatuh / harness", desc: "例: 高さ2m以上の作業では、墜落制止用器具（フルハーネス型）の使用が義務化されています。→ Penggunaan alat pencegah jatuh tipe full-harness diwajibkan saat bekerja di ketinggian 2 meter atau lebih. Regulasi diperketat sejak 2019." },
  { id: 1241, category: "anzen", source: "vocab-exam", type: "vocab", furi: "ひらいらっか", jp: "飛来・落下", id_text: "Bahaya benda terbang / jatuh dari atas", desc: "例: 飛来・落下による事故を防ぐため、上部作業中は下の立入を禁止します。→ Untuk mencegah kecelakaan akibat benda terbang atau jatuh, masuk ke area bawah pekerjaan atas dilarang. Helm dan safety shoes wajib di seluruh area konstruksi." },
  { id: 1242, category: "anzen", source: "vocab-exam", type: "vocab", furi: "ねっちゅうしょう", jp: "熱中症", id_text: "Heat stroke / serangan panas", desc: "例: 夏の屋外作業では、こまめな水分・塩分補給で熱中症を予防します。→ Saat kerja luar ruangan di musim panas, minum air dan suplemen garam secara rutin mencegah heat stroke." },
  { id: 1243, category: "anzen", source: "vocab-exam", type: "vocab", furi: "ふんじん", jp: "粉じん", id_text: "Debu / partikel berbahaya (dust)", desc: "例: 粉じんが多い現場では、防じんマスクを着用して作業します。→ Di lokasi dengan debu tinggi, gunakan masker anti-debu saat bekerja. Paparan debu jangka panjang dapat menyebabkan pneumokoniosis (penyakit paru akibat debu)." },
  { id: 1244, category: "anzen", source: "vocab-exam", type: "vocab", furi: "りすくあせすめんと", jp: "リスクアセスメント", id_text: "Penilaian risiko (risk assessment)", desc: "例: 作業前にリスクアセスメントを行い、危険を特定・評価・対策して記録します。→ Sebelum kerja, lakukan penilaian risiko: identifikasi bahaya, evaluasi tingkat risiko, tetapkan tindakan pencegahan, dan dokumentasikan." },
  { id: 1245, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "ひやりはっと", jp: "ヒヤリハット", id_text: "Near miss / hampir celaka", desc: "例: ヒヤリハット報告書を提出・共有することで、重大事故の予防につながります。→ Melaporkan dan berbagi near miss membantu mencegah kecelakaan serius." },
  { id: 1246, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "きけんよちくんれん", jp: "KYT（危険予知訓練）", id_text: "Pelatihan prediksi bahaya (KYT)", desc: "例: KYTでは、作業前にチーム全員で現場の危険箇所を指摘し合い、対策を決めます。→ Dalam KYT, seluruh tim saling menunjukkan titik berbahaya di lokasi sebelum kerja dimulai dan menetapkan tindakan pencegahan." },
  { id: 1247, category: "doboku_haisui", source: "vocab-supplementary", type: "vocab", furi: "こうかんくい", jp: "鋼管杭", id_text: "Tiang pancang pipa baja", desc: "例: 軟弱地盤では鋼管杭を支持層まで打ち込む。→ Pada tanah lunak, tiang pipa baja dipancang hingga lapisan pendukung. Jenis tiang pracetak berbahan baja, kuat menahan beban lateral." },
  { id: 1248, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ピーシーぐい", jp: "PC杭", id_text: "Tiang pancang beton prategang", desc: "例: PC杭はプレストレストコンクリート製の既製杭である。→ PC杭 adalah tiang pracetak dari beton prategang (prestressed concrete). Digunakan sebagai pondasi dalam di tanah berbatu." },
  { id: 1249, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ピーエイチシーぐい", jp: "PHC杭", id_text: "Tiang beton prategang tegangan tinggi", desc: "例: PHC杭はPC杭より強度が高く、大型建築物の基礎に使われる。→ PHC杭 memiliki kekuatan lebih tinggi dari PC杭, dipakai untuk pondasi bangunan besar. PHC = Pretensioned spun High strength Concrete." },
  { id: 1250, category: "sekou", source: "vocab-exam", type: "vocab", furi: "しーとぱいる", jp: "シートパイル", id_text: "Sheet pile / turap baja", desc: "例: シートパイルを連続して打ち込み、土砂の崩壊を防ぐ。→ Sheet pile dipancang berurutan untuk mencegah longsornya tanah. Sama dengan 鋼矢板; istilah katakana lebih umum di lapangan." },
  { id: 1251, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "あーすあんかー", jp: "アースアンカー", id_text: "Angkur tanah / ground anchor", desc: "例: 急傾斜地の擁壁にはアースアンカーを使って引張力を確保する。→ Pada dinding penahan di lereng curam, earth anchor digunakan untuk menahan gaya tarik. Kabel atau batang baja ditanam ke tanah keras." },
  { id: 1252, category: "kenchiku_shiage", source: "vocab-exam", type: "vocab", furi: "あすふぁるとぼうすい", jp: "アスファルト防水", id_text: "Waterproofing aspal", desc: "例: 屋上の防水にはアスファルト防水が多く使われる。→ Waterproofing aspal banyak digunakan pada atap beton. Metode ini melapis permukaan dengan lembaran aspal yang dipanaskan atau dilekatkan (トーチ工法)." },
  { id: 1253, category: "kenchiku_shiage", source: "vocab-exam", type: "vocab", furi: "しーとぼうすい", jp: "シート防水", id_text: "Waterproofing lembaran (sheet)", desc: "例: シート防水は合成ゴムや塩化ビニルのシートを貼り付ける工法である。→ Sheet waterproofing menggunakan lembaran karet sintetis atau PVC yang ditempelkan ke permukaan. Lebih cepat pasang dibanding aspal." },
  { id: 1254, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "とまくぼうすい", jp: "塗膜防水", id_text: "Waterproofing lapisan coating", desc: "例: 塗膜防水はウレタン系材料をローラーで塗布して防水層を形成する。→ Coating waterproofing membentuk lapisan kedap air dengan cara mengoleskan material uretan menggunakan roller. Cocok untuk bentuk permukaan tidak beraturan." },
  { id: 1255, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "しつじゅんようじょう", jp: "湿潤養生", id_text: "Perawatan beton dengan pembasahan", desc: "例: 打設後のコンクリートは湿潤養生を行い、乾燥によるクラックを防ぐ。→ Setelah pengecoran, beton dirawat dengan menjaga kelembaban (湿潤養生) untuk mencegah retak akibat pengeringan terlalu cepat." },
  { id: 1256, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "じょうきようじょう", jp: "蒸気養生", id_text: "Perawatan beton dengan uap panas", desc: "例: プレキャスト製品は蒸気養生で短期間に強度を出す。→ Produk precast (pracetak) menggunakan steam curing (蒸気養生) untuk mencapai kekuatan awal dalam waktu singkat. Suhu dijaga sekitar 60–80°C." },
  { id: 1257, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ひまくようじょう", jp: "被膜養生", id_text: "Perawatan beton dengan lapisan membran", desc: "例: 被膜養生剤を散布して、コンクリート表面から水分が蒸発するのを防ぐ。→ Agen membran disemprotkan ke permukaan beton untuk mencegah penguapan air. Metode ini tidak memerlukan penyiraman berkala." },
  { id: 1258, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "すぺーさー", jp: "スペーサー", id_text: "Penyangga tulangan / beton tahu", desc: "例: スペーサーはかぶり厚さを一定に保つために鉄筋の下に置く。→ Spacer (beton tahu) diletakkan di bawah tulangan untuk menjaga ketebalan selimut beton tetap sesuai standar. Terbuat dari mortar atau plastik." },
  { id: 1259, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "うちつぎめ", jp: "打ち継ぎ目", id_text: "Sambungan pengecoran beton", desc: "例: 打ち継ぎ目は構造的弱点になりやすいため、位置を適切に設けること。→ Construction joint (打ち継ぎ目) adalah batas antara pengecoran lama dan baru, yang rawan menjadi titik lemah struktural jika tidak dikerjakan dengan benar." },
  { id: 1260, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "せぱれーたー", jp: "セパレーター", id_text: "Pengikat jarak bekisting (form tie)", desc: "例: セパレーターは両側の型枠を一定間隔に保持する金属製スペーサーである。→ Separator adalah pengikat logam yang menjaga jarak antar dua sisi bekisting agar tetap konsisten saat pengecoran beton." },
  { id: 1261, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "かたわくりけいざい", jp: "型枠離型剤", id_text: "Minyak/agen pelepas bekisting", desc: "例: 型枠離型剤を塗布することで、脱型時にコンクリートが型枠に張り付くのを防ぐ。→ Release agent (離型剤) dioleskan ke permukaan bekisting sebelum pengecoran agar mudah dilepas setelah beton mengeras." },
  { id: 1262, category: "kenchiku_kutai", source: "vocab-exam", type: "vocab", furi: "すらんぷしけん", jp: "スランプ試験", id_text: "Uji slump (kekentalan beton segar)", desc: "例: 生コンの品質確認のためにスランプ試験を現場で実施する。→ Slump test dilakukan di lapangan untuk mengecek konsistensi (kekentalan) beton segar sebelum pengecoran. Nilai slump yang lebih tinggi berarti beton lebih encer." },
  { id: 1263, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ぶりーでぃんぐ", jp: "ブリーディング", id_text: "Bleeding (naiknya air ke permukaan beton)", desc: "例: ブリーディングが過剰だと表面強度が低下し、クラックの原因となる。→ Bleeding adalah fenomena air naik ke permukaan beton segar akibat gravitasi. Jika berlebihan, permukaan beton menjadi lemah dan mudah retak." },
  { id: 1264, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "じゃんか", jp: "ジャンカ", id_text: "Sarang lebah / cacat beton keropos", desc: "例: 締固め不足や生コンの分離によってジャンカが発生する。→ Janka (honeycomb) adalah cacat pada beton dimana terdapat rongga-rongga yang terlihat di permukaan, akibat pemadatan yang kurang atau beton terlalu encer." },
  { id: 1265, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "くらっく", jp: "クラック", id_text: "Retak / retakan pada beton", desc: "例: 乾燥収縮や過大な応力によってコンクリートにクラックが生じる。→ Retakan (クラック) pada beton bisa disebabkan oleh penyusutan pengeringan, pembebanan berlebih, atau perawatan yang tidak tepat." },
  { id: 1266, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "てっきんたんさき", jp: "鉄筋探査機", id_text: "Alat deteksi/pencari tulangan beton", desc: "例: 鉄筋探査機（電磁波レーダー）でコンクリート内部の鉄筋位置を確認する。→ Rebar detector menggunakan gelombang elektromagnetik untuk mendeteksi posisi dan kedalaman tulangan di dalam beton tanpa merusaknya." },
  { id: 1267, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "べーすぷれーと", jp: "ベースプレート", id_text: "Pelat dasar kolom baja", desc: "例: 鉄骨柱の下部にベースプレートを設け、アンカーボルトで基礎と固定する。→ Base plate adalah pelat baja yang dipasang di bawah kolom baja, disambungkan ke pondasi beton menggunakan anchor bolt untuk menyalurkan beban." },
  { id: 1268, category: "sekou", source: "vocab-exam", type: "vocab", furi: "くいうちき", jp: "杭打ち機", id_text: "Mesin pemancang tiang", desc: "例: 杭打ち機（パイルドライバー）で鋼管杭を所定深さまで打ち込む。→ Mesin pemancang (pile driver) digunakan untuk memancang tiang ke dalam tanah hingga kedalaman yang ditentukan." },
  { id: 1269, category: "doboku_haisui", source: "vocab-supplementary", type: "vocab", furi: "えきじょうか", jp: "液状化", id_text: "Likuefaksi / pencairan tanah", desc: "例: 地震時に砂質地盤が液状化すると、構造物が沈下・傾斜する恐れがある。→ Likuefaksi (液状化) terjadi saat gempa bumi menyebabkan tanah berpasir jenuh air kehilangan kekuatan dan berperilaku seperti cairan." },
  { id: 1270, category: "doboku_haisui", source: "vocab-supplementary", type: "vocab", furi: "じたいりょく", jp: "地耐力", id_text: "Daya dukung tanah", desc: "例: 建物を建てる前に地耐力を確認し、必要に応じて地盤改良を行う。→ Daya dukung tanah (地耐力) adalah kemampuan tanah menahan beban dari struktur di atasnya. Diukur melalui uji N-value (ボーリング調査) atau uji plat beban." },
  { id: 1271, category: "kenchiku_kutai", source: "vocab-supplementary", type: "vocab", furi: "あんかーぼると", jp: "アンカーボルト", id_text: "Baut angkur / anchor bolt", desc: "例: アンカーボルトはベースプレートと基礎コンクリートを緊結する締結部材である。→ Anchor bolt adalah baut yang ditanam di pondasi beton untuk mengikat base plate kolom baja." },
  { id: 1272, category: "kenchiku_shiage", source: "vocab-exam", type: "vocab", furi: "せっこうボード", jp: "石膏ボード", id_text: "Papan gipsum / gypsum board", desc: "例: 石膏ボードは内壁や天井の仕上げに広く使われる。→ Papan gipsum banyak dipakai untuk finishing dinding dalam dan plafon. Material ringan, mudah dipotong, dan memiliki sifat tahan api (準不燃). Disebut juga プラスターボード." },
  { id: 1273, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "けいりょうてっこつしたじ", jp: "軽量鉄骨下地", id_text: "Rangka baja ringan (LGS) untuk dinding/plafon", desc: "例: 軽量鉄骨下地にビスで石膏ボードを留めて壁を仕上げる。→ Papan gipsum disekrup ke rangka baja ringan untuk membentuk dinding finishing. Rangka ini disusun dari ランナー (runner) dan スタッド (stud)." },
  { id: 1274, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "てんじょうしたじ", jp: "天井下地", id_text: "Rangka substrat plafon", desc: "例: 天井下地は野縁受けと野縁で構成され、その上に石膏ボードを張る。→ Rangka plafon terdiri dari penggantung (野縁受け) dan besi furring (野縁), lalu papan gipsum dipasang di atasnya sebagai penutup plafon." },
  { id: 1275, category: "setsubi_kougu", source: "vocab-exam", type: "vocab", furi: "システムてんじょう", jp: "システム天井", id_text: "Plafon sistem / suspended ceiling modular", desc: "例: オフィスビルのシステム天井は照明・空調・防災設備を一体で収める。→ Plafon sistem pada gedung perkantoran mengintegrasikan pencahayaan, AC, dan peralatan kebakaran dalam satu modul yang dapat dibongkar-pasang untuk perawatan." },
  { id: 1276, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "フリーアクセスフロア", jp: "フリーアクセスフロア", id_text: "Lantai akses bebas / raised access floor", desc: "例: OAフロアは床下空間に電気・LANケーブルを自由に配線できる二重床構造だ。→ Raised floor (OAフロア) adalah struktur lantai ganda yang memungkinkan kabel listrik dan LAN diatur bebas di ruang bawah lantai gedung perkantoran." },
  { id: 1277, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ALCパネル", jp: "ALCパネル", id_text: "Panel beton ringan otoklaf (ALC)", desc: "例: ALCパネルは軽量で断熱性・耐火性に優れ、外壁や床・屋根に使用される。→ Panel ALC (Autoclaved Lightweight Concrete) sangat ringan, memiliki sifat insulasi panas dan tahan api yang baik, digunakan untuk dinding luar, lantai, dan" },
  { id: 1278, category: "sekou", source: "vocab-exam", type: "vocab", furi: "カーテンウォール", jp: "カーテンウォール", id_text: "Dinding tirai / curtain wall", desc: "例: 高層ビルのカーテンウォールは建物の荷重を負担しない外壁で、アルミや金属パネルで構成される。→ Curtain wall pada gedung tinggi adalah dinding luar non-struktural yang tidak menanggung beban, biasanya terbuat dari aluminium atau panel logam." },
  { id: 1279, category: "sekou", source: "vocab-exam", type: "vocab", furi: "サイディング", jp: "サイディング", id_text: "Siding / pelapis dinding eksterior", desc: "例: 窯業系サイディングは戸建て住宅の外壁仕上げとして広く使われている。→ Siding berbahan keramik (窯業系) adalah penutup dinding luar yang paling umum untuk rumah tinggal di Jepang. Tersedia juga jenis metal dan kayu." },
  { id: 1280, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "コーキング", jp: "コーキング", id_text: "Caulking / pengisian celah sambungan", desc: "例: サイディングのパネル継ぎ目にコーキング材を充填して防水性を確保する。→ Material caulking diisikan pada celah sambungan antar panel siding untuk memastikan ketahanan air." },
  { id: 1281, category: "sekou", source: "vocab-exam", type: "vocab", furi: "プライマー", jp: "プライマー", id_text: "Primer / lapisan dasar perekat", desc: "例: シーリング材を充填する前に、目地面にプライマーを塗布して接着力を高める。→ Primer dioleskan ke permukaan celah sebelum aplikasi sealant untuk meningkatkan daya rekat. Tanpa primer, sealant dapat mudah terlepas dari substrat." },
  { id: 1282, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "バックアップざい", jp: "バックアップ材", id_text: "Backer rod / pengisi belakang sealant", desc: "例: 目地が深い場合はバックアップ材を入れてシーリングの厚みを適切に調整する。→ Jika celah terlalu dalam, backer rod (biasanya busa polyethylene bulat)" },
  { id: 1283, category: "kenchiku_shiage", source: "vocab-exam", type: "vocab", furi: "ぼうすいシート", jp: "防水シート", id_text: "Membran / lembaran waterproof", desc: "例: 屋根の仕上げ材の下に防水シートを敷いて雨水の浸入を防ぐ。→ Membran waterproof dipasang di bawah penutup atap untuk mencegah rembesan air hujan masuk ke struktur bangunan. Termasuk jenis アスファルトルーフィング." },
  { id: 1284, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "みずきり", jp: "水切り", id_text: "Flashing / talang pengarah air hujan", desc: "例: 外壁の最下部に水切りを取り付けて、雨水が壁内部へ回り込まないようにする。→ Flashing dipasang di bagian bawah dinding luar untuk mengalirkan air hujan menjauhi struktur bangunan." },
  { id: 1285, category: "kenchiku_shiage", source: "vocab-exam", type: "vocab", furi: "めじ", jp: "目地", id_text: "Nat / celah sambungan antar tile", desc: "例: タイル貼り完了後、目地材（セメント系）を充填して目地を仕上げる。→ Setelah pemasangan tile selesai, material nat (umumnya berbasis semen) diisikan untuk mengisi celah antar tile. Lebar目地 biasanya 3〜10mm tergantung jenis tile." },
  { id: 1286, category: "kenchiku_shiage", source: "vocab-exam", type: "vocab", furi: "モルタル", jp: "モルタル", id_text: "Mortar / adukan semen dan pasir", desc: "例: 外壁タイルの下地にモルタルを塗り付け、平滑に均してからタイルを張る。→ Mortar dioleskan sebagai dasar sebelum tile dipasang, kemudian diratakan. Komposisi umum: semen : pasir = 1 : 3 (volumetrik)." },
  { id: 1287, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "ふきつけとそう", jp: "吹付け塗装", id_text: "Pengecatan semprot / spray painting", desc: "例: 吹付け塗装はエアスプレーで塗料を霧状に吹き付け、広い面積を均一に仕上げる工法だ。→ Pengecatan semprot menggunakan semprotan udara bertekanan untuk menghasilkan lapisan cat yang merata di area luas seperti dinding beton dan fasad bangunan." },
  { id: 1288, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ビニルゆかシート", jp: "ビニル床シート", id_text: "Lembaran lantai vinil", desc: "例: トイレや厨房などの水まわりにはビニル床シートが多く使用される。→ Lembaran lantai vinil banyak dipakai di toilet dan dapur karena tahan air, mudah dibersihkan, dan relatif mudah dipasang." },
  { id: 1289, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ちょうじゃくシート", jp: "長尺シート", id_text: "Long sheet: lembaran lantai panjang minim sambung", desc: "例: 廊下や通路に長尺シートを施工すると継ぎ目が少なく衛生的に管理できる。→ Long sheet banyak dipakai di koridor dan area publik karena sambungan sedikit sehingga mudah dijaga kebersihannya." },
  { id: 1290, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "したじしょり", jp: "下地処理", id_text: "Persiapan substrat / surface preparation", desc: "例: 塗装工事の前に下地処理として汚れ・旧塗膜・錆を除去して素地を整える。→ Sebelum pengecatan atau pemasangan finishing, substrat dibersihkan dari kotoran, cat lama, dan karat. Kualitas下地処理 menentukan daya tahan lapisan finishing." },
  { id: 1291, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "かべクロス", jp: "壁クロス", id_text: "Wallcovering vinil / wallpaper dinding", desc: "例: 壁クロスは下地ボードにのりで貼り付ける内装仕上げの最終工程だ。→ Wallpaper vinil (壁クロス) ditempel pada papan gipsum menggunakan lem sebagai tahap akhir finishing interior. Jenis paling umum adalah ビニルクロス (vinyl cloth)." },
  { id: 1292, category: "kenchiku_shiage", source: "vocab-exam", type: "vocab", furi: "スタッド", jp: "スタッド", id_text: "Stud / tiang vertikal baja ringan LGS", desc: "例: LGS工事でスタッドをランナーに差し込んで間仕切り壁の骨組みを組む。→ Stud adalah profil baja ringan berbentuk C yang dimasukkan secara vertikal ke dalam runner untuk membentuk rangka dinding partisi." },
  { id: 1293, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "ランナー", jp: "ランナー", id_text: "Runner / rel horizontal LGS di lantai dan plafon", desc: "例: ランナーは床と天井にアンカーで固定され、スタッドを保持するU形の鋼材だ。→ Runner adalah profil baja berbentuk U yang dipasang di lantai dan plafon menggunakan anchor, berfungsi sebagai landasan dan penahan untuk stud pada sistem" },
  { id: 1294, category: "hoon", source: "vocab-supplementary", type: "vocab", furi: "ロックウールきゅうおんばん", jp: "ロックウール吸音板", id_text: "Panel rockwool / ceiling tile penyerap suara", desc: "例: ロックウール吸音板はシステム天井に多く使われ、吸音性と防火性を兼ね備える。→ Panel akustik rockwool banyak dipakai pada sistem plafon karena dapat menyerap suara sekaligus memiliki sifat tahan api." },
  { id: 1295, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "ふねんざいりょう", jp: "不燃材料", id_text: "Material tidak dapat terbakar (non-combustible)", desc: "例: 石膏ボードやALCパネルは建築基準法で不燃材料として認定されている。→ Papan gipsum dan panel ALC diakui sebagai材料 tidak dapat terbakar (不燃材料) berdasarkan Undang-Undang Standar Bangunan Jepang." },
  { id: 1296, category: "kenchiku_shiage", source: "vocab-supplementary", type: "vocab", furi: "せっちゃくこうほう", jp: "接着工法", id_text: "Metode pemasangan adhesif (tile/board)", desc: "例: 内装タイルの接着工法では有機系接着剤を下地に塗布してタイルを張り付ける。→ Pada metode adhesif untuk tile interior, lem organik dioleskan ke substrat kemudian tile ditempel langsung." },
  { id: 1297, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "はんまーどりる", jp: "ハンマードリル", id_text: "Bor rotary / hammer drill", desc: "例: ハンマードリルはコンクリートへの穴あけや斫り作業に使う。→ Hammer drill digunakan untuk mengebor beton dan pekerjaan bongkaran (斫り). Wajib pakai pelindung telinga saat operasi." },
  { id: 1298, category: "sekou", source: "vocab-exam", type: "vocab", furi: "いんぱくとどらいばー", jp: "インパクトドライバー", id_text: "Impact driver / bor sekrup bertenaga", desc: "例: インパクトドライバーはビスやボルトを素早く締め付ける電動工具だ。→ Impact driver adalah alat listrik untuk mengencangkan baut dan sekrup dengan cepat. Berbeda dari drill driver biasa karena memberikan pukulan rotasi." },
  { id: 1299, category: "sekou", source: "vocab-exam", type: "vocab", furi: "ういんち", jp: "ウインチ", id_text: "Winch / derek penarik bermotor", desc: "例: ウインチで重い資材を引き上げる作業では、ロープの点検が欠かせない。→ Saat menarik material berat dengan winch, pemeriksaan tali/rantai dan kapasitas beban wajib dilakukan sebelum operasi." },
  { id: 1300, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ぱいぷばいす", jp: "パイプバイス", id_text: "Ragum pipa / pipe vise", desc: "例: パイプバイスで鋼管を固定してからねじ切り加工を行う。→ Kencangkan pipa baja di ragum pipa (pipe vise) sebelum melakukan threading/penyayatan ulir dengan ねじ切り機. Cegah pipa bergeser saat dikerjakan." },
  { id: 1301, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ぱいぷべんだー", jp: "パイプベンダー", id_text: "Pembengkok pipa / pipe bender", desc: "例: パイプベンダーで鋼管を所定の角度に曲げる。最小曲げ半径に注意すること。→ Gunakan pipe bender untuk menekuk pipa baja ke sudut yang ditentukan. Perhatikan radius tekukan minimum agar pipa tidak penyok atau retak." },
  { id: 1302, category: "sekou", source: "vocab-exam", type: "vocab", furi: "ゆあつじゃっき", jp: "油圧ジャッキ", id_text: "Dongkrak hidrolik / hydraulic jack", desc: "例: 油圧ジャッキで重量物を持ち上げて位置を調整する。→ Dongkrak hidrolik digunakan untuk mengangkat beban berat atau menyesuaikan posisi material konstruksi. Pastikan landasan stabil sebelum mengoperasikan." },
  { id: 1303, category: "denki", source: "vocab-supplementary", type: "vocab", furi: "あっちゃくこうぐ", jp: "圧着工具", id_text: "Alat crimping / tang krimping kabel", desc: "例: 圧着工具で電線端子を確実に圧着し、接触不良を防ぐ。→ Gunakan alat crimping untuk menjepitkan terminal kabel dengan benar guna mencegah kontak yang buruk. Warna gagang: merah=端子用, kuning=リングスリーブ用." },
  { id: 1304, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "とるくれんち", jp: "トルクレンチ", id_text: "Kunci torsi / torque wrench", desc: "例: フランジボルトの締め付けはトルクレンチで規定トルク値を守る。→ Saat mengencangkan baut flens, gunakan kunci torsi sesuai nilai torsi yang ditentukan dalam spesifikasi. Mencegah over-torque yang bisa merusak ulir atau sambungan." },
  { id: 1305, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "しゃこまんりき", jp: "シャコ万力", id_text: "Klem-C / C-clamp / ragum penjepit", desc: "例: 溶接作業中、シャコ万力で部材を固定して位置ずれを防ぐ。→ Saat pengelasan, gunakan C-clamp untuk memfix material agar tidak bergeser. Juga disebut Cクランプ. Digunakan saat menjepit papan, profil baja, atau pipa selama pengerjaan." },
  { id: 1306, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "たっぷ・だいす", jp: "タップ・ダイス", id_text: "Tap & dies / alat pembuat ulir", desc: "例: タップで金属に雌ねじを切り、ダイスで丸棒に雄ねじを切る。→ Tap digunakan untuk membuat ulir dalam (mur/雌ねじ), sedangkan dies untuk membuat ulir luar (baut/雄ねじ) pada batang logam. Keduanya adalah alat threading manual." },
  { id: 1307, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "かなきりのこ", jp: "金切りのこ", id_text: "Gergaji besi / hacksaw", desc: "例: 金切りのこは鋼管や鉄棒の手動切断に使う。刃は消耗したら交換する。→ Gergaji besi digunakan untuk memotong pipa baja, besi batang, atau profil logam secara manual. Bilah gergaji (刃) dapat diganti saat sudah aus." },
  { id: 1308, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ほーるそー", jp: "ホールソー", id_text: "Hole saw / mata bor pemotong lubang bulat", desc: "例: ホールソーで壁や天井に配管用の円形穴を開ける。→ Hole saw digunakan untuk membuat lubang bulat besar di dinding atau plafon untuk jalur pipa (配管) atau kabel listrik. Dipasang pada electric drill." },
  { id: 1309, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "がすばーなー", jp: "ガスバーナー", id_text: "Pembakar gas / gas torch / burner", desc: "例: ガスバーナーは銅管のろう付けや防水材の炙り加工に使用する。→ Gas torch digunakan untuk penyolderan pipa tembaga (ろう付け/brazing) atau pemanasan material waterproofing. Pastikan ventilasi cukup dan jauh dari bahan mudah terbakar." },
  { id: 1310, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ぜつえんていこうけい", jp: "絶縁抵抗計", id_text: "Megger / alat ukur tahanan isolasi kabel", desc: "例: 絶縁抵抗計（メガー）で電線の絶縁状態を確認し、漏電がないかを検査する。→ Megger digunakan untuk mengukur resistansi isolasi kabel listrik. Memastikan tidak ada kebocoran arus (漏電) ke ground sebelum sistem dinyalakan." },
  { id: 1311, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "せっちていこうけい", jp: "接地抵抗計", id_text: "Earth tester / alat ukur tahanan grounding", desc: "例: 接地抵抗計でアース極の接地抵抗値が規定値以下かを確認する。→ Earth tester digunakan untuk mengukur nilai tahanan grounding (接地/アース) dan memastikan instalasi pembumian memenuhi standar keamanan listrik." },
  { id: 1312, category: "sekou", source: "vocab-exam", type: "vocab", furi: "でんどうどりる", jp: "電動ドリル", id_text: "Bor listrik / electric drill", desc: "例: 電動ドリルは木材・金属・コンクリートへの穴あけに使う汎用工具だ。→ Bor listrik adalah alat serbaguna untuk mengebor kayu, logam, dan beton." },
  { id: 1313, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "えあこんぷれっさー", jp: "エアコンプレッサー", id_text: "Kompresor udara / air compressor", desc: "例: エアコンプレッサーは釘打ち機やエアブロー清掃など幅広い作業に使用される。→ Kompresor udara digunakan untuk berbagai pekerjaan: alat tembak paku (釘打ち機), pembersihan debu dengan udara bertekanan, dan pengecatan semprot." },
  { id: 1314, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "こんくりーとかったー", jp: "コンクリートカッター", id_text: "Gergaji beton / concrete cutter / floor saw", desc: "例: コンクリートカッターで床スラブに配管用の溝を切る。粉塵対策と給水が必須。→ Concrete cutter digunakan untuk memotong alur jalur pipa di lantai beton. Wajib menggunakan proteksi debu (防塵マスク) dan pendingin air saat operasi." },
  { id: 1315, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ちっぱー", jp: "チッパー", id_text: "Pahat pneumatik / chipping hammer", desc: "例: チッパーはコンクリートのはつり作業や古い仕上げ材の除去に使う。→ Chipping hammer (chipper) digunakan untuk membongkar beton (斫り/はつり) atau mengupas material finishing lama. Gunakan goggles dan pelindung telinga saat operasi." },
  { id: 1316, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "じぐそー", jp: "ジグソー", id_text: "Jigsaw / gergaji listrik serabut", desc: "例: ジグソーは曲線や複雑な形状の切断に適した電動のこぎりだ。→ Jigsaw adalah gergaji listrik yang cocok untuk memotong bentuk melengkung atau pola kompleks pada kayu, lembaran logam, atau papan gipsum di lokasi konstruksi." },
  { id: 1317, category: "sekou", source: "vocab-exam", type: "vocab", furi: "ぼーるばん", jp: "ボール盤", id_text: "Mesin bor duduk / drill press", desc: "例: ボール盤は精密な穴あけ作業に使う据え置き型の電動ドリルだ。→ Drill press adalah mesin bor stasioner yang digunakan untuk pengeboran presisi di bengkel atau area persiapan material. Lebih akurat dari electric drill genggam." },
  { id: 1318, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "ぼうばくこうぐ", jp: "防爆工具", id_text: "Alat anti-percikan / explosion-proof tools", desc: "例: ガス管周辺での作業には防爆工具を使用し、火花による爆発を防ぐ。→ Alat anti-percikan (防爆工具) wajib digunakan saat bekerja di sekitar pipa gas atau ruang dengan gas mudah terbakar, untuk mencegah ledakan akibat percikan api." },
  { id: 1319, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "すこや", jp: "スコヤ", id_text: "Siku presisi / try square / engineer's square", desc: "例: スコヤで部材の直角を確認してから溶接や加工を行う。→ Try square (スコヤ) digunakan untuk memeriksa sudut siku-siku (90°) pada material sebelum pengelasan atau pengerjaan lebih lanjut." },
  { id: 1320, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "ぷらいやー", jp: "プライヤー", id_text: "Tang jepit / pliers", desc: "例: プライヤーはナットや配管継手など円筒物をつかんで回す作業に使う。→ Pliers digunakan untuk mencengkeram dan memutar mur, fitting pipa, atau benda silindris lainnya." },
  { id: 1321, category: "haikan", source: "vocab-exam", type: "vocab", furi: "しんくうぽんぷ", jp: "真空ポンプ", id_text: "Pompa vakum / vacuum pump", desc: "例: 真空ポンプは冷媒配管の施工後、真空引きして水分・空気を除去するために使う。→ Pompa vakum digunakan setelah pemasangan pipa refrigerant (冷媒管) untuk mengosongkan udara dan kelembaban melalui proses vakumisasi (真空引き)" },
  { id: 1322, category: "career", source: "vocab-supplementary", type: "vocab", furi: "せこうけいかくしょ", jp: "施工計画書", id_text: "Dokumen rencana pelaksanaan konstruksi", desc: "例: 施工計画書は着工前に作成し、監理者に提出する。→ Dokumen rencana pelaksanaan dibuat sebelum mulai kerja dan diserahkan ke pengawas. Mencakup metode kerja, jadwal, keselamatan, dan pengelolaan kualitas." },
  { id: 1323, category: "career", source: "vocab-exam", type: "vocab", furi: "ケーワイシート", jp: "KYシート", id_text: "Lembar prediksi bahaya (KY)", desc: "例: 朝礼でKYシートを記入し、今日の危険ポイントを共有した。→ Saat apel pagi, lembar KY diisi dan titik bahaya hari itu dibagikan ke semua pekerja. Berbeda dengan KYボード — シート adalah formulir tertulis per sesi." },
  { id: 1324, category: "career", source: "vocab-exam", type: "vocab", furi: "しんきにゅうじょうしゃカード", jp: "新規入場者カード", id_text: "Kartu pendataan pekerja baru", desc: "例: 新規入場者カードには、氏名・緊急連絡先・保有資格などを記入する。→ Kartu pekerja baru diisi dengan nama, kontak darurat, dan sertifikasi yang dimiliki. Wajib diserahkan sebelum pertama kali masuk lokasi." },
  { id: 1325, category: "career", source: "vocab-supplementary", type: "vocab", furi: "グリーンファイル", jp: "グリーンファイル", id_text: "Green file — kumpulan dokumen keselamatan", desc: "例: グリーンファイルには、安全衛生計画書・KY記録・作業員名簿などが綴られる。→ Green file memuat rencana K3, catatan KY, daftar tenaga kerja, dll. Disimpan di lokasi dan diperiksa oleh pengawas proyek." },
  { id: 1327, category: "career", source: "vocab-supplementary", type: "vocab", furi: "バーチャート", jp: "バーチャート", id_text: "Jadwal balok (Gantt chart konstruksi)", desc: "例: バーチャートは見やすいが、作業の関連性が分かりにくい。→ Jadwal balok mudah dibaca tapi tidak menunjukkan ketergantungan antar pekerjaan. Cocok untuk proyek sederhana atau laporan kemajuan ke klien." },
  { id: 1328, category: "career", source: "vocab-supplementary", type: "vocab", furi: "ネットワークこうていひょう", jp: "ネットワーク工程表", id_text: "Jadwal jaringan / CPM schedule", desc: "例: ネットワーク工程表でクリティカルパスを特定し、遅延リスクを管理した。→ Dengan jadwal jaringan, jalur kritis diidentifikasi untuk mengelola risiko keterlambatan. Menunjukkan urutan dan ketergantungan antar pekerjaan." },
  { id: 1329, category: "career", source: "vocab-supplementary", type: "vocab", furi: "できだか", jp: "出来高", id_text: "Nilai pekerjaan yang telah selesai (progres)", desc: "例: 今月の出来高は契約金額の40%に達した。→ Progres bulan ini mencapai 40% dari nilai kontrak. Digunakan untuk penagihan bertahap (partial billing) dan laporan kemajuan proyek." },
  { id: 1330, category: "career", source: "vocab-supplementary", type: "vocab", furi: "ぶがかり", jp: "歩掛り", id_text: "Koefisien produktivitas tenaga kerja", desc: "例: 配管工事の歩掛りは、1mあたり何人工かかるかを示す。→ Koefisien kerja pipa menunjukkan berapa orang-hari yang dibutuhkan per meter. Digunakan untuk estimasi biaya tenaga kerja dalam RAB." },
  { id: 1331, category: "career", source: "vocab-supplementary", type: "vocab", furi: "ちょくせつかせつ", jp: "直接仮設", id_text: "Pekerjaan sementara langsung (per lokasi)", desc: "例: 直接仮設には、各工事専用の足場・型枠支保工などが含まれる。→ Pekerjaan sementara langsung mencakup perancah dan bekisting yang khusus untuk satu area pekerjaan tertentu. Berbeda dari 共通仮設." },
  { id: 1332, category: "career", source: "vocab-supplementary", type: "vocab", furi: "きょうつうかせつ", jp: "共通仮設", id_text: "Pekerjaan sementara bersama (seluruh proyek)", desc: "例: 共通仮設には、現場事務所・トイレ・電力引込などが含まれる。→ Pekerjaan sementara bersama mencakup kantor lapangan, toilet, dan sambungan listrik yang dipakai semua pihak di proyek." },
  { id: 1333, category: "career", source: "vocab-supplementary", type: "vocab", furi: "げんかかんり", jp: "原価管理", id_text: "Manajemen biaya / pengendalian harga pokok", desc: "例: 原価管理では、実際原価と計画原価を比較して差異を分析する。→ Dalam manajemen biaya, biaya aktual dibandingkan dengan biaya rencana untuk menganalisis selisih. Termasuk dalam 4 pilar施工管理 (Q, C, D, S)." },
  { id: 1334, category: "career", source: "vocab-exam", type: "vocab", furi: "せっけいとしょ", jp: "設計図書", id_text: "Dokumen desain (gambar + spesifikasi)", desc: "例: 設計図書には、設計図・仕様書・現場説明書などが含まれる。→ Dokumen desain mencakup gambar kerja, spesifikasi teknis, dan penjelasan lapangan. Menjadi dasar kontrak dan pelaksanaan." },
  { id: 1335, category: "career", source: "vocab-supplementary", type: "vocab", furi: "しゅんこうず", jp: "竣工図", id_text: "Gambar as-built (setelah selesai dibangun)", desc: "例: 竣工図は、実際に施工した内容を反映した最終図面で、引渡し時に提出する。→ Gambar as-built mencerminkan kondisi yang benar-benar dibangun, diserahkan saat serah terima ke klien. Berbeda dari gambar desain awal." },
  { id: 1336, category: "career", source: "vocab-supplementary", type: "vocab", furi: "せこうず", jp: "施工図", id_text: "Gambar kerja lapangan (shop drawing)", desc: "例: 施工図は設計図書をもとに現場で作業できるよう詳細化した図面である。→ Gambar kerja adalah gambar detail yang dibuat dari dokumen desain agar bisa langsung digunakan di lapangan. Dibuat oleh kontraktor, disetujui pengawas." },
  { id: 1337, category: "career", source: "vocab-supplementary", type: "vocab", furi: "うちあわせきろく", jp: "打合せ記録", id_text: "Notulen / catatan rapat koordinasi", desc: "例: 打合せ記録には、日時・参加者・決定事項・担当者を明記する。→ Notulen rapat mencantumkan tanggal, peserta, keputusan, dan penanggung jawab. Dokumen penting sebagai bukti kesepakatan di lapangan." },
  { id: 1338, category: "career", source: "vocab-supplementary", type: "vocab", furi: "こうじにっぽう", jp: "工事日報", id_text: "Laporan harian pekerjaan konstruksi", desc: "例: 工事日報には、当日の作業内容・人員数・天気・問題点を記録する。→ Laporan harian mencatat jenis pekerjaan, jumlah tenaga kerja, cuaca, dan kendala hari itu. Diisi oleh pengawas lapangan setiap hari." },
  { id: 1339, category: "career", source: "vocab-supplementary", type: "vocab", furi: "ざいりょうはんにゅう", jp: "材料搬入", id_text: "Pengiriman / penerimaan material ke lokasi", desc: "例: 材料搬入時は、納品書と照合して数量・品番を確認する。→ Saat material tiba, jumlah dan nomor produk dicocokkan dengan surat jalan. Proses ini mendahului 検収 (penerimaan resmi setelah inspeksi)." },
  { id: 1340, category: "career", source: "vocab-general", type: "vocab", furi: "けんしゅう", jp: "検収", id_text: "Inspeksi & penerimaan material resmi", desc: "例: 検収では、材料の品質・数量・規格が仕様書と一致するか確認する。→ Dalam inspeksi penerimaan, kualitas, jumlah, dan spesifikasi material dikonfirmasi sesuai dokumen. Setelah 検収 dinyatakan lulus, material sah digunakan." },
  { id: 1341, category: "career", source: "vocab-general", type: "vocab", furi: "ぜせい", jp: "是正", id_text: "Tindakan koreksi / perbaikan ketidaksesuaian", desc: "例: 検査で不適合が見つかり、是正処置を施工者に指示した。→ Ketidaksesuaian ditemukan saat inspeksi, dan tindakan koreksi diperintahkan ke kontraktor. Dalam sistem ISO 9001, 是正処置は根本原因の除去を含む." },
  { id: 1342, category: "career", source: "vocab-supplementary", type: "vocab", furi: "ひきわたし", jp: "引渡し", id_text: "Serah terima bangunan / fasilitas ke klien", desc: "例: 引渡し前に竣工検査を行い、合格後に鍵と竣工図書を施主に渡す。→ Sebelum serah terima, inspeksi akhir dilakukan; lulus → kunci dan dokumen diserahkan ke pemilik. Menandai berakhirnya tanggung jawab kontraktor." },
  { id: 1343, category: "career", source: "vocab-exam", type: "vocab", furi: "せこうたいせいだいちょう", jp: "施工体制台帳", id_text: "Buku besar struktur pelaksana proyek", desc: "例: 施工体制台帳には、元請け・下請け・専門業者の情報を記載する。→ Buku besar ini memuat informasi kontraktor utama, sub-kontraktor, dan spesialis. Wajib dibuat pada proyek dengan nilai tertentu ke atas." },
  { id: 1344, category: "career", source: "vocab-supplementary", type: "vocab", furi: "そうごうせこうけいかくしょ", jp: "総合施工計画書", id_text: "Rencana pelaksanaan konstruksi menyeluruh", desc: "例: 総合施工計画書は工事全体を俯瞰した計画書で、着工前に作成される。→ Dokumen ini merangkum rencana keseluruhan proyek dan dibuat sebelum pekerjaan dimulai. Menjadi acuan bagi semua 施工計画書 per bidang pekerjaan." },
  { id: 1345, category: "career", source: "vocab-supplementary", type: "vocab", furi: "ひんしつかんりけいかくしょ", jp: "品質管理計画書", id_text: "Dokumen rencana manajemen kualitas", desc: "例: 品質管理計画書には、検査項目・頻度・担当者・合否基準を定める。→ Dokumen ini menetapkan item inspeksi, frekuensi, penanggung jawab, dan kriteria lulus/gagal. Bagian dari sistem ISO 9001 yang diterapkan di proyek konstruksi." },
  { id: 1346, category: "hourei", source: "vocab-teori", type: "vocab", furi: "きょか", jp: "許可", id_text: "Izin / lisensi usaha konstruksi", desc: "例: 建設業を営むには知事または大臣の許可が必要だ。→ Menjalankan usaha konstruksi wajib mendapat izin dari gubernur atau menteri. 許可なしで工事受注 = 違法（いほう）." },
  { id: 1347, category: "hourei", source: "vocab-teori", type: "vocab", furi: "うけおいけいやく", jp: "請負契約", id_text: "Kontrak borongan / construction contract", desc: "例: 建設工事は発注者と元請けの請負契約に基づいて行われる。→ Pekerjaan konstruksi dilakukan berdasarkan kontrak borongan antara pemilik proyek dan kontraktor utama." },
  { id: 1348, category: "hourei", source: "vocab-teori", type: "vocab", furi: "もとうけ", jp: "元請け", id_text: "Kontraktor utama / prime contractor", desc: "例: 元請けは発注者から直接工事を受注し、下請け全体を管理する。→ Pihak yang menerima proyek langsung dari pemilik; bertanggung jawab atas seluruh sub-kontraktor." },
  { id: 1349, category: "hourei", source: "vocab-teori", type: "vocab", furi: "したうけ", jp: "下請け", id_text: "Sub-kontraktor / sub-contractor", desc: "例: 元請けから工事の一部を受注するのが下請け業者だ。→ Pihak yang menerima sebagian pekerjaan dari kontraktor utama. 二次下請け・三次下請けと連鎖する場合もある." },
  { id: 1350, category: "hourei", source: "vocab-teori", type: "vocab", furi: "ろうどうきじゅんかんとくしょ", jp: "労働基準監督署", id_text: "Kantor Inspeksi Standar Ketenagakerjaan", desc: "例: 労働災害が起きたら、労働基準監督署に速やかに報告する義務がある。→ Jika terjadi kecelakaan kerja, wajib segera melapor ke Kantor Inspeksi. 報告を怠ると労災かくし（犯罪）になる." },
  { id: 1351, category: "hourei", source: "vocab-teori", type: "vocab", furi: "ゆうきゅうきゅうか", jp: "有給休暇", id_text: "Cuti berbayar / paid leave", desc: "例: 6ヶ月継続勤務かつ出勤率80%以上で、10日の有給休暇が付与される。→ Setelah bekerja 6 bulan dengan tingkat kehadiran ≥80%, berhak atas 10 hari cuti berbayar. Hak ini diatur dalam 労働基準法." },
  { id: 1352, category: "hourei", source: "vocab-teori", type: "vocab", furi: "わりましちんぎん", jp: "割増賃金", id_text: "Upah premi / overtime premium pay", desc: "例: 時間外労働の割増賃金は、通常の25%増し以上と法律で定められている。→ Upah lembur minimal 1.25× gaji normal sesuai UU Standar Ketenagakerjaan. Lembur >60jam/bulan = 1.5×." },
  { id: 1353, category: "hourei", source: "vocab-teori", type: "vocab", furi: "ばっそく", jp: "罰則", id_text: "Sanksi / hukuman pidana pelanggaran UU", desc: "例: 建設業法違反には罰則があり、業許可の取消しや罰金が科せられる。→ Pelanggaran UU Konstruksi dikenai sanksi berupa pencabutan izin usaha atau denda. 罰則を知ることは法令遵守の基本." },
  { id: 1354, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "あんぜんかんりしゃ", jp: "安全管理者", id_text: "Safety manager / manajer keselamatan kerja", desc: "例: 常時50人以上の事業場には安全管理者の選任が義務付けられている。→ Wajib ada safety manager di tempat kerja dengan ≥50 pekerja tetap. Berbeda dari 衛生管理者 yang fokus pada kesehatan." },
  { id: 1356, category: "anzen", source: "vocab-teori", type: "vocab", furi: "さんだいさいがい", jp: "三大災害", id_text: "Tiga besar kecelakaan konstruksi", desc: "例: 建設業の三大災害は①墜落・転落②建設機械③崩壊・倒壊だ。→ ①Jatuh dari ketinggian (墜落・転落) = terbanyak, ②Kecelakaan mesin konstruksi, ③Runtuh/kolaps. 安全教育では必ず覚える基礎知識." },
  { id: 1357, category: "anzen", source: "vocab-teori", type: "vocab", furi: "あんぜんたい", jp: "安全帯", id_text: "Sabuk/harness keselamatan (generic term)", desc: "例: 高所作業では安全帯（ハーネス型）の着用が義務付けられている。→ Pekerjaan ketinggian wajib memakai safety harness. 2022年以降、フルハーネス型が原則。胴ベルト型は限られた条件のみ." },
  { id: 1358, category: "anzen", source: "vocab-teori", type: "vocab", furi: "ふるはーねすがた", jp: "フルハーネス型", id_text: "Full-body harness — standar keselamatan ketinggian", desc: "例: 高さ6.75m以上（建設業は5m以上）ではフルハーネス型安全帯が義務。→ Di ketinggian ≥5m (konstruksi), wajib pakai full harness (bukan sabuk biasa). Mengurangi risiko cedera dalam saat jatuh." },
  { id: 1359, category: "anzen", source: "vocab-teori", type: "vocab", furi: "たちいりきんし", jp: "立入禁止", id_text: "Dilarang masuk / no-entry zone", desc: "例: 重機の旋回範囲内は立入禁止区域として必ずロープで囲う。→ Area ayunan alat berat wajib dipasang tali dan tanda 'Dilarang Masuk'. 看板や標識の設置義務あり." },
  { id: 1360, category: "anzen", source: "vocab-teori", type: "vocab", furi: "ほごぐ", jp: "保護具", id_text: "APD / alat pelindung diri (general term)", desc: "例: 建設現場ではヘルメット・安全靴・安全帯が基本的な保護具だ。→ Helm, sepatu safety, dan harness adalah APD dasar di site konstruksi. 作業内容に応じた適切な保護具の選定が重要." },
  { id: 1361, category: "anzen", source: "vocab-teori", type: "vocab", furi: "かんでん", jp: "感電", id_text: "Sengatan listrik / electric shock", desc: "例: 電気工事では感電事故を防ぐため、必ず電源を切ってから作業する。→ Dalam pekerjaan listrik, selalu matikan sumber daya sebelum bekerja untuk mencegah sengatan. 感電は最悪の場合死亡事故になる." },
  { id: 1364, category: "sekou", source: "vocab-teori", type: "vocab", furi: "せこうけいかく", jp: "施工計画", id_text: "Rencana pelaksanaan konstruksi", desc: "例: 施工計画は工事着工前に作成し、工程・品質・安全の方針を定める。→ Dibuat sebelum pekerjaan dimulai, menetapkan kebijakan jadwal, kualitas, dan keselamatan." },
  { id: 1365, category: "sekou", source: "vocab-supplementary", type: "vocab", furi: "こうていひょう", jp: "工程表", id_text: "Bagan jadwal konstruksi (Gantt chart / network)", desc: "例: 工程表で各作業の開始・終了予定日と担当者を管理する。→ Jadwal menampilkan tanggal mulai/selesai setiap pekerjaan. バーチャート = mudah dibaca; ネットワーク工程表 = menampilkan ketergantungan antar pekerjaan." },
  { id: 1368, category: "hourei", source: "vocab-teori", type: "vocab", furi: "はっちゅうしゃ", jp: "発注者", id_text: "Pemilik proyek / project owner / client", desc: "例: 発注者は工事の内容・期間・金額を決め、元請けと請負契約を結ぶ。→ Pihak yang memesan proyek, menentukan isi/durasi/anggaran, dan menandatangani kontrak borongan." },
  { id: 1369, category: "hourei", source: "vocab-supplementary", type: "vocab", furi: "せんもんぎょうしゃ", jp: "専門業者", id_text: "Kontraktor spesialis / specialty contractor", desc: "例: 電気・空調・配管などは各分野の専門業者が施工する。→ Listrik, AC, dan perpipaan dikerjakan oleh kontraktor spesialis masing-masing bidang. 元請けが全体調整し、各専門業者が実施工を担う." },
  { id: 1370, category: "haikan", source: "vocab-teori", type: "vocab", furi: "れいばい", jp: "冷媒", id_text: "Refrigeran / zat pendingin AC (HFC dll)", desc: "例: エアコンの冷媒管には冷媒が封入されており、接続時には漏れ試験が必須だ。→ Pipa refrigeran AC berisi zat pendingin; sambungan wajib diuji kebocoran setelah pemasangan. 冷媒管の接続後は必ず漏れ確認." },
  { id: 1371, category: "haikan", source: "vocab-teori", type: "vocab", furi: "こうばい", jp: "勾配", id_text: "Kemiringan pipa drainase agar aliran lancar", desc: "例: 排水管は水が自然に流れるよう、必ず適切な勾配をつけて配管する。→ Pipa drainase harus dipasang dengan kemiringan yang cukup agar air mengalir secara gravitasi. 勾配不足 → 水が溜まり、流れが悪くなる." },
  { id: 1372, category: "haikan", source: "vocab-teori", type: "vocab", furi: "すいあつしけん", jp: "水圧試験", id_text: "Uji tekanan hidraulik / hydraulic pressure test", desc: "例: 配管工事完了後、接続部の漏れを確認するために水圧試験を実施する。→ Setelah pipa selesai dipasang, uji tekanan air dilakukan untuk memastikan tidak ada kebocoran. 試験圧力は仕様書の規定値で行う." },
  { id: 1373, category: "haikan", source: "vocab-supplementary", type: "vocab", furi: "もれしけん", jp: "漏れ試験", id_text: "Uji kebocoran (gas/refrigeran/pipa)", desc: "例: ガス管溶接後は必ず漏れ試験を行い、ガス漏れがないことを確認する。→ Setelah pengelasan pipa gas, wajib uji kebocoran sebelum dioperasikan. 冷媒管でも配線でも: 接続後の漏れ確認は鉄則." },
  { id: 1374, category: "haikan", source: "vocab-teori", type: "vocab", furi: "さどる", jp: "サドル", id_text: "Saddle / braket penopang pipa di dinding/plafon", desc: "例: サドルは配管を壁・天井・床に固定するための支持金具だ。→ Braket pelana untuk menempelkan pipa ke dinding, plafon, atau lantai. サドル間隔が広すぎると配管がたわむ（lendut）." },
  { id: 1375, category: "haikan", source: "vocab-teori", type: "vocab", furi: "つぎて", jp: "継手", id_text: "Fitting / komponen sambungan antar pipa", desc: "例: 継手には、エルボ（曲がり）・チーズ（T字）・ソケット（直線）などがある。→ Berbagai jenis fitting: elbow (belok), tee (T), socket (lurus). 材料・用途・接合方法によって選定が変わる." },
  { id: 1376, category: "haikan", source: "vocab-teori", type: "vocab", furi: "ふらんじ", jp: "フランジ", id_text: "Flensa / sambungan pipa dengan baut (mudah dibuka)", desc: "例: バルブや機器との接続にはフランジ接合が使われ、メンテナンスが容易だ。→ Sambungan flensa menggunakan baut sehingga mudah dibuka untuk perawatan. 溶接・ねじに比べて着脱が簡単." },
  { id: 1377, category: "haikan", source: "vocab-teori", type: "vocab", furi: "ばるぶ", jp: "バルブ", id_text: "Katup / valve (mengatur aliran dalam pipa)", desc: "例: バルブは流体の開閉・流量調節に使う。ゲート・ボール・グローブ・逆止めなど種類が多い。→ Mengatur buka/tutup aliran. Jenis: gate valve (全開/全閉), ball valve (cepat), globe (kontrol aliran), check valve (searah)." },
  { id: 1378, category: "denki", source: "vocab-teori", type: "vocab", furi: "はいせん", jp: "配線", id_text: "Pengkabelan / wiring (instalasi kabel listrik)", desc: "例: 配線工事では、電線の太さ・種類・配線ルートを図面通りに施工する。→ Instalasi kabel listrik sesuai gambar: ukuran kabel, jenis, dan rute harus tepat. 誤配線 → 漏電・感電・火災のリスク." },
  { id: 1379, category: "denki", source: "vocab-teori", type: "vocab", furi: "ぶんき", jp: "分岐", id_text: "Percabangan / branch (listrik atau pipa)", desc: "例: 幹線から各フロアへの分岐は、分電盤を介して行われる。→ Dari feeder utama, percabangan ke tiap lantai melalui panel distribusi. 電気でも配管でも: 幹線から分岐して各末端へ." },
  { id: 1380, category: "denki", source: "vocab-teori", type: "vocab", furi: "でんねつせん", jp: "電熱線", id_text: "Kabel pemanas elektrik anti-beku pipa luar", desc: "例: 寒冷地の屋外配管には、凍結防止のために電熱線を巻き付けて保温する。→ Di daerah dingin, kawat pemanas dililitkan pada pipa luar ruangan untuk mencegah pembekuan. 保温材と組み合わせて使用することが多い." },
  { id: 1381, category: "gaiyou", source: "vocab-jac", type: "vocab", furi: "おはようございます", jp: "おはようございます", id_text: "Selamat pagi (formal)", desc: "例: 現場に到着したら「おはようございます」と挨拶する。→ Saat tiba di site, ucapkan selamat pagi kepada semua orang. ⚠️ Di konstruksi, sering dipakai sepanjang hari bukan hanya pagi hari." },
  { id: 1382, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "よろしくおねがいします", jp: "よろしくお願いします", id_text: "Mohon bimbingannya / salam kenal (serba guna)", desc: "例: 初日の挨拶「よろしくお願いします」／作業依頼の最後にも使う。→ Dipakai saat: pertama kali bertemu, menitipkan tugas ke orang lain, memohon bantuan. Frasa yang paling sering dibutuhkan di lapangan." },
  { id: 1383, category: "gaiyou", source: "vocab-jac", type: "vocab", furi: "ありがとうございます", jp: "ありがとうございます", id_text: "Terima kasih (formal)", desc: "例: 仕事を手伝ってもらったら「ありがとうございます」。→ Ucapkan setelah dibantu atau menerima sesuatu. Versi kasual ke sesama pekerja: ありがとう (tanpa ございます)." },
  { id: 1384, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "すみません", jp: "すみません", id_text: "Permisi / maaf / excuse me (serbaguna)", desc: "例: 通路をふさいでいるとき「すみません」／何か頼むときにも使う。→ Dipakai untuk: meminta izin lewat, minta tolong, meminta perhatian seseorang, atau minta maaf ringan. Frasa paling serbaguna di tempat kerja Jepang." },
  { id: 1385, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "わかりました", jp: "わかりました", id_text: "Sudah mengerti / paham (merespons instruksi)", desc: "例: 監督から指示を受けたら「わかりました」と返事する。→ Respons standar saat menerima instruksi dari atasan. Lebih formal dari 分かった (wakata). Wajib biasakan ini agar tidak dianggap tidak mendengarkan." },
  { id: 1386, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "わかりません", jp: "わかりません", id_text: "Tidak mengerti / tidak tahu", desc: "例: 指示が聞き取れなかったら「わかりません。もう一度お願いします」と言う。→ Jika tidak mengerti, selalu bilang dengan jelas — jangan pura-pura mengerti! Tambahkan もう一度お願いします untuk minta diulang." },
  { id: 1387, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "もういちどいってください", jp: "もう一度言ってください", id_text: "Tolong ulangi sekali lagi", desc: "例: 聞き取れなかったとき「すみません、もう一度言ってください」。→ Kalimat wajib untuk meminta pengulangan. Tidak perlu malu menggunakannya — lebih baik bertanya daripada melakukan pekerjaan yang salah." },
  { id: 1388, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "てつだってください", jp: "手伝ってください", id_text: "Tolong bantu saya", desc: "例: 重い材料を運ぶとき「手伝ってください」と頼む。→ Minta bantuan saat mengangkat beban berat, kesulitan teknis, dsb. Versi lebih sopan: お手伝いいただけますか？" },
  { id: 1389, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "ちょっとまってください", jp: "ちょっと待ってください", id_text: "Tolong tunggu sebentar", desc: "例: 準備が終わっていないとき「ちょっと待ってください」と言う。→ Minta waktu sebentar sebelum mulai atau menjawab. Sopan dan alami di lapangan. ちょっと = sedikit/sebentar." },
  { id: 1390, category: "gaiyou", source: "vocab-jac", type: "vocab", furi: "おさきにしつれいします", jp: "お先に失礼します", id_text: "Pamit pulang duluan sebelum orang lain selesai", desc: "例: 仕事が終わって先に帰るとき「お先に失礼します」と言う。→ Ucapkan saat pulang/pergi sebelum rekan kerja lain. Wajib di budaya kerja Jepang — tidak bilang ini dianggap tidak sopan." },
  { id: 1391, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "おつかれさまでした", jp: "お疲れ様でした", id_text: "Terima kasih kerja kerasnya (akhir hari / selesai)", desc: "例: 一日の作業が終わったとき「お疲れ様でした」と言い合う。→ Ucapkan di akhir shift kepada semua orang. Berbeda dari お疲れ様です (sedang berlangsung) vs です (formal ongoing). Respon yang sama: お疲れ様でした." },
  { id: 1392, category: "gaiyou", source: "vocab-jac", type: "vocab", furi: "りょうかいしました", jp: "了解しました", id_text: "Siap / roger / mengerti dan akan dilaksanakan", desc: "例: 作業指示を受けて「了解しました、すぐ取りかかります」。→ Lebih aktif dari わかりました — menyiratkan kesiapan untuk bertindak. Di lapangan sering dipersingkat menjadi 了解（りょうかい）. ⚠️ Ke atasan: 承知しました (shouchiشimashita) lebih formal." },
  { id: 1393, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "おわりました", jp: "終わりました", id_text: "Sudah selesai (laporan penyelesaian tugas)", desc: "例: 作業が完了したら監督に「○○の作業が終わりました」と報告する。→ Laporan setelah menyelesaikan tugas. Selalu laporkan ke pengawas saat pekerjaan selesai — jangan diam saja. Bisa ditambahkan: 確認をお願いします (mohon diperiksa)." },
  { id: 1394, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "きをつけて", jp: "気をつけて", id_text: "Hati-hati! / Be careful! (kepada orang lain)", desc: "例: 危険な場所を通る仲間に「気をつけて」と声をかける。→ Ucapkan kepada rekan yang sedang melewati area berbahaya atau pulang kerja. Versi lebih kuat: 気をつけてください (formal) atau 危ない！ (darurat)." },
  { id: 1395, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "おねがいします", jp: "お願いします", id_text: "Mohon / tolong (saat meminta sesuatu)", desc: "例: 資材を運んでほしいとき「○○をお願いします」と頼む。→ Tambahkan setelah permintaan apapun: 確認をお願いします (tolong cek), 手伝いをお願いします (tolong bantu), dll. Lebih sopan dari ください saja." },
  { id: 1396, category: "gaiyou", source: "vocab-jac", type: "vocab", furi: "かくにんします", jp: "確認します", id_text: "Saya akan memastikan / mengecek", desc: "例: 指示の内容が不明なとき「確認してから報告します」。→ Ungkapkan saat perlu memverifikasi sesuatu sebelum menjawab. 確認 = konfirmasi/verifikasi. Jangan asal bilang OK kalau belum yakin — bilang 確認します!" },
  { id: 1397, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "いってきます／いってらっしゃい", jp: "行ってきます／行ってらっしゃい", id_text: "Hati-hati di jalan (pasangan sapaan saat pergi)", desc: "例: 現場に向かう前「行ってきます」→ 残る人「行ってらっしゃい」。→ Pasangan sapaan saat seseorang berangkat meninggalkan tempat. Juga dipakai antar rekan kerja di site besar." },
  { id: 1398, category: "gaiyou", source: "vocab-supplementary", type: "vocab", furi: "おせわになっております", jp: "お世話になっております", id_text: "Terima kasih atas bimbingan selama ini (formal)", desc: "例: 電話や会議の冒頭「お世話になっております、○○の田中です」。→ Kalimat pembuka formal dalam telepon atau rapat. Setara dengan 'thank you for your continued support'. Wajib di lingkungan kerja profesional Jepang." },
  { id: 1399, category: "career", source: "vocab-jac", type: "vocab", furi: "ほうこく", jp: "報告", id_text: "Laporan kepada atasan", desc: "例: 作業が完了したら上司に「○○が終わりました」と報告する。→ Setelah menyelesaikan tugas, langsung laporkan ke atasan. ほうれんそうの「ほう」。問題が起きたときも迷わず報告すること。報告なしは信頼を失う。" },
  { id: 1400, category: "career", source: "vocab-jac", type: "vocab", furi: "れんらく", jp: "連絡", id_text: "Komunikasi / pemberitahuan antar tim", desc: "例: 材料が足りなくなったら現場監督に連絡する。→ Jika material habis, segera hubungi supervisor. ほうれんそうの「れん」。こまめな連絡が現場の混乱を防ぐ。情報は抱え込まず共有する。" },
  { id: 1401, category: "career", source: "vocab-jac", type: "vocab", furi: "そうだん", jp: "相談", id_text: "Konsultasi / diskusi dengan atasan/senior", desc: "例: やり方が分からないときは一人で悩まず先輩に相談する。→ Kalau tidak tahu caranya, konsultasikan dengan senior — jangan coba-coba sendiri. ほうれんそうの「そう」。迷ったら必ず相談。" },
  { id: 1402, category: "career", source: "vocab-jac", type: "vocab", furi: "ほうれんそう", jp: "ほう・れん・そう", id_text: "Lapor–Hubungi–Konsultasi: 3 pilar komunikasi kerja", desc: "例: 建設現場では「ほう・れん・そう」が基本中の基本。ほう=報告、れん=連絡、そう=相談。→ Konsep fundamental komunikasi di tempat kerja Jepang. Tanpa ほうれんそう, koordinasi lapangan gagal. JAC テキストで必出。" },
  { id: 1403, category: "career", source: "vocab-jac", type: "vocab", furi: "しじ", jp: "指示", id_text: "Instruksi / perintah kerja dari atasan", desc: "例: 監督から指示を受けたら、内容をメモして「わかりました」と返事する。→ Saat menerima instruksi, catat isinya dan respons dengan jelas. 指示に従って作業する = bekerja sesuai arahan. 指示なしで勝手に動かない。" },
  { id: 1404, category: "career", source: "vocab-general", type: "vocab", furi: "けいご", jp: "敬語", id_text: "Bahasa hormat Jepang (kepada atasan/klien)", desc: "例: 上司や発注者には敬語を使う。「食べる」→「いただく」、「言う」→「おっしゃる」。→ Bahasa hormat digunakan kepada atasan, senior, dan klien. Keigo dasar: ～ます/～ます form = sudah cukup di lapangan." },
  { id: 1405, category: "career", source: "vocab-supplementary", type: "vocab", furi: "みだしなみ", jp: "身だしなみ", id_text: "Penampilan / kerapian diri di tempat kerja", desc: "例: 現場では清潔な作業着・正しくかぶったヘルメット・安全靴が身だしなみの基本。→ Penampilan di site: seragam bersih, helm benar, sepatu safety. 身だしなみが良い = kesan profesional, kepercayaan atasan meningkat." },
  { id: 1406, category: "career", source: "vocab-general", type: "vocab", furi: "ちこく", jp: "遅刻", id_text: "Terlambat / keterlambatan masuk kerja", desc: "例: 遅刻しそうなときは、必ず事前に上司に連絡する。無断遅刻は厳禁。→ Jika akan terlambat, WAJIB hubungi atasan lebih dulu. Terlambat tanpa kabar (無断遅刻) = pelanggaran serius. 朝礼の時間に間に合うよう余裕を持って出勤する。" },
  { id: 1407, category: "career", source: "vocab-general", type: "vocab", furi: "けっきん", jp: "欠勤", id_text: "Tidak masuk kerja / absen", desc: "例: 体調不良で欠勤する場合は、始業時間前に会社へ電話連絡する。→ Kalau sakit dan tidak bisa masuk, telepon perusahaan SEBELUM jam kerja dimulai. 無断欠勤 = 最悪の場合、解雇の原因になる。欠勤の際は診断書が必要な場合もある。" },
  { id: 1408, category: "career", source: "vocab-jac", type: "vocab", furi: "とどけで", jp: "届け出", id_text: "Notifikasi / pelaporan resmi (izin/cuti/absen)", desc: "例: 遅刻・欠勤・早退の場合は届け出（とどけで）が必要。→ Terlambat, absen, atau pulang lebih awal semua memerlukan pemberitahuan resmi. 事前の届け出 = izin sebelumnya. 事後報告より事前届けが原則。" },
  { id: 1409, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "たいちょうかんり", jp: "体調管理", id_text: "Manajemen kondisi fisik / menjaga kesehatan diri", desc: "例: プロとして毎日の体調管理は自分の責任だ。睡眠・食事・水分補給の3つが基本。→ Sebagai profesional, menjaga kondisi tubuh adalah tanggung jawab pribadi. 体調不良で作業すると事故・ミスの原因になる。JAC テキスト必出トピック。" },
  { id: 1410, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "たいちょうふりょう", jp: "体調不良", id_text: "Kondisi badan tidak fit / merasa tidak enak badan", desc: "例: 体調不良を感じたら無理せず、すぐに上司に「体調が悪いです」と報告する。→ Kalau tidak enak badan, jangan dipaksakan — langsung lapor ke atasan. 高所作業・機械操作中の体調不良は重大事故の原因になる。" },
  { id: 1411, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "すいぶんほきゅう", jp: "水分補給", id_text: "Minum air / rehidrasi (cegah heat stroke)", desc: "例: 夏の現場では、1時間ごとに水分補給して熱中症を予防する。→ Di musim panas, minum air setiap jam untuk cegah heat stroke. のどが渇く前に飲む = minum sebelum merasa haus. スポーツドリンクで電解質も補充する。" },
  { id: 1412, category: "career", source: "vocab-jac", type: "vocab", furi: "きゅうけい", jp: "休憩", id_text: "Istirahat / break kerja (hak berdasarkan UU)", desc: "例: 労働基準法で6時間超は45分、8時間超は60分の休憩が義務づけられている。→ UU mewajibkan istirahat: kerja >6 jam = 45 menit, >8 jam = 60 menit. 休憩時間は賃金が発生しない。Tetapi tidak bisa dipotong oleh perusahaan." },
  { id: 1413, category: "career", source: "vocab-jac", type: "vocab", furi: "ざんぎょう", jp: "残業", id_text: "Lembur / kerja lebih dari jam normal", desc: "例: 残業は36協定の範囲内で行い、残業代（割増賃金）が支払われる。→ Lembur dilakukan dalam batas 36 perjanjian dan dibayar upah premi. 36協定なしの残業 = 違法。残業時間の上限: 原則45時間/月。" },
  { id: 1414, category: "career", source: "vocab-supplementary", type: "vocab", furi: "じかんげんしゅ", jp: "時間厳守", id_text: "Tepat waktu / kepatuhan terhadap jadwal", desc: "例: 朝礼・作業開始・材料搬入など、すべての時間を厳守することが信頼の基本。→ Semua jadwal — apel, mulai kerja, pengiriman material — harus tepat waktu. 「5分前行動」= siap 5 menit sebelum waktu yang ditetapkan. Kebiasaan di Jepang." },
  { id: 1415, category: "career", source: "vocab-supplementary", type: "vocab", furi: "きゅうよめいさい", jp: "給与明細", id_text: "Slip gaji / rincian pembayaran upah bulanan", desc: "例: 毎月の給与明細を確認し、残業代・各種控除が正しいか確認する。→ Cek slip gaji setiap bulan: pastikan upah lembur dan potongan sudah benar. 不明な点は会社の担当者に相談する権利がある。給与明細の交付は法律上の義務。" },
  { id: 1416, category: "hourei", source: "vocab-teori", type: "vocab", furi: "とくていぎのう", jp: "特定技能", id_text: "SSW / Specified Skilled Worker — izin kerja Jepang", desc: "例: 特定技能は2019年創設の在留資格で、人手不足の14分野（建設・製造・介護など）で就労できる。→ Status tinggal baru 2019 untuk bekerja di 14 bidang kekurangan tenaga kerja. 特定技能1号: max 5年, 家族帯同不可 / 2号: 更新可能, 家族帯同可。" },
  { id: 1417, category: "hourei", source: "vocab-teori", type: "vocab", furi: "ざいりゅうかーど", jp: "在留カード", id_text: "Kartu izin tinggal / residence card", desc: "例: 在留カードは常に携帯義務。警察・入管に求められたら提示する。住所変更後14日以内に届け出が必要。→ Wajib dibawa setiap saat. Jika diminta polisi/imigrasi, wajib tunjukkan. Masa berlaku tertera di kartu — jangan sampai kedaluwarsa." },
  { id: 1418, category: "hourei", source: "vocab-teori", type: "vocab", furi: "ざいりゅうしかく", jp: "在留資格", id_text: "Status tinggal / jenis izin untuk tinggal & kerja", desc: "例: 在留資格の種類によって、働ける仕事の範囲が決まる。資格外の仕事をすると不法就労になる。→ Jenis status tinggal menentukan pekerjaan yang boleh dilakukan. 特定技能・技能実習・留学など種類が多い。" },
  { id: 1419, category: "hourei", source: "vocab-teori", type: "vocab", furi: "ざいりゅうきかん", jp: "在留期間", id_text: "Masa berlaku izin tinggal", desc: "例: 特定技能1号の在留期間は最長5年。期限が切れる前に更新の手続きが必要。→ Max 5 tahun untuk SSW 1. Wajib proses perpanjangan sebelum kedaluwarsa. 在留期間を過ぎると不法滞在（オーバーステイ）となり強制退去の対象。" },
  { id: 1420, category: "hourei", source: "vocab-general", type: "vocab", furi: "しゅうろう", jp: "就労", id_text: "Bekerja / kegiatan kerja berdasarkan izin tinggal", desc: "例: 在留資格の範囲外での就労は「不法就労」として処罰される。雇用主も罰則の対象。→ Kerja di luar izin tinggal = kerja ilegal, bisa dipenjara/dideportasi. Majikan juga kena sanksi. 特定技能では指定分野のみ就労可。" },
  { id: 1421, category: "hourei", source: "vocab-teori", type: "vocab", furi: "こうしん", jp: "更新", id_text: "Perpanjangan (visa / izin tinggal / kontrak)", desc: "例: 在留期間の更新は期限の3ヶ月前から申請できる。忘れずに早めに手続きをする。→ Perpanjangan masa tinggal bisa diajukan mulai 3 bulan sebelum kedaluwarsa. 契約の更新, 免許の更新にも使う同じ単語。" },
  { id: 1422, category: "hourei", source: "vocab-teori", type: "vocab", furi: "しゃかいほけん", jp: "社会保険", id_text: "Asuransi sosial — umbrella semua asuransi wajib", desc: "例: 社会保険とは健康保険・厚生年金・雇用保険などの総称で、一定規模の会社では加入義務がある。→ Istilah umum untuk semua asuransi wajib. 保険料は会社と従業員が折半。外国人も加入対象で、一定条件で給付を受けられる。" },
  { id: 1423, category: "hourei", source: "vocab-teori", type: "vocab", furi: "けんこうほけん", jp: "健康保険", id_text: "Asuransi kesehatan — 30% tanggungan sendiri", desc: "例: 健康保険に加入すると、病院の医療費が原則3割負担になる。→ Dengan asuransi kesehatan, biaya medis jadi 30% tanggungan sendiri (70% ditanggung). 保険証（ほけんしょう）が交付され、病院で提示する。" },
  { id: 1424, category: "hourei", source: "vocab-supplementary", type: "vocab", furi: "こうせいねんきん", jp: "厚生年金", id_text: "Pensiun perusahaan / employees' pension insurance", desc: "例: 厚生年金保険料は会社と従業員で折半し、将来の年金受給権が積み上がる。→ Premi pensiun ditanggung bersama (50%:50%). Setelah pensiun, berhak menerima uang pensiun. 外国人は帰国時に「脱退一時金」を受け取れる場合あり。" },
  { id: 1425, category: "hourei", source: "vocab-teori", type: "vocab", furi: "こようほけん", jp: "雇用保険", id_text: "Asuransi ketenagakerjaan (tunjangan pengangguran)", desc: "例: 雇用保険に加入していれば、失業時に失業給付（失業手当）が支給される。→ Jika kehilangan pekerjaan, dapat tunjangan pengangguran dari asuransi ini. 保険料は会社と従業員の両方が負担。育児・介護休業給付もここから。" },
  { id: 1426, category: "hourei", source: "vocab-supplementary", type: "vocab", furi: "ほけんしょう", jp: "保険証", id_text: "Kartu asuransi kesehatan / health insurance card", desc: "例: 病院に行くときは保険証を持参する。提示することで3割負担になる。紛失したらすぐ会社に連絡。→ Bawa kartu asuransi setiap kali ke dokter. 忘れた場合は一旦全額負担になるが後で差額が戻る場合あり。" },
  { id: 1427, category: "anzen", source: "vocab-teori", type: "vocab", furi: "へるめっと", jp: "ヘルメット", id_text: "Helm keselamatan / hard hat", desc: "例: 建設現場ではヘルメット（保護帽）の着用が義務。あご紐を必ず締める。→ Helm WAJIB di semua site konstruksi — tidak hanya di area kerja aktif. Melindungi kepala dari benda jatuh. JIS T8131規格品を使用。約2年で定期交換。" },
  { id: 1428, category: "anzen", source: "vocab-teori", type: "vocab", furi: "あんぜんぐつ", jp: "安全靴", id_text: "Sepatu safety / steel-toe boots", desc: "例: 安全靴は先芯（つまさき保護）入りで、重量物が落下しても足先を守る。→ Sepatu safety punya pelindung baja di ujung kaki. JIS T8101規格品を選ぶ。現場では必ず着用。スニーカーや普通の靴は不可。" },
  { id: 1429, category: "anzen", source: "vocab-supplementary", type: "vocab", furi: "ぼうじんますく", jp: "防じんマスク", id_text: "Masker anti-debu / dust respirator", desc: "例: コンクリート切断・はつり作業では防じんマスク（DS2以上）を着用する。→ Saat memotong beton/keramik, wajib pakai masker anti-debu. 通常のマスク（布・サージカル）では粉じん・シリカを防げない。塵肺（じんぱい）予防のために必須。" },
  { id: 1430, category: "anzen", source: "vocab-general", type: "vocab", furi: "みみせん", jp: "耳栓", id_text: "Penyumbat telinga / earplugs", desc: "例: 85dB以上の騒音環境（グラインダー・チッパー使用時）では耳栓または耳覆いを着用する義務がある。→ Lingkungan >85 dB wajib pakai pelindung telinga. Paparan bising berkepanjangan → 騒音性難聴 (tuli akibat kebisingan) yang tidak bisa sembuh." },
  { id: 1431, category: "anzen", source: "vocab-teori", type: "vocab", furi: "ほごめがね", jp: "保護めがね", id_text: "Kacamata pelindung / safety goggles", desc: "例: 金属を切断・研磨するとき、飛散する破片から目を守るため保護めがねを着用する。→ Wajib pakai saat menggerinda/memotong logam atau beton. コンタクトレンズ使用者は特に注意 — 粒子が目の中に入ると取り出せない。" },
  { id: 1433, category: "career", source: "vocab-teori", type: "vocab", furi: "けんせつきゃりああっぷしすてむ", jp: "CCUS（建設キャリアアップシステム）", id_text: "CCUS — kartu IC rekam riwayat karier konstruksi", desc: "例: CCUSカードを現場で毎日打刻すると、就業実績・資格・経験がデジタル管理される。→ Swipe kartu CCUS tiap hari merekam riwayat kerja secara digital. 外国人SSW労働者も登録が推奨（義務化進行中）。レベル評価で処遇改善につながる。" },
  { id: 1434, category: "career", source: "vocab-teori", type: "vocab", furi: "ぎのうれべる", jp: "技能レベル", id_text: "Level keahlian CCUS — level 1 (magang) s.d. 4", desc: "例: CCUSでは技能レベルが4段階で評価：レベル1=見習い → レベル4=職長・班長クラス。→ Level makin tinggi, upah yang wajar makin tinggi dan kesempatan kerja makin luas. SSWは経験を積みながらレベルアップを目指す。" },
  { id: 1435, category: "setsubi_kougu", source: "vocab-jac", type: "vocab", furi: "しつがいき", jp: "室外機", id_text: "Unit luar AC / outdoor unit (kompresor+kondenser)", desc: "例: 室外機は建物の外に設置し、冷媒を圧縮して熱を外に放出する。室外機と室内機は冷媒管で接続する。→ Unit luar berisi kompresor dan kondenser. 設置場所は通気性確保が必須 — 囲ったり日光が強すぎると効率低下。" },
  { id: 1436, category: "haikan", source: "vocab-jac", type: "vocab", furi: "しつないき", jp: "室内機", id_text: "Unit dalam AC / indoor unit (evaporator & fan)", desc: "例: 室内機は壁や天井に取り付け、蒸発器で冷媒が蒸発するときの吸熱作用で室内を冷やす。→ Unit dalam dipasang di dinding/plafon, mendinginkan ruangan melalui evaporasi refrigeran. ドレン配管で結露水を外部に排水する。" },
  { id: 1437, category: "haikan", source: "vocab-jac", type: "vocab", furi: "ふれあかこう", jp: "フレア加工", id_text: "Flare processing — kembangkan ujung pipa tembaga", desc: "例: 冷媒管の接続はフレア加工で行い、フレアツールで銅管の端を拡張してからフレアナットで締め付ける。→ Ujung pipa tembaga dikembangkan dengan flare tool sebelum disambung. フレア不完全 → 冷媒漏れの原因。正確な加工が品質を左右する重要工程。" },
  { id: 1438, category: "haikan", source: "vocab-jac", type: "vocab", furi: "どれんはいかん", jp: "ドレン配管", id_text: "Pipa drain AC — alirkan air kondensasi unit dalam", desc: "例: 室内機で発生した結露水（ドレン水）はドレン配管を通じて屋外または排水管へ排水する。→ Air kondensasi dari unit dalam dialirkan ke luar lewat pipa drain. 勾配不足 → 水が逆流・水漏れ。ドレン配管は必ず下り勾配（1/100以上）で施工。" }
];
